def _safe_qwen_path_mtime(path: Path) -> float:
    if path.is_symlink():
        return 0.0
    try:
        return path.stat().st_mtime
    except Exception:
        return 0.0


def _safe_qwen_checkpoint_dir(checkpoint_path: Path) -> Optional[Path]:
    if checkpoint_path.is_symlink():
        return None
    try:
        resolved = checkpoint_path.resolve(strict=True)
    except Exception:
        return None
    if not resolved.is_dir():
        return None
    return resolved


def _safe_qwen_checkpoint_file(checkpoint_root: Path, name: str) -> bool:
    return (
        _safe_existing_regular_file_within_root_impl(checkpoint_root / name, checkpoint_root)
        is not None
    )


def _qwen_checkpoint_is_usable(checkpoint_path: Path, metadata: Dict[str, Any]) -> bool:
    checkpoint_root = _safe_qwen_checkpoint_dir(checkpoint_path)
    if checkpoint_root is None:
        return False
    platform_name = normalize_qwen_platform((metadata or {}).get("runtime_platform"))
    if platform_name == QWEN_PLATFORM_AUTO and is_qwen_mlx_model_id(
        (metadata or {}).get("model_id") or (metadata or {}).get("requested_model_id")
    ):
        platform_name = QWEN_PLATFORM_MLX
    if platform_name == QWEN_PLATFORM_MLX:
        return _safe_qwen_checkpoint_file(
            checkpoint_root, "adapters.safetensors"
        ) and _safe_qwen_checkpoint_file(checkpoint_root, "adapter_config.json")
    return _safe_qwen_checkpoint_file(checkpoint_root, "adapter_config.json") and any(
        _safe_qwen_checkpoint_file(checkpoint_root, name)
        for name in ("adapter_model.safetensors", "adapter_model.bin")
    )


def _resolve_qwen_run_checkpoint_path(run_dir: Path, raw_path: Any) -> Optional[Path]:
    raw = str(raw_path or "").strip()
    if not raw:
        return None
    try:
        run_root = run_dir.resolve(strict=True)
    except Exception:
        return None
    candidate = Path(raw).expanduser()
    if not candidate.is_absolute():
        candidate = run_root / candidate
    if candidate.is_symlink():
        return None
    try:
        resolved = candidate.resolve(strict=True)
    except Exception:
        return None
    if not _path_is_within_root_impl(resolved, run_root):
        return None
    if not resolved.is_dir():
        return None
    return resolved


def _list_qwen_model_entries() -> List[Dict[str, Any]]:
    """Return registry entries for custom Qwen fine-tunes (if any)."""
    try:
        runs_root = _qwen_training_runs_root(create=False, detail="qwen_run_path_invalid")
    except HTTPException:
        return []
    if not runs_root.exists():
        return []
    candidates: List[Dict[str, Any]] = []
    run_dirs: List[Path] = []
    for path in runs_root.iterdir():
        if path.is_symlink():
            continue
        try:
            run_dir = path.resolve(strict=True)
        except Exception:
            continue
        if not _path_is_within_root_impl(run_dir, runs_root):
            continue
        if not run_dir.is_dir():
            continue
        run_dirs.append(run_dir)
    run_dirs = sorted(run_dirs, key=_safe_qwen_path_mtime, reverse=True)
    for run_dir in run_dirs:
        meta_path = _safe_existing_regular_file_within_root_impl(
            run_dir / QWEN_METADATA_FILENAME, run_dir
        )
        metadata: Dict[str, Any] = {}
        if meta_path is not None:
            try:
                loaded = json.loads(meta_path.read_text(encoding="utf-8"))
                if isinstance(loaded, dict):
                    metadata = loaded
            except Exception:
                metadata = {}
        model_id = str(metadata.get("id") or run_dir.name)
        latest = metadata.get("latest_checkpoint")
        latest_path = _resolve_qwen_run_checkpoint_path(run_dir, latest or "latest")
        if latest_path is None or not latest_path.exists():
            latest_path = None
            checkpoints = metadata.get("checkpoints") or []
            for candidate in checkpoints:
                candidate_path = _resolve_qwen_run_checkpoint_path(run_dir, candidate)
                if candidate_path and candidate_path.exists():
                    latest_path = candidate_path
                    break
        if latest_path is None or not latest_path.exists():
            # Skip incomplete/corrupt runs that don't expose a usable checkpoint.
            continue
        if not _qwen_checkpoint_is_usable(latest_path, metadata):
            continue
        created_at = metadata.get("created_at")
        if not isinstance(created_at, (int, float)):
            try:
                created_at = float(run_dir.stat().st_mtime)
            except Exception:
                created_at = None
        candidates.append(
            {
                "id": model_id,
                "label": str(metadata.get("label") or run_dir.name),
                "type": "finetune",
                "metadata": metadata,
                "path": str(latest_path),
                "created_at": created_at,
            }
        )
    candidates.sort(
        key=lambda item: (
            float(item.get("created_at"))
            if isinstance(item.get("created_at"), (int, float))
            else 0.0
        ),
        reverse=True,
    )
    entries: List[Dict[str, Any]] = []
    seen_ids: set[str] = set()
    for candidate in candidates:
        cid = str(candidate.get("id") or "")
        if not cid or cid in seen_ids:
            continue
        seen_ids.add(cid)
        entries.append(candidate)
    return entries


def _get_qwen_model_entry(model_id: str) -> Optional[Dict[str, Any]]:
    for entry in _list_qwen_model_entries():
        if str(entry.get("id")) == str(model_id):
            return entry
    return None


def _prepare_for_qwen_training() -> None:
    _prepare_for_training_impl(
        unload_inference_runtimes_fn=lambda: _unload_inference_runtimes_impl(
            unload_non_qwen_fn=lambda: _unload_non_qwen_runtimes_impl(
                predictor_manager=predictor_manager,
                unload_sam3_text_fn=_unload_sam3_text_runtime,
                suspend_clip_fn=_suspend_clip_backbone,
                unload_dinov3_fn=_unload_dinov3_backbone,
                unload_detector_fn=_unload_detector_inference,
                torch_module=torch,
                logger=logger,
            ),
            unload_qwen_fn=_unload_qwen_runtime,
            torch_module=torch,
        )
    )


def _finalize_qwen_training_environment() -> None:
    _finalize_training_environment_impl(
        resume_classifier_fn=_resume_classifier_backbone,
        torch_module=torch,
    )


def _bytes_to_mb(value: int) -> float:
    return round(value / (1024 * 1024), 2)


def _qwen_memory_snapshot() -> Dict[str, Any]:
    process_ram_mb = None
    system_total_mb = None
    system_available_mb = None
    try:
        process_ram_mb = _bytes_to_mb(int(psutil.Process(os.getpid()).memory_info().rss))
        vm = psutil.virtual_memory()
        system_total_mb = _bytes_to_mb(int(vm.total))
        system_available_mb = _bytes_to_mb(int(vm.available))
    except Exception:
        pass
    payload: Dict[str, Any] = {
        "backend": "system",
        "devices": [],
        "process_ram_mb": process_ram_mb,
        "system_total_mb": system_total_mb,
        "system_available_mb": system_available_mb,
    }
    try:
        if torch.cuda.is_available():
            devices: List[Dict[str, Any]] = []
            for idx in range(torch.cuda.device_count()):
                device_info: Dict[str, Any] = {"index": idx}
                try:
                    props = torch.cuda.get_device_properties(idx)
                    device_info["name"] = props.name
                    device_info["total_mb"] = _bytes_to_mb(int(props.total_memory))
                except Exception:
                    device_info["name"] = f"cuda:{idx}"
                try:
                    free_bytes, total_bytes = torch.cuda.mem_get_info(idx)
                    total_mb = _bytes_to_mb(int(total_bytes))
                    free_mb = _bytes_to_mb(int(free_bytes))
                    device_info["total_mb"] = total_mb
                    device_info["free_mb"] = free_mb
                    device_info["used_mb"] = round(total_mb - free_mb, 2)
                except Exception:
                    device_info["free_mb"] = None
                    device_info["used_mb"] = None
                try:
                    device_info["allocated_mb"] = _bytes_to_mb(
                        int(torch.cuda.memory_allocated(idx))
                    )
                    device_info["reserved_mb"] = _bytes_to_mb(int(torch.cuda.memory_reserved(idx)))
                except Exception:
                    pass
                devices.append(device_info)
            payload["backend"] = "cuda"
            payload["devices"] = devices
            return payload
    except Exception as exc:  # noqa: BLE001
        payload["error"] = str(exc)
    if MLX_CORE is not None:
        payload["backend"] = "mlx"
        try:
            payload["mlx_active_mb"] = _bytes_to_mb(int(MLX_CORE.get_active_memory()))
        except Exception:
            payload["mlx_active_mb"] = None
        try:
            payload["mlx_peak_mb"] = _bytes_to_mb(int(MLX_CORE.get_peak_memory()))
        except Exception:
            payload["mlx_peak_mb"] = None
        try:
            payload["mlx_cache_mb"] = _bytes_to_mb(int(MLX_CORE.get_cache_memory()))
        except Exception:
            payload["mlx_cache_mb"] = None
    elif TATOR_ALLOW_MPS and _torch_mps_available_impl(torch):
        payload["backend"] = "mps"
        payload["devices"] = [{"index": "mps", "name": "Apple Metal Performance Shaders"}]
    return payload


def _qwen_cache_snapshot_path(model_id: str) -> Optional[Path]:
    raw = str(model_id or "").strip()
    if not raw:
        return None
    candidate = Path(raw).expanduser()
    if candidate.exists():
        return candidate.resolve()
    try:
        repo_path = _qwen_cache_repo_path(raw)
        if repo_path and repo_path.exists():
            for ref_name in ("main", "master"):
                ref_path = repo_path / "refs" / ref_name
                try:
                    commit = ref_path.read_text(encoding="utf-8").strip()
                except Exception:
                    commit = ""
                if commit:
                    snapshot_path = repo_path / "snapshots" / commit
                    if snapshot_path.exists():
                        return snapshot_path.resolve()
            snapshots_dir = repo_path / "snapshots"
            if snapshots_dir.exists():
                snapshot_dirs = [path for path in snapshots_dir.iterdir() if path.is_dir()]
                if snapshot_dirs:
                    return max(snapshot_dirs, key=lambda path: path.stat().st_mtime).resolve()
    except Exception:
        pass
    try:
        from huggingface_hub import try_to_load_from_cache
    except Exception:
        return None
    for filename in ("config.json", "tokenizer_config.json", "preprocessor_config.json"):
        try:
            cached = try_to_load_from_cache(raw, filename)
        except Exception:
            cached = None
        if isinstance(cached, str) and cached and os.path.exists(cached):
            cached_path = Path(cached).resolve()
            if "snapshots" in cached_path.parts:
                return cached_path.parent
            return cached_path.parent
    return None


def _qwen_snapshot_has_weights(snapshot_path: Optional[Path]) -> bool:
    if snapshot_path is None or not snapshot_path.exists() or not snapshot_path.is_dir():
        return False
    for pattern in (
        "*.safetensors",
        "*.bin",
        "*.gguf",
        "*.npz",
        "model.safetensors.index.json",
        "pytorch_model.bin.index.json",
    ):
        try:
            if any(snapshot_path.glob(pattern)):
                return True
        except Exception:
            continue
    return False


def _format_qwen_bytes(byte_count: Optional[int]) -> str:
    try:
        value = float(byte_count or 0)
    except Exception:
        value = 0.0
    units = ("B", "KB", "MB", "GB", "TB")
    for unit in units:
        if value < 1024.0 or unit == units[-1]:
            if unit == "B":
                return f"{int(value)} {unit}"
            return f"{value:.1f} {unit}"
        value /= 1024.0
    return f"{value:.1f} TB"


def _qwen_cache_repo_path(model_id: str) -> Optional[Path]:
    raw = str(model_id or "").strip()
    if not raw or raw.startswith(("http://", "https://")):
        return None
    candidate = Path(raw).expanduser()
    if candidate.exists():
        return candidate.resolve()
    cache_root = (
        os.environ.get("HUGGINGFACE_HUB_CACHE")
        or os.environ.get("HF_HUB_CACHE")
        or os.environ.get("TRANSFORMERS_CACHE")
    )
    if cache_root:
        hub_dir = Path(cache_root).expanduser()
    else:
        hf_home = Path(os.environ.get("HF_HOME", "~/.cache/huggingface")).expanduser()
        hub_dir = hf_home / "hub"
    return hub_dir / f"models--{raw.replace('/', '--')}"


def _qwen_cache_tree_stats(paths: Sequence[Optional[Path]]) -> Dict[str, Any]:
    total_bytes = 0
    file_count = 0
    newest_mtime = 0.0
    seen: Set[Tuple[int, int]] = set()
    for root in paths:
        if root is None:
            continue
        try:
            root_path = Path(root)
        except Exception:
            continue
        if not root_path.exists():
            continue
        try:
            iterator = root_path.rglob("*") if root_path.is_dir() else iter([root_path])
            for path in iterator:
                try:
                    if not path.is_file():
                        continue
                    stat_result = path.stat()
                except Exception:
                    continue
                inode_key = (int(getattr(stat_result, "st_dev", 0)), int(getattr(stat_result, "st_ino", 0)))
                if inode_key in seen:
                    continue
                seen.add(inode_key)
                file_count += 1
                total_bytes += int(getattr(stat_result, "st_size", 0) or 0)
                newest_mtime = max(newest_mtime, float(getattr(stat_result, "st_mtime", 0.0) or 0.0))
        except Exception:
            continue
    return {"bytes": total_bytes, "files": file_count, "newest_mtime": newest_mtime}


def _qwen_loaded_for_model(model_id: str, platform_name: str) -> bool:
    effective_id = _effective_qwen_model_id_for_platform(model_id, platform_name)
    if qwen_model is not None and qwen_loaded_effective_model_id == effective_id:
        return True
    cache_suffix = f":{effective_id}"
    try:
        return any(str(key).endswith(cache_suffix) for key in qwen_caption_cache.keys())
    except Exception:
        return False


def _qwen_model_local_state(
    model_id: Optional[str],
    platform_name: Optional[str] = None,
    *,
    entry_path: Optional[str] = None,
) -> Dict[str, Any]:
    raw_model_id = str(model_id or QWEN_MODEL_NAME).strip() or QWEN_MODEL_NAME
    platform = platform_name or _resolve_qwen_runtime_platform(raw_model_id)
    effective_id = _effective_qwen_model_id_for_platform(raw_model_id, platform)
    local_path = Path(entry_path).expanduser() if entry_path else None
    if local_path and local_path.exists():
        snapshot_path = local_path.resolve()
        local = True
        partial = False
    else:
        snapshot_path = _qwen_cache_snapshot_path(effective_id)
        has_weights = _qwen_snapshot_has_weights(snapshot_path)
        local = bool(snapshot_path and has_weights)
        partial = bool(snapshot_path and not has_weights)
    return {
        "model_id": raw_model_id,
        "effective_model_id": effective_id,
        "platform": platform,
        "local": bool(local),
        "partial": bool(partial),
        "needs_download": not bool(local),
        "cache_path": str(snapshot_path) if snapshot_path else None,
        "loaded": _qwen_loaded_for_model(raw_model_id, platform),
    }


def _qwen_progress_start(
    *,
    kind: str,
    model_id: Optional[str],
    platform: Optional[str],
    message: str,
    max_new_tokens: Optional[int] = None,
) -> str:
    now = time.time()
    availability = _qwen_model_local_state(model_id, platform)
    run_id = uuid.uuid4().hex
    qwen_cancel_event.clear()
    with qwen_progress_lock:
        qwen_progress_state.clear()
        qwen_progress_state.update(
            {
                "run_id": run_id,
                "active": True,
                "kind": kind,
                "phase": "prepare",
                "phase_label": "Preparing",
                "progress": 0.02,
                "message": message,
                "model_id": availability.get("effective_model_id") or model_id,
                "platform": availability.get("platform") or platform,
                "local": availability.get("local"),
                "partial": availability.get("partial"),
                "needs_download": availability.get("needs_download"),
                "cache_path": availability.get("cache_path"),
                "loaded": availability.get("loaded"),
                "input_tokens": None,
                "generated_tokens": 0,
                "max_new_tokens": max_new_tokens,
                "token_preview": "",
                "started_at": now,
                "updated_at": now,
                "completed_at": None,
                "error": None,
                "cancel_requested": False,
                "cancel_force": False,
                "step_id": None,
                "step_index": None,
                "step_total": None,
                "step_label": None,
                "step_detail": None,
                "step_region": None,
                "step_plan": [],
                "live_output": "",
                "log_lines": [
                    f"{time.strftime('%H:%M:%S')} queued {kind} for {availability.get('effective_model_id') or model_id or 'Qwen'}",
                ],
            }
        )
    if kind == "caption":
        _qwen_caption_io_reset_latest(run_id)
        _qwen_caption_io_record(
            {
                "event": "run_start",
                "source": "qwen_caption",
                "model_id": availability.get("effective_model_id") or model_id,
                "runtime_platform": availability.get("platform") or platform,
                "max_new_tokens": max_new_tokens,
                "message": message,
            }
        )
    return run_id


class QwenCancellationRequested(RuntimeError):
    """Raised when the active Qwen request has been cancelled."""


def _qwen_cancel_requested() -> bool:
    return qwen_cancel_event.is_set()


def _raise_if_qwen_cancelled() -> None:
    if _qwen_cancel_requested():
        raise QwenCancellationRequested("qwen_cancelled")


def _schedule_qwen_backend_restart_after_cancel(delay_seconds: float = 0.4) -> None:
    def _restart() -> None:
        time.sleep(max(0.05, float(delay_seconds)))
        logger.warning("[qwen-cancel] exiting backend with restart code %s", QWEN_CANCEL_RESTART_EXIT_CODE)
        os._exit(QWEN_CANCEL_RESTART_EXIT_CODE)

    threading.Thread(target=_restart, name="qwen-cancel-backend-restart", daemon=True).start()


def _qwen_progress_cancelled(message: str) -> None:
    now = time.time()
    with qwen_progress_lock:
        qwen_progress_state.update(
            {
                "active": False,
                "phase": "cancelled",
                "phase_label": "Cancelled",
                "progress": 1.0,
                "message": message,
                "updated_at": now,
                "completed_at": now,
                "error": "cancelled",
                "cancel_requested": True,
            }
        )


def cancel_qwen_caption(*, force: bool = False) -> Dict[str, Any]:
    now = time.time()
    with qwen_progress_lock:
        active = bool(qwen_progress_state.get("active"))
        kind = qwen_progress_state.get("kind")
        run_id = qwen_progress_state.get("run_id")
        if not active or kind != "caption":
            return {
                "cancelled": False,
                "active": active,
                "kind": kind,
                "message": "No active Qwen caption request.",
            }
        qwen_cancel_event.set()
        message = (
            "Caption cancellation requested; restarting backend to stop the active Qwen process"
            if force
            else "Caption cancellation requested"
        )
        qwen_progress_state.update(
            {
                "phase": "cancelling",
                "phase_label": "Cancelling",
                "message": message,
                "updated_at": now,
                "cancel_requested": True,
                "cancel_force": bool(force),
            }
        )
        lines = qwen_progress_state.get("log_lines")
        if not isinstance(lines, list):
            lines = []
        lines.append(f"{time.strftime('%H:%M:%S')} {message}")
        qwen_progress_state["log_lines"] = lines[-80:]
    if force:
        _schedule_qwen_backend_restart_after_cancel()
    return {
        "cancelled": True,
        "active": active,
        "kind": kind,
        "run_id": run_id,
        "force": bool(force),
        "message": message,
    }


def _qwen_progress_log(message: str) -> None:
    text = str(message or "").strip()
    if not text:
        return
    line = f"{time.strftime('%H:%M:%S')} {text}"
    with qwen_progress_lock:
        if not qwen_progress_state.get("active"):
            return
        lines = qwen_progress_state.get("log_lines")
        if not isinstance(lines, list):
            lines = []
        lines.append(line)
        qwen_progress_state["log_lines"] = lines[-80:]
        qwen_progress_state["updated_at"] = time.time()


def _clean_qwen_step_plan(step_plan: Sequence[Mapping[str, Any]]) -> List[Dict[str, Any]]:
    cleaned: List[Dict[str, Any]] = []
    for index, raw_entry in enumerate(step_plan):
        if not isinstance(raw_entry, Mapping):
            continue
        raw_id = str(raw_entry.get("id") or "").strip()
        step_id = raw_id or f"step_{index + 1}"
        entry: Dict[str, Any] = {
            "id": step_id,
            "label": str(raw_entry.get("label") or step_id).strip() or step_id,
        }
        detail = str(raw_entry.get("detail") or "").strip()
        if detail:
            entry["detail"] = detail
        region = raw_entry.get("region")
        if isinstance(region, Mapping):
            entry["region"] = _clean_qwen_step_region(region)
        cleaned.append(entry)
    return cleaned


def _clean_qwen_step_region(region: Optional[Mapping[str, Any]]) -> Optional[Dict[str, Any]]:
    if not isinstance(region, Mapping):
        return None
    cleaned: Dict[str, Any] = {}
    for key in ("x", "y", "width", "height", "image_width", "image_height"):
        if key not in region:
            continue
        try:
            cleaned[key] = float(region.get(key))
        except (TypeError, ValueError):
            continue
    for key in ("image_name", "label", "kind"):
        value = str(region.get(key) or "").strip()
        if value:
            cleaned[key] = value
    if bool(region.get("full_image")):
        cleaned["full_image"] = True
    if not cleaned:
        return None
    return cleaned


def _qwen_caption_step_entry(step_id: str, label: str, detail: str = "") -> Dict[str, str]:
    entry = {"id": step_id, "label": label}
    if detail:
        entry["detail"] = detail
    return entry


def _build_qwen_caption_step_plan(
    *,
    caption_mode: str,
    total_windows: int,
    two_stage: bool,
    is_thinking: bool,
    force_unload: bool,
    caption_model_id: str,
    refinement_model_id: str,
) -> List[Dict[str, str]]:
    plan: List[Dict[str, str]] = [
        _qwen_caption_step_entry("prepare", "Prepare image and prompts"),
        _qwen_caption_step_entry(
            "load_model",
            "Load caption model",
            (
                f"Caption model: {caption_model_id}; refinement model: {refinement_model_id}"
                if refinement_model_id and refinement_model_id != caption_model_id
                else f"Caption model: {caption_model_id}"
            ),
        ),
    ]
    if caption_mode == "windowed":
        for window_index in range(1, max(1, int(total_windows or 1)) + 1):
            plan.append(
                _qwen_caption_step_entry(
                    f"window_{window_index}",
                    f"Window observation {window_index}/{max(1, int(total_windows or 1))}",
                    (
                        "Crop caption used as source material before final composition; "
                        "Draft + refine does not run per crop."
                    ),
                )
            )
    if two_stage and is_thinking:
        plan.extend(
            [
                _qwen_caption_step_entry(
                    "draft_caption",
                    "Two-stage 1/2: draft full image",
                    "Thinking-only full-image draft pass after any window observations are collected.",
                ),
                _qwen_caption_step_entry(
                    "refine_draft",
                    "Two-stage 2/2: refine draft",
                    "Editor pass over the draft, full prompt context, and raw first-stage outputs. Separate from window merge.",
                ),
            ]
        )
    else:
        plan.append(
            _qwen_caption_step_entry(
                "generate_full",
                "Compose full-image caption",
                "Uses the full image, generated detection context, and any window observations already collected.",
            )
        )
    if caption_mode == "windowed":
        plan.append(
            _qwen_caption_step_entry(
                "merge_windows",
                "Window merge: fold in sub-captions",
                "Windowed-only editor pass that runs after full-image composition when crop captions exist.",
            )
        )
    plan.append(
        _qwen_caption_step_entry(
            "postprocess",
            "Quality guard checks",
            "Cleanup, coverage refinement, and language checks run only if needed.",
        )
    )
    if force_unload:
        plan.append(_qwen_caption_step_entry("unload_model", "Unload caption model"))
    plan.append(_qwen_caption_step_entry("finalize", "Finalize caption"))
    return plan


def _qwen_progress_begin_output_section(label: str) -> None:
    text = str(label or "").strip()
    if not text:
        return
    with qwen_progress_lock:
        existing = str(qwen_progress_state.get("live_output") or "")
    prefix = "\n\n" if existing else ""
    _qwen_progress_update(token_preview="", generated_tokens=0, live_output_piece=f"{prefix}{text}\n")


def _start_qwen_cache_monitor(
    *,
    model_id: str,
    platform: str,
    phase: str,
    phase_label: str,
    paths: Sequence[Optional[Path]],
    start_progress: float,
    max_progress: float,
) -> Tuple[threading.Event, threading.Thread]:
    stop_event = threading.Event()

    def _monitor() -> None:
        started = time.time()
        last_bytes: Optional[int] = None
        last_change = started
        last_log = ""
        while not stop_event.wait(2.0):
            now = time.time()
            stats = _qwen_cache_tree_stats(paths)
            byte_count = int(stats.get("bytes") or 0)
            file_count = int(stats.get("files") or 0)
            delta: Optional[int] = None
            if last_bytes is not None:
                delta = byte_count - last_bytes
                if delta > 0:
                    last_change = now
            last_bytes = byte_count
            elapsed = max(0.0, now - started)
            stale_elapsed = max(0.0, now - last_change)
            span = max(0.0, max_progress - start_progress)
            progress = start_progress + span * min(1.0, elapsed / 240.0)
            message_bits = [
                f"{_format_qwen_bytes(byte_count)} cached",
                f"{file_count} files",
                f"{int(elapsed)}s elapsed",
            ]
            if delta is not None and delta > 0:
                message_bits.append(f"+{_format_qwen_bytes(delta)} since last check")
            elif stale_elapsed >= 20:
                message_bits.append(f"no cache growth for {int(stale_elapsed)}s")
            message = f"{phase_label} {'; '.join(message_bits)}"
            _qwen_progress_update(
                phase=phase,
                phase_label=phase_label,
                progress=progress,
                message=message,
                model_id=model_id,
                platform=platform,
            )
            if message != last_log:
                _qwen_progress_log(message)
                last_log = message

    thread = threading.Thread(target=_monitor, name="qwen-cache-monitor", daemon=True)
    thread.start()
    return stop_event, thread


def _qwen_progress_update(
    *,
    phase: Optional[str] = None,
    phase_label: Optional[str] = None,
    progress: Optional[float] = None,
    message: Optional[str] = None,
    model_id: Optional[str] = None,
    platform: Optional[str] = None,
    input_tokens: Optional[int] = None,
    generated_tokens: Optional[int] = None,
    max_new_tokens: Optional[int] = None,
    token_piece: Optional[str] = None,
    token_preview: Optional[str] = None,
    step_id: Optional[str] = None,
    step_index: Optional[int] = None,
    step_total: Optional[int] = None,
    step_label: Optional[str] = None,
    step_detail: Optional[str] = None,
    step_region: Optional[Mapping[str, Any]] = None,
    step_plan: Optional[Sequence[Mapping[str, Any]]] = None,
    live_output: Optional[str] = None,
    live_output_piece: Optional[str] = None,
    live_output_reset: bool = False,
    append_token_preview_to_live_output: bool = False,
) -> None:
    now = time.time()
    with qwen_progress_lock:
        if not qwen_progress_state.get("active"):
            return
        if qwen_progress_state.get("cancel_requested") and phase not in {"cancelling", "cancelled"}:
            qwen_progress_state["updated_at"] = now
            return
        cleaned_plan: Optional[List[Dict[str, Any]]] = None
        if step_plan is not None:
            cleaned_plan = _clean_qwen_step_plan(step_plan)
            qwen_progress_state["step_plan"] = cleaned_plan
            if step_total is None:
                step_total = len(cleaned_plan)
        if step_id is not None:
            current_step_id = str(step_id or "").strip() or None
            qwen_progress_state["step_id"] = current_step_id
            plan_for_lookup = cleaned_plan
            if plan_for_lookup is None:
                existing_plan = qwen_progress_state.get("step_plan")
                plan_for_lookup = existing_plan if isinstance(existing_plan, list) else []
            if current_step_id and plan_for_lookup:
                for idx, entry in enumerate(plan_for_lookup):
                    if not isinstance(entry, Mapping):
                        continue
                    if str(entry.get("id") or "") == current_step_id:
                        if step_index is None:
                            step_index = idx + 1
                        if step_total is None:
                            step_total = len(plan_for_lookup)
                        if step_label is None:
                            step_label = str(entry.get("label") or "")
                        if step_detail is None and entry.get("detail"):
                            step_detail = str(entry.get("detail") or "")
                        if step_region is None and isinstance(entry.get("region"), Mapping):
                            step_region = entry.get("region")  # type: ignore[assignment]
                        break
        if step_index is not None:
            try:
                qwen_progress_state["step_index"] = max(1, int(step_index))
            except Exception:
                pass
        if step_total is not None:
            try:
                qwen_progress_state["step_total"] = max(1, int(step_total))
            except Exception:
                pass
        if step_label is not None:
            qwen_progress_state["step_label"] = str(step_label)
        if step_detail is not None:
            qwen_progress_state["step_detail"] = str(step_detail)
        if step_region is not None:
            qwen_progress_state["step_region"] = _clean_qwen_step_region(step_region)
        if phase is not None:
            qwen_progress_state["phase"] = phase
        if phase_label is not None:
            qwen_progress_state["phase_label"] = phase_label
        if progress is not None:
            qwen_progress_state["progress"] = clamp_progress(
                progress,
                fallback=qwen_progress_state.get("progress", 0.0),
            )
        if message is not None:
            qwen_progress_state["message"] = message
        if model_id is not None:
            qwen_progress_state["model_id"] = model_id
        if platform is not None:
            qwen_progress_state["platform"] = platform
        if input_tokens is not None:
            qwen_progress_state["input_tokens"] = input_tokens
        if generated_tokens is not None:
            qwen_progress_state["generated_tokens"] = generated_tokens
        if max_new_tokens is not None:
            qwen_progress_state["max_new_tokens"] = max_new_tokens
        if token_preview is not None:
            qwen_progress_state["token_preview"] = str(token_preview)[-4000:]
            if append_token_preview_to_live_output and token_preview:
                current_live = str(qwen_progress_state.get("live_output") or "")
                qwen_progress_state["live_output"] = f"{current_live}{token_preview}"[-16000:]
        if token_piece:
            current = str(qwen_progress_state.get("token_preview") or "")
            qwen_progress_state["token_preview"] = f"{current}{token_piece}"[-4000:]
            if generated_tokens is None:
                qwen_progress_state["generated_tokens"] = int(
                    qwen_progress_state.get("generated_tokens") or 0
                ) + 1
        if live_output_reset:
            qwen_progress_state["live_output"] = ""
        if live_output is not None:
            qwen_progress_state["live_output"] = str(live_output)[-16000:]
        if live_output_piece:
            current_live = str(qwen_progress_state.get("live_output") or "")
            qwen_progress_state["live_output"] = f"{current_live}{live_output_piece}"[-16000:]
        qwen_progress_state["updated_at"] = now


def _qwen_progress_token(token_piece: str, *, generated_tokens: Optional[int], max_new_tokens: Optional[int]) -> None:
    if not token_piece:
        return
    with qwen_progress_lock:
        current_generated = int(qwen_progress_state.get("generated_tokens") or 0)
        is_caption_run = qwen_progress_state.get("kind") == "caption"
    generated = generated_tokens if generated_tokens is not None else current_generated + 1
    max_tokens = max_new_tokens
    if max_tokens is None:
        with qwen_progress_lock:
            max_tokens = qwen_progress_state.get("max_new_tokens")
    try:
        max_token_count = max(1, int(max_tokens or 0))
    except Exception:
        max_token_count = 1
    fraction = min(1.0, float(generated) / float(max_token_count))
    _qwen_progress_update(
        phase="generate",
        phase_label="Generating",
        progress=0.55 + (0.35 * fraction),
        message="Generating response tokens",
        generated_tokens=int(generated),
        max_new_tokens=max_tokens,
        token_piece=token_piece,
        live_output_piece=token_piece if is_caption_run else None,
    )


def _qwen_caption_io_logging_enabled() -> bool:
    if os.environ.get("TATOR_QWEN_LOG_ALL_IO", "").strip().lower() in {"1", "true", "yes", "on"}:
        return True
    with qwen_progress_lock:
        return qwen_progress_state.get("kind") == "caption" and bool(qwen_progress_state.get("active"))


def _qwen_caption_io_snapshot() -> Dict[str, Any]:
    with qwen_progress_lock:
        return {
            "run_id": qwen_progress_state.get("run_id"),
            "kind": qwen_progress_state.get("kind"),
            "phase": qwen_progress_state.get("phase"),
            "phase_label": qwen_progress_state.get("phase_label"),
            "step_id": qwen_progress_state.get("step_id"),
            "step_index": qwen_progress_state.get("step_index"),
            "step_total": qwen_progress_state.get("step_total"),
            "step_label": qwen_progress_state.get("step_label"),
            "step_detail": qwen_progress_state.get("step_detail"),
        }


def _qwen_caption_io_jsonable(value: Any) -> Any:
    if isinstance(value, Image.Image):
        return {
            "type": "image",
            "mode": value.mode,
            "width": int(value.width),
            "height": int(value.height),
        }
    if isinstance(value, dict):
        return {str(key): _qwen_caption_io_jsonable(item) for key, item in value.items()}
    if isinstance(value, (list, tuple)):
        return [_qwen_caption_io_jsonable(item) for item in value]
    return _agent_trace_full_jsonable(value)


def _qwen_caption_io_safe_int(value: Any) -> Optional[int]:
    if value is None:
        return None
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def _qwen_caption_io_paths(run_id: Optional[str]) -> Tuple[Path, Path, Path, Path]:
    log_root = globals().get("LOG_ROOT", Path("logs"))
    run_root = log_root / "qwen_caption_io"
    safe_run_id = re.sub(r"[^a-zA-Z0-9_.-]+", "_", str(run_id or "manual"))[:80] or "manual"
    return (
        run_root / f"{safe_run_id}.jsonl",
        run_root / f"{safe_run_id}.log",
        log_root / "qwen_caption_io_latest.jsonl",
        log_root / "qwen_caption_io_latest.log",
    )


def _qwen_caption_io_prepare_parent(path: Path) -> Optional[Path]:
    try:
        if _storage_path_has_symlink_component(path.parent):
            return None
        path.parent.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(path.parent):
            return None
        parent_root = path.parent.resolve(strict=True)
        if not parent_root.is_dir():
            return None
        return parent_root
    except Exception:
        return None


def _qwen_caption_io_prepare_file(path: Path) -> Optional[Path]:
    try:
        parent_root = _qwen_caption_io_prepare_parent(path)
        if parent_root is None:
            return None
        if path.is_symlink():
            path.unlink(missing_ok=True)
        elif path.exists() and not path.is_file():
            return None
        try:
            path.resolve(strict=False).relative_to(parent_root)
        except Exception:
            return None
        return path
    except Exception:
        return None


def _qwen_caption_io_write_file(path: Path, text: str, *, append: bool) -> None:
    safe_path = _qwen_caption_io_prepare_file(path)
    if safe_path is None:
        return
    flags = os.O_WRONLY | os.O_CREAT | (os.O_APPEND if append else os.O_TRUNC)
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    fd = os.open(safe_path, flags, 0o644)
    mode = "a" if append else "w"
    with os.fdopen(fd, mode, encoding="utf-8") as handle:
        handle.write(text)


def _write_temp_text_no_follow(path: Path, text: str, *, exclusive: bool = False) -> None:
    flags = os.O_WRONLY | os.O_CREAT
    flags |= os.O_EXCL if exclusive else os.O_TRUNC
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    fd = os.open(path, flags, 0o644)
    with os.fdopen(fd, "w", encoding="utf-8") as handle:
        handle.write(text)


def _write_temp_binary_no_follow(
    path: Path, writer: Callable[[Any], None], *, exclusive: bool = False
) -> None:
    flags = os.O_WRONLY | os.O_CREAT
    flags |= os.O_EXCL if exclusive else os.O_TRUNC
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    fd = os.open(path, flags, 0o644)
    with os.fdopen(fd, "wb") as handle:
        writer(handle)


def _qwen_caption_io_reset_latest(run_id: Optional[str]) -> None:
    jsonl_path, text_path, latest_jsonl_path, latest_text_path = _qwen_caption_io_paths(run_id)
    for path in (latest_jsonl_path, latest_text_path):
        try:
            _qwen_caption_io_write_file(path, "", append=False)
        except Exception as exc:
            logger.debug("[qwen-caption-io] failed to reset %s: %s", path, exc)
    for path in (jsonl_path, text_path):
        try:
            _qwen_caption_io_prepare_parent(path)
        except Exception:
            pass


def _qwen_caption_io_message_text(messages: Optional[Sequence[Mapping[str, Any]]]) -> str:
    lines: List[str] = []
    for message in messages or []:
        role = str(message.get("role") or "message")
        lines.append(f"[{role}]")
        content = message.get("content")
        if isinstance(content, str):
            lines.append(content)
            continue
        if not isinstance(content, (list, tuple)):
            lines.append(str(content))
            continue
        for item in content:
            if not isinstance(item, Mapping):
                lines.append(str(item))
                continue
            item_type = str(item.get("type") or "")
            if item_type == "text":
                lines.append(str(item.get("text") or ""))
            elif item_type == "image":
                image = item.get("image")
                if isinstance(image, Image.Image):
                    lines.append(f"<image {image.width}x{image.height} mode={image.mode}>")
                else:
                    lines.append("<image>")
            else:
                lines.append(str(_qwen_caption_io_jsonable(item)))
    return "\n".join(lines).strip()


def _qwen_caption_io_record(record: Mapping[str, Any]) -> None:
    if not _qwen_caption_io_logging_enabled():
        return
    snapshot = _qwen_caption_io_snapshot()
    run_id = snapshot.get("run_id")
    try:
        record_payload = dict(record)
    except Exception:
        record_payload = {"event": "record_encode_failed", "record": str(record)}
    payload = {
        "ts": time.time(),
        "time": time.strftime("%Y-%m-%d %H:%M:%S", time.localtime()),
        "event_id": uuid.uuid4().hex,
        **snapshot,
        **record_payload,
    }
    try:
        jsonl_path, text_path, latest_jsonl_path, latest_text_path = _qwen_caption_io_paths(run_id)
    except Exception as exc:
        logger.debug("[qwen-caption-io] failed to resolve log paths: %s", exc)
        return
    try:
        jsonable = _qwen_caption_io_jsonable(payload)
    except Exception:
        jsonable = {"type": "qwen_caption_io_encode_failed", "record": str(payload)}
    for path in (jsonl_path, latest_jsonl_path):
        try:
            _qwen_caption_io_write_file(
                path, json.dumps(jsonable, ensure_ascii=False) + "\n", append=True
            )
        except Exception as exc:
            logger.debug("[qwen-caption-io] failed to write %s: %s", path, exc)
    try:
        readable = _qwen_caption_io_readable(payload)
    except Exception as exc:
        logger.debug("[qwen-caption-io] failed to format readable log: %s", exc)
        readable = ""
    if readable:
        for path in (text_path, latest_text_path):
            try:
                _qwen_caption_io_write_file(path, readable, append=True)
            except Exception as exc:
                logger.debug("[qwen-caption-io] failed to write %s: %s", path, exc)


def _qwen_caption_io_readable(record: Mapping[str, Any]) -> str:
    event = str(record.get("event") or "event")
    call_id = str(record.get("call_id") or "")
    step = str(record.get("step_label") or record.get("step_id") or "")
    title = f"===== {record.get('time')} {event}"
    if call_id:
        title = f"{title} call={call_id}"
    if step:
        title = f"{title} step={step}"
    lines = [f"{title} ====="]
    for key in (
        "source",
        "runtime_platform",
        "model_id",
        "max_new_tokens",
        "decode_override",
        "chat_template_kwargs",
        "image_width",
        "image_height",
        "loop_detected",
    ):
        if key in record and record.get(key) is not None:
            lines.append(f"{key}: {record.get(key)}")
    messages = record.get("messages")
    message_text = _qwen_caption_io_message_text(messages if isinstance(messages, (list, tuple)) else None)
    if message_text:
        lines.extend(["", "--- messages ---", message_text])
    for key, heading in (
        ("system_prompt", "system prompt"),
        ("user_prompt", "user prompt"),
        ("rendered_prompt", "rendered prompt"),
        ("prompt_text", "prompt text"),
        ("raw_output", "raw output"),
        ("trimmed_output", "trimmed output"),
        ("output_text", "output text"),
    ):
        value = record.get(key)
        if value:
            lines.extend(["", f"--- {heading} ---", str(value)])
    lines.append("")
    return "\n".join(lines) + "\n"


def _qwen_caption_io_input(
    *,
    call_id: str,
    source: str,
    model_id: str,
    runtime_platform: Optional[str] = None,
    messages: Optional[Sequence[Mapping[str, Any]]] = None,
    prompt_text: Optional[str] = None,
    rendered_prompt: Optional[str] = None,
    system_prompt: Optional[str] = None,
    user_prompt: Optional[str] = None,
    image_width: Optional[int] = None,
    image_height: Optional[int] = None,
    max_new_tokens: Optional[int] = None,
    decode_override: Optional[Dict[str, Any]] = None,
    chat_template_kwargs: Optional[Dict[str, Any]] = None,
) -> None:
    _qwen_caption_io_record(
        {
            "event": "input",
            "call_id": call_id,
            "source": source,
            "runtime_platform": runtime_platform,
            "model_id": model_id,
            "messages": messages,
            "prompt_text": prompt_text,
            "rendered_prompt": rendered_prompt,
            "system_prompt": system_prompt,
            "user_prompt": user_prompt,
            "image_width": image_width,
            "image_height": image_height,
            "max_new_tokens": _qwen_caption_io_safe_int(max_new_tokens),
            "decode_override": decode_override,
            "chat_template_kwargs": chat_template_kwargs,
        }
    )


def _qwen_caption_io_output(
    *,
    call_id: Optional[str],
    source: str,
    model_id: str,
    runtime_platform: Optional[str] = None,
    output_text: str,
    loop_detected: bool = False,
) -> None:
    _qwen_caption_io_record(
        {
            "event": "output",
            "call_id": call_id,
            "source": source,
            "runtime_platform": runtime_platform,
            "model_id": model_id,
            "output_text": output_text,
            "loop_detected": bool(loop_detected),
        }
    )


def _qwen_maybe_trim_repetition_loop_output(
    output_text: str,
    *,
    triggered: bool = False,
    replace_live_output: bool = True,
) -> str:
    if not output_text:
        return output_text
    if not triggered and not _caption_repetition_loop_detected_impl(output_text):
        return output_text
    cleaned = _truncate_repeated_caption_loop_impl(output_text)
    if not cleaned:
        cleaned = output_text
    _qwen_caption_io_record(
        {
            "event": "loop_trim",
            "call_id": qwen_llm_call_id_var.get(),
            "raw_output": output_text,
            "trimmed_output": cleaned,
            "loop_detected": True,
        }
    )
    update_kwargs: Dict[str, Any] = {
        "phase": "cleanup",
        "phase_label": "Stopping Loop",
        "progress": 0.90,
        "message": "Stopped a repeated caption loop; cleaning generated text",
        "token_preview": cleaned,
    }
    if replace_live_output:
        update_kwargs["live_output"] = cleaned
    _qwen_progress_update(**update_kwargs)
    logger.warning("[qwen] stopped repeated caption loop after %s generated chars", len(output_text))
    return cleaned


def _qwen_progress_finish(message: str, *, token_preview: Optional[str] = None) -> None:
    now = time.time()
    with qwen_progress_lock:
        if qwen_progress_state.get("cancel_requested") or qwen_cancel_event.is_set():
            qwen_progress_state.update(
                {
                    "active": False,
                    "phase": "cancelled",
                    "phase_label": "Cancelled",
                    "progress": 1.0,
                    "message": "Qwen request cancelled",
                    "updated_at": now,
                    "completed_at": now,
                    "error": "cancelled",
                    "cancel_requested": True,
                }
            )
            return
        if token_preview is not None:
            qwen_progress_state["token_preview"] = str(token_preview)[-4000:]
        qwen_progress_state.update(
            {
                "active": False,
                "phase": "complete",
                "phase_label": "Complete",
                "progress": 1.0,
                "message": message,
                "loaded": qwen_model is not None or bool(qwen_caption_cache),
                "updated_at": now,
                "completed_at": now,
                "error": None,
            }
        )


def _qwen_progress_error(message: str) -> None:
    now = time.time()
    with qwen_progress_lock:
        if qwen_progress_state.get("cancel_requested") or qwen_cancel_event.is_set():
            qwen_progress_state.update(
                {
                    "active": False,
                    "phase": "cancelled",
                    "phase_label": "Cancelled",
                    "progress": 1.0,
                    "message": "Qwen request cancelled",
                    "updated_at": now,
                    "completed_at": now,
                    "error": "cancelled",
                    "cancel_requested": True,
                }
            )
            return
        qwen_progress_state.update(
            {
                "active": False,
                "phase": "error",
                "phase_label": "Error",
                "progress": 1.0,
                "message": message,
                "updated_at": now,
                "completed_at": now,
                "error": message,
            }
        )


def _http_exception_detail_text(exc: HTTPException) -> str:
    detail = getattr(exc, "detail", None)
    if isinstance(detail, str):
        return detail
    if detail is None:
        return ""
    try:
        return json.dumps(detail, ensure_ascii=False)
    except Exception:
        return str(detail)


def qwen_progress() -> Dict[str, Any]:
    with qwen_progress_lock:
        snapshot = dict(qwen_progress_state)
    snapshot["memory"] = _qwen_memory_snapshot()
    snapshot["vram"] = snapshot["memory"]
    snapshot["loaded"] = qwen_model is not None or bool(qwen_caption_cache)
    return snapshot


