def _resolve_default_inference_device() -> str:
    try:
        return _resolve_torch_inference_device_impl(
            TATOR_INFERENCE_DEVICE_PREF,
            torch_module=torch,
            prefer_mps=TATOR_ALLOW_MPS,
        )
    except RuntimeError as exc:  # noqa: BLE001
        logger.warning(
            "Invalid TATOR_INFERENCE_DEVICE=%s (%s); falling back to cpu.",
            TATOR_INFERENCE_DEVICE_PREF,
            exc,
        )
        return "cpu"


device = _resolve_default_inference_device()
if torch.cuda.is_available():
    try:
        torch.backends.cuda.matmul.allow_tf32 = True
        torch.backends.cudnn.allow_tf32 = True
    except Exception as exc:  # noqa: BLE001
        logger.warning("Failed to enable TF32: %s", exc)
SUPPORTED_CLIP_MODELS = [
    "ViT-L/14",
    "ViT-B/16",
    "ViT-B/32",
]
DEFAULT_CLIP_MODEL = SUPPORTED_CLIP_MODELS[0]

clip_model = None
clip_preprocess = None
clip_model_name: Optional[str] = None
_clip_reload_needed = False
_skip_clip_load = os.environ.get("TATOR_SKIP_CLIP_LOAD", "").strip() == "1"
if _skip_clip_load:
    print("Skipping CLIP model load (TATOR_SKIP_CLIP_LOAD=1).")
