logger = logging.getLogger("localinferenceapi")
logger.setLevel(logging.INFO)
if not logger.handlers:
    handler = logging.StreamHandler()
    handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
    logger.addHandler(handler)
logger.propagate = False

# Cache for repeated calls
SAM_CACHE_LIMIT = 8
sam_cache_lock = threading.Lock()
sam_preload_cache: "OrderedDict[str, Tuple[np.ndarray, str]]" = OrderedDict()
sam_preload_cache_bytes = 0


def _store_preloaded_image(token: str, np_img: np.ndarray, variant: str) -> None:
    global sam_preload_cache_bytes
    arr = np.ascontiguousarray(np_img)
    arr_bytes = arr.nbytes
    if SAM_PRELOAD_MAX_BYTES > 0 and arr_bytes > SAM_PRELOAD_MAX_BYTES:
        logger.warning(
            "Skipping preload store: image too large (%d bytes > %d)",
            arr_bytes,
            SAM_PRELOAD_MAX_BYTES,
        )
        return
    with sam_cache_lock:
        # Remove existing entry bytes
        if token in sam_preload_cache:
            old_arr, _ = sam_preload_cache[token]
            sam_preload_cache_bytes -= getattr(old_arr, "nbytes", 0)
        sam_preload_cache[token] = (arr, variant)
        sam_preload_cache.move_to_end(token)
        sam_preload_cache_bytes += arr_bytes
        while len(sam_preload_cache) > SAM_CACHE_LIMIT or (
            SAM_PRELOAD_MAX_BYTES > 0 and sam_preload_cache_bytes > SAM_PRELOAD_MAX_BYTES
        ):
            _, (evicted_arr, _) = sam_preload_cache.popitem(last=False)
            sam_preload_cache_bytes -= getattr(evicted_arr, "nbytes", 0)


def _fetch_preloaded_image(token: str, variant: str) -> Optional[np.ndarray]:
    with sam_cache_lock:
        item = sam_preload_cache.get(token)
        if not item:
            return None
        arr, stored_variant = item
        # Allow reuse across variants; cache holds raw image arrays only.
        sam_preload_cache.move_to_end(token)
        return arr


def _predict_with_cache(
    np_img: np.ndarray,
    token: Optional[str],
    variant: str,
    *,
    image_name: Optional[str] = None,
    **predict_kwargs: Any,
):
    normalized = _default_variant(variant)
    if normalized == "sam3" and not active_sam3_enable_segmentation:
        height, width = np_img.shape[:2]
        mask = np.zeros((height, width), dtype=np.uint8)
        box = predict_kwargs.get("box")
        point_coords = predict_kwargs.get("point_coords")
        if box is not None and len(box) >= 4:
            try:
                x1 = int(round(float(box[0])))
                y1 = int(round(float(box[1])))
                x2 = int(round(float(box[2])))
                y2 = int(round(float(box[3])))
            except (TypeError, ValueError):
                x1 = y1 = x2 = y2 = 0
            x1 = max(0, min(x1, width))
            x2 = max(0, min(x2, width))
            y1 = max(0, min(y1, height))
            y2 = max(0, min(y2, height))
            if x2 > x1 and y2 > y1:
                mask[y1:y2, x1:x2] = 1
        elif point_coords is not None:
            try:
                px = int(round(float(point_coords[0][0])))
                py = int(round(float(point_coords[0][1])))
            except Exception:
                px = py = 0
            px = max(0, min(px, width - 1))
            py = max(0, min(py, height - 1))
            size = 2
            x1 = max(0, px - size)
            x2 = min(width, px + size)
            y1 = max(0, py - size)
            y2 = min(height, py + size)
            mask[y1:y2, x1:x2] = 1
        masks = np.asarray([mask], dtype=np.uint8)
        return masks, None, None
    return predictor_manager.predict(
        np_img, token, variant, image_name=image_name, **predict_kwargs
    )


def _default_variant(value: Optional[str]) -> str:
    return (value or "sam1").lower()


_job_id_counter = itertools.count(1)


@dataclass
class SamPreloadJob:
    request_id: int
    variant: str
    generation: Optional[int]
    image_token: Optional[str]
    image_base64: Optional[str]
    image_name: Optional[str]
    slot: str
    event: threading.Event
    result: Optional['SamPreloadResponse'] = None
    error: Optional[Exception] = None


class SamPreloadManager:
    def __init__(self):
        self.queue: "queue.Queue[Optional[SamPreloadJob]]" = queue.Queue()
        self.lock = threading.Lock()
        self.latest_request_id: Dict[Tuple[str, str], int] = {}
        self.latest_generation: Dict[str, int] = {}
        self.stop_event = threading.Event()
        self.worker = threading.Thread(target=self._worker, name="sam-preload-worker", daemon=True)
        self.worker.start()

    def stop(self) -> None:
        self.stop_event.set()
        self.queue.put(None)
        self.worker.join(timeout=1.0)

    def submit(
        self,
        *,
        variant: str,
        generation: Optional[int],
        image_token: Optional[str],
        image_base64: Optional[str],
        image_name: Optional[str],
        slot: str,
    ) -> 'SamPreloadResponse':
        job = SamPreloadJob(
            request_id=next(_job_id_counter),
            variant=variant,
            generation=generation,
            image_token=image_token,
            image_base64=image_base64,
            image_name=image_name,
            slot=slot,
            event=threading.Event(),
        )
        request_key = self._request_key(job.slot, job.variant)
        with self.lock:
            self.latest_request_id[request_key] = job.request_id
            if generation is not None:
                prev = self.latest_generation.get(variant)
                if prev is None or generation > prev:
                    self.latest_generation[variant] = generation
        self.queue.put(job)
        job.event.wait()
        if job.error:
            raise job.error
        return job.result  # type: ignore[return-value]

    def _worker(self) -> None:
        while not self.stop_event.is_set():
            job = self.queue.get()
            if job is None:
                self.queue.task_done()
                break
            try:
                if self._is_superseded(job):
                    job.result = SamPreloadResponse(
                        status="superseded", width=0, height=0, token=job.image_token or ""
                    )
                else:
                    job.result = self._process_job(job)
            except Exception as exc:  # noqa: BLE001 - propagate to caller
                job.error = exc
            finally:
                job.event.set()
                self.queue.task_done()

    @staticmethod
    def _request_key(slot: str, variant: str) -> Tuple[str, str]:
        return (slot or "current", variant)

    def _is_superseded(self, job: SamPreloadJob) -> bool:
        with self.lock:
            latest_id = self.latest_request_id.get(self._request_key(job.slot, job.variant))
            latest_generation = self.latest_generation.get(job.variant)
        if latest_id is not None and job.request_id < latest_id:
            return True
        if (
            job.generation is not None
            and latest_generation is not None
            and job.generation < latest_generation
        ):
            return True
        return False

    def _process_job(self, job: SamPreloadJob) -> 'SamPreloadResponse':
        variant = job.variant
        try:
            slot_name = predictor_manager.resolve_slot(job.slot, allow_disabled_fallback=False)
        except ValueError as exc:
            detail = str(exc)
            status = "slot_disabled" if detail.startswith("slot_disabled:") else "slot_invalid"
            return SamPreloadResponse(
                status=status, width=0, height=0, token=job.image_token or ""
            )
        image_name = job.image_name

        if job.image_token:
            cached = _fetch_preloaded_image(job.image_token, variant)
            if cached is not None:
                if self._is_superseded(job):
                    return SamPreloadResponse(
                        status="superseded",
                        width=int(cached.shape[1]),
                        height=int(cached.shape[0]),
                        token=job.image_token,
                    )
                predictor_manager.set_slot_with_wait(
                    slot_name, cached, job.image_token, variant, image_name
                )
                height, width = cached.shape[:2]
                return SamPreloadResponse(
                    status="ready", width=int(width), height=int(height), token=job.image_token
                )
            if not job.image_base64:
                raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="image_token_not_found")

        if not job.image_base64:
            raise HTTPException(
                status_code=HTTP_428_PRECONDITION_REQUIRED, detail="image_base64_required"
            )

        np_img = self._decode_base64(job.image_base64)
        token = hashlib.md5(np_img.tobytes()).hexdigest()
        _store_preloaded_image(token, np_img, variant)

        if self._is_superseded(job):
            return SamPreloadResponse(
                status="superseded",
                width=int(np_img.shape[1]),
                height=int(np_img.shape[0]),
                token=token,
            )

        predictor_manager.set_slot_with_wait(slot_name, np_img, token, variant, image_name)
        height, width = np_img.shape[:2]
        return SamPreloadResponse(status="ready", width=int(width), height=int(height), token=token)

    @staticmethod
    def _decode_base64(image_base64: str) -> np.ndarray:
        _, np_img = _decode_image_base64_impl(
            image_base64,
            max_bytes=BASE64_IMAGE_MAX_BYTES,
            max_dim=BASE64_IMAGE_MAX_DIM,
            allow_downscale=True,
        )
        return np_img


def _extract_qwen_json_block(text: str) -> Tuple[str, List[Dict[str, Any]]]:
    snippet, detections = _extract_qwen_json_block_impl(text)
    if not detections:
        raise HTTPException(
            status_code=HTTP_422_UNPROCESSABLE_CONTENT,
            detail="qwen_parse_error:no_json_block_found",
        )
    return snippet, detections


def _qwen_items_from_payload(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    return [item for item in items if isinstance(item, dict)]


def _qwen_bbox_results(
    items: List[Dict[str, Any]],
    proc_w: int,
    proc_h: int,
    full_w: int,
    full_h: int,
    *,
    limit: int,
) -> List['QwenDetection']:
    results: List[QwenDetection] = []
    for item in items:
        bbox = (
            _extract_numeric_sequence(item.get("bbox_2d"), length=4)
            or _extract_numeric_sequence(item.get("bbox"), length=4)
            or _extract_numeric_sequence(item.get("box"), length=4)
        )
        if not bbox:
            continue
        scaled = _scale_bbox_to_image(bbox, proc_w, proc_h, full_w, full_h)
        if not scaled:
            continue
        left, top, right, bottom = scaled
        yolo_box = _xyxy_to_yolo_norm_list(full_w, full_h, left, top, right, bottom)
        label = item.get("label") or item.get("class") or item.get("name")
        results.append(
            QwenDetection(bbox=yolo_box, qwen_label=str(label) if label else None, source="bbox")
        )
        if len(results) >= limit:
            break
    return results


def _qwen_bbox_sam_results(
    items: List[Dict[str, Any]],
    proc_w: int,
    proc_h: int,
    pil_img: Image.Image,
    np_img: np.ndarray,
    token: Optional[str],
    variant: str,
    *,
    image_name: Optional[str],
    limit: int,
) -> List['QwenDetection']:
    results: List[QwenDetection] = []
    for item in items:
        bbox = (
            _extract_numeric_sequence(item.get("bbox_2d"), length=4)
            or _extract_numeric_sequence(item.get("bbox"), length=4)
            or _extract_numeric_sequence(item.get("box"), length=4)
        )
        if not bbox:
            continue
        scaled = _scale_bbox_to_image(bbox, proc_w, proc_h, pil_img.width, pil_img.height)
        if not scaled:
            continue
        sub_box = np.array(list(scaled), dtype=np.float32)
        masks, _, _ = _predict_with_cache(
            np_img,
            token,
            variant,
            image_name=image_name,
            box=sub_box,
            multimask_output=False,
        )
        mask = masks[0]
        left, top, right, bottom = _mask_to_bounding_box(mask)
        if right <= left or bottom <= top:
            continue
        yolo_box = _xyxy_to_yolo_norm_list(pil_img.width, pil_img.height, left, top, right, bottom)
        label = item.get("label") or item.get("class") or item.get("name")
        results.append(
            QwenDetection(
                bbox=yolo_box, qwen_label=str(label) if label else None, source="bbox_sam"
            )
        )
        if len(results) >= limit:
            break
    return results


def _qwen_point_results(
    items: List[Dict[str, Any]],
    proc_w: int,
    proc_h: int,
    pil_img: Image.Image,
    np_img: np.ndarray,
    token: Optional[str],
    variant: str,
    *,
    image_name: Optional[str],
    limit: int,
) -> List['QwenDetection']:
    results: List[QwenDetection] = []
    for item in items:
        point = _extract_numeric_sequence(item.get("point_2d") or item.get("point"), length=2)
        if not point:
            continue
        scaled_point = _scale_point_to_image(point, proc_w, proc_h, pil_img.width, pil_img.height)
        if not scaled_point:
            continue
        coords = np.array([[scaled_point[0], scaled_point[1]]], dtype=np.float32)
        labels = np.array([1], dtype=np.int64)
        masks, _, _ = _predict_with_cache(
            np_img,
            token,
            variant,
            image_name=image_name,
            point_coords=coords,
            point_labels=labels,
            multimask_output=False,
        )
        mask = masks[0]
        left, top, right, bottom = _mask_to_bounding_box(mask)
        if right <= left or bottom <= top:
            continue
        yolo_box = _xyxy_to_yolo_norm_list(pil_img.width, pil_img.height, left, top, right, bottom)
        label = item.get("label") or item.get("class") or item.get("name")
        results.append(
            QwenDetection(bbox=yolo_box, qwen_label=str(label) if label else None, source="point")
        )
        if len(results) >= limit:
            break
    return results


def _sam3_text_detections(
    pil_img: Image.Image,
    payload: Dict[str, Any],
    text_prompt: str,
    limit: Optional[int],
    *,
    min_score: Optional[float] = None,
    masks_arr: Optional[np.ndarray] = None,
    min_size: Optional[float] = None,
    simplify_epsilon: Optional[float] = None,
    collected_masks: Optional[List[np.ndarray]] = None,
) -> List[QwenDetection]:
    width, height = pil_img.width, pil_img.height
    boxes_source = payload.get("boxes")
    scores_source = payload.get("scores")
    masks = payload.get("masks")
    if isinstance(boxes_source, torch.Tensor):
        boxes_iter: Sequence[Any] = boxes_source.cpu().numpy()
    elif boxes_source is None:
        boxes_iter = []
    else:
        boxes_iter = boxes_source
    if isinstance(scores_source, torch.Tensor):
        scores_iter: Sequence[Any] = scores_source.cpu().numpy().tolist()
    elif scores_source is None:
        scores_iter = []
    else:
        scores_iter = scores_source
    if masks_arr is None and masks is not None:
        if isinstance(masks, torch.Tensor):
            masks_arr = masks.cpu().numpy()
        else:
            masks_arr = np.asarray(masks)
    detections: List[QwenDetection] = []
    if limit is None:
        numeric_limit: Optional[int] = None
    else:
        try:
            numeric_limit = int(limit)
        except (TypeError, ValueError):
            numeric_limit = None
        else:
            if numeric_limit <= 0:
                numeric_limit = None
    # Prefer highest-score boxes first when scores are available, since we may be limiting outputs.
    order = list(range(len(boxes_iter)))
    try:
        if scores_iter is not None and len(scores_iter) >= len(order):
            order.sort(
                key=lambda i: (
                    float(scores_iter[i])
                    if i < len(scores_iter) and scores_iter[i] is not None
                    else -1e9
                ),
                reverse=True,
            )
    except Exception:
        order = list(range(len(boxes_iter)))

    for idx in order:
        box = boxes_iter[idx]
        coords = np.asarray(box, dtype=np.float32).tolist()
        if len(coords) < 4:
            continue
        x_min, y_min, x_max, y_max = coords[:4]
        if x_max <= x_min or y_max <= y_min:
            continue
        yolo_box = _xyxy_to_yolo_norm_list(width, height, x_min, y_min, x_max, y_max)
        score_val = None
        if idx < len(scores_iter):
            try:
                score_val = float(scores_iter[idx])
            except (TypeError, ValueError):
                score_val = None
        if min_score is not None and score_val is not None and score_val < min_score:
            continue
        area = max(0.0, (x_max - x_min) * (y_max - y_min))
        if masks_arr is not None and idx < len(masks_arr):
            try:
                area = float(np.count_nonzero(masks_arr[idx]))
            except Exception:
                area = area
        if min_size is not None:
            try:
                if area < float(min_size):
                    continue
            except Exception:
                pass
        mask_payload = None
        mask_value = None
        if masks_arr is not None and idx < len(masks_arr):
            mask_value = masks_arr[idx]
            mask_payload = _encode_binary_mask_impl(mask_value, max_bytes=MASK_ENCODE_MAX_BYTES)
        if collected_masks is not None:
            collected_masks.append(mask_value)
        detections.append(
            QwenDetection(
                bbox=yolo_box,
                qwen_label=text_prompt,
                source="sam3_text",
                score=score_val,
                mask=mask_payload,
                simplify_epsilon=simplify_epsilon,
            )
        )
        if numeric_limit is not None and len(detections) >= numeric_limit:
            break
    if detections or masks_arr is None:
        return detections
    for idx, mask in enumerate(masks_arr):
        x_min, y_min, x_max, y_max = _mask_to_bounding_box(mask)
        if x_max <= x_min or y_max <= y_min:
            continue
        yolo_box = _xyxy_to_yolo_norm_list(width, height, x_min, y_min, x_max, y_max)
        score_val = None
        if idx < len(scores_iter):
            try:
                score_val = float(scores_iter[idx])
            except (TypeError, ValueError):
                score_val = None
        if min_score is not None and score_val is not None and score_val < min_score:
            continue
        area = max(0.0, (x_max - x_min) * (y_max - y_min))
        try:
            area = float(np.count_nonzero(mask))
        except Exception:
            area = area
        if min_size is not None:
            try:
                if area < float(min_size):
                    continue
            except Exception:
                pass
        detections.append(
            QwenDetection(
                bbox=yolo_box,
                qwen_label=text_prompt,
                source="sam3_text",
                score=score_val,
                mask=_encode_binary_mask_impl(mask, max_bytes=MASK_ENCODE_MAX_BYTES),
                simplify_epsilon=simplify_epsilon,
            )
        )
        if collected_masks is not None:
            collected_masks.append(mask)
        if numeric_limit is not None and len(detections) >= numeric_limit:
            break
    return detections


def _run_sam3_text_inference(
    pil_img: Image.Image,
    text_prompt: str,
    threshold: float,
    mask_threshold: float,
    limit: Optional[int],
    *,
    return_masks: bool = False,
    min_size: Optional[float] = None,
    simplify_epsilon: Optional[float] = None,
    processor_override: Optional[Any] = None,
    state: Optional[Any] = None,
) -> List[QwenDetection] | Tuple[List[QwenDetection], Optional[List[np.ndarray]]]:
    """
    Run SAM3 text inference. By default returns detections list; callers that need masks should
    inspect the second element when `return_masks=True`.
    """
    if processor_override is not None:
        processor = processor_override
    else:
        _, processor, _ = _ensure_sam3_text_runtime()
    try:
        processor.set_confidence_threshold(float(threshold))
    except Exception:
        # If the processor refuses the threshold, continue with its default.
        pass
    normalized_limit: Optional[int]
    if limit is None:
        normalized_limit = None
    else:
        try:
            parsed_limit = int(limit)
        except (TypeError, ValueError):
            normalized_limit = None
        else:
            normalized_limit = parsed_limit if parsed_limit > 0 else None
    img_state = state if state is not None else processor.set_image(pil_img)
    masks_arr: Optional[np.ndarray] = None
    try:
        output = processor.set_text_prompt(state=img_state, prompt=text_prompt)
    except KeyError:
        # Box-only checkpoints (enable_segmentation=False) do not emit pred_masks.
        # Fall back to raw model output and extract boxes/scores manually.
        try:
            raw = processor.model.forward_grounding(
                backbone_out=img_state.get("backbone_out", {}),
                find_input=processor.find_stage,
                find_target=None,
                geometric_prompt=img_state.get(
                    "geometric_prompt", processor.model._get_dummy_prompt()
                ),
            )
            boxes_xyxy = raw.get("pred_boxes_xyxy")
            if boxes_xyxy is None:
                boxes_xyxy = raw.get("pred_boxes")
            scores = None
            logits = raw.get("pred_logits")
            if logits is not None:
                try:
                    scores = torch.sigmoid(logits.squeeze(-1))
                except Exception:  # noqa: BLE001
                    try:
                        scores = torch.sigmoid(logits)
                    except Exception:  # noqa: BLE001
                        scores = None
            output = {
                "boxes": boxes_xyxy,
                "scores": scores,
                # no masks for box-only checkpoints
            }
        except Exception as exc:  # noqa: BLE001
            logger.warning("SAM3 box-only text prompt fallback failed: %s", exc)
            raise HTTPException(
                status_code=HTTP_500_INTERNAL_SERVER_ERROR,
                detail=f"sam3_text_grounding_failed:{exc}",
            ) from exc
    try:
        if output is not None and hasattr(output, "pred_masks"):
            masks = output.pred_masks
            if masks is not None:
                try:
                    masks_arr = masks.cpu().numpy()
                except Exception:
                    try:
                        masks_arr = np.asarray(masks)
                    except Exception:
                        masks_arr = None
        if masks_arr is not None:
            try:
                masks_arr = (masks_arr >= float(mask_threshold)).astype(np.uint8)
            except Exception:
                # If thresholding fails, keep the raw masks.
                pass
    except Exception:
        masks_arr = None
    collected_masks: Optional[List[np.ndarray]] = [] if return_masks else None
    preds = _sam3_text_detections(
        pil_img,
        output,
        text_prompt,
        normalized_limit,
        min_score=float(threshold),
        masks_arr=masks_arr,
        min_size=min_size,
        simplify_epsilon=simplify_epsilon,
        collected_masks=collected_masks,
    )
    aligned_masks: Optional[List[np.ndarray]]
    if collected_masks is None:
        aligned_masks = None
    else:
        aligned_masks = collected_masks
    return (preds, aligned_masks) if return_masks else preds


def _sam3_window_mask_to_full(
    crop_mask: Optional[np.ndarray],
    *,
    full_w: int,
    full_h: int,
    crop_w: int,
    crop_h: int,
    offset_x: int,
    offset_y: int,
) -> Optional[np.ndarray]:
    if crop_mask is None:
        return None
    try:
        mask_arr = _coerce_mask_to_2d(crop_mask)
        if mask_arr is None:
            return None
        mask_arr = (mask_arr > 0).astype(np.uint8)
        if mask_arr.shape != (crop_h, crop_w):
            mask_img = Image.fromarray((mask_arr * 255).astype(np.uint8))
            resampling = getattr(Image, "Resampling", Image).NEAREST
            mask_img = mask_img.resize((crop_w, crop_h), resampling)
            mask_arr = (np.asarray(mask_img) > 0).astype(np.uint8)
    except Exception:
        return None
    if full_w <= 0 or full_h <= 0 or crop_w <= 0 or crop_h <= 0:
        return None
    offset_x_int = int(offset_x)
    offset_y_int = int(offset_y)
    dest_left = max(0, min(full_w, offset_x_int))
    dest_top = max(0, min(full_h, offset_y_int))
    src_left = max(0, -offset_x_int)
    src_top = max(0, -offset_y_int)
    copy_w = min(crop_w - src_left, full_w - dest_left)
    copy_h = min(crop_h - src_top, full_h - dest_top)
    if copy_w <= 0 or copy_h <= 0:
        return None
    full_mask = np.zeros((full_h, full_w), dtype=np.uint8)
    full_mask[dest_top : dest_top + copy_h, dest_left : dest_left + copy_w] = mask_arr[
        src_top : src_top + copy_h,
        src_left : src_left + copy_w,
    ]
    return full_mask


def _sam3_detection_iou_xyxy(
    a_xyxy: Tuple[float, float, float, float],
    b_xyxy: Tuple[float, float, float, float],
) -> float:
    ax1, ay1, ax2, ay2 = a_xyxy
    bx1, by1, bx2, by2 = b_xyxy
    ix1 = max(ax1, bx1)
    iy1 = max(ay1, by1)
    ix2 = min(ax2, bx2)
    iy2 = min(ay2, by2)
    iw = max(0.0, ix2 - ix1)
    ih = max(0.0, iy2 - iy1)
    inter = iw * ih
    if inter <= 0:
        return 0.0
    a_area = max(0.0, ax2 - ax1) * max(0.0, ay2 - ay1)
    b_area = max(0.0, bx2 - bx1) * max(0.0, by2 - by1)
    denom = a_area + b_area - inter
    return inter / denom if denom > 0 else 0.0


def _fuse_sam3_windowed_detections(
    pairs: List[Tuple[QwenDetection, Optional[np.ndarray]]],
    *,
    img_w: int,
    img_h: int,
    merge_iou: float,
    limit: Optional[int],
) -> Tuple[List[QwenDetection], List[Optional[np.ndarray]]]:
    if not pairs:
        return [], []
    numeric_limit: Optional[int]
    if limit is None:
        numeric_limit = None
    else:
        try:
            numeric_limit = int(limit)
        except (TypeError, ValueError):
            numeric_limit = None
        else:
            if numeric_limit <= 0:
                numeric_limit = None
    prepared: List[Tuple[QwenDetection, Optional[np.ndarray], Tuple[float, float, float, float], float]] = []
    for det, mask in pairs:
        xyxy = _yolo_to_xyxy(img_w, img_h, det.bbox)
        x1, y1, x2, y2 = xyxy
        if x2 <= x1 or y2 <= y1:
            continue
        try:
            score = float(det.score) if det.score is not None else 0.0
        except (TypeError, ValueError):
            score = 0.0
        prepared.append((det, mask, xyxy, score))
    prepared.sort(key=lambda item: item[3], reverse=True)
    kept: List[Tuple[QwenDetection, Optional[np.ndarray], Tuple[float, float, float, float]]] = []
    for det, mask, xyxy, _score in prepared:
        duplicate = any(
            _sam3_detection_iou_xyxy(xyxy, kept_xyxy) > merge_iou
            for _kept_det, _kept_mask, kept_xyxy in kept
        )
        if duplicate:
            continue
        kept.append((det, mask, xyxy))
        if numeric_limit is not None and len(kept) >= numeric_limit:
            break
    detections = [item[0] for item in kept]
    masks = [item[1] for item in kept]
    return detections, masks


def _positive_int_or_none(value: Optional[int]) -> Optional[int]:
    if value is None:
        return None
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return None
    return parsed if parsed > 0 else None


def _sam3_window_limit_pair(limit: Optional[int]) -> Tuple[Optional[int], Optional[int]]:
    final_limit = _positive_int_or_none(limit)
    if final_limit is None:
        return None, None
    # In windowed mode a small final cap should not also starve each tile. Search
    # each crop more broadly, then apply the requested cap after full-image fusion.
    return max(final_limit, 50), final_limit


def _sam3_window_coverage_warnings(
    *,
    img_w: int,
    img_h: int,
    slices: List[np.ndarray],
    starts: List[Tuple[int, int]],
) -> List[str]:
    warnings: List[str] = [f"windowed_image_size:{img_w}x{img_h}"]
    if img_w <= 0 or img_h <= 0 or not slices:
        warnings.append("windowed_coverage_fraction:0.0000")
        warnings.append("windowed_uncovered_pixels:0")
        return warnings
    min_x, min_y = img_w, img_h
    max_x, max_y = 0, 0
    coverage = np.zeros((img_h, img_w), dtype=np.bool_)
    for tile, start in zip(slices, starts, strict=False):
        try:
            offset_x, offset_y = int(start[0]), int(start[1])
        except Exception:
            continue
        tile_h = int(getattr(tile, "shape", [0, 0])[0] or 0)
        tile_w = int(getattr(tile, "shape", [0, 0])[1] or 0)
        if tile_w <= 0 or tile_h <= 0:
            continue
        left = max(0, min(img_w, offset_x))
        top = max(0, min(img_h, offset_y))
        right = max(left, min(img_w, offset_x + tile_w))
        bottom = max(top, min(img_h, offset_y + tile_h))
        if right <= left or bottom <= top:
            continue
        coverage[top:bottom, left:right] = True
        min_x = min(min_x, left)
        min_y = min(min_y, top)
        max_x = max(max_x, right)
        max_y = max(max_y, bottom)
    covered = int(np.count_nonzero(coverage))
    total = max(1, img_w * img_h)
    uncovered = max(0, total - covered)
    if covered <= 0:
        min_x = min_y = max_x = max_y = 0
    warnings.append(f"windowed_coverage_bounds:{min_x},{min_y},{max_x},{max_y}")
    warnings.append(f"windowed_coverage_fraction:{covered / total:.4f}")
    warnings.append(f"windowed_uncovered_pixels:{uncovered}")
    if uncovered:
        warnings.append("windowed_incomplete_coverage")
    return warnings


def _run_sam3_text_windowed_inference(
    pil_img: Image.Image,
    text_prompt: str,
    threshold: float,
    mask_threshold: float,
    limit: Optional[int],
    *,
    window_size: Optional[int],
    window_overlap: Optional[float],
    merge_iou: Optional[float],
    min_size: Optional[float] = None,
    simplify_epsilon: Optional[float] = None,
) -> Tuple[List[QwenDetection], List[Optional[np.ndarray]], List[str]]:
    img_w, img_h = pil_img.size
    warnings: List[str] = []
    raw_slice_size = int(window_size) if window_size is not None else 672
    raw_overlap = float(window_overlap) if window_overlap is not None else 0.1
    raw_merge_iou = float(merge_iou) if merge_iou is not None else 0.5
    slice_size, overlap, resolved_merge_iou = _clamp_slice_params_impl(
        raw_slice_size,
        raw_overlap,
        raw_merge_iou,
        img_w,
        img_h,
        warnings,
    )
    try:
        slices, starts = _slice_image_sahi(pil_img, slice_size, overlap)
    except HTTPException:
        raise
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail=f"sam3_window_slice_failed:{exc}",
        ) from exc
    if not slices:
        return [], [], [*warnings, "no_windows"]
    warnings.extend(
        _sam3_window_coverage_warnings(
            img_w=img_w,
            img_h=img_h,
            slices=slices,
            starts=starts,
        )
    )
    per_window_limit, final_limit = _sam3_window_limit_pair(limit)
    _, processor, _ = _ensure_sam3_text_runtime()
    pairs: List[Tuple[QwenDetection, Optional[np.ndarray]]] = []
    for tile, start in zip(slices, starts, strict=False):
        offset_x, offset_y = int(start[0]), int(start[1])
        crop = Image.fromarray(tile).convert("RGB")
        crop_w, crop_h = crop.size
        crop_detections, crop_masks = _run_sam3_text_inference(
            crop,
            text_prompt,
            threshold,
            mask_threshold,
            per_window_limit,
            return_masks=True,
            min_size=min_size,
            simplify_epsilon=simplify_epsilon,
            processor_override=processor,
        )
        for idx, det in enumerate(crop_detections):
            x1, y1, x2, y2 = _yolo_to_xyxy(crop_w, crop_h, det.bbox)
            full_x1 = max(0.0, min(float(img_w), float(offset_x) + x1))
            full_y1 = max(0.0, min(float(img_h), float(offset_y) + y1))
            full_x2 = max(full_x1, min(float(img_w), float(offset_x) + x2))
            full_y2 = max(full_y1, min(float(img_h), float(offset_y) + y2))
            if full_x2 <= full_x1 or full_y2 <= full_y1:
                continue
            crop_mask = crop_masks[idx] if crop_masks is not None and idx < len(crop_masks) else None
            full_mask = _sam3_window_mask_to_full(
                crop_mask,
                full_w=img_w,
                full_h=img_h,
                crop_w=crop_w,
                crop_h=crop_h,
                offset_x=offset_x,
                offset_y=offset_y,
            )
            full_bbox = _xyxy_to_yolo_norm_list(img_w, img_h, full_x1, full_y1, full_x2, full_y2)
            det.bbox = full_bbox
            det.source = "sam3_text"
            if full_mask is not None:
                det.mask = _encode_binary_mask_impl(full_mask, max_bytes=MASK_ENCODE_MAX_BYTES)
            pairs.append((det, full_mask))
    detections, fused_masks = _fuse_sam3_windowed_detections(
        pairs,
        img_w=img_w,
        img_h=img_h,
        merge_iou=resolved_merge_iou,
        limit=final_limit,
    )
    raw_detection_count = len(pairs)
    final_detection_count = len(detections)
    warnings.append(f"windowed_tiles:{len(slices)}")
    warnings.append(f"windowed_slice_size:{slice_size}")
    warnings.append(f"windowed_overlap:{overlap:.2f}")
    warnings.append(f"windowed_per_window_limit:{per_window_limit if per_window_limit is not None else 'unlimited'}")
    warnings.append(f"windowed_final_limit:{final_limit if final_limit is not None else 'unlimited'}")
    warnings.append(f"windowed_raw_detections:{raw_detection_count}")
    warnings.append(f"windowed_final_detections:{final_detection_count}")
    warnings.append(f"windowed_fused_detections:{max(0, raw_detection_count - final_detection_count)}")
    warnings.append(f"windowed_merge_iou:{resolved_merge_iou:.2f}")
    return detections, fused_masks, warnings


def _run_sam3_visual_inference(
    pil_img: Image.Image,
    bbox_xywh: Tuple[float, float, float, float],
    threshold: float,
    mask_threshold: float,
    limit: Optional[int],
    *,
    return_masks: bool = False,
    min_size: Optional[float] = None,
    simplify_epsilon: Optional[float] = None,
    text_prompt: Optional[str] = None,
    processor_override: Optional[Any] = None,
    state: Optional[Any] = None,
) -> List[QwenDetection] | Tuple[List[QwenDetection], Optional[List[np.ndarray]]]:
    """
    Run SAM3 with a single positive visual (box) prompt. By default returns detections list;
    callers that need masks should inspect the second element when `return_masks=True`.
    """
    if processor_override is not None:
        processor = processor_override
    else:
        _, processor, _ = _ensure_sam3_text_runtime()
    try:
        processor.set_confidence_threshold(float(threshold))
    except Exception:
        pass
    normalized_limit: Optional[int]
    if limit is None:
        normalized_limit = None
    else:
        try:
            normalized_limit = max(1, int(limit))
        except (TypeError, ValueError):
            normalized_limit = None
    img_state = state if state is not None else processor.set_image(pil_img)
    semantic_prompt = str(text_prompt or "").strip()
    if semantic_prompt:
        try:
            img_state = processor.set_text_prompt(semantic_prompt, state=img_state)
        except Exception as exc:  # noqa: BLE001
            logger.debug("SAM3 visual semantic prompt failed; continuing visual-only: %s", exc)
    img_w, img_h = float(pil_img.width), float(pil_img.height)
    x, y, w, h = bbox_xywh
    cx = (x + w / 2.0) / img_w
    cy = (y + h / 2.0) / img_h
    w_norm = w / img_w
    h_norm = h / img_h
    try:
        output = processor.add_geometric_prompt([cx, cy, w_norm, h_norm], True, state=img_state)
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"sam3_visual_prompt_failed:{exc}"
        ) from exc
    masks_arr: Optional[np.ndarray] = None
    mask_logits = None
    if isinstance(output, Mapping):
        if "masks_logits" in output and output.get("masks_logits") is not None:
            mask_logits = output.get("masks_logits")
        elif "masks" in output and output.get("masks") is not None:
            mask_logits = output.get("masks")
    if mask_logits is None and isinstance(img_state, Mapping):
        if "masks_logits" in img_state and img_state.get("masks_logits") is not None:
            mask_logits = img_state.get("masks_logits")
        elif "masks" in img_state and img_state.get("masks") is not None:
            mask_logits = img_state.get("masks")
    try:
        threshold_val = float(mask_threshold)
    except Exception:
        threshold_val = 0.5
    threshold_val = max(0.0, min(1.0, threshold_val))
    # Normalize mask logits into a numpy array before thresholding.
    try:

        def _sigmoid_np(arr: np.ndarray) -> np.ndarray:
            try:
                return 1.0 / (1.0 + np.exp(-np.clip(arr, -50, 50)))
            except Exception:
                return 1.0 / (1.0 + np.exp(-arr))

        if isinstance(mask_logits, (list, tuple)):
            if any(isinstance(m, torch.Tensor) for m in mask_logits):
                stacked = [
                    m.detach().cpu().numpy() if isinstance(m, torch.Tensor) else np.asarray(m)
                    for m in mask_logits
                ]
                mask_logits = np.stack(stacked)
            else:
                mask_logits = np.asarray(mask_logits)
        if isinstance(mask_logits, torch.Tensor):
            try:
                probs = mask_logits
                try:
                    min_v = float(probs.min())
                    max_v = float(probs.max())
                    if not (0.0 <= min_v <= 1.0 and 0.0 <= max_v <= 1.0):
                        probs = torch.sigmoid(probs)
                except Exception:
                    probs = torch.sigmoid(probs)
                masks_arr = (probs > threshold_val).cpu().numpy()
            except Exception:
                masks_arr = mask_logits.detach().cpu().numpy()
        elif mask_logits is not None:
            masks_np = np.asarray(mask_logits)
            if masks_np.dtype == object:
                try:
                    masks_np = np.stack([np.asarray(m) for m in masks_np])
                except Exception:
                    masks_np = None
            if masks_np is not None:
                if masks_np.dtype == bool or (
                    np.issubdtype(masks_np.dtype, np.floating)
                    and np.nanmin(masks_np) >= 0.0
                    and np.nanmax(masks_np) <= 1.0
                ):
                    probs_np = masks_np
                else:
                    probs_np = _sigmoid_np(masks_np)
                masks_arr = probs_np > threshold_val
        # Normalize mask shape to (N, H, W) where possible
        if masks_arr is not None:
            masks_arr = np.asarray(masks_arr)
            if masks_arr.dtype == object:
                flattened = [np.asarray(m) for m in masks_arr]
                masks_arr = np.stack(flattened)
            if masks_arr.ndim == 2:
                masks_arr = masks_arr[None, ...]
            elif masks_arr.ndim == 4 and masks_arr.shape[1] == 1:
                masks_arr = masks_arr[:, 0, ...]
            elif masks_arr.ndim == 4 and masks_arr.shape[-1] == 1:
                masks_arr = masks_arr[..., 0]
    except Exception:
        masks_arr = None

    def _to_numpy_safe(val: Any) -> Optional[np.ndarray]:
        if val is None:
            return None
        if isinstance(val, torch.Tensor):
            try:
                return val.detach().cpu().numpy()
            except Exception:
                return None
        try:
            return np.asarray(val)
        except Exception:
            return None

    payload_for_detection: Dict[str, Any] = {}
    if isinstance(output, Mapping):
        boxes_val = _to_numpy_safe(output.get("boxes"))
        scores_val = _to_numpy_safe(output.get("scores"))
        masks_val = _to_numpy_safe(output.get("masks"))
        if boxes_val is not None:
            payload_for_detection["boxes"] = boxes_val
        if scores_val is not None:
            payload_for_detection["scores"] = scores_val
        if masks_val is not None:
            payload_for_detection["masks"] = masks_val
    collected_masks: Optional[List[np.ndarray]] = [] if return_masks else None
    detections = _sam3_text_detections(
        pil_img,
        payload_for_detection,
        "visual",
        normalized_limit,
        min_score=float(threshold),
        masks_arr=masks_arr,
        min_size=min_size,
        simplify_epsilon=simplify_epsilon,
        collected_masks=collected_masks,
    )
    # Drop the seed box if SAM returns it again (dedupe by IoU against the input box).
    seed_xyxy = (
        bbox_xywh[0],
        bbox_xywh[1],
        bbox_xywh[0] + bbox_xywh[2],
        bbox_xywh[1] + bbox_xywh[3],
    )

    def _iou(
        box_a: Tuple[float, float, float, float], box_b: Tuple[float, float, float, float]
    ) -> float:
        ax1, ay1, ax2, ay2 = box_a
        bx1, by1, bx2, by2 = box_b
        ix1, iy1 = max(ax1, bx1), max(ay1, by1)
        ix2, iy2 = min(ax2, bx2), min(ay2, by2)
        iw, ih = max(0.0, ix2 - ix1), max(0.0, iy2 - iy1)
        inter = iw * ih
        if inter <= 0:
            return 0.0
        area_a = max(0.0, (ax2 - ax1)) * max(0.0, (ay2 - ay1))
        area_b = max(0.0, (bx2 - bx1)) * max(0.0, (by2 - by1))
        denom = area_a + area_b - inter
        return inter / denom if denom > 0 else 0.0

    aligned_masks: Optional[List[np.ndarray]]
    if collected_masks is None:
        aligned_masks = None
    else:
        aligned_masks = collected_masks
    if detections:
        filtered_dets: List[QwenDetection] = []
        filtered_masks: List[np.ndarray] = []
        for det_idx, det in enumerate(detections):
            bbox = det.bbox or []
            if len(bbox) < 4:
                continue
            det_xyxy = _yolo_to_xyxy_int(pil_img.width, pil_img.height, bbox)
            if _iou(seed_xyxy, det_xyxy) > 0.9:
                continue
            filtered_dets.append(det)
            if aligned_masks is not None and det_idx < len(aligned_masks):
                filtered_masks.append(aligned_masks[det_idx])
        detections = filtered_dets
        if aligned_masks is not None:
            aligned_masks = filtered_masks
    return (detections, aligned_masks) if return_masks else detections


def _run_sam3_visual_inference_multi(
    pil_img: Image.Image,
    bboxes_xywh: List[Tuple[float, float, float, float]],
    bbox_labels: Optional[List[bool]],
    threshold: float,
    mask_threshold: float,
    limit: Optional[int],
    *,
    return_masks: bool = False,
    min_size: Optional[float] = None,
    simplify_epsilon: Optional[float] = None,
    text_prompt: Optional[str] = None,
    processor_override: Optional[Any] = None,
    state: Optional[Any] = None,
) -> List[QwenDetection] | Tuple[List[QwenDetection], Optional[List[np.ndarray]]]:
    """
    Run SAM3 with multiple positive visual (box) prompts. Uses a shared image state
    to accumulate prompts and returns detections from the combined prompt set.
    """
    if processor_override is not None:
        processor = processor_override
    else:
        _, processor, _ = _ensure_sam3_text_runtime()
    try:
        processor.set_confidence_threshold(float(threshold))
    except Exception:
        pass
    normalized_limit: Optional[int]
    if limit is None:
        normalized_limit = None
    else:
        try:
            normalized_limit = max(1, int(limit))
        except (TypeError, ValueError):
            normalized_limit = None
    if not isinstance(bboxes_xywh, (list, tuple)) or not bboxes_xywh:
        empty = ([], []) if return_masks else []
        return empty
    cleaned_boxes: List[Tuple[float, float, float, float]] = []
    for bbox in bboxes_xywh:
        if not isinstance(bbox, (list, tuple)) or len(bbox) < 4:
            continue
        try:
            x, y, w, h = (float(bbox[0]), float(bbox[1]), float(bbox[2]), float(bbox[3]))
        except (TypeError, ValueError):
            continue
        cleaned_boxes.append((x, y, w, h))
    if not cleaned_boxes:
        empty = ([], []) if return_masks else []
        return empty
    labels: List[bool]
    if bbox_labels is None:
        labels = [True] * len(cleaned_boxes)
    else:
        labels = list(bbox_labels)
        if len(labels) < len(cleaned_boxes):
            labels.extend([True] * (len(cleaned_boxes) - len(labels)))
        elif len(labels) > len(cleaned_boxes):
            labels = labels[: len(cleaned_boxes)]
    img_state = state if state is not None else processor.set_image(pil_img)
    semantic_prompt = str(text_prompt or "").strip()
    if semantic_prompt:
        try:
            img_state = processor.set_text_prompt(semantic_prompt, state=img_state)
        except Exception as exc:  # noqa: BLE001
            logger.debug("SAM3 visual semantic prompt failed; continuing visual-only: %s", exc)
    img_w, img_h = float(pil_img.width), float(pil_img.height)
    output = None
    for bbox_xywh, label in zip(cleaned_boxes, labels, strict=False):
        x, y, w, h = bbox_xywh
        cx = (x + w / 2.0) / img_w
        cy = (y + h / 2.0) / img_h
        w_norm = w / img_w
        h_norm = h / img_h
        try:
            output = processor.add_geometric_prompt(
                [cx, cy, w_norm, h_norm], bool(label), state=img_state
            )
        except Exception as exc:  # noqa: BLE001
            raise HTTPException(
                status_code=HTTP_500_INTERNAL_SERVER_ERROR,
                detail=f"sam3_visual_prompt_failed:{exc}",
            ) from exc
    masks_arr: Optional[np.ndarray] = None
    mask_logits = None
    if isinstance(output, Mapping):
        if "masks_logits" in output and output.get("masks_logits") is not None:
            mask_logits = output.get("masks_logits")
        elif "masks" in output and output.get("masks") is not None:
            mask_logits = output.get("masks")
    if mask_logits is None and isinstance(img_state, Mapping):
        if "masks_logits" in img_state and img_state.get("masks_logits") is not None:
            mask_logits = img_state.get("masks_logits")
        elif "masks" in img_state and img_state.get("masks") is not None:
            mask_logits = img_state.get("masks")
    try:
        threshold_val = float(mask_threshold)
    except Exception:
        threshold_val = 0.5
    threshold_val = max(0.0, min(1.0, threshold_val))
    try:

        def _sigmoid_np(arr: np.ndarray) -> np.ndarray:
            try:
                return 1.0 / (1.0 + np.exp(-np.clip(arr, -50, 50)))
            except Exception:
                return 1.0 / (1.0 + np.exp(-arr))

        if isinstance(mask_logits, (list, tuple)):
            if any(isinstance(m, torch.Tensor) for m in mask_logits):
                stacked = [
                    m.detach().cpu().numpy() if isinstance(m, torch.Tensor) else np.asarray(m)
                    for m in mask_logits
                ]
                mask_logits = np.stack(stacked)
            else:
                mask_logits = np.asarray(mask_logits)
        if isinstance(mask_logits, torch.Tensor):
            try:
                probs = mask_logits
                try:
                    min_v = float(probs.min())
                    max_v = float(probs.max())
                    if not (0.0 <= min_v <= 1.0 and 0.0 <= max_v <= 1.0):
                        probs = torch.sigmoid(probs)
                except Exception:
                    probs = torch.sigmoid(probs)
                masks_arr = (probs > threshold_val).cpu().numpy()
            except Exception:
                masks_arr = mask_logits.detach().cpu().numpy()
        elif mask_logits is not None:
            masks_np = np.asarray(mask_logits)
            if masks_np.dtype == bool or (
                np.issubdtype(masks_np.dtype, np.floating)
                and np.nanmin(masks_np) >= 0.0
                and np.nanmax(masks_np) <= 1.0
            ):
                probs_np = masks_np
            else:
                probs_np = _sigmoid_np(masks_np)
            masks_arr = probs_np > threshold_val
        if masks_arr is not None:
            masks_arr = np.asarray(masks_arr)
            if masks_arr.dtype == object:
                flattened = [np.asarray(m) for m in masks_arr]
                masks_arr = np.stack(flattened)
            if masks_arr.ndim == 2:
                masks_arr = masks_arr[None, ...]
            elif masks_arr.ndim == 4 and masks_arr.shape[1] == 1:
                masks_arr = masks_arr[:, 0, ...]
            elif masks_arr.ndim == 4 and masks_arr.shape[-1] == 1:
                masks_arr = masks_arr[..., 0]
    except Exception:
        masks_arr = None

    def _to_numpy_safe(val: Any) -> Optional[np.ndarray]:
        if val is None:
            return None
        if isinstance(val, torch.Tensor):
            try:
                return val.detach().cpu().numpy()
            except Exception:
                return None
        try:
            return np.asarray(val)
        except Exception:
            return None

    payload_for_detection: Dict[str, Any] = {}
    if isinstance(output, Mapping):
        boxes_val = _to_numpy_safe(output.get("boxes"))
        scores_val = _to_numpy_safe(output.get("scores"))
        masks_val = _to_numpy_safe(output.get("masks"))
        if boxes_val is not None:
            payload_for_detection["boxes"] = boxes_val
        if scores_val is not None:
            payload_for_detection["scores"] = scores_val
        if masks_val is not None:
            payload_for_detection["masks"] = masks_val
    collected_masks: Optional[List[np.ndarray]] = [] if return_masks else None
    detections = _sam3_text_detections(
        pil_img,
        payload_for_detection,
        "visual",
        normalized_limit,
        min_score=float(threshold),
        masks_arr=masks_arr,
        min_size=min_size,
        simplify_epsilon=simplify_epsilon,
        collected_masks=collected_masks,
    )
    seed_boxes_xyxy = [(bx[0], bx[1], bx[0] + bx[2], bx[1] + bx[3]) for bx in bboxes_xywh]

    def _iou(
        box_a: Tuple[float, float, float, float], box_b: Tuple[float, float, float, float]
    ) -> float:
        ax1, ay1, ax2, ay2 = box_a
        bx1, by1, bx2, by2 = box_b
        ix1, iy1 = max(ax1, bx1), max(ay1, by1)
        ix2, iy2 = min(ax2, bx2), min(ay2, by2)
        iw, ih = max(0.0, ix2 - ix1), max(0.0, iy2 - iy1)
        inter = iw * ih
        if inter <= 0:
            return 0.0
        area_a = max(0.0, (ax2 - ax1)) * max(0.0, (ay2 - ay1))
        area_b = max(0.0, (bx2 - bx1)) * max(0.0, (by2 - by1))
        denom = area_a + area_b - inter
        return inter / denom if denom > 0 else 0.0

    aligned_masks: Optional[List[np.ndarray]]
    if collected_masks is None:
        aligned_masks = None
    else:
        aligned_masks = collected_masks
    if detections:
        filtered_dets: List[QwenDetection] = []
        filtered_masks: List[np.ndarray] = []
        for det_idx, det in enumerate(detections):
            bbox = det.bbox or []
            if len(bbox) < 4:
                continue
            det_xyxy = _yolo_to_xyxy_int(pil_img.width, pil_img.height, bbox)
            if any(_iou(seed_xyxy, det_xyxy) > 0.9 for seed_xyxy in seed_boxes_xyxy):
                continue
            filtered_dets.append(det)
            if aligned_masks is not None and det_idx < len(aligned_masks):
                filtered_masks.append(aligned_masks[det_idx])
        detections = filtered_dets
        if aligned_masks is not None:
            aligned_masks = filtered_masks
    return (detections, aligned_masks) if return_masks else detections


def _qwen_runtime_platform_from_runtime(runtime: Any) -> str:
    if isinstance(runtime, QwenRuntime):
        return runtime.platform
    return QWEN_PLATFORM_TRANSFORMERS


def _qwen_runtime_model_id(runtime: Any) -> Optional[str]:
    if isinstance(runtime, QwenRuntime):
        return runtime.model_id
    return None


def _resolve_qwen_runtime_platform(
    model_id: Optional[str] = None,
    *,
    adapter_path: Optional[Path] = None,
    metadata: Optional[Dict[str, Any]] = None,
) -> str:
    meta_platform = normalize_qwen_platform((metadata or {}).get("runtime_platform"))
    meta_id = str((metadata or {}).get("id") or "")
    if meta_platform == QWEN_PLATFORM_MLX and meta_id and meta_id != "default":
        return QWEN_PLATFORM_MLX
    if meta_platform == QWEN_PLATFORM_TRANSFORMERS and meta_id and meta_id != "default":
        return QWEN_PLATFORM_TRANSFORMERS
    raw_model_id = str(model_id or "").strip()
    if raw_model_id in QWEN_TRANSFORMERS_MODEL_IDS and not raw_model_id.startswith("Qwen/Qwen3-VL-"):
        return QWEN_PLATFORM_TRANSFORMERS
    return select_qwen_platform(
        QWEN_INFERENCE_PLATFORM,
        model_id=model_id,
        adapter_path=adapter_path,
        mlx_import_error=MLX_VLM_IMPORT_ERROR,
        mlx_load_fn=MLX_VLM_LOAD,
        mlx_generate_fn=MLX_VLM_GENERATE,
    )


def _qwen_mlx_dependency_error() -> Optional[str]:
    if MLX_VLM_IMPORT_ERROR is not None:
        return str(MLX_VLM_IMPORT_ERROR)
    if MLX_VLM_LOAD is None or MLX_VLM_GENERATE is None:
        return "mlx_vlm_generate_unavailable"
    return None


def _qwen_mlx_incompatible_model_detail(model_id: str) -> Optional[str]:
    metadata = qwen_mlx_metadata_for_model(str(model_id or ""))
    if (
        metadata.get("vision_inference_supported") is False
        or metadata.get("inference_supported") is False
    ):
        note = str(metadata.get("compatibility_note") or "").strip()
        if not note:
            note = "Selected MLX checkpoint is not marked as compatible with image inference."
        return f"{model_id}: {note}"
    return None


def _qwen_weight_key_has_language(key: str) -> bool:
    text = str(key or "")
    return text.startswith("language_model.") or ".language_model." in text


def _qwen_weight_key_has_vision(key: str) -> bool:
    text = str(key or "")
    return (
        text.startswith("vision_tower.")
        or ".vision_tower." in text
        or text.startswith("visual.")
        or ".visual." in text
        or text.startswith("vision_model.")
        or ".vision_model." in text
    )


def _qwen_config_is_vision_model(model_id: str, config_path: Optional[Path]) -> bool:
    config_data: Dict[str, Any] = {}
    if config_path is not None:
        try:
            config_data = json.loads(config_path.read_text(encoding="utf-8"))
        except Exception:
            config_data = {}
    model_type = str(config_data.get("model_type") or "").lower()
    return (
        "vl" in model_type
        or "vision_start_token_id" in config_data
        or "vision_end_token_id" in config_data
        or "qwen3-vl" in str(model_id or "").lower()
    )


def _qwen_mlx_checkpoint_index_incompatibility_detail(
    model_id: str,
    index_path: Path,
    *,
    config_path: Optional[Path] = None,
) -> Optional[str]:
    try:
        index_data = json.loads(index_path.read_text(encoding="utf-8"))
    except Exception:
        return None
    weight_map = index_data.get("weight_map")
    if not isinstance(weight_map, dict) or not weight_map:
        return None
    keys = [str(key) for key in weight_map.keys()]
    has_language = any(_qwen_weight_key_has_language(key) for key in keys)
    has_vision = any(_qwen_weight_key_has_vision(key) for key in keys)
    if not has_language or has_vision:
        return None
    resolved_config_path = config_path or index_path.with_name("config.json")
    if not _qwen_config_is_vision_model(str(model_id), resolved_config_path):
        return None
    return (
        f"{model_id}: checkpoint advertises a Qwen3-VL config, but its safetensor index "
        "contains language weights and no visual/vision weights. It cannot run image "
        "captioning or detection; select a full Qwen3-VL MLX checkpoint."
    )


def _qwen_mlx_cached_checkpoint_incompatibility_detail(
    model_id: str, availability: Mapping[str, Any]
) -> Optional[str]:
    candidate_paths: List[Path] = []
    for raw_path in (
        availability.get("cache_path") if isinstance(availability, Mapping) else None,
        _qwen_cache_repo_path(str(model_id)),
    ):
        if not raw_path:
            continue
        try:
            path = Path(str(raw_path)).expanduser()
        except Exception:
            continue
        if path.exists() and path not in candidate_paths:
            candidate_paths.append(path)

    index_paths: List[Path] = []
    for base in candidate_paths:
        direct = base / "model.safetensors.index.json"
        if direct.exists():
            index_paths.append(direct)
        try:
            index_paths.extend(base.glob("snapshots/*/model.safetensors.index.json"))
        except Exception:
            continue

    seen: Set[Path] = set()
    for index_path in index_paths:
        if index_path in seen:
            continue
        seen.add(index_path)
        detail = _qwen_mlx_checkpoint_index_incompatibility_detail(model_id, index_path)
        if detail:
            return detail
    return None


def _qwen_mlx_cached_model_incompatibility_detail(model_id: str) -> Optional[str]:
    availability = {"cache_path": _qwen_cache_snapshot_path(str(model_id))}
    return _qwen_mlx_cached_checkpoint_incompatibility_detail(str(model_id), availability)


def _qwen_mlx_remote_checkpoint_incompatibility_detail(model_id: str) -> Optional[str]:
    raw = str(model_id or "").strip()
    if not raw or raw.startswith(("http://", "https://")):
        return None
    if Path(raw).expanduser().exists():
        return None
    try:
        from huggingface_hub import hf_hub_download
    except Exception:
        return None
    try:
        config_path = Path(hf_hub_download(raw, "config.json"))
    except Exception:
        config_path = None
    try:
        index_path = Path(hf_hub_download(raw, "model.safetensors.index.json"))
    except Exception:
        return None
    return _qwen_mlx_checkpoint_index_incompatibility_detail(
        raw,
        index_path,
        config_path=config_path,
    )


def _effective_qwen_mlx_settings_model_id() -> str:
    if _qwen_mlx_incompatible_model_detail(QWEN_MLX_MODEL_NAME):
        return QWEN_MLX_DEFAULT_MODEL
    if _qwen_mlx_cached_model_incompatibility_detail(QWEN_MLX_MODEL_NAME):
        return QWEN_MLX_DEFAULT_MODEL
    return QWEN_MLX_MODEL_NAME


def _qwen_mlx_entry_with_runtime_state(entry: Mapping[str, Any]) -> Dict[str, Any]:
    item = dict(entry)
    model_id = str(item.get("id") or item.get("model_id") or "").strip()
    if not model_id:
        return item
    availability = _qwen_model_local_state(model_id, QWEN_PLATFORM_MLX)
    item["availability"] = availability
    cached_incompatible = _qwen_mlx_cached_checkpoint_incompatibility_detail(
        model_id, availability
    )
    if cached_incompatible:
        item["vision_inference_supported"] = False
        item["inference_supported"] = False
        item["training_supported"] = False
        item["compatibility_note"] = cached_incompatible
        item["training_note"] = cached_incompatible
    return item


def _qwen_mlx_runtime_model_options() -> List[Dict[str, Any]]:
    entries: List[Dict[str, Any]] = []
    for entry in QWEN_MLX_MODEL_OPTIONS:
        enriched = _qwen_mlx_entry_with_runtime_state(entry)
        if (
            enriched.get("vision_inference_supported") is False
            or enriched.get("inference_supported") is False
        ):
            continue
        entries.append(enriched)
    return entries


def _bind_mlx_generation_stream_for_current_thread() -> None:
    if MLX_CORE is None:
        return
    try:
        generate_module = importlib.import_module("mlx_vlm.generate")
        generate_module.generation_stream = MLX_CORE.new_stream(MLX_CORE.default_device())
    except Exception as exc:  # noqa: BLE001
        logger.debug("[qwen] unable to bind MLX generation stream for current thread: %s", exc)


def _effective_qwen_model_id_for_platform(model_id: Optional[str], platform_name: str) -> str:
    raw = str(model_id or QWEN_MODEL_NAME).strip() or QWEN_MODEL_NAME
    if platform_name == QWEN_PLATFORM_MLX:
        return resolve_mlx_model_id(
            raw,
            default_mlx_model_id=_effective_qwen_mlx_settings_model_id(),
            default_quantization=QWEN_MLX_DEFAULT_QUANTIZATION,
        )
    return raw


def _load_qwen_mlx_runtime(model_id: str, adapter_path: Optional[Path] = None) -> QwenRuntime:
    _raise_if_qwen_cancelled()
    if MLX_VLM_LOAD is None or MLX_VLM_GENERATE is None:
        detail = _qwen_mlx_dependency_error() or "mlx_vlm_unavailable"
        raise HTTPException(status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=f"qwen_mlx_missing:{detail}")
    resolved_model_id = _effective_qwen_model_id_for_platform(model_id, QWEN_PLATFORM_MLX)
    incompatible_detail = _qwen_mlx_incompatible_model_detail(str(resolved_model_id))
    if incompatible_detail:
        detail = f"qwen_mlx_incompatible_checkpoint:{incompatible_detail}"
        _qwen_progress_error(f"MLX Qwen model is not image-compatible: {incompatible_detail}")
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    availability = _qwen_model_local_state(resolved_model_id, QWEN_PLATFORM_MLX)
    cached_incompatible_detail = _qwen_mlx_cached_checkpoint_incompatibility_detail(
        str(resolved_model_id), availability
    )
    if cached_incompatible_detail:
        detail = f"qwen_mlx_incompatible_checkpoint:{cached_incompatible_detail}"
        _qwen_progress_error(f"MLX Qwen model is not image-compatible: {cached_incompatible_detail}")
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    remote_incompatible_detail = _qwen_mlx_remote_checkpoint_incompatibility_detail(
        str(resolved_model_id)
    )
    if remote_incompatible_detail:
        detail = f"qwen_mlx_incompatible_checkpoint:{remote_incompatible_detail}"
        _qwen_progress_error(f"MLX Qwen model is not image-compatible: {remote_incompatible_detail}")
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    _qwen_progress_update(
        phase="download" if availability.get("needs_download") else "load",
        phase_label="Downloading" if availability.get("needs_download") else "Loading",
        progress=0.10 if availability.get("needs_download") else 0.18,
        message=(
            "MLX weights are not cached yet; downloading before load"
            if availability.get("needs_download")
            else "Loading MLX Qwen model"
        ),
        model_id=str(resolved_model_id),
        platform=QWEN_PLATFORM_MLX,
    )
    _raise_if_qwen_cancelled()
    try:
        load_kwargs = {}
        if adapter_path:
            load_kwargs["adapter_path"] = str(adapter_path)
        monitor_paths = [
            availability.get("cache_path") and Path(str(availability.get("cache_path"))),
            _qwen_cache_repo_path(str(resolved_model_id)),
        ]
        stop_monitor, monitor_thread = _start_qwen_cache_monitor(
            model_id=str(resolved_model_id),
            platform=QWEN_PLATFORM_MLX,
            phase="download" if availability.get("needs_download") else "load",
            phase_label="Downloading" if availability.get("needs_download") else "Loading",
            paths=monitor_paths,
            start_progress=0.10 if availability.get("needs_download") else 0.18,
            max_progress=0.34 if availability.get("needs_download") else 0.36,
        )
        try:
            model_local, processor_local = MLX_VLM_LOAD(str(resolved_model_id), **load_kwargs)
        finally:
            stop_monitor.set()
            monitor_thread.join(timeout=1.0)
    except Exception as exc:  # noqa: BLE001
        detail = _format_qwen_load_error_impl(exc, torch_module=torch)
        _qwen_progress_log(f"MLX Qwen load failed: {detail}")
        raise HTTPException(
            status_code=HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"qwen_mlx_load_failed:{detail}",
        ) from exc
    _raise_if_qwen_cancelled()
    final_stats = _qwen_cache_tree_stats(
        [
            availability.get("cache_path") and Path(str(availability.get("cache_path"))),
            _qwen_cache_repo_path(str(resolved_model_id)),
        ]
    )
    _qwen_progress_log(
        "MLX Qwen load returned; "
        f"{_format_qwen_bytes(int(final_stats.get('bytes') or 0))} cached across "
        f"{int(final_stats.get('files') or 0)} files"
    )
    _qwen_progress_update(
        phase="load",
        phase_label="Loaded",
        progress=0.38,
        message="MLX Qwen model loaded",
        model_id=str(resolved_model_id),
        platform=QWEN_PLATFORM_MLX,
    )
    config = None
    if MLX_LOAD_CONFIG is not None:
        try:
            config = MLX_LOAD_CONFIG(str(resolved_model_id))
        except Exception:
            config = getattr(model_local, "config", None)
    else:
        config = getattr(model_local, "config", None)
    return QwenRuntime(
        model=model_local,
        processor=processor_local,
        platform=QWEN_PLATFORM_MLX,
        model_id=str(resolved_model_id),
        config=config,
    )


def _ensure_qwen_mlx_ready(model_id: Optional[str] = None, adapter_path: Optional[Path] = None) -> QwenRuntime:
    global qwen_model, qwen_processor, qwen_device, qwen_last_error, loaded_qwen_model_id
    global qwen_runtime_platform, qwen_loaded_effective_model_id, qwen_runtime_config
    requested_model_id = _effective_qwen_model_id_for_platform(
        model_id or (active_qwen_metadata or {}).get("model_id") or QWEN_MODEL_NAME,
        QWEN_PLATFORM_MLX,
    )
    adapter_key = str(adapter_path or "")
    runtime_key = f"{active_qwen_model_id}:{QWEN_PLATFORM_MLX}:{requested_model_id}:{adapter_key}"
    if (
        qwen_model is not None
        and qwen_processor is not None
        and loaded_qwen_model_id == runtime_key
        and qwen_runtime_platform == QWEN_PLATFORM_MLX
        and qwen_loaded_effective_model_id == requested_model_id
    ):
        return QwenRuntime(
            model=qwen_model,
            processor=qwen_processor,
            platform=QWEN_PLATFORM_MLX,
            model_id=requested_model_id,
            config=qwen_runtime_config,
        )
    with qwen_lock:
        if (
            qwen_model is not None
            and qwen_processor is not None
            and loaded_qwen_model_id == runtime_key
            and qwen_runtime_platform == QWEN_PLATFORM_MLX
            and qwen_loaded_effective_model_id == requested_model_id
        ):
            return QwenRuntime(
                model=qwen_model,
                processor=qwen_processor,
                platform=QWEN_PLATFORM_MLX,
                model_id=requested_model_id,
                config=qwen_runtime_config,
            )
        try:
            runtime = _load_qwen_mlx_runtime(requested_model_id, adapter_path=adapter_path)
        except HTTPException as exc:
            qwen_last_error = str(exc.detail)
            raise
        qwen_model = runtime.model
        qwen_processor = runtime.processor
        qwen_device = QWEN_PLATFORM_MLX
        qwen_runtime_platform = QWEN_PLATFORM_MLX
        qwen_loaded_effective_model_id = runtime.model_id
        qwen_runtime_config = runtime.config
        loaded_qwen_model_id = runtime_key
        qwen_last_error = None
        return runtime


def _ensure_qwen_mlx_ready_for_caption(model_id_override: str) -> QwenRuntime:
    _raise_if_qwen_cancelled()
    global qwen_device, qwen_last_error, qwen_caption_cache, qwen_caption_order
    resolved_model_id = _effective_qwen_model_id_for_platform(
        model_id_override or QWEN_MLX_MODEL_NAME,
        QWEN_PLATFORM_MLX,
    )
    cache_key = f"caption:{QWEN_PLATFORM_MLX}:{resolved_model_id}"
    cache_limit = max(0, int(QWEN_CAPTION_CACHE_LIMIT or 0))
    if cache_limit == 0 and qwen_caption_cache:
        for key, entry in list(qwen_caption_cache.items()):
            _evict_qwen_caption_entry_impl(key, entry, torch_module=torch, gc_module=gc)
        qwen_caption_cache.clear()
        qwen_caption_order.clear()
        _clear_mlx_cache()
    cached = qwen_caption_cache.get(cache_key)
    if cached and cache_limit:
        try:
            qwen_caption_order.remove(cache_key)
        except ValueError:
            pass
        qwen_caption_order.append(cache_key)
        if isinstance(cached, QwenRuntime):
            return cached
        model_local, processor_local = cached
        return QwenRuntime(
            model=model_local,
            processor=processor_local,
            platform=QWEN_PLATFORM_MLX,
            model_id=resolved_model_id,
        )
    with qwen_lock:
        cached = qwen_caption_cache.get(cache_key)
        if cached and cache_limit:
            try:
                qwen_caption_order.remove(cache_key)
            except ValueError:
                pass
            qwen_caption_order.append(cache_key)
            if isinstance(cached, QwenRuntime):
                return cached
            model_local, processor_local = cached
            return QwenRuntime(
                model=model_local,
                processor=processor_local,
                platform=QWEN_PLATFORM_MLX,
                model_id=resolved_model_id,
            )
        try:
            runtime = _load_qwen_mlx_runtime(resolved_model_id)
        except HTTPException as exc:
            qwen_last_error = str(exc.detail)
            raise
        _raise_if_qwen_cancelled()
        qwen_device = QWEN_PLATFORM_MLX
        qwen_last_error = None
        if cache_limit:
            qwen_caption_cache[cache_key] = runtime
            qwen_caption_order.append(cache_key)
            while len(qwen_caption_order) > cache_limit:
                evict_key = qwen_caption_order.popleft()
                evict_entry = qwen_caption_cache.pop(evict_key, None)
                _evict_qwen_caption_entry_impl(evict_key, evict_entry, torch_module=torch, gc_module=gc)
        return runtime


def _ensure_qwen_ready():
    global qwen_model, qwen_processor, qwen_device, qwen_last_error, loaded_qwen_model_id
    global qwen_runtime_platform, qwen_loaded_effective_model_id, qwen_runtime_config
    _clear_unusable_active_qwen_model_path()
    metadata = active_qwen_metadata or {}
    adapter_path = active_qwen_model_path
    base_model_id = metadata.get("model_id") or QWEN_MODEL_NAME
    platform_name = _resolve_qwen_runtime_platform(
        str(base_model_id),
        adapter_path=adapter_path,
        metadata=metadata,
    )
    if platform_name == QWEN_PLATFORM_MLX:
        return _ensure_qwen_mlx_ready(str(base_model_id), adapter_path=adapter_path)
    if (
        QWEN_IMPORT_ERROR is not None
        or Qwen3VLForConditionalGeneration is None
        or AutoProcessor is None
        or process_vision_info is None
    ):
        detail = f"qwen_dependencies_missing:{QWEN_IMPORT_ERROR}"
        raise HTTPException(status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=detail)
    if packaging_version is not None:
        try:
            import transformers  # local import to avoid import-time failures

            if packaging_version.parse(transformers.__version__) < packaging_version.parse(
                QWEN_MIN_TRANSFORMERS
            ):
                raise HTTPException(
                    status_code=HTTP_503_SERVICE_UNAVAILABLE,
                    detail=f"qwen_transformers_too_old:{transformers.__version__}<{QWEN_MIN_TRANSFORMERS}",
                )
        except HTTPException:
            raise
        except Exception:
            # If we cannot resolve version info, continue and let the load fail if incompatible.
            pass
    if (
        qwen_model is not None
        and qwen_processor is not None
        and loaded_qwen_model_id == active_qwen_model_id
        and qwen_runtime_platform in (None, QWEN_PLATFORM_TRANSFORMERS)
    ):
        return QwenRuntime(
            model=qwen_model,
            processor=qwen_processor,
            platform=QWEN_PLATFORM_TRANSFORMERS,
            model_id=qwen_loaded_effective_model_id or str(base_model_id),
            config=qwen_runtime_config,
        )
    with qwen_lock:
        if (
            qwen_model is not None
            and qwen_processor is not None
            and loaded_qwen_model_id == active_qwen_model_id
            and qwen_runtime_platform in (None, QWEN_PLATFORM_TRANSFORMERS)
        ):
            return QwenRuntime(
                model=qwen_model,
                processor=qwen_processor,
                platform=QWEN_PLATFORM_TRANSFORMERS,
                model_id=qwen_loaded_effective_model_id or str(base_model_id),
                config=qwen_runtime_config,
            )
        try:
            device = _resolve_qwen_device_impl(QWEN_DEVICE_PREF, torch_module=torch)
        except RuntimeError as exc:  # noqa: BLE001
            qwen_last_error = str(exc)
            raise HTTPException(
                status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=f"qwen_device_unavailable:{exc}"
            ) from exc
        load_kwargs = qwen_transformers_load_kwargs(
            str(base_model_id),
            device=device,
            device_pref=QWEN_DEVICE_PREF,
            torch_module=torch,
        )
        if adapter_path and PeftModel is None:
            detail = "qwen_peft_missing"
            if PEFT_IMPORT_ERROR is not None:
                detail = f"{detail}:{PEFT_IMPORT_ERROR}"
            raise HTTPException(status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=detail)
        availability = _qwen_model_local_state(str(base_model_id), QWEN_PLATFORM_TRANSFORMERS)
        _qwen_progress_update(
            phase="download" if availability.get("needs_download") else "load",
            phase_label="Downloading" if availability.get("needs_download") else "Loading",
            progress=0.10 if availability.get("needs_download") else 0.18,
            message=(
                "Qwen weights are not cached yet; downloading before load"
                if availability.get("needs_download")
                else "Loading Qwen model"
            ),
            model_id=str(base_model_id),
            platform=QWEN_PLATFORM_TRANSFORMERS,
        )

        def _load_candidate(candidate_id: str, processor_source: str) -> Tuple[Any, Any]:
            local_only = _hf_offline_enabled()
            model_local = _load_qwen_vl_model(
                str(candidate_id), load_kwargs, local_files_only=local_only
            )
            if adapter_path:
                model_local = PeftModel.from_pretrained(model_local, str(adapter_path))
            if not load_kwargs.get("device_map"):
                model_local.to(device)
            model_local.eval()
            processor_local = AutoProcessor.from_pretrained(
                processor_source,
                min_pixels=QWEN_MIN_PIXELS,
                max_pixels=QWEN_MAX_PIXELS,
                local_files_only=local_only,
            )
            return model_local, processor_local

        def _load_with_online_retry(candidate_id: str, processor_source: str) -> Tuple[Any, Any]:
            try:
                return _load_candidate(candidate_id, processor_source)
            except Exception as exc:  # noqa: BLE001
                if _hf_offline_enabled():
                    logger.warning("[qwen] offline load failed; retrying with HF online: %s", exc)
                    _set_hf_offline(False)
                    try:
                        return _load_candidate(candidate_id, processor_source)
                    finally:
                        _enable_hf_offline_defaults()
                raise

        try:
            processor_source = str(adapter_path) if adapter_path else str(base_model_id)
            model, processor = _load_with_online_retry(str(base_model_id), processor_source)
        except Exception as exc:  # noqa: BLE001
            fallback_id = _strip_qwen_model_suffix_impl(str(base_model_id))
            if fallback_id:
                try:
                    logger.warning(
                        "Qwen model %s not found; falling back to %s", base_model_id, fallback_id
                    )
                    processor_source = str(adapter_path) if adapter_path else str(fallback_id)
                    model, processor = _load_with_online_retry(str(fallback_id), processor_source)
                except Exception as fallback_exc:  # noqa: BLE001
                    qwen_last_error = str(fallback_exc)
                    detail = _format_qwen_load_error_impl(fallback_exc, torch_module=torch)
                    raise HTTPException(
                        status_code=HTTP_503_SERVICE_UNAVAILABLE,
                        detail=f"qwen_load_failed:{detail}",
                    ) from fallback_exc
            else:
                qwen_last_error = str(exc)
                detail = _format_qwen_load_error_impl(exc, torch_module=torch)
                raise HTTPException(
                    status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=f"qwen_load_failed:{detail}"
                ) from exc
        qwen_model = model
        qwen_processor = processor
        qwen_device = device
        qwen_runtime_platform = QWEN_PLATFORM_TRANSFORMERS
        qwen_loaded_effective_model_id = str(base_model_id)
        qwen_runtime_config = getattr(model, "config", None)
        qwen_last_error = None
        loaded_qwen_model_id = active_qwen_model_id
        _enable_hf_offline_defaults()
        _qwen_progress_update(
            phase="load",
            phase_label="Loaded",
            progress=0.38,
            message="Qwen model loaded",
            model_id=str(base_model_id),
            platform=QWEN_PLATFORM_TRANSFORMERS,
        )
        return QwenRuntime(
            model=model,
            processor=processor,
            platform=QWEN_PLATFORM_TRANSFORMERS,
            model_id=str(base_model_id),
            config=qwen_runtime_config,
        )


def _unload_qwen_runtime() -> None:
    """Release Qwen model/processor to free device memory."""
    global qwen_model, qwen_processor, qwen_device, qwen_last_error, loaded_qwen_model_id
    global qwen_runtime_platform, qwen_loaded_effective_model_id, qwen_runtime_config
    global qwen_caption_cache, qwen_caption_order
    state = {
        "qwen_model": qwen_model,
        "qwen_processor": qwen_processor,
        "qwen_device": qwen_device,
        "qwen_last_error": qwen_last_error,
        "loaded_qwen_model_id": loaded_qwen_model_id,
        "qwen_caption_cache": qwen_caption_cache,
        "qwen_caption_order": qwen_caption_order,
    }
    _unload_qwen_runtime_impl(
        state=state,
        torch_module=torch,
        gc_module=gc,
        logger=logger,
        deque_factory=deque,
    )
    qwen_model = state["qwen_model"]
    qwen_processor = state["qwen_processor"]
    qwen_device = state["qwen_device"]
    qwen_last_error = state["qwen_last_error"]
    loaded_qwen_model_id = state["loaded_qwen_model_id"]
    qwen_runtime_platform = None
    qwen_loaded_effective_model_id = None
    qwen_runtime_config = None
    qwen_caption_cache = state["qwen_caption_cache"]
    qwen_caption_order = state["qwen_caption_order"]
    _clear_mlx_cache()


def _ensure_qwen_ready_for_caption(model_id_override: str) -> Tuple[Any, Any]:
    _raise_if_qwen_cancelled()
    global qwen_device, qwen_last_error
    global qwen_caption_cache, qwen_caption_order
    platform_name = _resolve_qwen_runtime_platform(str(model_id_override), adapter_path=None)
    if platform_name == QWEN_PLATFORM_MLX:
        return _ensure_qwen_mlx_ready_for_caption(model_id_override)
    state = {
        "qwen_caption_cache": qwen_caption_cache,
        "qwen_caption_order": qwen_caption_order,
        "qwen_device": qwen_device,
        "qwen_last_error": qwen_last_error,
    }
    device_pref = QWEN_DEVICE_PREF
    if device_pref == "auto":
        try:
            resolved_device = _resolve_qwen_device_impl(QWEN_DEVICE_PREF, torch_module=torch)
            device_pref = str(resolved_device)
        except Exception:
            device_pref = QWEN_DEVICE_PREF
    # Captioning should never use multi-GPU sharding; force a concrete device id if possible.
    if device_pref == "cuda":
        device_pref = "cuda:0"
    if device_pref != "auto" and state.get("qwen_caption_cache"):
        for cache_key, cache_entry in list(state["qwen_caption_cache"].items()):
            if not cache_entry:
                continue
            try:
                cached_model, _ = cache_entry
            except Exception:
                continue
            try:
                hf_map = getattr(cached_model, "hf_device_map", None)
                if hf_map:
                    unique_devices = {str(dev) for dev in hf_map.values()}
                    if len(unique_devices) > 1:
                        _evict_qwen_caption_entry_impl(
                            cache_key,
                            cache_entry,
                            torch_module=torch,
                            gc_module=gc,
                        )
                        state["qwen_caption_cache"].pop(cache_key, None)
                        try:
                            state["qwen_caption_order"].remove(cache_key)
                        except ValueError:
                            pass
            except Exception:
                continue
    availability = _qwen_model_local_state(str(model_id_override), QWEN_PLATFORM_TRANSFORMERS)
    _qwen_progress_update(
        phase="download" if availability.get("needs_download") else "load",
        phase_label="Downloading" if availability.get("needs_download") else "Loading",
        progress=0.10 if availability.get("needs_download") else 0.18,
        message=(
            "Caption model weights are not cached yet; downloading before load"
            if availability.get("needs_download")
            else "Loading Qwen caption model"
        ),
        model_id=str(model_id_override),
        platform=QWEN_PLATFORM_TRANSFORMERS,
    )
    _raise_if_qwen_cancelled()
    try:
        model, processor = _ensure_qwen_ready_for_caption_impl(
            model_id_override,
            state=state,
            qwen_lock=qwen_lock,
            import_error=QWEN_IMPORT_ERROR,
            qwen_model_cls=Qwen3VLForConditionalGeneration,
            qwen_processor_cls=AutoProcessor,
            process_vision_info=process_vision_info,
            packaging_version=packaging_version,
            min_transformers=QWEN_MIN_TRANSFORMERS,
            resolve_device_fn=lambda: _resolve_qwen_device_impl(device_pref, torch_module=torch),
            device_pref=device_pref,
            torch_module=torch,
            load_qwen_model_fn=_load_qwen_vl_model,
            hf_offline_enabled_fn=_hf_offline_enabled,
            set_hf_offline_fn=_set_hf_offline,
            enable_hf_offline_defaults_fn=_enable_hf_offline_defaults,
            strip_model_suffix_fn=_strip_qwen_model_suffix_impl,
            format_load_error_fn=lambda exc: _format_qwen_load_error_impl(exc, torch_module=torch),
            min_pixels=QWEN_MIN_PIXELS,
            max_pixels=QWEN_MAX_PIXELS,
            caption_cache_limit=QWEN_CAPTION_CACHE_LIMIT,
            evict_entry_fn=lambda cache_key, cache_entry: _evict_qwen_caption_entry_impl(
                cache_key,
                cache_entry,
                torch_module=torch,
                gc_module=gc,
            ),
            logger=logger,
        )
    except RuntimeError as exc:  # noqa: BLE001
        detail = str(exc)
        raise HTTPException(status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=detail) from exc
    _raise_if_qwen_cancelled()
    qwen_caption_cache = state["qwen_caption_cache"]
    qwen_caption_order = state["qwen_caption_order"]
    qwen_device = state["qwen_device"]
    qwen_last_error = state["qwen_last_error"]
    _qwen_progress_update(
        phase="load",
        phase_label="Loaded",
        progress=0.38,
        message="Qwen caption model loaded",
        model_id=str(model_id_override),
        platform=QWEN_PLATFORM_TRANSFORMERS,
    )
    return QwenRuntime(
        model=model,
        processor=processor,
        platform=QWEN_PLATFORM_TRANSFORMERS,
        model_id=str(model_id_override),
    )


