def _postprocess_features_for_head(
    feats_np: np.ndarray,
    *,
    head: Dict[str, Any],
    geometry_records: Optional[Sequence[Mapping[str, Any]]] = None,
) -> np.ndarray:
    feats_np = np.asarray(feats_np, dtype=np.float32)
    normalize_embeddings = bool(head.get("normalize_embeddings"))
    if normalize_embeddings:
        feats_np = _embedding_normalize_rows(feats_np)
    transform = head.get("embedding_adjustment_transform")
    if transform and geometry_records is not None:
        covariates, _names = _embedding_covariates_from_records(geometry_records)
        feats_np = apply_size_bias_residualizer(
            feats_np,
            covariates,
            transform,
            normalize=True,
        )
    if normalize_embeddings and str(head.get("classifier_type") or "").lower() == "mlp":
        feats_np = _embedding_normalize_rows(feats_np)
    center_vals = head.get("embedding_center_values")
    std_vals = head.get("embedding_std_values")
    if center_vals is not None:
        center_arr = np.asarray(center_vals, dtype=np.float32).reshape(1, -1)
        if center_arr.shape[1] == feats_np.shape[1]:
            feats_np = feats_np - center_arr
    if std_vals is not None:
        std_arr = np.asarray(std_vals, dtype=np.float32).reshape(1, -1)
        if std_arr.shape[1] == feats_np.shape[1]:
            std_arr = np.where(std_arr == 0, 1.0, std_arr)
            feats_np = feats_np / std_arr
    return feats_np.astype(np.float32, copy=False)


def _cached_clip_backbone_for_head(
    clip_name: str,
    device_name: str,
) -> Tuple[Optional[Any], Optional[Any]]:
    model_name = str(clip_name or DEFAULT_CLIP_MODEL).strip() or DEFAULT_CLIP_MODEL
    device_key = str(device_name or device)
    key = (model_name, device_key)
    with _agent_clip_backbones_lock:
        lock = _agent_clip_locks.get(key)
        if lock is None:
            lock = threading.Lock()
            _agent_clip_locks[key] = lock
    with lock:
        cached = _agent_clip_backbones.get(key)
        if cached is not None:
            return cached
        try:
            model_obj, preprocess_obj = clip.load(model_name, device=device_key)
        except Exception as exc:  # noqa: BLE001
            logger.warning("Failed to load CLIP backbone %s for classifier head: %s", model_name, exc)
            return None, None
        _agent_clip_backbones[key] = (model_obj, preprocess_obj)
        return model_obj, preprocess_obj


def _encode_pil_batch_for_head(
    images: Sequence[Image.Image],
    *,
    head: Dict[str, Any],
    batch_size_override: Optional[int] = None,
    device_override: Optional[str] = None,
    geometry_records: Optional[Sequence[Mapping[str, Any]]] = None,
) -> Optional[np.ndarray]:
    if not images:
        return None
    encoder_type = str(head.get("encoder_type") or "clip").strip().lower()
    aggregation = _embedding_normalize_aggregation(head.get("embedding_aggregation"))
    if aggregation == "local_salad":
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_auto_class_disabled")
    batch_size = int(batch_size_override or 0) or len(images)
    batch_size = max(1, min(batch_size, len(images)))
    features: List[np.ndarray] = []
    if encoder_type == "dinov3":
        global dinov3_model, dinov3_processor, dinov3_model_name, dinov3_model_device, dinov3_initialized
        model_name = str(
            head.get("encoder_model") or head.get("clip_model") or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL or ""
        ).strip()
        target_device = device_override or _dinov3_resolve_device_impl(
            device, cuda_disabled=dinov3_cuda_disabled
        )
        if (
            dinov3_model is None
            or dinov3_processor is None
            or (model_name and dinov3_model_name != model_name)
            or (dinov3_model_device and dinov3_model_device != target_device)
        ):
            with dinov3_lock:
                if (
                    dinov3_model is None
                    or dinov3_processor is None
                    or (model_name and dinov3_model_name != model_name)
                    or (dinov3_model_device and dinov3_model_device != target_device)
                ):
                    load_name = model_name or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
                    model_obj, processor_obj = _load_dinov3_backbone(
                        load_name,
                        target_device,
                    )
                    if model_obj is not None and processor_obj is not None:
                        dinov3_model = model_obj
                        dinov3_processor = processor_obj
                        dinov3_model_name = load_name
                        dinov3_model_device = target_device
                        dinov3_initialized = True
        if dinov3_model is None or dinov3_processor is None:
            return None
        device_name = device_override or dinov3_model_device or target_device or device
        for idx in range(0, len(images), batch_size):
            batch = images[idx : idx + batch_size]
            inputs = dinov3_processor(images=batch, return_tensors="pt")
            inputs = {k: v.to(device_name) for k, v in inputs.items()}
            with torch.no_grad():
                outputs = dinov3_model(**inputs)
            pooling = _embedding_normalize_dinov3_pooling(head.get("dinov3_pooling"))
            last_hidden = getattr(outputs, "last_hidden_state", None)
            if pooling == "pooler" and hasattr(outputs, "pooler_output") and outputs.pooler_output is not None:
                feats = outputs.pooler_output
            elif pooling == "patch_mean" and last_hidden is not None and last_hidden.ndim == 3 and last_hidden.shape[1] > 1:
                feats = last_hidden[:, 1:, :].mean(dim=1)
            elif pooling == "cls_patch_concat" and last_hidden is not None and last_hidden.ndim == 3 and last_hidden.shape[1] > 1:
                cls_feats = last_hidden[:, 0, :]
                patch_feats = last_hidden[:, 1:, :].mean(dim=1)
                cls_feats = torch.nn.functional.normalize(cls_feats, dim=-1)
                patch_feats = torch.nn.functional.normalize(patch_feats, dim=-1)
                feats = torch.cat([cls_feats, patch_feats], dim=-1)
            elif last_hidden is not None:
                feats = last_hidden[:, 0, :]
            else:
                feats = outputs[0]
            feats_np = feats.detach().float().cpu().numpy()
            features.append(feats_np)
    elif encoder_type == "cradio":
        model_name = normalize_cradio_model(head.get("encoder_model") or head.get("clip_model") or CRADIO_DEFAULT_MODEL)
        backend = str(head.get("cradio_backend") or os.environ.get("CRADIO_BACKEND") or "auto").strip()
        target_device = device_override or resolve_cradio_torch_device(backend, model_name=model_name)
        model_obj, processor_obj, resolved_model, device_name = _load_cradio_backbone_cached(
            model_name,
            target_device,
        )
        if model_obj is None or (processor_obj is None and device_name != "mlx"):
            return None
        pooling = normalize_cradio_pooling(head.get("cradio_pooling"))
        for idx in range(0, len(images), batch_size):
            batch = images[idx : idx + batch_size]
            feats_np = encode_cradio_images(
                model_obj,
                processor_obj,
                device_name,
                batch,
                pooling=pooling,
                normalize=False,
            )
            features.append(np.asarray(feats_np, dtype=np.float32))
    else:
        requested_clip_name = str(
            head.get("encoder_model") or head.get("clip_model") or clip_model_name or DEFAULT_CLIP_MODEL
        ).strip() or DEFAULT_CLIP_MODEL
        device_name = str(device_override or device)
        model_obj = None
        preprocess_obj = None
        if (
            clip_model is not None
            and clip_preprocess is not None
            and not _clip_reload_needed
            and clip_model_name == requested_clip_name
        ):
            model_obj = clip_model
            preprocess_obj = clip_preprocess
        elif clip_model_name == requested_clip_name and (
            clip_model is None or clip_preprocess is None or _clip_reload_needed
        ):
            _resume_clip_backbone()
            if (
                clip_model is not None
                and clip_preprocess is not None
                and clip_model_name == requested_clip_name
            ):
                model_obj = clip_model
                preprocess_obj = clip_preprocess
        if model_obj is None or preprocess_obj is None:
            model_obj, preprocess_obj = _cached_clip_backbone_for_head(
                requested_clip_name,
                device_name,
            )
        if model_obj is None or preprocess_obj is None:
            return None
        for idx in range(0, len(images), batch_size):
            batch = images[idx : idx + batch_size]
            batch_tensor = torch.stack([preprocess_obj(img) for img in batch]).to(device_name)
            with torch.no_grad():
                feats = model_obj.encode_image(batch_tensor).float()
            feats_np = feats.detach().cpu().numpy()
            features.append(feats_np)
    if not features:
        return None
    feats_np = np.concatenate(features, axis=0)
    return _postprocess_features_for_head(feats_np, head=head, geometry_records=geometry_records)


def _crop_item_views(item: Any) -> List[Image.Image]:
    if isinstance(item, (list, tuple)):
        return [view for view in item if isinstance(view, Image.Image)]
    if isinstance(item, Image.Image):
        return [item]
    return []


def _close_crop_item(item: Any) -> None:
    for view in _crop_item_views(item):
        try:
            view.close()
        except Exception:
            pass


def _encode_embedding_items_for_head(
    items: Sequence[Any],
    *,
    head: Dict[str, Any],
    batch_size_override: Optional[int] = None,
    device_override: Optional[str] = None,
    geometry_records: Optional[Sequence[Mapping[str, Any]]] = None,
) -> Optional[np.ndarray]:
    if not items:
        return None
    view_counts = [len(_crop_item_views(item)) for item in items]
    if all(count == 1 for count in view_counts):
        return _encode_pil_batch_for_head(
            [_crop_item_views(item)[0] for item in items],
            head=head,
            batch_size_override=batch_size_override,
            device_override=device_override,
            geometry_records=geometry_records,
        )
    if any(count <= 0 for count in view_counts):
        return None
    flat_images: List[Image.Image] = []
    for item in items:
        flat_images.extend(_crop_item_views(item))
    raw_head = dict(head)
    raw_head.pop("embedding_adjustment_transform", None)
    raw_head.pop("embedding_center_values", None)
    raw_head.pop("embedding_std_values", None)
    raw_features = _encode_pil_batch_for_head(
        flat_images,
        head=raw_head,
        batch_size_override=batch_size_override,
        device_override=device_override,
        geometry_records=None,
    )
    if raw_features is None or raw_features.shape[0] != len(flat_images):
        return None
    composed: List[np.ndarray] = []
    cursor = 0
    for count in view_counts:
        chunk = np.asarray(raw_features[cursor : cursor + count], dtype=np.float32)
        cursor += count
        chunk = _embedding_normalize_rows(chunk)
        composed.append(_embedding_normalize_rows(chunk.reshape(1, -1))[0])
    feats_np = np.stack(composed, axis=0).astype(np.float32, copy=False)
    return _postprocess_features_for_head(feats_np, head=head, geometry_records=geometry_records)


def _classifier_crop_for_head(
    pil_img: Image.Image,
    xyxy: Sequence[float],
    head: Optional[Mapping[str, Any]],
) -> Tuple[Any, Dict[str, Any]]:
    """Crop and preprocess an object using the classifier's saved embedding recipe."""
    img_w, img_h = pil_img.size
    x1, y1, x2, y2 = [float(v) for v in xyxy[:4]]
    crop_mode = str((head or {}).get("embedding_crop_mode") or (head or {}).get("crop_mode") or "padded_square")
    padding = _coerce_float(
        (head or {}).get("embedding_crop_padding_ratio")
        if (head or {}).get("embedding_crop_padding_ratio") is not None
        else (head or {}).get("crop_padding_ratio"),
        0.08,
        minimum=0.0,
        maximum=1.0,
    )
    preprocess_mode = _embedding_normalize_preprocess((head or {}).get("preprocess_mode"))
    canonical_size = min(1024, _coerce_int((head or {}).get("canonical_size"), 336, minimum=64))
    background_mode = _embedding_normalize_background_mode((head or {}).get("background_mode"))
    view_mode = _embedding_normalize_view_mode((head or {}).get("embedding_view_mode"))
    views, crop_xyxy, view_metadata = _embedding_make_crop_views(
        pil_img,
        [x1, y1, x2, y2],
        crop_mode=crop_mode,
        padding_ratio=padding,
        preprocess_mode=preprocess_mode,
        canonical_size=canonical_size,
        background_mode=background_mode,
        view_mode=view_mode,
    )
    record = {
        "bbox_xyxy": [float(x1), float(y1), float(x2), float(y2)],
        "crop_xyxy": [int(v) for v in crop_xyxy],
        "width": int(round(max(1.0, x2 - x1))),
        "height": int(round(max(1.0, y2 - y1))),
        "background_mode": background_mode,
        "embedding_view_mode": view_mode,
        "embedding_views": view_metadata,
    }
    return (tuple(views) if len(views) > 1 else views[0]), record


def _encode_pil_batch_for_active(images: Sequence[Image.Image]) -> Optional[np.ndarray]:
    head = _active_classifier_head_for_inference()
    if not isinstance(head, dict):
        head = {
            "encoder_type": active_encoder_type or "clip",
            "normalize_embeddings": active_head_normalize_embeddings,
            "embedding_center_values": (active_classifier_meta or {}).get(
                "embedding_center_values"
            ),
            "embedding_std_values": (active_classifier_meta or {}).get("embedding_std_values"),
        }
    return _encode_pil_batch_for_head(images, head=head)


def _encode_classifier_xyxy_for_active(
    pil_img: Image.Image,
    xyxy: Sequence[float],
) -> Optional[np.ndarray]:
    head = _active_classifier_head_for_inference()
    if not isinstance(head, dict):
        head = {
            "encoder_type": active_encoder_type or "clip",
            "normalize_embeddings": active_head_normalize_embeddings,
            "embedding_center_values": (active_classifier_meta or {}).get(
                "embedding_center_values"
            ),
            "embedding_std_values": (active_classifier_meta or {}).get("embedding_std_values"),
        }
    crop, record = _classifier_crop_for_head(pil_img, xyxy, head)
    try:
        return _encode_embedding_items_for_head([crop], head=head, geometry_records=[record])
    finally:
        _close_crop_item(crop)


def _active_classifier_head_for_inference() -> Optional[Dict[str, Any]]:
    """Return the active classifier as a normalized inference head when possible."""
    global active_classifier_head

    classifier_path = str(active_classifier_path or "").strip()
    if not classifier_path:
        if (
            clf is not None
            or active_labelmap_path
            or active_label_list
            or isinstance(active_classifier_head, dict)
        ):
            _clear_active_classifier_state("classifier_not_found")
        return None
    if not os.path.isfile(classifier_path):
        _clear_active_classifier_state("classifier_not_found")
        return None
    if isinstance(active_classifier_head, dict):
        return active_classifier_head
    try:
        head = _load_clip_head_from_classifier_impl(
            Path(classifier_path),
            joblib_load_fn=_joblib_load,
            http_exception_cls=HTTPException,
            clip_head_background_indices_fn=_clip_head_background_indices,
            resolve_head_normalize_embeddings_fn=_resolve_head_normalize_embeddings_impl,
            infer_clip_model_fn=_infer_clip_model_from_embedding_dim_impl,
            active_clip_model_name=clip_model_name,
            default_clip_model=DEFAULT_CLIP_MODEL,
            logger=logger,
        )
    except Exception as exc:  # noqa: BLE001
        logger.debug("Active classifier head unavailable for %s: %s", classifier_path, exc)
        return None
    if isinstance(head, dict):
        active_classifier_head = head
        return active_classifier_head
    return None


def _clear_active_classifier_state(error: Optional[str] = None) -> None:
    """Clear active classifier globals after the backing artifact is removed."""
    global clf, active_classifier_path, active_labelmap_path, active_label_list, clip_last_error
    global active_classifier_meta, active_head_normalize_embeddings, active_classifier_head

    with clip_lock:
        clf = None
        active_classifier_path = None
        active_labelmap_path = None
        active_label_list = []
        active_classifier_meta = {}
        active_head_normalize_embeddings = True
        active_classifier_head = None
        clip_last_error = error


def _clip_head_predict_proba(
    feats: Any,
    head: Dict[str, Any],
    *,
    empty_cache_fn: Optional[Callable[[], None]] = None,
) -> Optional[np.ndarray]:
    if feats is None:
        return None
    feats_np = (
        feats.detach().cpu().numpy() if isinstance(feats, torch.Tensor) else np.asarray(feats)
    )
    if feats_np.ndim != 2:
        return None
    classifier_type = str(head.get("classifier_type") or "").lower()
    if classifier_type == "mlp":
        layers = head.get("layers") or []
        if not isinstance(layers, list) or not layers:
            return None
        x = feats_np.astype(np.float32, copy=False)
        arcface = bool(head.get("arcface"))
        arcface_scale = _coerce_float(head.get("arcface_scale"), 1.0, minimum=1e-6)
        for layer_idx, layer in enumerate(layers):
            try:
                weight = np.asarray(layer.get("weight"), dtype=np.float32)
                bias = np.asarray(layer.get("bias"), dtype=np.float32)
            except Exception:
                return None
            if weight.ndim != 2 or bias.ndim != 1 or bias.shape[0] != weight.shape[0]:
                return None
            if x.shape[1] != weight.shape[1]:
                return None
            is_output_layer = layer_idx == len(layers) - 1
            if arcface and is_output_layer:
                x_norm = x / np.maximum(np.linalg.norm(x, axis=1, keepdims=True), 1e-12)
                weight_norm = weight / np.maximum(
                    np.linalg.norm(weight, axis=1, keepdims=True), 1e-12
                )
                x = (x_norm @ weight_norm.T) * arcface_scale
                continue
            x = x @ weight.T + bias
            ln_weight = layer.get("layer_norm_weight")
            if ln_weight is not None:
                try:
                    ln_weight = np.asarray(ln_weight, dtype=np.float32)
                    ln_bias = (
                        np.asarray(layer.get("layer_norm_bias"), dtype=np.float32)
                        if layer.get("layer_norm_bias") is not None
                        else None
                    )
                except Exception:
                    return None
                if ln_weight.shape != (x.shape[1],):
                    return None
                if ln_bias is not None and ln_bias.shape != (x.shape[1],):
                    return None
                eps = float(layer.get("layer_norm_eps") or 1e-5)
                mean = x.mean(axis=-1, keepdims=True)
                var = x.var(axis=-1, keepdims=True)
                x = (x - mean) / np.sqrt(var + eps)
                x = x * ln_weight
                if ln_bias is not None:
                    x = x + ln_bias
            activation = str(layer.get("activation") or "").lower()
            if activation in {"relu"}:
                x = np.maximum(0.0, x)
            elif activation in {"gelu"}:
                erf = np.vectorize(math.erf, otypes=[np.float32])
                x = 0.5 * x * (1.0 + erf(x / math.sqrt(2.0)))
        logits = x
    else:
        try:
            coef = np.asarray(head.get("coef"), dtype=np.float32)
            intercept = np.asarray(head.get("intercept"), dtype=np.float32)
        except Exception:
            return None
        if coef.ndim != 2:
            return None
        if feats_np.shape[1] != coef.shape[1]:
            return None
        if intercept.ndim == 1:
            intercept = intercept.reshape(1, -1)
        if intercept.ndim != 2 or intercept.shape[1] != coef.shape[0]:
            return None
        logits = feats_np @ coef.T + intercept
    proba_mode = str(head.get("proba_mode") or "softmax").lower()
    classes = _clip_head_classes(head)
    class_count = len(classes)
    if proba_mode == "binary":
        if class_count and class_count != 2:
            return None
    elif class_count and logits.shape[1] != class_count:
        return None
    if head.get("logit_adjustment_inference"):
        adjust = head.get("logit_adjustment")
        if adjust is not None:
            try:
                adj = np.asarray(adjust, dtype=np.float32).reshape(1, -1)
            except Exception:
                adj = None
            if adj is not None:
                if proba_mode == "binary" and logits.shape[1] == 1 and adj.shape[1] == 2:
                    logits = logits + (adj[:, 1:2] - adj[:, 0:1])
                elif adj.shape[1] == logits.shape[1]:
                    logits = logits + adj
    temp = head.get("temperature")
    if temp:
        try:
            logits = logits / float(temp)
        except Exception:
            pass
    if proba_mode == "binary":
        if logits.shape[1] != 1:
            logits = logits[:, :1]
        pos = 1.0 / (1.0 + np.exp(-logits))
        probs = np.concatenate([1.0 - pos, pos], axis=1)
    elif proba_mode == "ovr":
        probs = 1.0 / (1.0 + np.exp(-logits))
        row_sums = probs.sum(axis=1, keepdims=True)
        probs = probs / np.maximum(row_sums, 1e-12)
    else:
        logits = logits - np.max(logits, axis=1, keepdims=True)
        exp_logits = np.exp(logits)
        probs = exp_logits / np.sum(exp_logits, axis=1, keepdims=True)
    if empty_cache_fn is not None and torch.cuda.is_available():
        try:
            empty_cache_fn()
        except Exception:
            pass
    return probs.astype(np.float32, copy=False)


def _clip_auto_predict_details(feats_np: Any, *, background_guard: bool = True) -> Dict[str, Any]:
    head = _active_classifier_head_for_inference()
    if not isinstance(head, dict):
        return {"error": "classifier_head_unavailable"}
    proba_arr = _clip_head_predict_proba(feats_np, head)
    if proba_arr is None or proba_arr.ndim != 2 or proba_arr.shape[0] == 0:
        return {"error": "classifier_failed"}
    classes = _clip_head_classes(head)
    if not classes:
        return {"error": "classifier_no_classes"}
    row = proba_arr[0]
    order = sorted(range(len(classes)), key=lambda idx: float(row[idx]), reverse=True)
    bg_indices = set(_clip_head_background_indices(classes))
    best_idx = order[0] if order else None
    if background_guard and best_idx is not None and best_idx in bg_indices:
        for idx in order:
            if idx not in bg_indices:
                best_idx = idx
                break
    best_label = classes[best_idx] if best_idx is not None else None
    best_prob = float(row[best_idx]) if best_idx is not None else None
    second_idx = None
    for idx in order[1:]:
        if best_idx is None or idx != best_idx:
            second_idx = idx
            break
    second_label = classes[second_idx] if second_idx is not None else None
    second_prob = float(row[second_idx]) if second_idx is not None else None
    margin = None
    if best_prob is not None and second_prob is not None:
        margin = float(best_prob - second_prob)
    return {
        "label": best_label,
        "proba": best_prob,
        "second_label": second_label,
        "second_proba": second_prob,
        "margin": margin,
        "error": None,
    }


def _clip_head_keep_mask(
    proba_arr: np.ndarray,
    *,
    target_index: int,
    min_prob: float,
    margin: float,
    background_indices: Optional[Sequence[int]] = None,
    background_guard: bool = True,
    background_margin: float = 0.0,
) -> Optional[np.ndarray]:
    if proba_arr is None or proba_arr.ndim != 2:
        return None
    num_classes = proba_arr.shape[1]
    if target_index < 0 or target_index >= num_classes:
        return None
    target = proba_arr[:, target_index]
    if num_classes > 1:
        mask = np.ones(num_classes, dtype=bool)
        mask[target_index] = False
        best_other = np.max(proba_arr[:, mask], axis=1)
    else:
        best_other = np.zeros_like(target)
    keep = (target >= float(min_prob)) & ((target - best_other) >= float(margin))
    if background_guard and background_indices:
        bg = np.max(proba_arr[:, list(background_indices)], axis=1)
        keep &= (target - bg) >= float(background_margin)
    return keep


def _save_clip_head_artifacts(
    *,
    recipe_dir: Path,
    head: Dict[str, Any],
    min_prob: float,
    margin: float,
) -> None:
    def _prepare_clip_head_dir() -> Path:
        try:
            if _storage_path_has_symlink_component(recipe_dir):
                raise ValueError("recipe directory has a symlink component")
            recipe_dir.mkdir(parents=True, exist_ok=True)
            if _storage_path_has_symlink_component(recipe_dir) or not recipe_dir.is_dir():
                raise ValueError("recipe path is not a safe directory")
            recipe_root = recipe_dir.resolve(strict=True)
            raw_clip_dir = recipe_dir / "clip_head"
            if _storage_path_has_symlink_component(raw_clip_dir):
                raise ValueError("clip head directory has a symlink component")
            raw_clip_dir.mkdir(parents=True, exist_ok=True)
            if _storage_path_has_symlink_component(raw_clip_dir) or not raw_clip_dir.is_dir():
                raise ValueError("clip head path is not a safe directory")
            clip_root = raw_clip_dir.resolve(strict=True)
            if not _path_is_within_root_impl(clip_root, recipe_root):
                raise ValueError("clip head directory escapes recipe root")
            return raw_clip_dir
        except HTTPException:
            raise
        except Exception as exc:
            raise HTTPException(
                status_code=HTTP_400_BAD_REQUEST,
                detail="agent_recipe_clip_head_path_invalid",
            ) from exc

    def _prepare_clip_head_file(path: Path, clip_root: Path) -> None:
        try:
            if _storage_path_has_symlink_component(path.parent):
                raise ValueError("clip head artifact parent has a symlink component")
            if path.is_symlink():
                path.unlink(missing_ok=True)
            elif path.exists() and path.is_dir():
                raise ValueError("clip head artifact is a directory")
            target = path.resolve(strict=False)
            if not _path_is_within_root_impl(target, clip_root):
                raise ValueError("clip head artifact escapes clip root")
        except HTTPException:
            raise
        except Exception as exc:
            raise HTTPException(
                status_code=HTTP_400_BAD_REQUEST,
                detail="agent_recipe_clip_head_path_invalid",
            ) from exc

    clip_dir = recipe_dir / "clip_head"
    clip_dir = _prepare_clip_head_dir()
    clip_root = clip_dir.resolve(strict=True)
    head_path = clip_dir / "head.npz"
    _prepare_clip_head_file(head_path, clip_root)
    tmp_head_path = clip_dir / f".head.npz.{uuid.uuid4().hex}.tmp"
    _prepare_clip_head_file(tmp_head_path, clip_root)
    try:
        _write_temp_binary_no_follow(
            tmp_head_path,
            lambda handle: np.savez(handle, head=np.array([head], dtype=object)),
        )
        os.replace(tmp_head_path, head_path)
    finally:
        if tmp_head_path.exists() or tmp_head_path.is_symlink():
            tmp_head_path.unlink(missing_ok=True)
    meta = {
        "min_prob": float(min_prob),
        "margin": float(margin),
        "clip_model": head.get("clip_model"),
        "encoder_type": head.get("encoder_type"),
        "encoder_model": head.get("encoder_model"),
        "proba_mode": head.get("proba_mode"),
        "background_margin": head.get("background_margin"),
    }
    meta_path = clip_dir / "meta.json"
    _prepare_clip_head_file(meta_path, clip_root)
    tmp_meta_path = clip_dir / f".meta.json.{uuid.uuid4().hex}.tmp"
    _prepare_clip_head_file(tmp_meta_path, clip_root)
    try:
        _write_temp_text_no_follow(tmp_meta_path, json.dumps(meta, indent=2, ensure_ascii=True))
        os.replace(tmp_meta_path, meta_path)
    finally:
        if tmp_meta_path.exists() or tmp_meta_path.is_symlink():
            tmp_meta_path.unlink(missing_ok=True)


def _load_clip_head_artifacts(
    *,
    recipe_dir: Path,
    fallback_meta: Optional[Dict[str, Any]] = None,
) -> Optional[Dict[str, Any]]:
    clip_dir = recipe_dir / "clip_head"
    head_path = clip_dir / "head.npz"
    if not head_path.exists():
        return None
    try:
        data = np.load(head_path, allow_pickle=True)
        head_arr = data.get("head")
        head = head_arr.item() if head_arr is not None else None
    except Exception:
        head = None
    if not isinstance(head, dict):
        return None
    meta_path = clip_dir / "meta.json"
    meta: Dict[str, Any] = {}
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text())
        except Exception:
            meta = {}
    if fallback_meta and not meta:
        meta = dict(fallback_meta)
    head["min_prob"] = float(meta.get("min_prob") or head.get("min_prob") or 0.5)
    head["margin"] = float(meta.get("margin") or head.get("margin") or 0.0)
    if meta.get("background_margin") is not None:
        head["background_margin"] = meta.get("background_margin")
    if meta.get("clip_model"):
        head["clip_model"] = meta.get("clip_model")
    if meta.get("encoder_type"):
        head["encoder_type"] = meta.get("encoder_type")
    if meta.get("encoder_model"):
        head["encoder_model"] = meta.get("encoder_model")
    if meta.get("proba_mode"):
        head["proba_mode"] = meta.get("proba_mode")
    return head


def _score_detections_with_clip_head(
    detections: Sequence[Any],
    *,
    pil_img: Image.Image,
    clip_head: Dict[str, Any],
    score_mode: str,
) -> Optional[Dict[int, float]]:
    if not detections or pil_img is None or not isinstance(clip_head, dict):
        return None
    img_w, img_h = pil_img.size
    crops: List[Any] = []
    crop_records: List[Dict[str, Any]] = []
    det_refs: List[Any] = []
    target_indices: List[int] = []
    classes = _clip_head_classes(clip_head)
    for det in detections:
        label = None
        if isinstance(det, dict):
            label = det.get("label") or det.get("class_name")
        else:
            label = getattr(det, "label", None) or getattr(det, "class_name", None)
        target_idx = _find_clip_head_target_index(classes, label)
        if target_idx is None:
            continue
        ann = det if isinstance(det, dict) else det.__dict__
        xyxy = _resolve_agent_bbox_xyxy(ann, img_w, img_h, window_bbox_2d=ann.get("window_bbox_2d"))
        if xyxy is None:
            continue
        x1, y1, x2, y2 = xyxy
        x1 = max(0.0, min(float(img_w), x1))
        y1 = max(0.0, min(float(img_h), y1))
        x2 = max(0.0, min(float(img_w), x2))
        y2 = max(0.0, min(float(img_h), y2))
        if x2 <= x1 or y2 <= y1:
            continue
        crop, crop_record = _classifier_crop_for_head(pil_img, (x1, y1, x2, y2), clip_head)
        crops.append(crop)
        crop_records.append(crop_record)
        det_refs.append(det)
        target_indices.append(target_idx)
    if not crops:
        return None
    try:
        feats = _encode_embedding_items_for_head(crops, head=clip_head, geometry_records=crop_records)
        if feats is None:
            return None
        proba = _clip_head_predict_proba(feats, clip_head)
        if proba is None or proba.ndim != 2:
            return None
        scores: Dict[int, float] = {}
        for idx, det in enumerate(det_refs):
            target_idx = target_indices[idx]
            row = proba[idx]
            target_prob = float(row[target_idx])
            if score_mode == "clip_head_margin":
                if len(row) > 1:
                    best_other = float(np.max(np.delete(row, target_idx)))
                else:
                    best_other = 0.0
                score_val = target_prob - best_other
            else:
                score_val = target_prob
            scores[id(det)] = score_val
        return scores
    finally:
        for crop in crops:
            _close_crop_item(crop)


def _agent_classifier_review(
    detections: List[Dict[str, Any]],
    *,
    pil_img: Optional[Image.Image],
    classifier_head: Optional[Dict[str, Any]],
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    counts = {"classifier_checked": 0, "classifier_rejected": 0}
    if not detections or pil_img is None or not isinstance(classifier_head, dict):
        return detections, counts
    classes = _clip_head_classes(classifier_head)
    if not classes:
        return detections, counts
    img_w, img_h = pil_img.size
    bg_indices = _clip_head_background_indices(classes)
    min_prob = float(classifier_head.get("min_prob") or 0.5)
    margin = float(classifier_head.get("margin") or 0.0)
    background_margin = float(classifier_head.get("background_margin") or 0.0)
    pending: List[Dict[str, Any]] = []
    pending_crops: List[Any] = []
    pending_crop_records: List[Dict[str, Any]] = []
    reviewed: List[Dict[str, Any]] = []
    for det in detections:
        if not isinstance(det, dict):
            continue
        counts["classifier_checked"] += 1
        label = str(det.get("label") or det.get("class_name") or "").strip()
        target_idx = _find_clip_head_target_index(classes, label)
        if target_idx is None:
            det["classifier_accept"] = False
            counts["classifier_rejected"] += 1
            continue
        xyxy = det.get("bbox_xyxy_px")
        if not xyxy:
            xyxy = _resolve_agent_bbox_xyxy(
                det, img_w, img_h, window_bbox_2d=det.get("window_bbox_2d")
            )
        if not xyxy or len(xyxy) < 4:
            det["classifier_accept"] = False
            counts["classifier_rejected"] += 1
            continue
        x1, y1, x2, y2 = [float(v) for v in xyxy[:4]]
        if x2 <= x1 or y2 <= y1:
            det["classifier_accept"] = False
            counts["classifier_rejected"] += 1
            continue
        crop, crop_record = _classifier_crop_for_head(pil_img, (x1, y1, x2, y2), classifier_head)
        pending.append({"entry": det, "target_idx": target_idx})
        pending_crops.append(crop)
        pending_crop_records.append(crop_record)
    if not pending:
        return reviewed, counts
    empty_cache_fn = torch.cuda.empty_cache if torch.cuda.is_available() else None
    try:
        proba_arr = _predict_proba_batched_impl(
            pending_crops,
            classifier_head,
            batch_size=_resolve_classifier_batch(),
            encode_batch_fn=lambda items, head_obj, bs: _encode_embedding_items_for_head(
                items, head=head_obj, batch_size_override=bs, geometry_records=pending_crop_records
            ),
            predict_proba_fn=_clip_head_predict_proba,
            empty_cache_fn=empty_cache_fn,
        )
    finally:
        for crop in pending_crops:
            _close_crop_item(crop)
    if proba_arr is None or proba_arr.ndim != 2 or proba_arr.shape[0] != len(pending):
        for pending_entry in pending:
            pending_entry["entry"]["classifier_accept"] = False
        counts["classifier_rejected"] += len(pending)
        return reviewed, counts
    for row, pending_entry in zip(proba_arr, pending, strict=False):
        entry = pending_entry["entry"]
        target_idx = pending_entry["target_idx"]
        keep_mask = _clip_head_keep_mask(
            row.reshape(1, -1),
            target_index=target_idx,
            min_prob=min_prob,
            margin=margin,
            background_indices=bg_indices,
            background_guard=True,
            background_margin=background_margin,
        )
        accept = bool(keep_mask[0]) if keep_mask is not None and len(keep_mask) else False
        entry["classifier_accept"] = accept
        if not accept:
            counts["classifier_rejected"] += 1
            continue
        reviewed.append(entry)
    return reviewed, counts


def _agent_current_label_colors(labels: Sequence[str]) -> Dict[str, str]:
    global _AGENT_ACTIVE_LABEL_COLORS
    if _AGENT_ACTIVE_LABEL_COLORS:
        if all(lbl in _AGENT_ACTIVE_LABEL_COLORS for lbl in labels):
            return _AGENT_ACTIVE_LABEL_COLORS
    label_colors = _agent_label_color_map(labels)
    _AGENT_ACTIVE_LABEL_COLORS = label_colors
    return label_colors


def _agent_current_label_prefixes(labels: Sequence[str]) -> Dict[str, str]:
    global _AGENT_ACTIVE_LABEL_PREFIXES
    if _AGENT_ACTIVE_LABEL_PREFIXES:
        if all(lbl in _AGENT_ACTIVE_LABEL_PREFIXES for lbl in labels):
            return _AGENT_ACTIVE_LABEL_PREFIXES
    label_prefixes = _agent_label_prefix_map(labels)
    _AGENT_ACTIVE_LABEL_PREFIXES = label_prefixes
    return label_prefixes


def _compute_steps_seed_eval_threshold(payload: "AgentMiningRequest") -> float:
    base = float(payload.seed_threshold)
    floor = payload.steps_seed_eval_floor
    if floor is None:
        return base
    try:
        floor_val = float(floor)
    except Exception:
        return base
    return min(base, floor_val)


def _compute_steps_seed_eval_max_results(payload: "AgentMiningRequest") -> int:
    override = payload.steps_seed_eval_max_results
    if override is None:
        return int(payload.max_results)
    try:
        return int(override)
    except Exception:
        return int(payload.max_results)


def _agent_refresh_handle_index() -> None:
    global _AGENT_HANDLE_INDEX
    _AGENT_HANDLE_INDEX = _refresh_handle_index(
        list(_AGENT_ACTIVE_CLUSTERS or []),
        handle_fn=_agent_cluster_handle,
    )


def _agent_cluster_handle(cluster: Mapping[str, Any]) -> Optional[str]:
    return _cluster_handle(
        cluster,
        label_prefixes=_AGENT_ACTIVE_LABEL_PREFIXES,
        labelmap=_AGENT_ACTIVE_LABELMAP or [],
        label_prefix_map_fn=_agent_current_label_prefixes,
    )


def _agent_cluster_id_from_handle(handle: Optional[str]) -> Optional[int]:
    cid = _cluster_id_from_handle(
        handle,
        handle_index=_AGENT_HANDLE_INDEX,
        cluster_index=_AGENT_ACTIVE_CLUSTER_INDEX,
    )
    if cid is not None:
        return cid
    text = str(handle or "").strip()
    if not text:
        return None
    match = re.search(r"(\\d+)$", text)
    if match:
        cid = int(match.group(1))
        cluster = _AGENT_ACTIVE_CLUSTER_INDEX.get(cid)
        if cluster and _agent_cluster_handle(cluster) == text:
            return cid
    return None


def _agent_handles_from_cluster_ids(cluster_ids: Sequence[int]) -> List[str]:
    return _handles_from_cluster_ids(
        cluster_ids,
        cluster_index=_AGENT_ACTIVE_CLUSTER_INDEX,
        handle_fn=_agent_cluster_handle,
    )


def _agent_cluster_ids_from_handles(handles: Sequence[str]) -> List[int]:
    return _cluster_ids_from_handles(
        handles,
        handle_index=_AGENT_HANDLE_INDEX,
        cluster_index=_AGENT_ACTIVE_CLUSTER_INDEX,
    )


def _agent_register_detections(
    detections: Sequence[Dict[str, Any]],
    *,
    img_w: int,
    img_h: int,
    grid: Optional[Mapping[str, Any]] = None,
    labelmap: Optional[Sequence[str]] = None,
    background: Optional[Sequence[str]] = None,
    source_override: Optional[str] = None,
    owner_cell: Optional[str] = None,
    iou_thr: Optional[float] = None,
) -> Dict[str, Any]:
    global _AGENT_ACTIVE_CANDIDATES, _AGENT_ACTIVE_CANDIDATE_INDEX
    global _AGENT_ACTIVE_CLUSTERS, _AGENT_ACTIVE_CLUSTER_INDEX
    global _AGENT_NEXT_CANDIDATE_ID, _AGENT_NEXT_CLUSTER_ID

    if not detections:
        return {
            "candidate_ids": [],
            "cluster_ids": [],
            "new_clusters": 0,
            "updated_clusters": 0,
            "rejected": 0,
        }
    labelmap = list(labelmap or _AGENT_ACTIVE_LABELMAP or [])
    cleaned, rejected = _agent_sanitize_detection_items(
        list(detections),
        pil_img=None,
        classifier_head=None,
        img_w=img_w,
        img_h=img_h,
        labelmap=labelmap,
        background=background,
    )
    if _AGENT_ACTIVE_CANDIDATES is None:
        _AGENT_ACTIVE_CANDIDATES = []
    if _AGENT_ACTIVE_CLUSTERS is None:
        _AGENT_ACTIVE_CLUSTERS = []
    if iou_thr is None:
        iou_thr = PREPASS_CLUSTER_IOU
    new_cluster_ids: List[int] = []
    updated_cluster_ids: List[int] = []
    candidate_ids: List[int] = []
    for det in cleaned:
        candidate_id = _AGENT_NEXT_CANDIDATE_ID
        _AGENT_NEXT_CANDIDATE_ID += 1
        candidate_ids.append(candidate_id)
        source = source_override or det.get("source") or det.get("score_source") or "agent"
        source_primary = det.get("source_primary") or source
        source_prompt = det.get("source_prompt")
        source_exemplar_handles = det.get("source_exemplar_handles")
        source_detector_run_id = det.get("source_detector_run_id")
        source_list = set(det.get("source_list") or [])
        if source:
            source_list.add(str(source))
        cell = _agent_grid_cell_for_detection(det, img_w, img_h, grid)
        owner = owner_cell or cell
        candidate = {
            "candidate_id": candidate_id,
            "label": det.get("label"),
            "class_id": det.get("class_id"),
            "bbox_xyxy_px": det.get("bbox_xyxy_px"),
            "bbox_2d": det.get("bbox_2d"),
            "bbox_yolo": det.get("bbox_yolo"),
            "score": det.get("score"),
            "score_source": det.get("score_source") or det.get("source"),
            "source": source,
            "source_primary": source_primary,
            "source_prompt": source_prompt,
            "source_exemplar_handles": source_exemplar_handles,
            "source_detector_run_id": source_detector_run_id,
            "source_list": sorted(source_list) if source_list else None,
            "grid_cell": cell,
            "owner_cell": owner,
            "window_bbox_2d": det.get("window_bbox_2d"),
        }
        _AGENT_ACTIVE_CANDIDATES.append(candidate)
        _AGENT_ACTIVE_CANDIDATE_INDEX[candidate_id] = candidate
        cluster = _agent_cluster_match(det, _AGENT_ACTIVE_CLUSTERS, iou_thr=iou_thr)
        if cluster is None:
            cluster_id = _AGENT_NEXT_CLUSTER_ID
            _AGENT_NEXT_CLUSTER_ID += 1
            origin_tag = "prepass"
            cluster_entry = {
                "cluster_id": cluster_id,
                "label": det.get("label"),
                "class_id": det.get("class_id"),
                "bbox_xyxy_px": det.get("bbox_xyxy_px"),
                "bbox_2d": det.get("bbox_2d"),
                "bbox_yolo": det.get("bbox_yolo"),
                "score": det.get("score"),
                "score_source": det.get("score_source") or det.get("source"),
                "source": source,
                "source_primary": source_primary,
                "source_prompt": source_prompt,
                "source_exemplar_handles": source_exemplar_handles,
                "source_detector_run_id": source_detector_run_id,
                "source_list": sorted(source_list) if source_list else None,
                "origin": origin_tag,
                "candidate_ids": [candidate_id],
                "grid_cell": cell,
                "owner_cell": owner,
                "classifier_best": det.get("classifier_best"),
                "classifier_prob": det.get("classifier_prob"),
                "classifier_accept": det.get("classifier_accept"),
            }
            _AGENT_ACTIVE_CLUSTERS.append(cluster_entry)
            _AGENT_ACTIVE_CLUSTER_INDEX[cluster_id] = cluster_entry
            new_cluster_ids.append(cluster_id)
            candidate["cluster_id"] = cluster_id
            continue
        cluster_id = int(cluster.get("cluster_id"))
        candidate["cluster_id"] = cluster_id
        if owner and not cluster.get("owner_cell"):
            cluster["owner_cell"] = owner
        cluster.setdefault("candidate_ids", [])
        cluster["candidate_ids"] = list(cluster.get("candidate_ids") or []) + [candidate_id]
        cluster_sources = set(cluster.get("source_list") or [])
        if cluster.get("source"):
            cluster_sources.add(str(cluster.get("source")))
        cluster_sources.update(source_list)
        if cluster_sources:
            cluster["source_list"] = sorted(cluster_sources)
        cluster_score = _agent_det_score(cluster)
        det_score = _agent_det_score(det)
        replace = False
        if det_score is not None and (cluster_score is None or det_score > cluster_score):
            replace = True
        elif det_score is None and cluster_score is None and not cluster.get("bbox_xyxy_px"):
            replace = True
        if replace:
            keep_ids = list(cluster.get("candidate_ids") or [])
            keep_sources = list(cluster.get("source_list") or [])
            keep_classifier = {
                "classifier_best": cluster.get("classifier_best"),
                "classifier_prob": cluster.get("classifier_prob"),
                "classifier_accept": cluster.get("classifier_accept"),
            }
            cluster.update(
                {
                    "label": det.get("label"),
                    "class_id": det.get("class_id"),
                    "bbox_xyxy_px": det.get("bbox_xyxy_px"),
                    "bbox_2d": det.get("bbox_2d"),
                    "bbox_yolo": det.get("bbox_yolo"),
                    "score": det.get("score"),
                    "score_source": det.get("score_source") or det.get("source"),
                    "source": source,
                    "source_primary": source_primary,
                    "source_prompt": source_prompt,
                    "source_exemplar_handles": source_exemplar_handles,
                    "source_detector_run_id": source_detector_run_id,
                    "grid_cell": cell,
                }
            )
            cluster["candidate_ids"] = keep_ids
            if keep_sources:
                cluster["source_list"] = keep_sources
            for key, value in keep_classifier.items():
                if value is not None and cluster.get(key) is None:
                    cluster[key] = value
        else:
            if source_primary and cluster.get("source_primary") is None:
                cluster["source_primary"] = source_primary
            if source_prompt and cluster.get("source_prompt") is None:
                cluster["source_prompt"] = source_prompt
            if source_exemplar_handles and cluster.get("source_exemplar_handles") is None:
                cluster["source_exemplar_handles"] = list(source_exemplar_handles)
            if source_detector_run_id and cluster.get("source_detector_run_id") is None:
                cluster["source_detector_run_id"] = source_detector_run_id
        updated_cluster_ids.append(cluster_id)
    _agent_set_active_clusters(_AGENT_ACTIVE_CLUSTERS)
    return {
        "candidate_ids": candidate_ids,
        "cluster_ids": new_cluster_ids
        + [cid for cid in updated_cluster_ids if cid not in new_cluster_ids],
        "new_cluster_ids": new_cluster_ids,
        "updated_cluster_ids": updated_cluster_ids,
        "new_clusters": len(new_cluster_ids),
        "updated_clusters": len(updated_cluster_ids),
        "rejected": int(rejected),
    }


