@_register_agent_tool("think_missed_objects")
def _agent_tool_think_missed_objects(
    image_base64: Optional[str] = None,
    image_token: Optional[str] = None,
    notes: Optional[str] = None,
) -> Dict[str, Any]:
    overlay = _AGENT_ACTIVE_OVERLAY_IMAGE
    if overlay is None:
        base = _agent_overlay_base_image()
        if base is None:
            base, _, _ = _agent_resolve_image(image_base64, image_token)
        clusters = list(_AGENT_ACTIVE_CLUSTERS or [])
        labels = _agent_overlay_labels(clusters, _AGENT_ACTIVE_LABELMAP or [])
        label_colors = _agent_current_label_colors(labels) if labels else {}
        label_prefixes = _agent_current_label_prefixes(labels) if labels else {}
        overlay = base
        if clusters:
            overlay = _agent_render_detection_overlay(
                base,
                clusters,
                label_colors,
                dot_radius=_AGENT_ACTIVE_OVERLAY_DOT_RADIUS,
                label_prefixes=label_prefixes,
            )
    labels = list(_AGENT_ACTIVE_LABELMAP or [])
    usage_rows = _agent_grid_usage_rows(
        _AGENT_ACTIVE_GRID, _AGENT_GRID_TOOL_USAGE, _AGENT_GRID_TOOL_LAST
    )
    usage_text = _agent_grid_usage_text(usage_rows)
    prompt_lines = [
        "You are reviewing an annotated aerial image.",
        "Return JSON only: {\"missing_labels\": [...], \"missing_tiles\": [...], \"rationale\": \"...\"}.",
        "Use labelmap classes only. Use grid cells like A1, B2.",
        f"Labelmap: {', '.join(labels) if labels else 'none'}",
    ]
    if _AGENT_ACTIVE_OVERALL_CAPTION:
        prompt_lines.append(f"Overall caption: {_AGENT_ACTIVE_OVERALL_CAPTION}")
    if _AGENT_ACTIVE_WINDOWED_CAPTIONS:
        sample_caps = _AGENT_ACTIVE_WINDOWED_CAPTIONS[:8]
        cap_lines = []
        for entry in sample_caps:
            if isinstance(entry, dict):
                name = entry.get("window") or "window"
                cap = entry.get("caption") or ""
                cap_lines.append(f"{name}: {cap}")
        if cap_lines:
            prompt_lines.append("Windowed captions: " + " | ".join(cap_lines))
    if usage_text:
        prompt_lines.append(f"Tool usage by grid: {usage_text}")
    if notes:
        prompt_lines.append(f"Notes: {notes}")
    prompt = "\n".join(prompt_lines)
    try:
        raw, _, _ = _run_qwen_inference(
            prompt,
            overlay,
            max_new_tokens=256,
            system_prompt_override="Return JSON only.",
        )
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(
            status_code=HTTP_503_SERVICE_UNAVAILABLE, detail=f"think_missed_failed:{exc}"
        ) from exc
    json_text = _extract_balanced_json_impl(raw, "{", "}") or ""
    data: Dict[str, Any] = {}
    if json_text:
        try:
            data = json.loads(json_text)
        except Exception:
            data = {}
    missing_labels = data.get("missing_labels") if isinstance(data, dict) else None
    missing_tiles = data.get("missing_tiles") if isinstance(data, dict) else None
    rationale = data.get("rationale") if isinstance(data, dict) else None
    return {
        "missing_labels": missing_labels if isinstance(missing_labels, list) else [],
        "missing_tiles": missing_tiles if isinstance(missing_tiles, list) else [],
        "rationale": str(rationale or "").strip(),
    }


@_register_agent_tool("grid_label_counts")
def _agent_tool_grid_label_counts(
    image_base64: Optional[str] = None,
    image_token: Optional[str] = None,
    label: Optional[str] = None,
) -> Dict[str, Any]:
    del image_base64, image_token
    if not _AGENT_ACTIVE_GRID:
        raise HTTPException(status_code=HTTP_503_SERVICE_UNAVAILABLE, detail="grid_unavailable")
    clusters = list(_AGENT_ACTIVE_CLUSTERS or [])
    summary = _agent_grid_label_counts(
        grid=_AGENT_ACTIVE_GRID,
        clusters=clusters,
        label=label,
        labelmap=_AGENT_ACTIVE_LABELMAP or [],
    )
    agent_cells = []
    for cell in summary:
        if not isinstance(cell, dict):
            continue
        agent_cells.append(
            {
                "grid_cell": cell.get("grid_cell"),
                "total": cell.get("total"),
                "counts": cell.get("counts"),
            }
        )
    return {
        "label": _agent_fuzzy_align_label(label, _AGENT_ACTIVE_LABELMAP or []) if label else None,
        "cells": summary,
        "total_cells": len(summary),
        "__agent_view__": {
            "label": (
                _agent_fuzzy_align_label(label, _AGENT_ACTIVE_LABELMAP or []) if label else None
            ),
            "cells": agent_cells,
            "total_cells": len(summary),
        },
    }


@_register_agent_tool("get_labelmap")
def _agent_tool_get_labelmap(
    dataset_id: Optional[str] = None,
    classifier_id: Optional[str] = None,
) -> Dict[str, Any]:
    classes, glossary = _agent_load_labelmap_meta(dataset_id)
    head: Optional[Dict[str, Any]] = None
    if classifier_id:
        classifier_path = _resolve_agent_clip_classifier_path_impl(
            classifier_id,
            allowed_root=UPLOAD_ROOT / "classifiers",
            allowed_exts=CLASSIFIER_ALLOWED_EXTS,
            path_is_within_root_fn=_path_is_within_root_impl,
            http_exception_cls=HTTPException,
        )
        if classifier_path is not None:
            head = _load_clip_head_from_classifier_impl(
                classifier_path,
                joblib_load_fn=_joblib_load,
                http_exception_cls=HTTPException,
                clip_head_background_indices_fn=_clip_head_background_indices,
                resolve_head_normalize_embeddings_fn=_resolve_head_normalize_embeddings_impl,
                infer_clip_model_fn=_infer_clip_model_from_embedding_dim_impl,
                active_clip_model_name=clip_model_name,
                default_clip_model=DEFAULT_CLIP_MODEL,
                logger=logger,
            )
    else:
        head = _active_classifier_head_for_inference()
    background = _agent_background_classes_from_head(head)
    return {
        "classes": classes,
        "background_classes": background,
        "glossary": glossary,
        "rules": {
            "reject_background": True,
            "require_labelmap": True,
        },
    }


@_register_agent_tool("list_candidates")
def _agent_tool_list_candidates(
    image_base64: Optional[str] = None,
    image_token: Optional[str] = None,
    label: Optional[str] = None,
    source: Optional[str] = None,
    min_score: Optional[float] = None,
    include_scoreless: Optional[bool] = True,
    sort_by: Optional[str] = "score_desc",
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    del image_base64, image_token
    active = list(_AGENT_ACTIVE_CLUSTERS or _AGENT_ACTIVE_DETECTIONS or [])
    if not active:
        return {"candidates": [], "total": 0, "returned": 0, "filters": {}}
    label_filter = str(label).strip() if label else None
    aligned_label = _agent_fuzzy_align_label(label_filter, _AGENT_ACTIVE_LABELMAP or [])
    if aligned_label:
        label_filter = aligned_label
    source_filter = str(source).strip() if source else None
    source_terms = {term for term in (source_filter or "").split(",") if term.strip()}
    source_terms = {term.strip().lower() for term in source_terms}
    try:
        min_score_val = float(min_score) if min_score is not None else None
    except (TypeError, ValueError):
        min_score_val = None
    include_scoreless = True if include_scoreless is None else bool(include_scoreless)
    sort_key = (sort_by or "score_desc").strip().lower()

    def score_value(det: Dict[str, Any]) -> Optional[float]:
        raw = det.get("score")
        if raw is None:
            return None
        try:
            return float(raw)
        except (TypeError, ValueError):
            return None

    filtered: List[Dict[str, Any]] = []
    for idx, det in enumerate(active):
        if not isinstance(det, dict):
            continue
        det_label = str(det.get("label") or det.get("class_name") or "").strip()
        if label_filter and det_label and det_label != label_filter:
            continue
        det_score = score_value(det)
        if det_score is None:
            if not include_scoreless:
                continue
        elif min_score_val is not None and det_score < min_score_val:
            continue
        if source_terms:
            det_sources: Set[str] = set()
            for key in ("source", "score_source"):
                val = det.get(key)
                if val:
                    det_sources.add(str(val).strip().lower())
            source_list = det.get("source_list")
            if isinstance(source_list, (list, tuple)):
                for item in source_list:
                    if item:
                        det_sources.add(str(item).strip().lower())
            if not det_sources.intersection(source_terms):
                continue
        entry = {
            "cluster_id": (
                int(det.get("cluster_id")) if det.get("cluster_id") is not None else int(idx + 1)
            ),
            "handle": _agent_cluster_handle(det),
            "label": det_label,
            "class_id": det.get("class_id"),
            "score": det.get("score"),
            "score_source": det.get("score_source") or det.get("source") or "unknown",
            "source": det.get("source"),
            "source_list": det.get("source_list"),
            "candidate_count": len(det.get("candidate_ids") or []),
            "grid_cell": det.get("grid_cell"),
            "classifier_best": det.get("classifier_best"),
            "classifier_prob": det.get("classifier_prob"),
            "classifier_accept": det.get("classifier_accept"),
        }
        filtered.append(entry)

    if sort_key in {"score", "score_desc", "confidence"}:
        filtered.sort(
            key=lambda d: (score_value(d) if score_value(d) is not None else -1.0), reverse=True
        )
        sort_key = "score_desc"
    elif sort_key in {"score_asc", "confidence_asc"}:
        filtered.sort(key=lambda d: (score_value(d) if score_value(d) is not None else 1e9))
        sort_key = "score_asc"
    elif sort_key == "label":
        filtered.sort(key=lambda d: str(d.get("label") or ""))
    elif sort_key == "source":
        filtered.sort(key=lambda d: str(d.get("source") or ""))
    else:
        sort_key = "none"
    try:
        max_items_val = int(max_items) if max_items is not None else 0
    except (TypeError, ValueError):
        max_items_val = 0
    trimmed = filtered[:max_items_val] if max_items_val > 0 else filtered
    agent_candidates = []
    for item in trimmed:
        if not isinstance(item, dict):
            continue
        agent_candidates.append(
            {
                "handle": item.get("handle"),
                "label": item.get("label"),
                "grid_cell": item.get("grid_cell"),
                "score": item.get("score"),
                "score_source": item.get("score_source"),
                "source": item.get("source"),
                "source_list": item.get("source_list"),
                "verified": bool(item.get("classifier_accept")),
            }
        )
    return {
        "candidates": trimmed,
        "total": len(filtered),
        "returned": len(trimmed),
        "filters": {
            "label": label_filter,
            "source": source_filter,
            "min_score": min_score_val,
            "include_scoreless": include_scoreless,
            "sort_by": sort_key,
            "max_items": max_items_val,
        },
        "__agent_view__": {
            "candidates": agent_candidates,
            "total": len(filtered),
            "returned": len(trimmed),
            "filters": {
                "label": label_filter,
                "source": source_filter,
                "min_score": min_score_val,
                "include_scoreless": include_scoreless,
                "sort_by": sort_key,
                "max_items": max_items_val,
            },
        },
    }


@_register_agent_tool("submit_annotations")
def _agent_tool_submit_annotations(
    image_base64: Optional[str] = None,
    image_token: Optional[str] = None,
    annotations: Optional[List[Dict[str, Any]]] = None,
    cluster_ids: Optional[List[int]] = None,
    handles: Optional[List[str]] = None,
    include_all: Optional[bool] = None,
    dataset_id: Optional[str] = None,
    classifier_id: Optional[str] = None,
    window_bbox_2d: Optional[Sequence[float]] = None,
    iou: Optional[float] = None,
    cross_iou: Optional[float] = None,
    max_det: Optional[int] = None,
) -> Dict[str, Any]:
    global _AGENT_LAST_SUBMIT_DETECTIONS
    pil_img, _, _ = _agent_resolve_image(image_base64, image_token)
    img_w, img_h = pil_img.size
    labelmap = _agent_load_labelmap(dataset_id)
    head: Optional[Dict[str, Any]] = None
    if classifier_id:
        classifier_path = _resolve_agent_clip_classifier_path_impl(
            classifier_id,
            allowed_root=UPLOAD_ROOT / "classifiers",
            allowed_exts=CLASSIFIER_ALLOWED_EXTS,
            path_is_within_root_fn=_path_is_within_root_impl,
            http_exception_cls=HTTPException,
        )
        if classifier_path is not None:
            head = _load_clip_head_from_classifier_impl(
                classifier_path,
                joblib_load_fn=_joblib_load,
                http_exception_cls=HTTPException,
                clip_head_background_indices_fn=_clip_head_background_indices,
                resolve_head_normalize_embeddings_fn=_resolve_head_normalize_embeddings_impl,
                infer_clip_model_fn=_infer_clip_model_from_embedding_dim_impl,
                active_clip_model_name=clip_model_name,
                default_clip_model=DEFAULT_CLIP_MODEL,
                logger=logger,
            )
    else:
        head = _active_classifier_head_for_inference()
    background = _agent_background_classes_from_head(head)
    normalized_annotations: List[Dict[str, Any]] = []
    cluster_id_list: List[int] = []
    label_overrides: Dict[int, str] = {}
    if include_all:
        cluster_id_list = [
            int(c.get("cluster_id"))
            for c in (_AGENT_ACTIVE_CLUSTERS or [])
            if c.get("cluster_id") is not None
        ]
    if handles:
        cluster_id_list.extend(_agent_cluster_ids_from_handles(handles))
    if cluster_ids:
        cluster_id_list.extend([int(cid) for cid in cluster_ids])
    for ann in annotations or []:
        if isinstance(ann, (int, float)):
            cluster_id_list.append(int(ann))
            continue
        if isinstance(ann, dict) and ann.get("cluster_id") is not None:
            cid_val = int(ann.get("cluster_id"))
            cluster_id_list.append(cid_val)
            override_label = ann.get("label")
            if override_label:
                label_overrides[cid_val] = str(override_label)
            continue
        if (
            window_bbox_2d is not None
            and isinstance(ann, dict)
            and ann.get("window_bbox_2d") is None
        ):
            ann = {**ann, "window_bbox_2d": list(window_bbox_2d)}
        normalized_annotations.append(ann)
    if cluster_id_list:
        seen = set()
        for cid in cluster_id_list:
            if cid in seen:
                continue
            seen.add(cid)
            cluster = _AGENT_ACTIVE_CLUSTER_INDEX.get(int(cid))
            if not cluster:
                continue
            label = label_overrides.get(cid) or cluster.get("label")
            normalized_annotations.append(
                {
                    "label": label,
                    "bbox_xyxy_px": cluster.get("bbox_xyxy_px"),
                    "bbox_2d": cluster.get("bbox_2d"),
                    "bbox_yolo": cluster.get("bbox_yolo"),
                    "score": cluster.get("score"),
                    "score_source": cluster.get("score_source") or cluster.get("source"),
                    "class_id": cluster.get("class_id"),
                    "source": cluster.get("source") or "agent",
                    "source_list": cluster.get("source_list"),
                    "origin": cluster.get("origin"),
                }
            )
    cleaned, rejected = _agent_sanitize_detection_items(
        normalized_annotations,
        pil_img=pil_img,
        classifier_head=head,
        img_w=img_w,
        img_h=img_h,
        labelmap=labelmap,
        background=background,
    )

    def _unit_float(value: Optional[float], *, default: Optional[float]) -> Optional[float]:
        if value is None:
            return default
        try:
            parsed = float(value)
        except (TypeError, ValueError):
            return default
        if not math.isfinite(parsed):
            return default
        return max(0.0, min(1.0, parsed))

    iou_thr = _unit_float(iou, default=0.5)
    cross_iou_thr = _unit_float(cross_iou, default=0.8) if cross_iou is not None else None
    if cross_iou_thr is not None and cross_iou_thr <= 0.0:
        cross_iou_thr = None
    merged = _agent_merge_detections(
        cleaned,
        iou_thr=float(iou_thr if iou_thr is not None else 0.5),
        max_det=max_det,
        cross_iou=cross_iou_thr,
    )
    _AGENT_LAST_SUBMIT_DETECTIONS = list(merged)
    submitted_handles = _agent_handles_from_cluster_ids(cluster_id_list)
    agent_view = {
        "submitted_handles": sorted(set(submitted_handles)),
        "count": len(merged),
    }
    return {
        "detections": merged,
        "rejected": rejected,
        "count": len(merged),
        "__agent_view__": agent_view,
    }


def _agent_ensemble_filter_tmp_dir() -> Path:
    try:
        raw_dir = UPLOAD_ROOT / "tmp_ensemble"
        if _storage_path_has_symlink_component(raw_dir):
            raise ValueError("ensemble filter temp dir has a symlink component")
        raw_dir.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_dir) or not raw_dir.is_dir():
            raise ValueError("ensemble filter temp path is not a safe directory")
        resolved = raw_dir.resolve(strict=True)
        upload_root = UPLOAD_ROOT.resolve(strict=False)
        if not _path_is_within_root_impl(resolved, upload_root):
            raise ValueError("ensemble filter temp dir escapes upload root")
        return raw_dir
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="ensemble_filter_tmp_path_invalid",
        ) from exc


def _agent_prepare_ensemble_filter_tmp_file(path: Path, tmp_dir: Path) -> Path:
    try:
        tmp_root = tmp_dir.resolve(strict=True)
        if _storage_path_has_symlink_component(path.parent):
            raise ValueError("ensemble filter temp parent has a symlink component")
        if path.is_symlink() or (path.exists() and path.is_dir()):
            raise ValueError("ensemble filter temp leaf is not writable")
        target = path.resolve(strict=False)
        if not _path_is_within_root_impl(target, tmp_root):
            raise ValueError("ensemble filter temp leaf escapes temp root")
        return path
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="ensemble_filter_tmp_path_invalid",
        ) from exc


def _agent_cleanup_ensemble_filter_tmp_file(path: Path, tmp_dir: Path) -> None:
    try:
        tmp_root = tmp_dir.resolve(strict=True)
        parent = path.parent.resolve(strict=False)
        if parent != tmp_root:
            return
        if path.is_symlink() or path.is_file():
            path.unlink(missing_ok=True)
    except Exception:
        return


def _agent_apply_ensemble_filter(
    detections: List[Dict[str, Any]],
    *,
    dataset_id: Optional[str],
    image_name: Optional[str],
    classifier_id: Optional[str],
    job_id: Optional[str],
    feature_contract: Optional[Dict[str, Any]] = None,
    prepass_provenance: Optional[Dict[str, Any]] = None,
    trace_writer: Optional[Callable[[Dict[str, Any]], None]] = None,
    trace_full_writer: Optional[Callable[[Dict[str, Any]], None]] = None,
    trace_readable: Optional[Callable[[str], None]] = None,
    warnings: Optional[List[str]] = None,
) -> List[Dict[str, Any]]:
    if not job_id:
        return detections
    if not dataset_id or not image_name:
        if warnings is not None:
            warnings.append("ensemble_filter_missing_dataset_or_image")
        return detections
    job_id_raw = str(job_id or "").strip()
    safe_job_id = _sanitize_yolo_run_id_impl(job_id_raw)
    if not safe_job_id or safe_job_id != job_id_raw:
        if warnings is not None:
            warnings.append("ensemble_filter_job_invalid")
        return detections
    job_dir = (CALIBRATION_ROOT / safe_job_id).resolve()
    if not _path_is_within_root_impl(job_dir, CALIBRATION_ROOT.resolve()):
        if warnings is not None:
            warnings.append("ensemble_filter_job_invalid")
        return detections
    model_path = job_dir / "ensemble_mlp.pt"
    meta_path = job_dir / "ensemble_mlp.meta.json"
    score_tool = "score_ensemble_candidates.py"
    if not model_path.exists():
        alt_model = job_dir / "ensemble_xgb.json"
        alt_meta = job_dir / "ensemble_xgb.meta.json"
        if alt_model.exists() and alt_meta.exists():
            model_path = alt_model
            meta_path = alt_meta
            score_tool = "score_ensemble_candidates_xgb.py"
    if not model_path.exists() or not meta_path.exists():
        if warnings is not None:
            warnings.append("ensemble_filter_model_missing")
        return detections
    if not detections:
        return detections
    classifier_path = None
    if classifier_id:
        classifier_path = _resolve_agent_clip_classifier_path_impl(
            classifier_id,
            allowed_root=UPLOAD_ROOT / "classifiers",
            allowed_exts=CLASSIFIER_ALLOWED_EXTS,
            path_is_within_root_fn=_path_is_within_root_impl,
            http_exception_cls=HTTPException,
        )
    if classifier_path is None:
        if warnings is not None:
            warnings.append("ensemble_filter_classifier_missing")
        return detections

    tmp_dir = _agent_ensemble_filter_tmp_dir()
    tmp_paths: List[Path] = []
    try:
        stamp = uuid.uuid4().hex[:8]
        jsonl_path = _agent_prepare_ensemble_filter_tmp_file(
            tmp_dir / f"ensemble_{stamp}.jsonl", tmp_dir
        )
        features_path = _agent_prepare_ensemble_filter_tmp_file(
            tmp_dir / f"ensemble_{stamp}.npz", tmp_dir
        )
        scored_path = _agent_prepare_ensemble_filter_tmp_file(
            tmp_dir / f"ensemble_{stamp}.scored.jsonl", tmp_dir
        )
        tmp_paths = [jsonl_path, features_path, scored_path]
        _write_temp_text_no_follow(
            jsonl_path,
            json.dumps(
                {
                    "image": image_name,
                    "detections": detections,
                    "provenance": (
                        prepass_provenance if isinstance(prepass_provenance, dict) else None
                    ),
                },
                ensure_ascii=True,
            )
            + "\n",
            exclusive=True,
        )
        root_dir = Path(__file__).resolve().parent
        contract = dict(feature_contract or {})
        support_iou = float(contract.get("support_iou") or 0.5)
        min_crop_size = int(contract.get("min_crop_size") or 4)
        context_radius = contract.get("context_radius")
        embed_proj_dim = int(contract.get("embed_proj_dim") or 0)
        embed_proj_seed = int(contract.get("embed_proj_seed") or 42)
        image_embed_proj_dim = int(contract.get("image_embed_proj_dim") or 0)
        image_embed_proj_seed = int(contract.get("image_embed_proj_seed") or 4242)
        embed_l2_normalize = bool(True if contract.get("embed_l2_normalize") is None else contract.get("embed_l2_normalize"))
        build_cmd = [
            sys.executable,
            str(root_dir / "tools" / "build_ensemble_features.py"),
            "--input",
            str(jsonl_path),
            "--dataset",
            dataset_id,
            "--output",
            str(features_path),
            "--support-iou",
            str(support_iou),
            "--min-crop-size",
            str(min_crop_size),
            "--context-radius",
            str(float(context_radius) if context_radius is not None else 0.075),
            "--embed-proj-dim",
            str(embed_proj_dim),
            "--embed-proj-seed",
            str(embed_proj_seed),
            "--image-embed-proj-dim",
            str(image_embed_proj_dim),
            "--image-embed-proj-seed",
            str(image_embed_proj_seed),
            "--device",
            "cuda",
            "--classifier-id",
            str(classifier_path),
            "--require-classifier",
        ]
        if not embed_l2_normalize:
            build_cmd.append("--embed-no-l2-normalize")
        subprocess.run(build_cmd, check=True)
        if contract:
            built = np.load(features_path, allow_pickle=True)
            built_hash_raw = built.get("feature_schema_hash")
            if hasattr(built_hash_raw, "item"):
                try:
                    built_hash_raw = built_hash_raw.item()
                except Exception:
                    pass
            built_hash = str(built_hash_raw or "")
            expected_hash = str(contract.get("feature_schema_hash") or "").strip()
            if expected_hash and built_hash and built_hash != expected_hash:
                raise RuntimeError("ensemble_filter_feature_schema_mismatch")
            expected_labelmap = [str(x).strip() for x in contract.get("labelmap") or [] if str(x).strip()]
            if expected_labelmap:
                built_labelmap = [str(x).strip() for x in built.get("labelmap", []) if str(x).strip()]
                if built_labelmap != expected_labelmap:
                    raise RuntimeError("ensemble_filter_labelmap_mismatch")
        score_cmd = [
            sys.executable,
            str(root_dir / "tools" / score_tool),
            "--model",
            str(model_path),
            "--meta",
            str(meta_path),
            "--data",
            str(features_path),
            "--output",
            str(scored_path),
        ]
        subprocess.run(score_cmd, check=True)
        accepted: List[Dict[str, Any]] = []
        for line in scored_path.read_text().splitlines():
            if not line.strip():
                continue
            try:
                entry = json.loads(line)
            except Exception:
                continue
            if entry.get("ensemble_accept"):
                accepted.append(entry)
        if trace_writer:
            trace_writer(
                {
                    "type": "ensemble_filter",
                    "accepted": len(accepted),
                    "total": len(detections),
                    "job_id": job_id,
                }
            )
        if trace_full_writer:
            trace_full_writer(
                {
                    "type": "ensemble_filter",
                    "accepted": len(accepted),
                    "total": len(detections),
                    "job_id": job_id,
                }
            )
        if trace_readable:
            trace_readable(
                f"ensemble filter: accepted={len(accepted)} total={len(detections)} job={job_id}"
            )
        return accepted
    except HTTPException:
        raise
    except Exception as exc:  # noqa: BLE001
        if warnings is not None:
            warnings.append(f"ensemble_filter_failed:{exc}")
        if trace_readable:
            trace_readable(f"ensemble filter failed: {exc}")
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail=f"ensemble_filter_failed:{exc}",
        ) from exc
    finally:
        for tmp_path in tmp_paths:
            _agent_cleanup_ensemble_filter_tmp_file(tmp_path, tmp_dir)


def _agent_apply_edr_package_runtime(
    payload: QwenPrepassRequest,
) -> Tuple[QwenPrepassRequest, Optional[Dict[str, Any]]]:
    package_id = str(getattr(payload, "edr_package_id", "") or "").strip()
    if not package_id:
        return payload, None
    dataset_id = str(getattr(payload, "dataset_id", "") or "").strip()
    if not dataset_id:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail="edr_package_target_dataset_missing",
        )
    try:
        runtime = _resolve_edr_package_runtime_impl(
            packages_root=EDR_PACKAGES_ROOT,
            package_id=package_id,
            upload_root=UPLOAD_ROOT,
            yolo_job_root=YOLO_JOB_ROOT,
            rfdetr_job_root=RFDETR_JOB_ROOT,
            calibration_root=CALIBRATION_ROOT,
            classifiers_root=(UPLOAD_ROOT / "classifiers"),
        )
    except (FileNotFoundError, ValueError) as exc:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail="edr_package_not_found",
        ) from exc
    package_labelmap = [str(item).strip() for item in runtime.get("labelmap") or [] if str(item).strip()]
    runtime_config = dict(runtime.get("runtime_config") or {})
    if not package_labelmap:
        source_dataset_id = (
            str(runtime_config.get("recipe_source_dataset_id") or runtime_config.get("dataset_id") or "").strip()
        )
        if source_dataset_id:
            source_labelmap, _ = _agent_load_labelmap_meta(source_dataset_id)
            package_labelmap = [str(item).strip() for item in source_labelmap if str(item).strip()]
    if not package_labelmap:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail="edr_package_labelmap_missing",
        )
    dataset_labelmap, _ = _agent_load_labelmap_meta(dataset_id)
    dataset_labelmap = [str(item).strip() for item in dataset_labelmap if str(item).strip()]
    if package_labelmap and dataset_labelmap != package_labelmap:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail="edr_package_labelmap_mismatch",
        )
    classifier_id = (
        str(runtime.get("staged_classifier_id") or "").strip()
        or str(runtime_config.get("resolved_classifier_id") or runtime_config.get("classifier_id") or "").strip()
        or None
    )
    ensemble_job_id = str(runtime.get("staged_ensemble_job_id") or "").strip()
    if not ensemble_job_id:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail="edr_package_missing_calibration_bundle",
        )
    apply_ensemble = bool(
        payload.edr_package_apply_ensemble
        if payload.edr_package_apply_ensemble is not None
        else True
    )
    updates = {
        "dataset_id": dataset_id,
        "recipe_source_dataset_id": (
            str(runtime_config.get("recipe_source_dataset_id") or runtime_config.get("dataset_id") or "").strip()
            or None
        ),
        "labelmap": package_labelmap or dataset_labelmap or None,
        "labelmap_glossary": str(runtime.get("glossary_text") or runtime_config.get("labelmap_glossary") or "").strip() or None,
        "model_id": runtime_config.get("model_id") or payload.model_id,
        "model_variant": runtime_config.get("model_variant") or payload.model_variant,
        "enable_yolo": runtime_config.get("enable_yolo", payload.enable_yolo),
        "enable_rfdetr": runtime_config.get("enable_rfdetr", payload.enable_rfdetr),
        "yolo_id": runtime.get("staged_yolo_id") or runtime_config.get("yolo_id") or payload.yolo_id,
        "rfdetr_id": runtime.get("staged_rfdetr_id") or runtime_config.get("rfdetr_id") or payload.rfdetr_id,
        "sahi_window_size": runtime_config.get("sahi_window_size", payload.sahi_window_size),
        "sahi_overlap_ratio": runtime_config.get("sahi_overlap_ratio", payload.sahi_overlap_ratio),
        "classifier_id": classifier_id,
        "sam_variant": runtime_config.get("sam_variant") or payload.sam_variant,
        "enable_sam3_text": runtime_config.get("enable_sam3_text", payload.enable_sam3_text),
        "sam3_text_window_extension": runtime_config.get("sam3_text_window_extension", payload.sam3_text_window_extension),
        "sam3_text_window_mode": runtime_config.get("sam3_text_window_mode", payload.sam3_text_window_mode),
        "sam3_text_window_size": runtime_config.get("sam3_text_window_size", payload.sam3_text_window_size),
        "sam3_text_window_overlap": runtime_config.get("sam3_text_window_overlap", payload.sam3_text_window_overlap),
        "sam3_text_synonym_budget": 0,
        "enable_sam3_similarity": runtime_config.get("enable_sam3_similarity", payload.enable_sam3_similarity),
        "prepass_sam3_text_thr": runtime_config.get("prepass_sam3_text_thr", payload.prepass_sam3_text_thr),
        "prepass_similarity_score": runtime_config.get("prepass_similarity_score", payload.prepass_similarity_score),
        "similarity_min_exemplar_score": runtime_config.get("similarity_min_exemplar_score", payload.similarity_min_exemplar_score),
        "similarity_exemplar_strategy": runtime_config.get("similarity_exemplar_strategy", payload.similarity_exemplar_strategy),
        "similarity_exemplar_count": runtime_config.get("similarity_exemplar_count", payload.similarity_exemplar_count),
        "similarity_exemplar_seed": runtime_config.get("similarity_exemplar_seed", payload.similarity_exemplar_seed),
        "similarity_exemplar_fraction": runtime_config.get("similarity_exemplar_fraction", payload.similarity_exemplar_fraction),
        "similarity_exemplar_min": runtime_config.get("similarity_exemplar_min", payload.similarity_exemplar_min),
        "similarity_exemplar_max": runtime_config.get("similarity_exemplar_max", payload.similarity_exemplar_max),
        "similarity_exemplar_source_quota": runtime_config.get("similarity_exemplar_source_quota", payload.similarity_exemplar_source_quota),
        "similarity_window_mode": runtime_config.get("similarity_window_mode", payload.similarity_window_mode),
        "similarity_window_size": runtime_config.get("similarity_window_size", payload.similarity_window_size),
        "similarity_window_overlap": runtime_config.get("similarity_window_overlap", payload.similarity_window_overlap),
        "similarity_window_extension": runtime_config.get("similarity_window_extension", payload.similarity_window_extension),
        "grid_cols": runtime_config.get("grid_cols", payload.grid_cols),
        "grid_rows": runtime_config.get("grid_rows", payload.grid_rows),
        "grid_overlap_ratio": runtime_config.get("grid_overlap_ratio", payload.grid_overlap_ratio),
        "ensemble_enabled": apply_ensemble,
        "ensemble_job_id": ensemble_job_id if apply_ensemble else None,
        "iou": runtime_config.get("iou", payload.iou),
        "fusion_mode": runtime_config.get("fusion_mode") or payload.fusion_mode,
        "cross_class_dedupe_enabled": runtime_config.get("cross_class_dedupe_enabled", payload.cross_class_dedupe_enabled),
        "cross_class_dedupe_iou": runtime_config.get("cross_class_dedupe_iou", payload.cross_class_dedupe_iou),
        "prepass_caption": False,
        "prepass_caption_profile": runtime_config.get("prepass_caption_profile", payload.prepass_caption_profile),
        "prepass_caption_variant": runtime_config.get("prepass_caption_variant", payload.prepass_caption_variant),
        "prepass_caption_model_id": runtime_config.get("prepass_caption_model_id", payload.prepass_caption_model_id),
        "prepass_caption_max_tokens": runtime_config.get("prepass_caption_max_tokens", payload.prepass_caption_max_tokens),
        "tighten_fp": runtime_config.get("tighten_fp", payload.tighten_fp),
        "detector_conf": runtime_config.get("detector_conf", payload.detector_conf),
        "sam3_score_thr": runtime_config.get("sam3_score_thr", payload.sam3_score_thr),
        "sam3_mask_threshold": runtime_config.get("sam3_mask_threshold", payload.sam3_mask_threshold),
        "classifier_min_prob": runtime_config.get("classifier_min_prob", payload.classifier_min_prob),
        "classifier_margin": runtime_config.get("classifier_margin", payload.classifier_margin),
        "classifier_bg_margin": runtime_config.get("classifier_bg_margin", payload.classifier_bg_margin),
        "scoreless_iou": runtime_config.get("scoreless_iou", payload.scoreless_iou),
        "edr_package_id": package_id,
        "edr_package_apply_ensemble": apply_ensemble,
    }
    sam3_checkpoint_path = str(runtime.get("sam3_checkpoint_path") or "").strip()
    if sam3_checkpoint_path:
        global active_sam3_checkpoint
        active_sam3_checkpoint = sam3_checkpoint_path
    return model_copy_update(payload, updates), runtime


@_register_agent_tool("log_observation")
def _agent_tool_log_observation(
    text: Optional[str] = None,
    bbox_2d: Optional[Sequence[float]] = None,
    window_bbox_2d: Optional[Sequence[float]] = None,
    grid_cell: Optional[str] = None,
    label_hint: Optional[str] = None,
) -> Dict[str, Any]:
    cleaned = _agent_clean_observation_text(text, max_len=160)
    if not cleaned:
        return {"ok": False, "error": "observation_missing"}
    payload: Dict[str, Any] = {
        "ok": True,
        "observation": cleaned,
    }
    if label_hint:
        payload["label_hint"] = str(label_hint)
    if grid_cell:
        payload["grid_cell"] = str(grid_cell)
    _ = bbox_2d
    _ = window_bbox_2d
    return payload


@_register_agent_tool("log_status")
def _agent_tool_log_status(text: Optional[str] = None) -> Dict[str, Any]:
    cleaned = _agent_clean_observation_text(text, max_len=160)
    if not cleaned:
        return {"ok": False, "error": "status_missing"}
    return {"ok": True, "status": cleaned}


def _agent_tool_specs_text(grid_enabled: bool = False) -> str:
    tool_names = [
        "get_tile_context",
        "get_tile_context_chunk",
        "get_global_context",
        "get_global_context_chunk",
        "view_cell_raw",
        "view_cell_overlay",
        "view_full_overlay",
        "list_candidates",
        "grid_label_counts",
        "look_and_inspect",
        "zoom_and_detect",
        "sam3_text",
        "sam3_similarity",
        "qwen_infer",
        "classify_crop",
        "image_zoom_in_tool",
        "think_missed_objects",
        "submit_annotations",
        "log_observation",
        "log_status",
    ]
    tools = _agent_tool_specs_facade(grid_enabled=bool(grid_enabled), tool_names=tool_names)
    return json.dumps(tools, ensure_ascii=False, indent=2)


def _agent_tool_specs(grid_enabled: bool = False) -> List[Dict[str, Any]]:
    """Return the tool specs as a list for Hermes-style tool templates."""
    try:
        return json.loads(_agent_tool_specs_text(grid_enabled=grid_enabled))
    except Exception:
        return []


def _agent_tool_specs_facade(
    *,
    grid_enabled: bool,
    tool_names: Sequence[str],
) -> List[Dict[str, Any]]:
    grid_cell = {
        "type": "string",
        "description": "Grid cell reference (e.g., C2). Columns are letters, rows are numbers; top-left is A1.",
    }
    required_grid = ["grid_cell"] if grid_enabled else []
    handle_list = {
        "type": "array",
        "description": "Handles returned by list_candidates/get_tile_context (e.g., LV12).",
        "items": {"type": "string"},
    }
    handle = {
        "type": "string",
        "description": "Handle returned by list_candidates/get_tile_context (e.g., LV12).",
    }
    label = {"type": "string", "description": "Canonical labelmap class."}
    prompt = {"type": "string", "description": "Single-term prompt/synonym for SAM3."}
    intent = {"type": "string", "description": "Short note on what you are searching for."}
    tool_map = {
        "get_tile_context": {
            "name": "get_tile_context",
            "description": "Return tile context (cluster handles, counts, captions, tool usage).",
            "parameters": {
                "type": "object",
                "properties": {"grid_cell": grid_cell},
                "required": required_grid,
            },
        },
        "get_tile_context_chunk": {
            "name": "get_tile_context_chunk",
            "description": "Fetch a chunk of a large tile context payload by handle + chunk_index.",
            "parameters": {
                "type": "object",
                "properties": {
                    "context_handle": {"type": "string"},
                    "chunk_index": {"type": "number"},
                },
                "required": ["context_handle", "chunk_index"],
            },
        },
        "get_global_context": {
            "name": "get_global_context",
            "description": "Return global context (tile summaries, counts, captions).",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
        "get_global_context_chunk": {
            "name": "get_global_context_chunk",
            "description": "Fetch a chunk of a large global context payload by handle + chunk_index.",
            "parameters": {
                "type": "object",
                "properties": {
                    "context_handle": {"type": "string"},
                    "chunk_index": {"type": "number"},
                },
                "required": ["context_handle", "chunk_index"],
            },
        },
        "view_cell_raw": {
            "name": "view_cell_raw",
            "description": "Return the raw image crop for a grid cell (no detection dots).",
            "parameters": {
                "type": "object",
                "properties": {"grid_cell": grid_cell},
                "required": required_grid,
            },
        },
        "view_cell_overlay": {
            "name": "view_cell_overlay",
            "description": "Return the overlay crop for a grid cell (colored dots + handles).",
            "parameters": {
                "type": "object",
                "properties": {"grid_cell": grid_cell},
                "required": required_grid,
            },
        },
        "view_full_overlay": {
            "name": "view_full_overlay",
            "description": "Return the full image with grid + detection overlay and tool usage summary.",
            "parameters": {"type": "object", "properties": {}, "required": []},
        },
        "list_candidates": {
            "name": "list_candidates",
            "description": "List current cluster candidates (handles, labels, scores, grid cells).",
            "parameters": {
                "type": "object",
                "properties": {
                    "label": {"type": "string"},
                    "min_score": {"type": "number"},
                    "include_scoreless": {"type": "boolean"},
                    "sort_by": {
                        "type": "string",
                        "enum": ["score_desc", "score_asc", "label", "source", "none"],
                    },
                    "max_items": {"type": "number"},
                },
                "required": [],
            },
        },
        "grid_label_counts": {
            "name": "grid_label_counts",
            "description": "Return per-grid-cell counts (no IDs).",
            "parameters": {
                "type": "object",
                "properties": {"label": {"type": "string"}},
                "required": [],
            },
        },
        "look_and_inspect": {
            "name": "look_and_inspect",
            "description": "Inspect a grid cell visually and propose candidate objects.",
            "parameters": {
                "type": "object",
                "properties": {
                    "grid_cell": grid_cell,
                    "intent": intent,
                    "max_objects": {"type": "number"},
                },
                "required": required_grid,
            },
        },
        "zoom_and_detect": {
            "name": "zoom_and_detect",
            "description": "Run detector on a grid cell (zoomed crop).",
            "parameters": {
                "type": "object",
                "properties": {
                    "grid_cell": grid_cell,
                    "intent": intent,
                    "confirm_label": label,
                    "confirm_topk": {"type": "number"},
                },
                "required": required_grid,
            },
        },
        "sam3_text": {
            "name": "sam3_text",
            "description": "Run SAM3 text prompt for a single term; assign canonical label.",
            "parameters": {
                "type": "object",
                "properties": {"grid_cell": grid_cell, "label": label, "prompt": prompt},
                "required": (required_grid + ["label"]) if required_grid else ["label"],
            },
        },
        "sam3_similarity": {
            "name": "sam3_similarity",
            "description": "Run SAM3 similarity from exemplar handles; assign canonical label.",
            "parameters": {
                "type": "object",
                "properties": {
                    "grid_cell": grid_cell,
                    "label": label,
                    "exemplar_handles": handle_list,
                },
                "required": (
                    (required_grid + ["label", "exemplar_handles"])
                    if required_grid
                    else ["label", "exemplar_handles"]
                ),
            },
        },
        "qwen_infer": {
            "name": "qwen_infer",
            "description": "Ask Qwen-VL to propose new boxes for a list of labels.",
            "parameters": {
                "type": "object",
                "properties": {
                    "grid_cell": grid_cell,
                    "items": {"type": "array", "items": {"type": "string"}},
                    "prompt_type": {"type": "string", "enum": ["bbox", "point"]},
                    "intent": intent,
                },
                "required": required_grid,
            },
        },
        "classify_crop": {
            "name": "classify_crop",
            "description": "Classify a cluster crop to verify its label.",
            "parameters": {
                "type": "object",
                "properties": {"handle": handle, "label_hint": label, "topk": {"type": "number"}},
                "required": ["handle"],
            },
        },
        "image_zoom_in_tool": {
            "name": "image_zoom_in_tool",
            "description": "Return a zoomed image for a grid cell or handle.",
            "parameters": {
                "type": "object",
                "properties": {"grid_cell": grid_cell, "handle": handle, "intent": intent},
                "required": [],
            },
        },
        "think_missed_objects": {
            "name": "think_missed_objects",
            "description": "Analyze overlay + captions to suggest missing labels/tiles.",
            "parameters": {
                "type": "object",
                "properties": {"notes": {"type": "string"}},
                "required": [],
            },
        },
        "submit_annotations": {
            "name": "submit_annotations",
            "description": "Submit final annotations using handles or include_all.",
            "parameters": {
                "type": "object",
                "properties": {"handles": handle_list, "include_all": {"type": "boolean"}},
                "required": [],
            },
        },
        "log_observation": {
            "name": "log_observation",
            "description": "Log a single-line observation about what you see (max 160 chars).",
            "parameters": {
                "type": "object",
                "properties": {"text": {"type": "string"}},
                "required": ["text"],
            },
        },
        "log_status": {
            "name": "log_status",
            "description": "Log a short status update (max 160 chars).",
            "parameters": {
                "type": "object",
                "properties": {"text": {"type": "string"}},
                "required": ["text"],
            },
        },
    }
    specs: List[Dict[str, Any]] = []
    for name in tool_names:
        spec = tool_map.get(name)
        if not spec:
            continue
        specs.append({"type": "function", "function": spec})
    return specs


