def _agent_mining_cache_root(cache_root: Path, *, create: bool = False) -> Path:
    raw_root = Path(cache_root)
    if _storage_path_has_symlink_component(raw_root):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    if create:
        raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    if raw_root.exists() and not raw_root.is_dir():
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    if _storage_path_has_symlink_component(raw_root):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    return raw_root.resolve(strict=False)


def _agent_mining_cache_child_dir(cache_root: Path, child_name: str, *, create: bool = False) -> Path:
    clean_name = Path(str(child_name or "")).name
    if not clean_name or clean_name != str(child_name):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    root = _agent_mining_cache_root(cache_root, create=create)
    raw_child = root / clean_name
    if _storage_path_has_symlink_component(raw_child):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    if create:
        raw_child.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_child):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    if raw_child.exists() and not raw_child.is_dir():
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid")
    try:
        child = raw_child.resolve(strict=False)
        child.relative_to(root)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="agent_mining_cache_path_invalid") from exc
    return child


def _write_auto_label_result_json(job_id: str, payload: Dict[str, Any]) -> None:
    job_id_text = str(job_id or "").strip()
    job_id_path = Path(job_id_text)
    if not job_id_text or job_id_path.is_absolute() or ".." in job_id_path.parts:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    if _storage_path_has_symlink_component(AUTO_LABEL_ROOT):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    AUTO_LABEL_ROOT.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(AUTO_LABEL_ROOT):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    root = AUTO_LABEL_ROOT.resolve(strict=True)
    job_dir = root / job_id_text
    if _storage_path_has_symlink_component(job_dir):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    job_dir.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(job_dir):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    try:
        job_dir.resolve(strict=True).relative_to(root)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid") from exc
    result_path = job_dir / "result.json"
    if result_path.is_symlink():
        result_path.unlink(missing_ok=True)
    elif result_path.exists() and not result_path.is_file():
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="auto_label_job_path_invalid")
    tmp_path = result_path.with_suffix(f".json.tmp.{os.getpid()}")
    if tmp_path.is_symlink():
        tmp_path.unlink(missing_ok=True)
    _write_temp_text_no_follow(tmp_path, json.dumps(payload, indent=2))
    os.replace(tmp_path, result_path)


def _enforce_agent_mining_cache_limits(cache_root: Path, allow_when_running: bool = False) -> None:
    """Prune agent mining cache by TTL and size caps."""
    try:
        cache_root = _agent_mining_cache_root(cache_root, create=True)
    except Exception:
        return
    if not allow_when_running:
        with AGENT_MINING_JOBS_LOCK:
            for job in AGENT_MINING_JOBS.values():
                if getattr(job, "status", None) == "running":
                    return

    now = time.time()
    ttl_seconds = AGENT_MINING_CACHE_TTL_HOURS * 3600 if AGENT_MINING_CACHE_TTL_HOURS > 0 else 0

    def _iter_entries():
        for entry in cache_root.iterdir():
            try:
                stat = entry.lstat()
            except Exception:
                continue
            yield entry, stat.st_mtime

    def _remove_cache_entry(entry: Path) -> int:
        if entry.is_symlink():
            size = entry.lstat().st_size
            entry.unlink(missing_ok=True)
            return size
        if entry.is_dir():
            size = _dir_size_bytes_impl(entry)
            shutil.rmtree(entry, ignore_errors=True)
            return size
        size = entry.stat().st_size
        entry.unlink(missing_ok=True)
        return size

    # TTL purge
    if ttl_seconds > 0:
        for entry, mtime in list(_iter_entries()):
            if now - mtime > ttl_seconds:
                try:
                    _remove_cache_entry(entry)
                except Exception:
                    pass

    # Size purge
    max_bytes = AGENT_MINING_CACHE_MAX_BYTES
    if max_bytes <= 0:
        return
    try:
        total = _dir_size_bytes_impl(cache_root)
    except Exception:
        return
    if total <= max_bytes:
        return
    entries = sorted(list(_iter_entries()), key=lambda pair: pair[1])
    for entry, _ in entries:
        if total <= max_bytes:
            break
        try:
            size = _remove_cache_entry(entry)
            total = max(0, total - size)
        except Exception:
            continue


def _purge_directory(root: Path) -> int:
    """Delete all entries under a directory and return count removed."""
    removed = 0
    try:
        if not root.exists():
            return 0
        for entry in root.iterdir():
            try:
                if entry.is_symlink():
                    entry.unlink(missing_ok=True)
                elif entry.is_dir():
                    shutil.rmtree(entry, ignore_errors=True)
                else:
                    entry.unlink(missing_ok=True)
                removed += 1
            except Exception:
                continue
    except Exception:
        return removed
    return removed


_TERMINAL_JOB_STATUSES = {"succeeded", "completed", "failed", "cancelled"}
_DESTRUCTIVE_DELETE_ACTIVE_STATUSES = {"queued", "running", "cancelling"}


def _iter_nested_string_values(value: Any) -> Iterator[str]:
    if isinstance(value, str):
        yield value
        return
    if isinstance(value, dict):
        for nested in value.values():
            yield from _iter_nested_string_values(nested)
        return
    if isinstance(value, (list, tuple, set)):
        for nested in value:
            yield from _iter_nested_string_values(nested)


def _iter_nested_key_values(value: Any):
    if isinstance(value, dict):
        for key, nested in value.items():
            yield str(key), nested
            yield from _iter_nested_key_values(nested)
        return
    if isinstance(value, (list, tuple, set)):
        for nested in value:
            yield from _iter_nested_key_values(nested)


def _job_payload_references_run_id(payload: Any, run_id: str) -> bool:
    if not run_id:
        return False
    run_id_norm = str(run_id)
    for key, value in _iter_nested_key_values(payload):
        if key not in {"run_id", "base_run_id", "job_id"}:
            continue
        if str(value or "").strip() == run_id_norm:
            return True
    return False


def _active_jobs_block_run_delete(
    registry: Dict[str, Any],
    lock: threading.Lock,
    run_id: str,
    run_dir: Path,
) -> bool:
    try:
        root = run_dir.resolve(strict=False)
    except Exception:
        root = run_dir
    with lock:
        jobs = list(registry.values())
    for job in jobs:
        status = str(getattr(job, "status", "") or "").strip().lower()
        if status not in _DESTRUCTIVE_DELETE_ACTIVE_STATUSES:
            continue
        if str(getattr(job, "job_id", "") or "") == str(run_id):
            return True
        payloads = [
            getattr(job, "config", {}) or {},
            getattr(job, "request", {}) or {},
            getattr(job, "result", {}) or {},
        ]
        if any(_job_payload_references_run_id(payload, run_id) for payload in payloads):
            return True
        for raw_value in _iter_nested_string_values(payloads):
            text = raw_value.strip()
            if not text:
                continue
            try:
                candidate = Path(text).expanduser().resolve(strict=False)
            except Exception:
                continue
            if _path_is_within_root_impl(candidate, root):
                return True
    return False


def _active_job_registry_blocking_run_delete(
    run_id: str,
    run_dir: Path,
    registries: Sequence[Tuple[str, Dict[str, Any], threading.Lock]],
) -> Optional[str]:
    for name, registry, lock in registries:
        if _active_jobs_block_run_delete(registry, lock, run_id, run_dir):
            return name
    return None


def _active_jobs_reference_path_root(
    registry: Dict[str, Any], lock: threading.Lock, path_root: Path
) -> bool:
    try:
        root = path_root.resolve(strict=False)
    except Exception:
        root = path_root
    with lock:
        jobs = list(registry.values())
    for job in jobs:
        status = str(getattr(job, "status", "") or "").strip().lower()
        if status not in _DESTRUCTIVE_DELETE_ACTIVE_STATUSES:
            continue
        payloads = [
            getattr(job, "config", {}) or {},
            getattr(job, "request", {}) or {},
        ]
        for raw_value in _iter_nested_string_values(payloads):
            text = raw_value.strip()
            if not text:
                continue
            try:
                candidate = Path(text).expanduser().resolve(strict=False)
            except Exception:
                continue
            if _path_is_within_root_impl(candidate, root):
                return True
    return False


def _job_payload_references_dataset_id(payload: Any, dataset_id: str) -> bool:
    dataset_id_norm = str(dataset_id or "").strip()
    if not dataset_id_norm:
        return False
    for key, value in _iter_nested_key_values(payload):
        key_norm = str(key or "").strip().lower()
        if key_norm != "dataset_id" and not key_norm.endswith("_dataset_id"):
            continue
        if str(value or "").strip() == dataset_id_norm:
            return True
    return False


def _active_jobs_reference_dataset_id(
    registry: Dict[str, Any], lock: threading.Lock, dataset_id: str
) -> bool:
    with lock:
        jobs = list(registry.values())
    for job in jobs:
        status = str(getattr(job, "status", "") or "").strip().lower()
        if status not in _DESTRUCTIVE_DELETE_ACTIVE_STATUSES:
            continue
        payloads = [
            getattr(job, "config", {}) or {},
            getattr(job, "request", {}) or {},
            getattr(job, "result", {}) or {},
        ]
        if any(_job_payload_references_dataset_id(payload, dataset_id) for payload in payloads):
            return True
    return False


