def _agent_cache_running_jobs() -> bool:
    """Return True if any agent mining job is currently running."""
    with AGENT_MINING_JOBS_LOCK:
        for job in AGENT_MINING_JOBS.values():
            if getattr(job, "status", None) == "running":
                return True
    return False


