def _unwrap_single_root_dir(extract_root: Path) -> Path:
    entries = [p for p in extract_root.iterdir() if p.name not in {"__MACOSX"}]
    if len(entries) == 1 and entries[0].is_dir():
        return entries[0]
    return extract_root


def _normalise_relative_path(raw_path: Optional[str]) -> Path:
    raw = str(raw_path or "").replace("\\", "/").strip()
    if not raw:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    while raw.startswith("/"):
        raw = raw[1:]
    path = Path(raw)
    if path.is_absolute() or ".." in path.parts:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    parts = [part for part in path.parts if part not in {"", "."}]
    if not parts:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    return Path(*parts)


def _annotation_normalise_split(split: Optional[str]) -> str:
    normalized = str(split or "train").strip().lower()
    if normalized not in {"train", "val"}:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_split")
    return normalized


def _annotation_normalise_image_relpath(raw_path: Optional[str]) -> Path:
    rel = _normalise_relative_path(raw_path)
    if rel.suffix.lower() not in DATASET_IMAGE_EXTENSIONS:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_image_relpath")
    return rel


def _dataset_raw_meta_storage_root_from_entry(entry: Dict[str, Any]) -> Path:
    registry_root = entry.get("registry_root")
    if registry_root:
        return Path(str(registry_root))
    return Path(str(entry.get("dataset_root") or ""))


def _dataset_meta_storage_root_from_entry(entry: Dict[str, Any]) -> Path:
    return _dataset_raw_meta_storage_root_from_entry(entry).resolve()


def _dataset_guarded_meta_storage_root_from_entry(
    entry: Dict[str, Any],
    *,
    ensure: bool = False,
    detail: str = "dataset_metadata_path_forbidden",
) -> Path:
    raw_root = _dataset_raw_meta_storage_root_from_entry(entry)
    try:
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("dataset metadata root has a symlink component")
        if ensure:
            raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("dataset metadata root has a symlink component")
        if raw_root.exists() and not raw_root.is_dir():
            raise ValueError("dataset metadata root is not a directory")
        return raw_root.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _dataset_overlay_root_from_entry(entry: Dict[str, Any], *, ensure: bool = False) -> Path:
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=ensure,
        detail="annotation_overlay_path_forbidden",
    )
    overlay_root = storage_root / DATASET_ANNOTATION_OVERLAY_DIRNAME
    if ensure:
        if _storage_path_has_symlink_component(overlay_root):
            raise HTTPException(
                status_code=HTTP_400_BAD_REQUEST,
                detail="annotation_overlay_path_forbidden",
            )
        overlay_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(overlay_root) or not overlay_root.is_dir():
            raise HTTPException(
                status_code=HTTP_400_BAD_REQUEST,
                detail="annotation_overlay_path_forbidden",
            )
    return overlay_root


def _dataset_meta_path_for_entry(entry: Dict[str, Any]) -> Path:
    return _dataset_meta_storage_root_from_entry(entry) / DATASET_META_NAME


def _dataset_effective_root_from_entry(entry: Dict[str, Any]) -> Path:
    storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
    if storage_mode == "linked":
        linked_status = str(entry.get("linked_root_status") or "").strip().lower()
        if linked_status in {"missing", "invalid", "not_allowlisted"}:
            if linked_status == "missing":
                raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing")
            detail = (
                "dataset_path_not_allowlisted"
                if linked_status == "not_allowlisted"
                else "dataset_path_not_found"
            )
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    root = Path(str(entry.get("dataset_root") or "")).resolve()
    if not root.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing")
    return root


def _normalize_labelmap_payload(raw_labelmap: Any) -> List[str]:
    if not isinstance(raw_labelmap, list):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_list_required")
    labels: List[str] = []
    seen: Set[str] = set()
    for item in raw_labelmap:
        label = str(item or "").strip()
        if not label:
            continue
        if "\n" in label or "\r" in label:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_invalid_class")
        key = label.lower()
        if key in seen:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_duplicate_class")
        seen.add(key)
        labels.append(label)
    if not labels:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_empty")
    return labels


def _annotation_labelmap_write_path(entry: Dict[str, Any], dataset_root: Path) -> Path:
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=False,
        detail="labelmap_path_forbidden",
    ).resolve()
    storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
    if storage_mode == "linked":
        return storage_root / "labelmap.txt"
    raw_path = entry.get("yolo_labelmap_path")
    labelmap_path = Path(str(raw_path)) if raw_path else (dataset_root / "labelmap.txt")
    labelmap_resolved = labelmap_path.resolve(strict=False)
    allowed_roots = [dataset_root.resolve(), storage_root]
    if not any(_path_is_within_root_impl(labelmap_resolved, root) for root in allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden")
    return labelmap_path


def _annotation_labelmap_read_path(
    entry: Dict[str, Any], dataset_root: Path, storage_root: Path
) -> Path:
    raw_path = entry.get("yolo_labelmap_path")
    labelmap_path = Path(str(raw_path)) if raw_path else (dataset_root / "labelmap.txt")
    allowed_roots = [dataset_root.resolve(), storage_root.resolve()]
    try:
        target_resolved = labelmap_path.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="labelmap_path_forbidden",
        ) from exc
    if not any(_path_is_within_root_impl(target_resolved, root) for root in allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden")
    if not labelmap_path.exists():
        return labelmap_path
    try:
        if _storage_path_has_symlink_component(labelmap_path.parent) or labelmap_path.is_symlink():
            raise ValueError("labelmap path has a symlink component")
        existing_resolved = labelmap_path.resolve(strict=True)
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="labelmap_path_forbidden",
        ) from exc
    if not existing_resolved.is_file() or not any(
        _path_is_within_root_impl(existing_resolved, root) for root in allowed_roots
    ):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden")
    return labelmap_path


def _annotation_write_labelmap_file(
    labelmap_path: Path, allowed_roots: Sequence[Path], labels: Sequence[str]
) -> None:
    tmp_path = labelmap_path.with_suffix(f"{labelmap_path.suffix}.{uuid.uuid4().hex}.tmp")
    try:
        if _storage_path_has_symlink_component(labelmap_path.parent):
            raise ValueError("labelmap parent has a symlink component")
        labelmap_path.parent.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(labelmap_path.parent):
            raise ValueError("labelmap parent has a symlink component")
        parent_resolved = labelmap_path.parent.resolve(strict=True)
        if not any(_path_is_within_root_impl(parent_resolved, root) for root in allowed_roots):
            raise ValueError("labelmap parent escapes allowed roots")
        for candidate in (tmp_path, labelmap_path):
            if candidate.is_symlink():
                candidate.unlink(missing_ok=True)
            elif candidate.exists() and candidate.is_dir():
                raise ValueError("labelmap target is a directory")
            target_resolved = candidate.resolve(strict=False)
            if not any(_path_is_within_root_impl(target_resolved, root) for root in allowed_roots):
                raise ValueError("labelmap target escapes allowed roots")
        _write_temp_text_no_follow(tmp_path, "\n".join(labels) + "\n")
        os.replace(tmp_path, labelmap_path)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="labelmap_path_forbidden",
        ) from exc
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)


def _linked_dataset_root_is_allowlisted(path: Path) -> bool:
    try:
        resolved = Path(path).expanduser().resolve()
    except Exception:
        return False
    for root in DATASET_LINK_ROOTS:
        try:
            root_resolved = Path(root).expanduser().resolve()
            if _path_is_within_root_impl(resolved, root_resolved):
                return True
        except Exception:
            continue
    return False


def _validate_linked_dataset_path(path_str: str) -> Path:
    raw = str(path_str or "").strip()
    if not raw:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_path_required")
    candidate = Path(raw).expanduser()
    if not candidate.is_absolute():
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="dataset_path_must_be_absolute"
        )
    resolved = candidate.resolve()
    if not resolved.exists() or not resolved.is_dir():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_path_not_found")
    if not _linked_dataset_root_is_allowlisted(resolved):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_path_not_allowlisted")
    return resolved


def _dataset_labelmap_file_within_root(dataset_root: Path, name: str) -> Path:
    root_resolved = dataset_root.resolve()
    candidate = dataset_root / name
    try:
        candidate_resolved = candidate.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden") from exc
    if not _path_is_within_root_impl(candidate_resolved, root_resolved):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden")
    if not candidate.exists():
        return candidate
    try:
        if _storage_path_has_symlink_component(candidate.parent) or candidate.is_symlink():
            raise ValueError("dataset labelmap has a symlink component")
        existing_resolved = candidate.resolve(strict=True)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden") from exc
    if not existing_resolved.is_file() or not _path_is_within_root_impl(
        existing_resolved, root_resolved
    ):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden")
    return candidate


def _dataset_labelmap_from_root(dataset_root: Path) -> List[str]:
    for name in ("labelmap.txt", "classes.txt", "labels.txt"):
        candidate = _dataset_labelmap_file_within_root(dataset_root, name)
        classes = _load_labelmap_file(candidate)
        if classes:
            return [str(x).strip() for x in classes if str(x).strip()]
    return []


def _validate_linked_dataset_shape(dataset_root: Path, *, strict: bool = True) -> Dict[str, Any]:
    layout = _detect_yolo_layout_impl(dataset_root)
    if not strict:
        return layout
    labelmap_path = dataset_root / "labelmap.txt"
    if not labelmap_path.exists():
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="dataset_shape_missing_labelmap"
        )
    _dataset_labelmap_file_within_root(dataset_root, "labelmap.txt")
    if layout.get("yolo_layout") in {"flat", "split"} and layout.get("yolo_ready"):
        return layout
    has_flat_images = (dataset_root / "images").exists()
    has_flat_labels = (dataset_root / "labels").exists()
    has_split_images = (dataset_root / "train" / "images").exists() or (
        dataset_root / "val" / "images"
    ).exists()
    has_split_labels = (dataset_root / "train" / "labels").exists() or (
        dataset_root / "val" / "labels"
    ).exists()
    if not (has_flat_images or has_split_images):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_shape_missing_images")
    if not (has_flat_labels or has_split_labels):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_shape_missing_labels")
    raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_shape_invalid_layout")


def _annotation_source_label_path(
    dataset_root: Path, yolo_layout: str, split: str, image_relpath: Path
) -> Path:
    if yolo_layout == "split":
        return dataset_root / split / "labels" / image_relpath.with_suffix(".txt")
    return dataset_root / "labels" / image_relpath.with_suffix(".txt")


def _annotation_overlay_label_path(
    entry: Dict[str, Any], split: str, image_relpath: Path, *, ensure: bool = True
) -> Path:
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=ensure)
    return overlay_root / "labels" / split / image_relpath.with_suffix(".txt")


def _annotation_text_relpath(image_relpath: Path) -> Path:
    if image_relpath.suffix:
        return image_relpath.with_suffix(".txt")
    return image_relpath / "index.txt"


def _annotation_legacy_text_name(image_relpath: Path) -> str:
    return f"{image_relpath.stem}.txt"


def _annotation_uses_split_text_path(
    split: Optional[str], yolo_layout: Optional[str] = None
) -> bool:
    return bool(split) and str(yolo_layout or "").strip().lower() == "split"


def _annotation_source_text_path(
    dataset_root: Path,
    image_relpath: Path,
    *,
    split: Optional[str] = None,
    yolo_layout: Optional[str] = None,
) -> Path:
    if _annotation_uses_split_text_path(split, yolo_layout):
        return dataset_root / str(split) / "text_labels" / _annotation_text_relpath(image_relpath)
    return dataset_root / "text_labels" / _annotation_text_relpath(image_relpath)


def _annotation_source_text_path_legacy(
    dataset_root: Path,
    image_relpath: Path,
    *,
    split: Optional[str] = None,
    yolo_layout: Optional[str] = None,
) -> Path:
    if _annotation_uses_split_text_path(split, yolo_layout):
        return dataset_root / str(split) / "text_labels" / _annotation_legacy_text_name(image_relpath)
    return dataset_root / "text_labels" / _annotation_legacy_text_name(image_relpath)


def _annotation_overlay_text_path(
    entry: Dict[str, Any],
    image_relpath: Path,
    *,
    split: Optional[str] = None,
    ensure: bool = True,
) -> Path:
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=ensure)
    if _annotation_uses_split_text_path(split, entry.get("yolo_layout")):
        return overlay_root / "text_labels" / str(split) / _annotation_text_relpath(image_relpath)
    return overlay_root / "text_labels" / _annotation_text_relpath(image_relpath)


def _annotation_overlay_text_path_legacy(
    entry: Dict[str, Any],
    image_relpath: Path,
    *,
    split: Optional[str] = None,
    ensure: bool = True,
) -> Path:
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=ensure)
    if _annotation_uses_split_text_path(split, entry.get("yolo_layout")):
        return overlay_root / "text_labels" / str(split) / _annotation_legacy_text_name(image_relpath)
    return overlay_root / "text_labels" / _annotation_legacy_text_name(image_relpath)


def _annotation_safe_text_path(path: Path, root: Path) -> Optional[Path]:
    try:
        root_resolved = root.resolve()
        resolved = path.resolve()
    except Exception:
        return None
    if not _path_is_within_root_impl(resolved, root_resolved):
        return None
    if not resolved.is_file():
        return None
    return resolved


def _annotation_read_text_within_root(path: Path, root: Path) -> Optional[str]:
    resolved = _annotation_safe_text_path(path, root)
    if resolved is None:
        return None
    return resolved.read_text(encoding="utf-8")


def _annotation_write_text_within_root(path: Path, root: Path, text: str) -> None:
    root_resolved = root.resolve()
    tmp_path = path.with_suffix(f"{path.suffix}.{uuid.uuid4().hex}.tmp")
    if _storage_path_has_symlink_component(root) or _storage_path_has_symlink_component(path.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="annotation_overlay_path_forbidden")
    path.parent.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(path.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="annotation_overlay_path_forbidden")
    try:
        parent_resolved = path.parent.resolve()
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="annotation_overlay_path_forbidden") from exc
    if not _path_is_within_root_impl(parent_resolved, root_resolved):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="annotation_overlay_path_forbidden")
    try:
        for candidate in (tmp_path, path):
            if candidate.is_symlink():
                candidate.unlink(missing_ok=True)
            elif candidate.exists() and candidate.is_dir():
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="annotation_overlay_path_forbidden",
                )
            try:
                target_resolved = candidate.resolve(strict=False)
            except Exception as exc:
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="annotation_overlay_path_forbidden",
                ) from exc
            if not _path_is_within_root_impl(target_resolved, root_resolved):
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="annotation_overlay_path_forbidden",
                )
        _write_temp_text_no_follow(tmp_path, text)
        os.replace(tmp_path, path)
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)


def _annotation_effective_label_lines(
    entry: Dict[str, Any], split: str, image_relpath: Path
) -> List[str]:
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=False)
    overlay_path = _annotation_overlay_label_path(entry, split, image_relpath, ensure=False)
    overlay_text = _annotation_read_text_within_root(overlay_path, overlay_root)
    if overlay_text is not None:
        return [ln.strip() for ln in overlay_text.splitlines() if ln.strip()]
    dataset_root = _dataset_effective_root_from_entry(entry)
    layout = str(entry.get("yolo_layout") or "flat")
    source_path = _annotation_source_label_path(dataset_root, layout, split, image_relpath)
    source_text = _annotation_read_text_within_root(source_path, dataset_root)
    if source_text is None:
        return []
    return [ln.strip() for ln in source_text.splitlines() if ln.strip()]


def _annotation_effective_text_label(
    entry: Dict[str, Any], image_relpath: Path, split: Optional[str] = None
) -> str:
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=False)
    layout = str(entry.get("yolo_layout") or "flat")
    overlay_paths: List[Path] = []
    if _annotation_uses_split_text_path(split, layout):
        overlay_paths.extend(
            [
                _annotation_overlay_text_path(
                    entry, image_relpath, split=split, ensure=False
                ),
                _annotation_overlay_text_path_legacy(
                    entry, image_relpath, split=split, ensure=False
                ),
            ]
        )
    overlay_paths.extend(
        [
            _annotation_overlay_text_path(entry, image_relpath, ensure=False),
            _annotation_overlay_text_path_legacy(entry, image_relpath, ensure=False),
        ]
    )
    for overlay_path in overlay_paths:
        overlay_text = _annotation_read_text_within_root(overlay_path, overlay_root)
        if overlay_text is not None:
            return overlay_text.strip()
    dataset_root = _dataset_effective_root_from_entry(entry)
    source_paths: List[Path] = []
    if _annotation_uses_split_text_path(split, layout):
        source_paths.extend(
            [
                _annotation_source_text_path(
                    dataset_root, image_relpath, split=split, yolo_layout=layout
                ),
                _annotation_source_text_path_legacy(
                    dataset_root, image_relpath, split=split, yolo_layout=layout
                ),
            ]
        )
    source_paths.extend(
        [
            _annotation_source_text_path(dataset_root, image_relpath),
            _annotation_source_text_path_legacy(dataset_root, image_relpath),
        ]
    )
    for source_path in source_paths:
        source_text = _annotation_read_text_within_root(source_path, dataset_root)
        if source_text is not None:
            return source_text.strip()
    return ""


def _annotation_source_text_value(
    dataset_root: Path,
    image_relpath: Path,
    *,
    split: Optional[str] = None,
    yolo_layout: Optional[str] = None,
) -> str:
    source_paths: List[Path] = []
    if _annotation_uses_split_text_path(split, yolo_layout):
        source_paths.extend(
            [
                _annotation_source_text_path(
                    dataset_root, image_relpath, split=split, yolo_layout=yolo_layout
                ),
                _annotation_source_text_path_legacy(
                    dataset_root, image_relpath, split=split, yolo_layout=yolo_layout
                ),
            ]
        )
    source_paths.extend(
        [
            _annotation_source_text_path(dataset_root, image_relpath),
            _annotation_source_text_path_legacy(dataset_root, image_relpath),
        ]
    )
    for source_path in source_paths:
        source_text = _annotation_read_text_within_root(source_path, dataset_root)
        if source_text is not None:
            return source_text.strip()
    return ""


def _annotation_text_split_rel_from_name(
    entry: Dict[str, Any],
    image_name: str,
    *,
    split: Optional[str] = None,
) -> Tuple[Optional[str], Path]:
    rel = _annotation_normalise_image_relpath(
        image_name if "." in str(image_name or "") else f"{image_name}.jpg"
    )
    explicit_split = _annotation_normalise_split(split) if split is not None else None
    layout = str(entry.get("yolo_layout") or "flat").strip().lower()
    if explicit_split:
        return explicit_split, rel
    if layout == "split" and len(rel.parts) >= 2 and rel.parts[0] in {"train", "val", "valid", "test"}:
        return _annotation_normalise_split(rel.parts[0]), Path(*rel.parts[1:])
    return None, rel


def _annotation_collect_images(entry: Dict[str, Any]) -> List[Dict[str, Any]]:
    dataset_root = _dataset_effective_root_from_entry(entry)
    dataset_root_resolved = dataset_root.resolve()
    out: List[Dict[str, Any]] = []
    yolo_layout = str(entry.get("yolo_layout") or "flat")

    def _append(split_name: str, images_dir: Path) -> None:
        if not images_dir.exists():
            return
        try:
            images_dir_resolved = images_dir.resolve()
        except Exception:
            return
        if not _path_is_within_root_impl(images_dir_resolved, dataset_root_resolved):
            return
        for image_path in _iter_yolo_images(images_dir):
            try:
                image_resolved = image_path.resolve()
            except Exception:
                continue
            if not _path_is_within_root_impl(image_resolved, dataset_root_resolved):
                continue
            try:
                rel = image_path.relative_to(images_dir)
            except Exception:
                rel = Path(image_path.name)
            out.append(
                {
                    "split": split_name,
                    "image_relpath": str(rel.as_posix()),
                    "image_name": rel.name,
                    "image_path": image_path,
                }
            )

    if yolo_layout == "split":
        _append("train", dataset_root / "train" / "images")
        _append("val", dataset_root / "val" / "images")
    else:
        images_root = dataset_root / "images"
        if not images_root.exists():
            images_root = dataset_root
        _append("train", images_root)
    return out


def _annotation_progress_from_rows(rows: Sequence[Dict[str, Any]]) -> Dict[str, Any]:
    total = len(rows)
    labeled = 0
    text_labeled = 0
    for row in rows:
        lines = row.get("label_lines") or []
        if isinstance(lines, list) and any(str(x).strip() for x in lines):
            labeled += 1
        text_label = str(row.get("text_label") or "").strip()
        if text_label:
            text_labeled += 1
    pct = (100.0 * labeled / total) if total > 0 else 0.0
    text_pct = (100.0 * text_labeled / total) if total > 0 else 0.0
    return {
        "images_total": total,
        "images_with_bbox_or_seg": labeled,
        "images_with_text_label": text_labeled,
        "percent_labeled": pct,
        "percent_text_labeled": text_pct,
    }


def _annotation_load_or_create_meta(entry: Dict[str, Any]) -> Tuple[Path, Dict[str, Any]]:
    meta_path = _dataset_meta_path_for_entry(entry)
    meta = _load_json_metadata(meta_path) or {}
    if not meta.get("id"):
        meta["id"] = entry.get("id") or meta_path.parent.name
    if not meta.get("label"):
        meta["label"] = entry.get("label") or meta.get("id")
    if "annotation_status" not in meta:
        meta["annotation_status"] = "new"
    if "annotation_notes" not in meta:
        meta["annotation_notes"] = ""
    if "annotation_cursor" not in meta:
        meta["annotation_cursor"] = None
    if "annotation_progress" not in meta:
        meta["annotation_progress"] = {}
    if "annotation_lock" not in meta:
        meta["annotation_lock"] = {}
    return meta_path, meta


def _annotation_persist_meta(entry: Dict[str, Any], meta: Dict[str, Any]) -> None:
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=True,
        detail="dataset_metadata_path_forbidden",
    )
    _write_dataset_metadata_json(storage_root / DATASET_META_NAME, storage_root, meta)


def _annotation_lock_is_active(lock: Dict[str, Any]) -> bool:
    if not isinstance(lock, dict):
        return False
    expires = lock.get("expires_at")
    try:
        expires_f = float(expires)
    except Exception:
        return False
    return expires_f > time.time()


def _path_identity(path: Path) -> Path:
    try:
        return path.resolve(strict=False)
    except RuntimeError:
        return path.absolute()


def _unlink_self_referential_symlink(path: Path) -> bool:
    if not path.is_symlink():
        return False
    try:
        target = Path(os.readlink(path))
    except OSError:
        return False
    if not target.is_absolute():
        target = path.parent / target
    if _path_identity(target) != _path_identity(path):
        return False
    path.unlink(missing_ok=True)
    return True


def _copy2_if_different(src: Path, dest: Path) -> None:
    src_resolved = src.resolve()
    if dest.is_symlink():
        dest.unlink(missing_ok=True)
        logger.warning("Removed artifact symlink before copy: %s", dest)
    elif src_resolved == _path_identity(dest):
        return
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="artifact_path_invalid")
    dest.parent.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="artifact_path_invalid")
    tmp_path = dest.with_suffix(dest.suffix + f".tmp.{os.getpid()}")
    if tmp_path.is_symlink():
        tmp_path.unlink(missing_ok=True)
    elif tmp_path.exists():
        if tmp_path.is_dir():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="artifact_path_invalid")
        tmp_path.unlink()
    try:
        shutil.copy2(src_resolved, tmp_path)
        os.replace(tmp_path, dest)
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)


def _link_or_copy_file(src: Path, dest: Path, *, overwrite: bool = False) -> None:
    src_resolved = src.resolve()
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    dest.parent.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    if not dest.is_symlink() and src_resolved == _path_identity(dest):
        return
    if dest.exists() or dest.is_symlink():
        if not overwrite:
            return
        if dest.is_dir():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    tmp_path = dest.with_suffix(dest.suffix + f".tmp.{os.getpid()}")
    if tmp_path.is_symlink():
        tmp_path.unlink(missing_ok=True)
    elif tmp_path.exists():
        if tmp_path.is_dir():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
        tmp_path.unlink()
    try:
        try:
            os.link(src_resolved, tmp_path)
        except Exception:
            shutil.copy2(src_resolved, tmp_path)
        os.replace(tmp_path, dest)
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)


def _build_linked_dataset_metadata(
    *,
    dataset_id: str,
    dataset_root: Path,
    label: Optional[str],
    context: Optional[str],
    notes: Optional[str],
) -> Dict[str, Any]:
    layout = _detect_yolo_layout_impl(dataset_root)
    yolo_labels_dir = layout.get("yolo_labels_dir")
    dataset_type = "bbox"
    if yolo_labels_dir and _yolo_labels_have_polygons_impl(Path(str(yolo_labels_dir))):
        dataset_type = "seg"
    train_images_dir = dataset_root / "train" / "images"
    val_images_dir = dataset_root / "val" / "images"
    train_count = len(_iter_yolo_images(train_images_dir)) if train_images_dir.exists() else 0
    val_count = len(_iter_yolo_images(val_images_dir)) if val_images_dir.exists() else 0
    image_count = train_count + val_count
    if image_count <= 0:
        image_count = _count_dataset_images_impl(dataset_root, iter_images_fn=_iter_yolo_images)
    meta: Dict[str, Any] = {
        "id": dataset_id,
        "label": str(label or dataset_id),
        "type": dataset_type,
        "context": str(context or ""),
        "created_at": time.time(),
        "source": "registry",
        "storage_mode": "linked",
        "linked_root": str(dataset_root),
        "signature": _compute_dir_signature_impl(dataset_root),
        "classes": _dataset_labelmap_from_root(dataset_root),
        "image_count": image_count,
        "train_count": train_count or None,
        "val_count": val_count or None,
        "annotation_status": "new",
        "annotation_notes": str(notes or ""),
        "annotation_cursor": None,
        "annotation_progress": {
            "images_total": image_count,
            "images_with_bbox_or_seg": 0,
            "images_with_text_label": 0,
            "percent_labeled": 0.0,
            "percent_text_labeled": 0.0,
        },
        "annotation_lock": {},
    }
    if not meta["train_count"]:
        meta.pop("train_count", None)
    if not meta["val_count"]:
        meta.pop("val_count", None)
    return meta


def _annotation_manifest_for_entry(entry: Dict[str, Any]) -> Dict[str, Any]:
    rows = _annotation_collect_images(entry)
    manifest_rows: List[Dict[str, Any]] = []
    for row in rows:
        split = _annotation_normalise_split(row.get("split"))
        image_relpath = _annotation_normalise_image_relpath(row.get("image_relpath"))
        label_lines = _annotation_effective_label_lines(entry, split, image_relpath)
        text_label = _annotation_effective_text_label(entry, image_relpath, split)
        manifest_rows.append(
            {
                "split": split,
                "image_relpath": str(image_relpath.as_posix()),
                "image_name": row.get("image_name") or image_relpath.name,
                "label_lines": label_lines,
                "text_label": text_label,
            }
        )
    progress = _annotation_progress_from_rows(manifest_rows)
    _meta_path, meta = _annotation_load_or_create_meta(entry)
    persisted_progress = (
        meta.get("annotation_progress") if isinstance(meta.get("annotation_progress"), dict) else {}
    )
    if persisted_progress != progress:
        meta["annotation_progress"] = progress
        _annotation_persist_meta(entry, meta)
    return {
        "dataset_id": entry.get("id"),
        "dataset_label": entry.get("label") or entry.get("id"),
        "dataset_root": entry.get("dataset_root"),
        "storage_mode": entry.get("storage_mode") or "managed",
        "linked_root": entry.get("linked_root"),
        "labelmap": list(entry.get("classes") or []),
        "yolo_layout": entry.get("yolo_layout") or "flat",
        "status": meta.get("annotation_status") or "new",
        "notes": str(meta.get("annotation_notes") or ""),
        "cursor": meta.get("annotation_cursor"),
        "lock": meta.get("annotation_lock") or {},
        "progress": progress,
        "images": manifest_rows,
    }


def _annotation_update_lock(
    meta: Dict[str, Any], payload: Dict[str, Any], *, force: bool = False
) -> Dict[str, Any]:
    editor_name = (
        str(payload.get("editor_name") or payload.get("holder") or "unknown").strip() or "unknown"
    )
    requested_session = str(payload.get("session_id") or "").strip()
    now = time.time()
    existing = meta.get("annotation_lock")
    existing_lock = existing if isinstance(existing, dict) else {}
    existing_active = _annotation_lock_is_active(existing_lock)
    existing_session = str(existing_lock.get("session_id") or "").strip()
    warning = None
    if existing_active:
        same_session = bool(requested_session and requested_session == existing_session)
        if not same_session and existing_session and not force:
            warning = "annotation_lock_active"
    if warning and not force:
        return {
            "ok": False,
            "warning": warning,
            "lock": existing_lock,
        }
    session_id = requested_session or existing_session or uuid.uuid4().hex
    lock = {
        "holder": editor_name,
        "session_id": session_id,
        "heartbeat_at": now,
        "expires_at": now + float(DATASET_ANNOTATION_SESSION_TTL_SECONDS),
    }
    meta["annotation_lock"] = lock
    return {
        "ok": True,
        "warning": warning,
        "lock": lock,
    }


def _annotation_release_lock(meta: Dict[str, Any], payload: Dict[str, Any]) -> Dict[str, Any]:
    existing = meta.get("annotation_lock")
    existing_lock = existing if isinstance(existing, dict) else {}
    requested_session = str(payload.get("session_id") or "").strip()
    force = bool(payload.get("force"))
    existing_active = _annotation_lock_is_active(existing_lock)
    if existing_active and not force:
        existing_session = str(existing_lock.get("session_id") or "").strip()
        if not requested_session or requested_session != existing_session:
            return {
                "ok": False,
                "warning": "annotation_lock_session_mismatch",
                "lock": existing_lock,
            }
    meta["annotation_lock"] = {}
    return {
        "ok": True,
        "lock": {},
    }


def _require_annotation_lock_owner(
    meta: Dict[str, Any],
    payload: Dict[str, Any],
    *,
    allow_force: bool = False,
) -> Dict[str, Any]:
    force = bool(payload.get("force"))
    existing = meta.get("annotation_lock")
    existing_lock = existing if isinstance(existing, dict) else {}
    existing_active = _annotation_lock_is_active(existing_lock)
    if not existing_active:
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="annotation_lock_required")
    if allow_force and force:
        return existing_lock
    requested_session = str(payload.get("session_id") or "").strip()
    if not requested_session:
        raise HTTPException(
            status_code=HTTP_409_CONFLICT, detail="annotation_lock_session_required"
        )
    existing_session = str(existing_lock.get("session_id") or "").strip()
    if requested_session != existing_session:
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="annotation_lock_active")
    return existing_lock


def _dataset_entry_has_active_annotation_lock(entry: Dict[str, Any]) -> bool:
    try:
        meta_path = _dataset_meta_path_for_entry(entry)
    except Exception:
        return False
    meta = _load_json_metadata(meta_path) or {}
    lock = meta.get("annotation_lock") if isinstance(meta, dict) else {}
    return _annotation_lock_is_active(lock if isinstance(lock, dict) else {})


def _dataset_delete_raw_path_contained(path: Path, allowed_roots: Sequence[Path]) -> bool:
    try:
        if _storage_path_has_symlink_component(path.parent):
            return False
        parent = path.parent.resolve(strict=False)
    except Exception:
        return False
    return any(_path_is_within_root_impl(parent, root.resolve()) for root in allowed_roots)


def _delete_dataset_tree_or_link(path: Path, allowed_roots: Sequence[Path]) -> None:
    if not _dataset_delete_raw_path_contained(path, allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")
    if path.is_symlink():
        path.unlink(missing_ok=True)
        return
    try:
        resolved = path.resolve(strict=True)
    except Exception:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing") from None
    if not resolved.exists() or not resolved.is_dir():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing")
    if not any(_path_is_within_root_impl(resolved, root.resolve()) for root in allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")
    shutil.rmtree(resolved, ignore_errors=True)


def _managed_dataset_roots() -> List[Path]:
    return [DATASET_REGISTRY_ROOT, SAM3_DATASET_ROOT, QWEN_DATASET_ROOT]


def _dataset_trash_root_for_source_root(
    source_root: Path,
    *,
    create: bool = False,
    detail: str = "dataset_trash_path_forbidden",
) -> Path:
    try:
        raw_root = Path(source_root)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("dataset source root has a symlink component")
        if not raw_root.exists() or not raw_root.is_dir():
            raise ValueError("dataset source root missing")
        trash_root = raw_root / DATASET_TRASH_DIRNAME
        if _storage_path_has_symlink_component(trash_root):
            raise ValueError("dataset trash root has a symlink component")
        if create:
            trash_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(trash_root):
            raise ValueError("dataset trash root has a symlink component")
        if trash_root.exists() and not trash_root.is_dir():
            raise ValueError("dataset trash root is not a directory")
        return trash_root.resolve(strict=False)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _dataset_trash_child_dir(
    trash_root: Path,
    trash_id: str,
    *,
    detail: str = "dataset_trash_path_forbidden",
) -> Path:
    raw_id = str(trash_id or "").strip()
    if (
        not raw_id
        or raw_id in {".", ".."}
        or "/" in raw_id
        or "\\" in raw_id
        or Path(raw_id).is_absolute()
    ):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    try:
        root = trash_root.resolve(strict=False)
        candidate = trash_root / raw_id
        if _storage_path_has_symlink_component(candidate):
            raise ValueError("dataset trash child has a symlink component")
        resolved = candidate.resolve(strict=False)
        if not _path_is_within_root_impl(resolved, root) or resolved.parent != root:
            raise ValueError("dataset trash child escapes root")
        return resolved
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _dataset_source_root_for_managed_path(
    path: Path,
    allowed_roots: Sequence[Path],
) -> Tuple[Path, Path]:
    try:
        if path.is_symlink():
            raise ValueError("managed dataset path is a symlink")
        resolved = path.resolve(strict=True)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing") from exc
    if not resolved.exists() or not resolved.is_dir():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing")
    for root in allowed_roots:
        try:
            root_resolved = root.resolve(strict=False)
        except Exception:
            continue
        if resolved.parent == root_resolved and resolved != root_resolved:
            return resolved, root_resolved
    raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")


def _dataset_unique_trash_id(dataset_name: str, trash_root: Path) -> str:
    base = _sanitize_yolo_run_id_impl(
        f"{dataset_name}-{time.strftime('%Y%m%d-%H%M%S')}-{uuid.uuid4().hex[:8]}"
    )
    return _unique_dataset_name(base or f"dataset-{uuid.uuid4().hex[:8]}", root=trash_root)


def _dataset_primary_meta_name_for_source_root(source_root: Path) -> str:
    try:
        root = source_root.resolve(strict=False)
        if root == QWEN_DATASET_ROOT.resolve(strict=False):
            return QWEN_METADATA_FILENAME
        if root == SAM3_DATASET_ROOT.resolve(strict=False):
            return SAM3_DATASET_META_NAME
    except Exception:
        pass
    return DATASET_META_NAME


def _soft_delete_managed_dataset_tree(
    path: Path,
    allowed_roots: Sequence[Path],
    *,
    dataset_id: str,
    entry: Dict[str, Any],
) -> Dict[str, Any]:
    if not _dataset_delete_raw_path_contained(path, allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")
    resolved, source_root = _dataset_source_root_for_managed_path(path, allowed_roots)
    trash_root = _dataset_trash_root_for_source_root(source_root, create=True)
    trash_id = _dataset_unique_trash_id(resolved.name, trash_root)
    trash_entry_dir = _dataset_trash_child_dir(trash_root, trash_id)
    if trash_entry_dir.exists() or trash_entry_dir.is_symlink():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="dataset_trash_target_exists")
    trash_entry_dir.mkdir(parents=True, exist_ok=False)
    dataset_trash_path = trash_entry_dir / resolved.name
    try:
        resolved.rename(dataset_trash_path)
        deleted_at = time.time()
        trash_meta = {
            "trash_id": trash_id,
            "deleted_at": deleted_at,
            "original_id": dataset_id,
            "original_name": resolved.name,
            "original_path": str(resolved),
            "source_root": str(source_root),
            "source": entry.get("source") or "registry",
            "storage_mode": "managed",
            "label": entry.get("label") or dataset_id,
            "dataset_dir_name": dataset_trash_path.name,
            "dataset_path": str(dataset_trash_path),
        }
        _write_dataset_metadata_json(
            trash_entry_dir / DATASET_TRASH_META_NAME,
            trash_entry_dir,
            trash_meta,
        )
    except Exception:
        if dataset_trash_path.exists() and not resolved.exists():
            try:
                dataset_trash_path.rename(resolved)
            except Exception:
                pass
        try:
            trash_entry_dir.rmdir()
        except Exception:
            pass
        raise
    return {
        "status": "trashed",
        "id": dataset_id,
        "storage_mode": "managed",
        "trash_id": trash_id,
        "trash_path": str(trash_entry_dir),
        "restore_available": True,
    }


def _dataset_trash_dataset_dir(entry_dir: Path, meta: Dict[str, Any]) -> Optional[Path]:
    raw_name = str(meta.get("dataset_dir_name") or "").strip()
    candidates: List[Path] = []
    if raw_name:
        candidates.append(entry_dir / raw_name)
    try:
        candidates.extend(
            child
            for child in entry_dir.iterdir()
            if child.name != DATASET_TRASH_META_NAME
        )
    except Exception:
        pass
    for candidate in candidates:
        try:
            if candidate.is_symlink() or _storage_path_has_symlink_component(candidate):
                continue
            resolved = candidate.resolve(strict=True)
            if (
                resolved.parent == entry_dir.resolve(strict=True)
                and resolved.exists()
                and resolved.is_dir()
            ):
                return resolved
        except Exception:
            continue
    return None


def _dataset_trash_entry_payload(
    entry_dir: Path,
    *,
    source_root: Path,
    source: str,
) -> Optional[Dict[str, Any]]:
    try:
        if entry_dir.is_symlink() or _storage_path_has_symlink_component(entry_dir):
            return None
        entry_resolved = entry_dir.resolve(strict=True)
        trash_root = _dataset_trash_root_for_source_root(source_root, create=False)
        if entry_resolved.parent != trash_root.resolve(strict=False):
            return None
    except Exception:
        return None
    meta = _load_json_metadata(entry_resolved / DATASET_TRASH_META_NAME) or {}
    dataset_dir = _dataset_trash_dataset_dir(entry_resolved, meta)
    if dataset_dir is None:
        return None
    original_id = str(meta.get("original_id") or dataset_dir.name).strip() or dataset_dir.name
    return {
        "trash_id": entry_resolved.name,
        "original_id": original_id,
        "label": meta.get("label") or original_id,
        "deleted_at": meta.get("deleted_at"),
        "storage_mode": "managed",
        "source": meta.get("source") or source,
        "source_root": str(source_root),
        "dataset_path": str(dataset_dir),
        "restore_id": _sanitize_yolo_run_id_impl(original_id) or dataset_dir.name,
    }


def list_dataset_trash_entries() -> List[Dict[str, Any]]:
    entries: List[Dict[str, Any]] = []
    roots = [
        ("registry", DATASET_REGISTRY_ROOT),
        ("sam3", SAM3_DATASET_ROOT),
        ("qwen", QWEN_DATASET_ROOT),
    ]
    for source, source_root in roots:
        try:
            trash_root = _dataset_trash_root_for_source_root(source_root, create=False)
        except HTTPException:
            continue
        if not trash_root.exists():
            continue
        try:
            children = sorted(trash_root.iterdir(), key=lambda p: p.stat().st_mtime, reverse=True)
        except Exception:
            continue
        for child in children:
            payload = _dataset_trash_entry_payload(child, source_root=source_root.resolve(strict=False), source=source)
            if payload is not None:
                entries.append(payload)
    entries.sort(key=lambda item: item.get("deleted_at") or 0, reverse=True)
    return entries


def _resolve_dataset_trash_entry(trash_id: str) -> Tuple[Path, Path, Path, Dict[str, Any]]:
    for source_root in _managed_dataset_roots():
        try:
            trash_root = _dataset_trash_root_for_source_root(source_root, create=False)
            entry_dir = _dataset_trash_child_dir(trash_root, trash_id)
        except HTTPException:
            continue
        if not entry_dir.exists():
            continue
        meta = _load_json_metadata(entry_dir / DATASET_TRASH_META_NAME) or {}
        dataset_dir = _dataset_trash_dataset_dir(entry_dir, meta)
        if dataset_dir is None:
            continue
        return source_root.resolve(strict=False), entry_dir, dataset_dir, meta
    raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_trash_entry_not_found")


def restore_dataset_trash_entry(
    trash_id: str,
    dataset_id: Optional[str] = None,
) -> Dict[str, Any]:
    source_root, entry_dir, dataset_dir, meta = _resolve_dataset_trash_entry(trash_id)
    requested = str(dataset_id or meta.get("original_id") or dataset_dir.name).strip()
    base_id = _sanitize_yolo_run_id_impl(requested) or "restored_dataset"
    restored_id = _unique_dataset_name(base_id, root=source_root)
    target_path = source_root / restored_id
    target_resolved: Optional[Path] = None
    def _rollback_restore_move() -> None:
        if target_resolved is not None and target_resolved.exists() and not dataset_dir.exists():
            try:
                target_resolved.rename(dataset_dir)
            except Exception:
                pass

    try:
        if _storage_path_has_symlink_component(target_path) or target_path.exists() or target_path.is_symlink():
            raise ValueError("dataset restore target invalid")
        target_resolved = target_path.resolve(strict=False)
        if target_resolved.parent != source_root.resolve(strict=False):
            raise ValueError("dataset restore target escapes root")
        dataset_dir.rename(target_resolved)
        meta_name = _dataset_primary_meta_name_for_source_root(source_root)
        restored_meta_path = target_resolved / meta_name
        restored_meta = _load_json_metadata(restored_meta_path) or {}
        restored_meta["id"] = restored_id
        restored_meta.setdefault("label", meta.get("label") or restored_id)
        restored_meta["restored_from_trash_id"] = trash_id
        restored_meta["restored_at"] = time.time()
        _write_dataset_metadata_json(restored_meta_path, target_resolved, restored_meta)
        trash_meta_path = entry_dir / DATASET_TRASH_META_NAME
        if trash_meta_path.exists() and not trash_meta_path.is_symlink():
            trash_meta_path.unlink(missing_ok=True)
        try:
            entry_dir.rmdir()
        except OSError:
            pass
    except HTTPException:
        _rollback_restore_move()
        raise
    except Exception as exc:
        _rollback_restore_move()
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_restore_forbidden") from exc
    return {
        "status": "restored",
        "id": restored_id,
        "dataset_root": str(target_path),
        "trash_id": trash_id,
    }


def _annotation_requested_status(payload: Dict[str, Any]) -> Optional[str]:
    if "status" not in payload:
        return None
    status_value = str(payload.get("status") or "").strip().lower()
    if status_value and status_value not in DATASET_ANNOTATION_STATUSES:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="invalid_annotation_status"
        )
    return status_value or None


def _normalise_annotation_snapshot_records(
    records: Any,
) -> List[Tuple[str, Path, bool, List[str], bool, str]]:
    if not isinstance(records, list):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="annotation_records_required")
    normalised: List[Tuple[str, Path, bool, List[str], bool, str]] = []
    for raw in records:
        if not isinstance(raw, dict):
            continue
        split = _annotation_normalise_split(raw.get("split"))
        rel = _annotation_normalise_image_relpath(raw.get("image_relpath") or raw.get("image_name"))
        label_lines_raw = raw.get("label_lines")
        has_label_lines = isinstance(label_lines_raw, list)
        label_lines: List[str] = []
        if has_label_lines:
            label_lines = [str(line).strip() for line in label_lines_raw if str(line).strip()]
        has_text_label = "text_label" in raw
        text_value = str(raw.get("text_label") or "").strip() if has_text_label else ""
        normalised.append((split, rel, has_label_lines, label_lines, has_text_label, text_value))
    return normalised


def _validate_annotation_snapshot_record_images(
    dataset_root: Path,
    yolo_layout: str,
    records: Sequence[Tuple[str, Path, bool, List[str], bool, str]],
) -> None:
    for split, rel, _has_label_lines, _label_lines, _has_text_label, _text_value in records:
        _resolve_annotation_image_path(dataset_root, yolo_layout, split, rel)


def _annotation_overlay_key_to_split_rel(key: str) -> Tuple[str, Path]:
    raw = str(key or "").strip()
    if ":" not in raw:
        raise ValueError("invalid_overlay_key")
    split_raw, rel_raw = raw.split(":", 1)
    split = _annotation_normalise_split(split_raw)
    rel = _annotation_normalise_image_relpath(rel_raw)
    return split, rel


def _annotation_overlay_archive_entries(entry: Dict[str, Any]) -> Dict[str, Path]:
    archive_entries: Dict[str, Path] = {}
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=False).resolve()
    if not overlay_root.exists():
        return archive_entries
    layout = str(entry.get("yolo_layout") or "flat")
    labels_root = overlay_root / "labels"
    for split in ("train", "val"):
        split_root = labels_root / split
        if not split_root.exists():
            continue
        split_root_resolved = split_root.resolve()
        if not _path_is_within_root_impl(split_root_resolved, overlay_root):
            continue
        for path in split_root.rglob("*.txt"):
            resolved = _annotation_safe_text_path(path, split_root_resolved)
            if resolved is None:
                continue
            rel = path.relative_to(split_root)
            target_rel = (
                (Path(split) / "labels" / rel) if layout == "split" else (Path("labels") / rel)
            )
            archive_entries[target_rel.as_posix()] = resolved
    text_root = overlay_root / "text_labels"
    if text_root.exists():
        text_root_resolved = text_root.resolve()
        if not _path_is_within_root_impl(text_root_resolved, overlay_root):
            return archive_entries
        for path in text_root.rglob("*.txt"):
            resolved = _annotation_safe_text_path(path, text_root_resolved)
            if resolved is None:
                continue
            rel = path.relative_to(text_root)
            if layout == "split" and len(rel.parts) > 1 and rel.parts[0] in {"train", "val"}:
                target_rel = Path(rel.parts[0]) / "text_labels" / Path(*rel.parts[1:])
            else:
                target_rel = Path("text_labels") / rel
            archive_entries[target_rel.as_posix()] = resolved
    return archive_entries


def _dataset_labelmap_archive_entries(entry: Dict[str, Any], dataset_root: Path) -> Dict[str, Path]:
    storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
    if storage_mode != "linked" or not entry.get("registry_root"):
        return {}
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=False,
        detail="labelmap_path_forbidden",
    ).resolve()
    labelmap_path = _annotation_labelmap_read_path(entry, dataset_root, storage_root)
    if not labelmap_path.exists():
        return {}
    try:
        resolved = labelmap_path.resolve(strict=True)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_path_forbidden") from exc
    if not resolved.is_file() or not _path_is_within_root_impl(resolved, storage_root):
        return {}
    return {"labelmap.txt": resolved}


def _persist_transient_overlays_to_entry(entry: Dict[str, Any], session: Dict[str, Any]) -> None:
    overlay_labels = (
        session.get("overlay_labels") if isinstance(session.get("overlay_labels"), dict) else {}
    )
    overlay_text = (
        session.get("overlay_text") if isinstance(session.get("overlay_text"), dict) else {}
    )
    if not overlay_labels and not overlay_text:
        return

    for key, label_lines_raw in overlay_labels.items():
        try:
            split, rel = _annotation_overlay_key_to_split_rel(str(key))
        except Exception:
            continue
        lines: List[str] = []
        if isinstance(label_lines_raw, list):
            lines = [str(line).strip() for line in label_lines_raw if str(line).strip()]
        label_path = _annotation_overlay_label_path(entry, split, rel)
        overlay_root = _dataset_overlay_root_from_entry(entry, ensure=True)
        _annotation_write_text_within_root(
            label_path,
            overlay_root,
            "\n".join(lines) + ("\n" if lines else ""),
        )

    for key, text_raw in overlay_text.items():
        try:
            split, rel = _annotation_overlay_key_to_split_rel(str(key))
        except Exception:
            continue
        text_path = _annotation_overlay_text_path(entry, rel, split=split)
        overlay_root = _dataset_overlay_root_from_entry(entry, ensure=True)
        _annotation_write_text_within_root(text_path, overlay_root, str(text_raw or "").strip())


def _extract_zip_safely_impl(
    zf: zipfile.ZipFile,
    extract_root: Path,
    *,
    max_entry_bytes: Optional[int],
    max_total_uncompressed_bytes: Optional[int],
    traversal_detail: str,
    symlink_detail: str,
    entry_too_large_detail: str,
    total_too_large_detail: str,
) -> None:
    root = extract_root.resolve()
    total_uncompressed = 0
    for info in zf.infolist():
        member_name = info.filename or ""
        member_win = PureWindowsPath(member_name)
        resolved_member = (extract_root / member_name).resolve()
        if (
            member_name.startswith("/")
            or member_name.startswith("\\")
            or member_win.is_absolute()
            or bool(member_win.drive)
            or (resolved_member != root and root not in resolved_member.parents)
        ):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=traversal_detail)
        mode = (info.external_attr >> 16) & 0xFFFF
        if stat.S_ISLNK(mode):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=symlink_detail)
        file_size = max(int(info.file_size or 0), 0)
        if max_entry_bytes and file_size > max_entry_bytes:
            raise HTTPException(
                status_code=HTTP_413_CONTENT_TOO_LARGE,
                detail=entry_too_large_detail,
            )
        total_uncompressed += file_size
        if max_total_uncompressed_bytes and total_uncompressed > max_total_uncompressed_bytes:
            raise HTTPException(
                status_code=HTTP_413_CONTENT_TOO_LARGE,
                detail=total_too_large_detail,
            )
    zf.extractall(extract_root)


def list_datasets():
    return _list_all_datasets()


def _persist_dataset_meta(dataset_root: Path, meta: Dict[str, Any]) -> Dict[str, Any]:
    _write_dataset_metadata_json(dataset_root / DATASET_META_NAME, dataset_root, meta)
    return meta


def upload_dataset_zip(
    file: UploadFile,
    dataset_id: Optional[str],
    dataset_type: Optional[str],
    context: Optional[str],
):
    temp_dir = Path(tempfile.mkdtemp(prefix="dataset_upload_"))
    target_root: Optional[Path] = None
    registry_root: Optional[Path] = None
    try:
        zip_path = temp_dir / "upload.zip"
        written = 0
        with zip_path.open("wb") as handle:
            while True:
                chunk = file.file.read(1024 * 1024)
                if not chunk:
                    break
                written += len(chunk)
                if DATASET_ZIP_MAX_BYTES and written > DATASET_ZIP_MAX_BYTES:
                    raise HTTPException(
                        status_code=HTTP_413_CONTENT_TOO_LARGE,
                        detail="dataset_zip_too_large",
                    )
                handle.write(chunk)
        extract_root = temp_dir / "extract"
        extract_root.mkdir(parents=True, exist_ok=True)
        try:
            with zipfile.ZipFile(zip_path, "r") as zf:
                _extract_zip_safely_impl(
                    zf,
                    extract_root,
                    max_entry_bytes=DATASET_ZIP_ENTRY_MAX_BYTES,
                    max_total_uncompressed_bytes=DATASET_ZIP_MAX_BYTES,
                    traversal_detail="dataset_zip_path_traversal",
                    symlink_detail="dataset_zip_symlink_unsupported",
                    entry_too_large_detail="dataset_zip_entry_too_large",
                    total_too_large_detail="dataset_zip_uncompressed_too_large",
                )
        except zipfile.BadZipFile as exc:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_zip_invalid") from exc
        source_root = _unwrap_single_root_dir(extract_root)
        base_id = dataset_id or Path(file.filename or "dataset").stem
        base_id = _sanitize_yolo_run_id_impl(base_id) or "dataset"
        registry_root = _dataset_registry_storage_root(
            create=True, detail="dataset_upload_target_invalid"
        )
        dataset_id_final = _unique_dataset_name(base_id, root=registry_root)
        target_root = _dataset_registry_child_dir(
            dataset_id_final, detail="dataset_upload_target_invalid"
        )
        if target_root.exists() or target_root.is_symlink():
            raise HTTPException(status_code=HTTP_409_CONFLICT, detail="dataset_upload_target_exists")
        shutil.copytree(source_root, target_root)

        meta_path = target_root / DATASET_META_NAME
        meta = _load_json_metadata(meta_path) or {}
        meta["id"] = dataset_id_final
        meta["label"] = meta.get("label") or dataset_id_final
        if dataset_type:
            meta["type"] = dataset_type
        else:
            meta.setdefault("type", "bbox")
        if context is not None:
            meta["context"] = context
        meta.setdefault("created_at", time.time())
        meta.setdefault("source", "registry")
        labelmap_path = target_root / "labelmap.txt"
        if labelmap_path.exists():
            try:
                labelmap = _load_labelmap_file(labelmap_path)
            except Exception:
                labelmap = []
            if labelmap and not meta.get("classes"):
                meta["classes"] = list(labelmap)
        train_images = target_root / "train" / "images"
        val_images = target_root / "val" / "images"
        train_count = len(_iter_yolo_images(train_images)) if train_images.exists() else 0
        val_count = len(_iter_yolo_images(val_images)) if val_images.exists() else 0
        if train_count or val_count:
            meta["train_count"] = train_count
            meta["val_count"] = val_count
            meta["image_count"] = train_count + val_count
        else:
            meta["image_count"] = _count_dataset_images_impl(
                target_root, iter_images_fn=_iter_yolo_images
            )
        meta["signature"] = _compute_dir_signature_impl(target_root)
        _persist_dataset_meta(target_root, meta)
        return meta
    except Exception:
        if target_root is not None and registry_root is not None:
            try:
                _delete_dataset_tree_or_link(target_root, [registry_root])
            except Exception:
                pass
        raise
    finally:
        try:
            file.file.close()
        except Exception:
            pass
        shutil.rmtree(temp_dir, ignore_errors=True)


def _resolve_dataset_entry(dataset_id: str) -> Dict[str, Any]:
    entry = _resolve_dataset_entry_impl(dataset_id, list_all_datasets_fn=_list_all_datasets)
    if not entry:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_not_found")
    return entry


def delete_dataset_entry(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
    registry_root_raw = entry.get("registry_root")
    registry_path = Path(str(registry_root_raw)) if registry_root_raw else None
    if _dataset_entry_has_active_annotation_lock(entry):
        raise HTTPException(
            status_code=HTTP_409_CONFLICT, detail="dataset_delete_blocked_annotation_lock"
        )
    blocking_registry_by_id = _active_job_registry_referencing_dataset_id(dataset_id)
    if blocking_registry_by_id:
        raise HTTPException(
            status_code=HTTP_409_CONFLICT,
            detail=f"dataset_delete_blocked_active_jobs:{blocking_registry_by_id}",
        )

    # Linked entries should remove only the registry record + overlay metadata, never the source dataset itself.
    if storage_mode == "linked":
        if registry_path is None:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")
        if registry_path.exists() or registry_path.is_symlink():
            _delete_dataset_tree_or_link(registry_path, [DATASET_REGISTRY_ROOT])
        return {"status": "deleted", "id": dataset_id, "storage_mode": "linked"}

    target_path = registry_path if registry_path is not None else Path(entry.get("dataset_root") or "")
    allowed_roots = [
        DATASET_REGISTRY_ROOT,
        SAM3_DATASET_ROOT,
        QWEN_DATASET_ROOT,
    ]
    if not target_path.exists() and not target_path.is_symlink():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="dataset_root_missing")
    if not _dataset_delete_raw_path_contained(target_path, allowed_roots):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_delete_forbidden")
    target_root = target_path.resolve(strict=False)
    blocking_registry = _active_job_registry_referencing_path_root(target_root)
    if blocking_registry:
        raise HTTPException(
            status_code=HTTP_409_CONFLICT,
            detail=f"dataset_delete_blocked_active_jobs:{blocking_registry}",
        )
    return _soft_delete_managed_dataset_tree(
        target_path,
        allowed_roots,
        dataset_id=dataset_id,
        entry=entry,
    )


def download_dataset_entry(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    dataset_root = _dataset_effective_root_from_entry(entry)
    override_entries = _annotation_overlay_archive_entries(entry)
    override_entries.update(_dataset_labelmap_archive_entries(entry, dataset_root))
    tmp_dir = Path(tempfile.mkdtemp(prefix="dataset_export_"))
    try:
        zip_path = tmp_dir / f"{dataset_id}.zip"
        with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as zf:
            override_relpaths = set(override_entries.keys())
            for path in dataset_root.rglob("*"):
                if not path.is_file():
                    continue
                if not _path_is_within_root_impl(path.resolve(), dataset_root):
                    continue
                rel = path.relative_to(dataset_root)
                if rel.parts and rel.parts[0] == DATASET_ANNOTATION_OVERLAY_DIRNAME:
                    continue
                if rel.as_posix() in override_relpaths:
                    continue
                zf.write(path, arcname=str(Path(dataset_root.name) / rel))
            for rel_posix, override_path in sorted(override_entries.items()):
                if not override_path.exists() or not override_path.is_file():
                    continue
                zf.write(override_path, arcname=str(Path(dataset_root.name) / Path(rel_posix)))
        return FileResponse(
            path=str(zip_path),
            media_type="application/zip",
            filename=f"{dataset_id}.zip",
            # Dataset export archives are transient and should not accumulate on disk.
            background=BackgroundTask(shutil.rmtree, tmp_dir, ignore_errors=True),
        )
    except Exception as exc:  # noqa: BLE001
        shutil.rmtree(tmp_dir, ignore_errors=True)
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"dataset_export_failed:{exc}"
        ) from exc


def _build_qwen_context(labelmap: Sequence[str], context: str) -> str:
    items = ", ".join(labelmap)
    ctx = (context or "").strip()
    if ctx:
        return f"{ctx}\nObjects of interest: {items}."
    return f"Objects of interest: {items}."


def _yolo_label_to_bbox(
    line: str, *, img_w: int, img_h: int
) -> Optional[Tuple[int, int, int, int]]:
    parts = line.strip().split()
    if len(parts) < 5:
        return None
    try:
        x = float(parts[1])
        y = float(parts[2])
        w = float(parts[3])
        h = float(parts[4])
    except Exception:
        return None
    x1 = int(round((x - w / 2) * img_w))
    y1 = int(round((y - h / 2) * img_h))
    x2 = int(round((x + w / 2) * img_w))
    y2 = int(round((y + h / 2) * img_h))
    x1 = max(0, min(img_w - 1, x1))
    y1 = max(0, min(img_h - 1, y1))
    x2 = max(0, min(img_w - 1, x2))
    y2 = max(0, min(img_h - 1, y2))
    if x2 <= x1 or y2 <= y1:
        return None
    return x1, y1, x2, y2


def build_qwen_dataset_from_yolo(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    if not entry.get("yolo_ready"):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_not_yolo_ready")
    dataset_root = _dataset_effective_root_from_entry(entry)
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=False,
        detail="dataset_metadata_path_forbidden",
    )
    labelmap_path = _annotation_labelmap_read_path(entry, dataset_root, storage_root)
    labelmap = [str(item).strip() for item in (entry.get("classes") or []) if str(item).strip()]
    if labelmap_path.exists():
        labelmap = [
            line.strip()
            for line in labelmap_path.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    if not labelmap:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="labelmap_missing")
    context = entry.get("context") or ""
    glossary = _load_dataset_glossary(
        storage_root,
        load_sam3_meta=lambda dataset_dir: _load_sam3_dataset_metadata_impl(
            dataset_dir,
            meta_name=SAM3_DATASET_META_NAME,
            load_json_metadata_fn=_load_json_metadata,
            persist_metadata_fn=lambda dataset_dir_inner, metadata: _persist_sam3_dataset_metadata_impl(
                dataset_dir_inner,
                metadata,
                meta_name=SAM3_DATASET_META_NAME,
                logger=logger,
                suppress_errors=True,
            ),
        ),
        load_qwen_meta=lambda dataset_dir: _load_qwen_dataset_metadata_impl(
            dataset_dir, meta_name=QWEN_METADATA_FILENAME, load_json_metadata_fn=_load_json_metadata
        ),
    )
    if not glossary and storage_root != dataset_root:
        glossary = _load_dataset_glossary(
            dataset_root,
            load_sam3_meta=lambda dataset_dir: _load_sam3_dataset_metadata_impl(
                dataset_dir,
                meta_name=SAM3_DATASET_META_NAME,
                load_json_metadata_fn=_load_json_metadata,
                persist_metadata_fn=lambda dataset_dir_inner, metadata: _persist_sam3_dataset_metadata_impl(
                    dataset_dir_inner,
                    metadata,
                    meta_name=SAM3_DATASET_META_NAME,
                    logger=logger,
                    suppress_errors=True,
                ),
            ),
            load_qwen_meta=lambda dataset_dir: _load_qwen_dataset_metadata_impl(
                dataset_dir, meta_name=QWEN_METADATA_FILENAME, load_json_metadata_fn=_load_json_metadata
            ),
        )
    if not glossary:
        seen_roots: Set[Path] = set()
        for root in (storage_root, dataset_root):
            if root in seen_roots:
                continue
            seen_roots.add(root)
            for _path, meta in _load_dataset_meta_candidates(root):
                raw = meta.get("labelmap_glossary")
                if raw:
                    glossary = _normalize_labelmap_glossary(raw)
                    break
            if glossary:
                break
    qwen_root = _qwen_dataset_storage_root(
        create=True, detail="qwen_dataset_target_invalid"
    )
    qwen_id = _unique_dataset_name(
        _sanitize_yolo_run_id_impl(str(dataset_id or "")) or "qwen_dataset",
        root=qwen_root,
    )
    target_root = _qwen_dataset_child_dir(
        qwen_id, create=True, detail="qwen_dataset_target_invalid"
    )
    (target_root / "train").mkdir(parents=True, exist_ok=True)
    (target_root / "val").mkdir(parents=True, exist_ok=True)

    context_line = _build_qwen_context(labelmap, context)
    counts = {"train": 0, "val": 0}
    annotation_lines: Dict[str, List[str]] = {"train": [], "val": []}

    def _process_image(split: str, image_relpath: Path, image_path: Path):
        try:
            image_resolved = image_path.resolve()
        except Exception:
            return
        if not _path_is_within_root_impl(image_resolved, dataset_root.resolve()):
            return
        try:
            img = Image.open(image_resolved)
            img_w, img_h = img.size
            img.close()
        except Exception:
            return
        detections = []
        lines = _annotation_effective_label_lines(entry, split, image_relpath)
        for line in lines:
            parts = line.strip().split()
            if len(parts) < 5:
                continue
            try:
                cls_idx = int(float(parts[0]))
            except Exception:
                continue
            if cls_idx < 0 or cls_idx >= len(labelmap):
                continue
            bbox = _yolo_label_to_bbox(line, img_w=img_w, img_h=img_h)
            if not bbox:
                continue
            x1, y1, x2, y2 = bbox
            detections.append(
                {
                    "label": labelmap[cls_idx],
                    "bbox": [x1, y1, x2, y2],
                    "point": [int(round((x1 + x2) / 2)), int(round((y1 + y2) / 2))],
                }
            )
        if not detections:
            return
        rel_name = image_relpath.as_posix()
        target_image = (target_root / split / image_relpath).resolve()
        if not _path_is_within_root_impl(target_image, (target_root / split).resolve()):
            return
        if not target_image.exists():
            _copy2_if_different(image_resolved, target_image)
        payload = {
            "image": rel_name,
            "context": context_line,
            "detections": detections,
        }
        annotation_lines[split].append(json.dumps(payload) + "\n")
        counts[split] += 1

    for row in _annotation_collect_images(entry):
        try:
            split = _annotation_normalise_split(row.get("split"))
            image_relpath = _annotation_normalise_image_relpath(row.get("image_relpath"))
        except HTTPException:
            continue
        image_path_raw = row.get("image_path")
        if image_path_raw is None:
            continue
        _process_image(split, image_relpath, Path(str(image_path_raw)))

    for split in ("train", "val"):
        _qwen_dataset_write_text_within_root(
            target_root / split / "annotations.jsonl",
            target_root,
            "".join(annotation_lines[split]),
        )
    _qwen_dataset_write_text_within_root(
        target_root / "labelmap.txt",
        target_root,
        "\n".join(labelmap) + "\n",
    )
    metadata = {
        "id": qwen_id,
        "label": qwen_id,
        "classes": labelmap,
        "context": context,
        "created_at": time.time(),
        "train_count": counts["train"],
        "val_count": counts["val"],
        "image_count": counts["train"] + counts["val"],
        "type": entry.get("type") or "bbox",
        "signature": _compute_dir_signature_impl(target_root),
    }
    if glossary:
        metadata["labelmap_glossary"] = glossary
    _qwen_dataset_write_text_within_root(
        target_root / "metadata.json",
        target_root,
        json.dumps(metadata, ensure_ascii=False, indent=2),
    )
    dataset_meta = {"context": context, "classes": labelmap, "created_at": int(time.time() * 1000)}
    _qwen_dataset_write_text_within_root(
        target_root / "dataset_meta.json",
        target_root,
        json.dumps(dataset_meta, ensure_ascii=False, indent=2),
    )
    return metadata


def check_dataset(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    _dataset_effective_root_from_entry(entry)
    if entry.get("yolo_ready") and entry.get("yolo_images_dir") and entry.get("yolo_labels_dir"):
        inputs = {
            "images_dir": entry.get("yolo_images_dir"),
            "labels_dir": entry.get("yolo_labels_dir"),
            "labelmap_path": entry.get("yolo_labelmap_path"),
        }
        data = _validate_clip_dataset_impl(
            inputs, http_exception_cls=HTTPException, load_labelmap_simple_fn=_load_labelmap_simple
        )
        return {"ok": True, "format": "yolo", "detail": data}
    if entry.get("qwen_ready"):
        return {
            "ok": True,
            "format": "qwen",
            "detail": {"train": entry.get("train_count"), "val": entry.get("val_count")},
        }
    return {
        "ok": False,
        "format": entry.get("format") or "unknown",
        "detail": "dataset_format_unrecognized",
    }


def _load_dataset_meta_candidates(dataset_root: Path) -> List[Tuple[Path, Dict[str, Any]]]:
    metas: List[Tuple[Path, Dict[str, Any]]] = []
    for name in (DATASET_META_NAME, QWEN_METADATA_FILENAME, SAM3_DATASET_META_NAME):
        path = dataset_root / name
        if not path.exists():
            continue
        meta = _load_json_metadata(path)
        if meta is not None:
            metas.append((path, meta))
    return metas


def _write_dataset_metadata_json(path: Path, root: Path, meta: Dict[str, Any]) -> None:
    try:
        if _storage_path_has_symlink_component(root):
            raise ValueError("dataset metadata root has a symlink component")
        if _storage_path_has_symlink_component(path.parent):
            raise ValueError("dataset metadata parent has a symlink component")
        if path.is_symlink():
            raise ValueError("dataset metadata path is a symlink")
        root_resolved = root.resolve(strict=False)
        target_resolved = path.resolve(strict=False)
        if not _path_is_within_root_impl(target_resolved, root_resolved):
            raise ValueError("dataset metadata path escapes root")
        _write_dataset_json_file(path, meta)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="dataset_metadata_path_forbidden",
        ) from exc


def get_dataset_glossary(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    dataset_root = _dataset_effective_root_from_entry(entry)
    storage_root = _dataset_meta_storage_root_from_entry(entry)
    labelmap = [str(x).strip() for x in (entry.get("classes") or []) if str(x).strip()]
    if not labelmap:
        labelmap = _dataset_labelmap_from_root(dataset_root)
    glossary = _load_dataset_glossary(
        dataset_root,
        load_sam3_meta=lambda dataset_dir: _load_sam3_dataset_metadata_impl(
            dataset_dir,
            meta_name=SAM3_DATASET_META_NAME,
            load_json_metadata_fn=_load_json_metadata,
            persist_metadata_fn=lambda dataset_dir_inner, metadata: _persist_sam3_dataset_metadata_impl(
                dataset_dir_inner,
                metadata,
                meta_name=SAM3_DATASET_META_NAME,
                logger=logger,
                suppress_errors=True,
            ),
        ),
        load_qwen_meta=lambda dataset_dir: _load_qwen_dataset_metadata_impl(
            dataset_dir, meta_name=QWEN_METADATA_FILENAME, load_json_metadata_fn=_load_json_metadata
        ),
    )
    if not glossary:
        roots = [storage_root]
        if storage_root != dataset_root:
            roots.append(dataset_root)
        for root in roots:
            for _path, meta in _load_dataset_meta_candidates(root):
                raw = meta.get("labelmap_glossary")
                if raw:
                    glossary = _normalize_labelmap_glossary(raw)
                    break
            if glossary:
                break
    default_glossary = _default_agent_glossary_for_labelmap(labelmap)
    return {
        "dataset_id": dataset_id,
        "glossary": glossary or "",
        "default_glossary": default_glossary,
        "classes": labelmap,
    }


def set_dataset_glossary(dataset_id: str, glossary: str):
    entry = _resolve_dataset_entry(dataset_id)
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=True,
        detail="dataset_metadata_path_forbidden",
    )
    normalized = _normalize_labelmap_glossary(glossary or "")
    updated = False
    for path, meta in _load_dataset_meta_candidates(storage_root):
        meta["labelmap_glossary"] = normalized
        _write_dataset_metadata_json(path, storage_root, meta)
        updated = True
    if not updated:
        meta = {"id": dataset_id, "labelmap_glossary": normalized}
        _write_dataset_metadata_json(storage_root / DATASET_META_NAME, storage_root, meta)
    return {"dataset_id": dataset_id, "glossary": normalized}


def get_text_label(dataset_id: str, image_name: str):
    entry = _resolve_dataset_entry(dataset_id)
    split, image_relpath = _annotation_text_split_rel_from_name(entry, image_name)
    caption = _annotation_effective_text_label(entry, image_relpath, split)
    if not caption:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="caption_not_found")
    return {"caption": caption}


def get_text_labels(dataset_id: str, image_names: Sequence[str]):
    entry = _resolve_dataset_entry(dataset_id)
    captions: Dict[str, str] = {}
    missing: List[str] = []
    for raw_name in image_names or []:
        image_name = str(raw_name or "").strip()
        if not image_name:
            continue
        try:
            split, image_relpath = _annotation_text_split_rel_from_name(entry, image_name)
        except HTTPException:
            missing.append(image_name)
            continue
        caption = _annotation_effective_text_label(entry, image_relpath, split)
        if caption:
            captions[image_name] = caption
        else:
            missing.append(image_name)
    return {"captions": captions, "missing": missing}


def set_text_label(dataset_id: str, image_name: str, payload: Dict[str, Any]):
    payload = payload or {}
    entry = _resolve_dataset_entry(dataset_id)
    try:
        meta_path = _dataset_meta_path_for_entry(entry)
    except Exception:
        meta_path = None
    meta = _load_json_metadata(meta_path) if meta_path is not None else None
    meta = meta if isinstance(meta, dict) else {}
    lock = meta.get("annotation_lock") if isinstance(meta.get("annotation_lock"), dict) else {}
    if _annotation_lock_is_active(lock):
        _require_annotation_lock_owner(meta, payload)
    split, image_relpath = _annotation_text_split_rel_from_name(
        entry,
        image_name,
        split=payload.get("split") if "split" in payload else None,
    )
    caption = str(payload.get("caption") or "").strip()
    text_path = _annotation_overlay_text_path(entry, image_relpath, split=split)
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=True)
    _annotation_write_text_within_root(text_path, overlay_root, caption)
    return {"status": "saved", "caption": caption}


def register_dataset_path(
    path: str,
    dataset_id: Optional[str],
    label: Optional[str],
    context: Optional[str],
    notes: Optional[str],
    force_new: Optional[bool] = None,
    strict: Optional[bool] = None,
):
    dataset_root = _validate_linked_dataset_path(path)
    _validate_linked_dataset_shape(dataset_root, strict=bool(strict is None or strict))
    source_signature = _compute_dir_signature_impl(dataset_root)
    if not bool(force_new):
        for candidate in _list_all_datasets():
            if str(candidate.get("storage_mode") or "").strip().lower() != "linked":
                continue
            linked_root_raw = str(candidate.get("linked_root") or "").strip()
            if linked_root_raw:
                try:
                    if Path(linked_root_raw).expanduser().resolve() == dataset_root:
                        return candidate
                except Exception:
                    pass
            if (
                source_signature
                and str(candidate.get("signature") or "").strip() == source_signature
            ):
                return candidate
    base_id = _sanitize_yolo_run_id_impl(dataset_id or dataset_root.name) or "linked_dataset"
    registry_root = _dataset_registry_storage_root(
        create=True, detail="dataset_register_target_invalid"
    )
    dataset_id_final = _unique_dataset_name(base_id, root=registry_root)
    registry_dir = _dataset_registry_child_dir(
        dataset_id_final, detail="dataset_register_target_invalid"
    )
    if registry_dir.exists() or registry_dir.is_symlink():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="dataset_register_target_exists")
    try:
        registry_dir.mkdir(parents=True, exist_ok=True)
        meta = _build_linked_dataset_metadata(
            dataset_id=dataset_id_final,
            dataset_root=dataset_root,
            label=label,
            context=context,
            notes=notes,
        )
        meta["signature"] = source_signature
        _write_dataset_metadata_json(registry_dir / DATASET_META_NAME, registry_dir, meta)
        entry = _resolve_dataset_entry_impl(dataset_id_final, list_all_datasets_fn=_list_all_datasets)
        if not entry:
            raise HTTPException(
                status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="dataset_register_failed"
            )
        return entry
    except Exception:
        try:
            _delete_dataset_tree_or_link(registry_dir, [registry_root])
        except Exception:
            pass
        raise


def _purge_expired_transient_sessions(now_ts: Optional[float] = None) -> int:
    now = float(now_ts) if now_ts is not None else time.time()
    removed = 0
    with DATASET_TRANSIENT_LOCK:
        stale_ids: List[str] = []
        for sid, session in DATASET_TRANSIENT_SESSIONS.items():
            expires_raw = session.get("expires_at")
            try:
                expires_at = float(expires_raw)
            except Exception:
                continue
            if expires_at <= now:
                stale_ids.append(sid)
        for sid in stale_ids:
            DATASET_TRANSIENT_SESSIONS.pop(sid, None)
            removed += 1
    return removed


def open_dataset_path(path: str, strict: Optional[bool] = None):
    _purge_expired_transient_sessions()
    dataset_root = _validate_linked_dataset_path(path)
    layout = _validate_linked_dataset_shape(dataset_root, strict=bool(strict is None or strict))
    session_id = uuid.uuid4().hex
    classes = _dataset_labelmap_from_root(dataset_root)
    label = dataset_root.name
    now = time.time()
    expires_at = now + float(DATASET_TRANSIENT_SESSION_TTL_SECONDS)
    with DATASET_TRANSIENT_LOCK:
        DATASET_TRANSIENT_SESSIONS[session_id] = {
            "session_id": session_id,
            "dataset_root": str(dataset_root),
            "label": label,
            "classes": classes,
            "yolo_layout": layout.get("yolo_layout") or "flat",
            "created_at": now,
            "updated_at": now,
            "expires_at": expires_at,
            "annotation_status": "new",
            "annotation_notes": "",
            "annotation_cursor": None,
            "annotation_progress": {},
            "annotation_lock": {},
            "overlay_labels": {},
            "overlay_text": {},
        }
    return {
        "session_id": session_id,
        "expires_at": expires_at,
        "dataset": {
            "id": f"transient:{session_id}",
            "label": label,
            "dataset_root": str(dataset_root),
            "storage_mode": "transient",
            "classes": classes,
            "yolo_layout": layout.get("yolo_layout") or "flat",
        },
    }


def _resolve_transient_session(session_id: str) -> Dict[str, Any]:
    sid = str(session_id or "").strip()
    if not sid:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="transient_session_required")
    now = time.time()
    with DATASET_TRANSIENT_LOCK:
        session = DATASET_TRANSIENT_SESSIONS.get(sid)
        if not session:
            raise HTTPException(
                status_code=HTTP_404_NOT_FOUND, detail="transient_session_not_found"
            )
        expires_raw = session.get("expires_at")
        try:
            expires_at = float(expires_raw)
        except Exception:
            expires_at = now + float(DATASET_TRANSIENT_SESSION_TTL_SECONDS)
        if expires_at <= now:
            DATASET_TRANSIENT_SESSIONS.pop(sid, None)
            raise HTTPException(status_code=410, detail="transient_session_expired")
        session = dict(session)
        session["updated_at"] = now
        session["expires_at"] = now + float(DATASET_TRANSIENT_SESSION_TTL_SECONDS)
        DATASET_TRANSIENT_SESSIONS[sid] = session
    _purge_expired_transient_sessions(now_ts=now)
    return session


def _persist_transient_session(session_id: str, payload: Dict[str, Any]) -> None:
    with DATASET_TRANSIENT_LOCK:
        if session_id in DATASET_TRANSIENT_SESSIONS:
            updated = dict(payload or {})
            now = time.time()
            updated["updated_at"] = now
            updated["expires_at"] = now + float(DATASET_TRANSIENT_SESSION_TTL_SECONDS)
            DATASET_TRANSIENT_SESSIONS[session_id] = updated


def delete_transient_dataset(session_id: str) -> Dict[str, Any]:
    sid = str(session_id or "").strip()
    if not sid:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="transient_session_required")
    with DATASET_TRANSIENT_LOCK:
        session = DATASET_TRANSIENT_SESSIONS.get(sid)
        if not session:
            raise HTTPException(
                status_code=HTTP_404_NOT_FOUND, detail="transient_session_not_found"
            )
        expires_raw = session.get("expires_at")
        now = time.time()
        try:
            expires_at = float(expires_raw)
        except Exception:
            expires_at = now + float(DATASET_TRANSIENT_SESSION_TTL_SECONDS)
        if expires_at <= now:
            DATASET_TRANSIENT_SESSIONS.pop(sid, None)
            raise HTTPException(status_code=410, detail="transient_session_expired")
        DATASET_TRANSIENT_SESSIONS.pop(sid, None)
    _purge_expired_transient_sessions()
    return {"status": "deleted", "session_id": sid}


def save_transient_dataset(
    session_id: str,
    dataset_id: Optional[str],
    label: Optional[str],
    context: Optional[str],
    notes: Optional[str],
):
    session = _resolve_transient_session(session_id)
    dataset_root = _validate_linked_dataset_path(str(session.get("dataset_root") or ""))
    base_id = _sanitize_yolo_run_id_impl(dataset_id or dataset_root.name) or "linked_dataset"
    registry_root = _dataset_registry_storage_root(
        create=True, detail="dataset_register_target_invalid"
    )
    dataset_id_final = _unique_dataset_name(base_id, root=registry_root)
    registry_dir = _dataset_registry_child_dir(
        dataset_id_final, detail="dataset_register_target_invalid"
    )
    if registry_dir.exists() or registry_dir.is_symlink():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="dataset_register_target_exists")
    try:
        registry_dir.mkdir(parents=True, exist_ok=True)
        meta = _build_linked_dataset_metadata(
            dataset_id=dataset_id_final,
            dataset_root=dataset_root,
            label=label or session.get("label"),
            context=context,
            notes=notes or session.get("annotation_notes"),
        )
        session_classes = [
            str(item).strip() for item in (session.get("classes") or []) if str(item).strip()
        ]
        if session_classes:
            meta["classes"] = session_classes
            meta["yolo_labelmap_path"] = str(registry_dir / "labelmap.txt")
            meta["labelmap_source"] = "registry_overlay"
        if isinstance(session.get("annotation_progress"), dict):
            meta["annotation_progress"] = dict(session.get("annotation_progress") or {})
        if session.get("annotation_cursor") is not None:
            meta["annotation_cursor"] = session.get("annotation_cursor")
        if session.get("annotation_status"):
            meta["annotation_status"] = session.get("annotation_status")
        if session_classes:
            _annotation_write_labelmap_file(
                registry_dir / "labelmap.txt",
                [registry_dir.resolve()],
                session_classes,
            )
        _write_dataset_metadata_json(registry_dir / DATASET_META_NAME, registry_dir, meta)
        persisted_entry = {
            "dataset_root": str(dataset_root),
            "registry_root": str(registry_dir),
            "yolo_layout": str(session.get("yolo_layout") or "flat"),
        }
        _persist_transient_overlays_to_entry(persisted_entry, session)
        entry = _resolve_dataset_entry_impl(dataset_id_final, list_all_datasets_fn=_list_all_datasets)
        if not entry:
            raise HTTPException(
                status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="dataset_register_failed"
            )
        return entry
    except Exception:
        try:
            _delete_dataset_tree_or_link(registry_dir, [registry_root])
        except Exception:
            pass
        raise


def start_dataset_annotation_session(dataset_id: str, payload: Dict[str, Any]):
    entry = _resolve_dataset_entry(dataset_id)
    _dataset_effective_root_from_entry(entry)
    _annotation_manifest_for_entry(entry)
    _meta_path, meta = _annotation_load_or_create_meta(entry)
    lock_update = _annotation_update_lock(
        meta, payload or {}, force=bool((payload or {}).get("force"))
    )
    if not lock_update.get("ok"):
        return {
            "status": "warning",
            "warning": lock_update.get("warning"),
            "lock": lock_update.get("lock"),
            "dataset_id": dataset_id,
        }
    _annotation_persist_meta(entry, meta)
    return {
        "status": "ok",
        "dataset_id": dataset_id,
        "lock": lock_update.get("lock"),
    }


def heartbeat_dataset_annotation_session(dataset_id: str, payload: Dict[str, Any]):
    return start_dataset_annotation_session(dataset_id, payload or {})


def stop_dataset_annotation_session(dataset_id: str, payload: Dict[str, Any]):
    entry = _resolve_dataset_entry(dataset_id)
    _meta_path, meta = _annotation_load_or_create_meta(entry)
    released = _annotation_release_lock(meta, payload or {})
    if not released.get("ok"):
        raise HTTPException(
            status_code=HTTP_409_CONFLICT,
            detail=released.get("warning") or "annotation_lock_active",
        )
    _annotation_persist_meta(entry, meta)
    return {"status": "ok", "dataset_id": dataset_id, "lock": {}}


def get_dataset_annotation_manifest(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    return _annotation_manifest_for_entry(entry)


def _resolve_annotation_image_path(
    dataset_root: Path, yolo_layout: str, split: str, image_relpath: Path
) -> Path:
    dataset_root = dataset_root.resolve()
    if yolo_layout == "split":
        image_path = dataset_root / split / "images" / image_relpath
    else:
        image_path = dataset_root / "images" / image_relpath
        if not image_path.exists():
            image_path = dataset_root / image_relpath
    if not image_path.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="annotation_image_not_found")
    resolved = image_path.resolve()
    if not _path_is_within_root_impl(resolved, dataset_root):
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="annotation_image_not_found")
    return resolved


def get_dataset_annotation_image(dataset_id: str, split: str, image_relpath: str):
    entry = _resolve_dataset_entry(dataset_id)
    dataset_root = _dataset_effective_root_from_entry(entry)
    split_norm = _annotation_normalise_split(split)
    rel = _annotation_normalise_image_relpath(image_relpath)
    image_path = _resolve_annotation_image_path(
        dataset_root, str(entry.get("yolo_layout") or "flat"), split_norm, rel
    )
    return FileResponse(str(image_path))


def save_dataset_annotation_snapshot(dataset_id: str, payload: Dict[str, Any]):
    payload = payload or {}
    entry = _resolve_dataset_entry(dataset_id)
    dataset_root = _dataset_effective_root_from_entry(entry)
    _meta_path, meta = _annotation_load_or_create_meta(entry)
    _require_annotation_lock_owner(meta, payload)
    status_value = _annotation_requested_status(payload)
    normalised_records = _normalise_annotation_snapshot_records(payload.get("records"))
    _validate_annotation_snapshot_record_images(
        dataset_root,
        str(entry.get("yolo_layout") or "flat"),
        normalised_records,
    )
    overlay_root = _dataset_overlay_root_from_entry(entry, ensure=True)
    for split, rel, has_label_lines, label_lines, has_text_label, text_value in normalised_records:
        if has_label_lines:
            label_path = _annotation_overlay_label_path(entry, split, rel)
            _annotation_write_text_within_root(
                label_path,
                overlay_root,
                "\n".join(label_lines) + ("\n" if label_lines else ""),
            )
        if has_text_label:
            text_path = _annotation_overlay_text_path(entry, rel, split=split)
            _annotation_write_text_within_root(text_path, overlay_root, text_value)

    if status_value:
        meta["annotation_status"] = status_value
    if "notes" in payload:
        meta["annotation_notes"] = str(payload.get("notes") or "")
    if "cursor" in payload:
        meta["annotation_cursor"] = payload.get("cursor")
    manifest = _annotation_manifest_for_entry(entry)
    meta["annotation_progress"] = manifest.get("progress") or {}
    _annotation_persist_meta(entry, meta)
    return {
        "status": "saved",
        "dataset_id": dataset_id,
        "progress": manifest.get("progress") or {},
    }


def patch_dataset_annotation_meta(dataset_id: str, payload: Dict[str, Any]):
    payload = payload or {}
    entry = _resolve_dataset_entry(dataset_id)
    _meta_path, meta = _annotation_load_or_create_meta(entry)
    _require_annotation_lock_owner(meta, payload)
    status_value = _annotation_requested_status(payload)
    saved_labelmap: Optional[List[str]] = None
    if "labelmap" in payload:
        saved_labelmap = _normalize_labelmap_payload(payload.get("labelmap"))
        dataset_root = _dataset_effective_root_from_entry(entry)
        labelmap_path = _annotation_labelmap_write_path(entry, dataset_root)
        storage_root = _dataset_guarded_meta_storage_root_from_entry(
            entry,
            ensure=False,
            detail="labelmap_path_forbidden",
        )
        storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
        allowed_labelmap_roots = (
            [storage_root.resolve()]
            if storage_mode == "linked"
            else [dataset_root.resolve(), storage_root.resolve()]
        )
        try:
            _annotation_write_labelmap_file(
                labelmap_path,
                allowed_labelmap_roots,
                saved_labelmap,
            )
        except HTTPException:
            raise
        except Exception as exc:  # noqa: BLE001
            raise HTTPException(
                status_code=HTTP_500_INTERNAL_SERVER_ERROR,
                detail=f"labelmap_save_failed:{exc}",
            ) from exc
        storage_root = _dataset_guarded_meta_storage_root_from_entry(
            entry,
            ensure=True,
            detail="dataset_metadata_path_forbidden",
        )
        dataset_meta = _load_json_metadata(_dataset_meta_path_for_entry(entry)) or dict(entry)
        dataset_meta["classes"] = list(saved_labelmap)
        dataset_meta["yolo_labelmap_path"] = str(labelmap_path)
        if storage_mode == "linked":
            dataset_meta["labelmap_source"] = "registry_overlay"
        dataset_meta["signature"] = _compute_dir_signature_impl(dataset_root)
        meta["classes"] = list(saved_labelmap)
        meta["yolo_labelmap_path"] = str(labelmap_path)
        if storage_mode == "linked":
            meta["labelmap_source"] = "registry_overlay"
        meta["signature"] = dataset_meta["signature"]
        _write_dataset_metadata_json(storage_root / DATASET_META_NAME, storage_root, dataset_meta)
    if status_value:
        meta["annotation_status"] = status_value
    if "notes" in payload:
        meta["annotation_notes"] = str(payload.get("notes") or "")
    if "cursor" in payload:
        meta["annotation_cursor"] = payload.get("cursor")
    _annotation_persist_meta(entry, meta)
    return {
        "status": "saved",
        "dataset_id": dataset_id,
        "annotation_status": meta.get("annotation_status") or "new",
        "annotation_notes": str(meta.get("annotation_notes") or ""),
        "annotation_cursor": meta.get("annotation_cursor"),
        "labelmap": saved_labelmap,
    }


def start_transient_annotation_session(session_id: str, payload: Dict[str, Any]):
    session = _resolve_transient_session(session_id)
    with DATASET_TRANSIENT_LOCK:
        lock_update = _annotation_update_lock(
            session, payload or {}, force=bool((payload or {}).get("force"))
        )
        session["updated_at"] = time.time()
        DATASET_TRANSIENT_SESSIONS[session_id] = session
    if not lock_update.get("ok"):
        return {
            "status": "warning",
            "session_id": session_id,
            "warning": lock_update.get("warning"),
            "lock": lock_update.get("lock"),
        }
    return {"status": "ok", "session_id": session_id, "lock": lock_update.get("lock")}


def heartbeat_transient_annotation_session(session_id: str, payload: Dict[str, Any]):
    return start_transient_annotation_session(session_id, payload or {})


def stop_transient_annotation_session(session_id: str, payload: Dict[str, Any]):
    session = _resolve_transient_session(session_id)
    with DATASET_TRANSIENT_LOCK:
        released = _annotation_release_lock(session, payload or {})
        if not released.get("ok"):
            raise HTTPException(
                status_code=HTTP_409_CONFLICT,
                detail=released.get("warning") or "annotation_lock_active",
            )
        session["updated_at"] = time.time()
        DATASET_TRANSIENT_SESSIONS[session_id] = session
    return {"status": "ok", "session_id": session_id, "lock": {}}


def get_transient_annotation_manifest(session_id: str):
    session = _resolve_transient_session(session_id)
    dataset_root = _validate_linked_dataset_path(str(session.get("dataset_root") or ""))
    yolo_layout = str(session.get("yolo_layout") or "flat")
    rows: List[Dict[str, Any]] = []
    overlay_labels = (
        session.get("overlay_labels") if isinstance(session.get("overlay_labels"), dict) else {}
    )
    overlay_text = (
        session.get("overlay_text") if isinstance(session.get("overlay_text"), dict) else {}
    )
    base_entry = {
        "dataset_root": str(dataset_root),
        "yolo_layout": yolo_layout,
        "registry_root": None,
    }
    for image in _annotation_collect_images(base_entry):
        split = _annotation_normalise_split(image.get("split"))
        rel = _annotation_normalise_image_relpath(image.get("image_relpath"))
        key = f"{split}:{rel.as_posix()}"
        if key in overlay_labels:
            lines = [str(x).strip() for x in (overlay_labels.get(key) or []) if str(x).strip()]
        else:
            source_path = _annotation_source_label_path(dataset_root, yolo_layout, split, rel)
            source_text = _annotation_read_text_within_root(source_path, dataset_root)
            lines = (
                [ln.strip() for ln in source_text.splitlines() if ln.strip()]
                if source_text is not None
                else []
            )
        if key in overlay_text:
            text_val = str(overlay_text.get(key) or "")
        else:
            text_val = _annotation_source_text_value(
                dataset_root,
                rel,
                split=split,
                yolo_layout=yolo_layout,
            )
        rows.append(
            {
                "split": split,
                "image_relpath": str(rel.as_posix()),
                "image_name": rel.name,
                "label_lines": lines,
                "text_label": text_val,
            }
        )
    progress = _annotation_progress_from_rows(rows)
    session["annotation_progress"] = progress
    session["updated_at"] = time.time()
    _persist_transient_session(session_id, session)
    return {
        "session_id": session_id,
        "dataset_label": session.get("label") or dataset_root.name,
        "dataset_root": str(dataset_root),
        "storage_mode": "transient",
        "labelmap": list(session.get("classes") or []),
        "yolo_layout": yolo_layout,
        "status": session.get("annotation_status") or "new",
        "notes": str(session.get("annotation_notes") or ""),
        "cursor": session.get("annotation_cursor"),
        "lock": (
            session.get("annotation_lock")
            if isinstance(session.get("annotation_lock"), dict)
            else {}
        ),
        "progress": progress,
        "images": rows,
    }


def get_transient_annotation_image(session_id: str, split: str, image_relpath: str):
    session = _resolve_transient_session(session_id)
    dataset_root = _validate_linked_dataset_path(str(session.get("dataset_root") or ""))
    split_norm = _annotation_normalise_split(split)
    rel = _annotation_normalise_image_relpath(image_relpath)
    image_path = _resolve_annotation_image_path(
        dataset_root, str(session.get("yolo_layout") or "flat"), split_norm, rel
    )
    return FileResponse(str(image_path))


def save_transient_annotation_snapshot(session_id: str, payload: Dict[str, Any]):
    payload = payload or {}
    session = _resolve_transient_session(session_id)
    _require_annotation_lock_owner(session, payload)
    status_value = _annotation_requested_status(payload)
    normalised_records = _normalise_annotation_snapshot_records(payload.get("records"))
    if normalised_records:
        dataset_root = _validate_linked_dataset_path(str(session.get("dataset_root") or ""))
        _validate_annotation_snapshot_record_images(
            dataset_root,
            str(session.get("yolo_layout") or "flat"),
            normalised_records,
        )
    overlay_labels = (
        session.get("overlay_labels") if isinstance(session.get("overlay_labels"), dict) else {}
    )
    overlay_text = (
        session.get("overlay_text") if isinstance(session.get("overlay_text"), dict) else {}
    )
    for split, rel, has_label_lines, label_lines, has_text_label, text_value in normalised_records:
        key = f"{split}:{rel.as_posix()}"
        if has_label_lines:
            overlay_labels[key] = label_lines
        if has_text_label:
            overlay_text[key] = text_value
    session["overlay_labels"] = overlay_labels
    session["overlay_text"] = overlay_text
    if status_value:
        session["annotation_status"] = status_value
    if "notes" in payload:
        session["annotation_notes"] = str(payload.get("notes") or "")
    if "cursor" in payload:
        session["annotation_cursor"] = payload.get("cursor")
    session["updated_at"] = time.time()
    _persist_transient_session(session_id, session)
    manifest = get_transient_annotation_manifest(session_id)
    return {"status": "saved", "session_id": session_id, "progress": manifest.get("progress") or {}}


def patch_transient_annotation_meta(session_id: str, payload: Dict[str, Any]):
    payload = payload or {}
    session = _resolve_transient_session(session_id)
    _require_annotation_lock_owner(session, payload)
    status_value = _annotation_requested_status(payload)
    saved_labelmap: Optional[List[str]] = None
    if "labelmap" in payload:
        saved_labelmap = _normalize_labelmap_payload(payload.get("labelmap"))
        session["classes"] = list(saved_labelmap)
        session["labelmap_source"] = "transient_session"
    if status_value:
        session["annotation_status"] = status_value
    if "notes" in payload:
        session["annotation_notes"] = str(payload.get("notes") or "")
    if "cursor" in payload:
        session["annotation_cursor"] = payload.get("cursor")
    session["updated_at"] = time.time()
    _persist_transient_session(session_id, session)
    return {
        "status": "saved",
        "session_id": session_id,
        "annotation_status": session.get("annotation_status") or "new",
        "annotation_notes": str(session.get("annotation_notes") or ""),
        "annotation_cursor": session.get("annotation_cursor"),
        "labelmap": saved_labelmap,
    }


