def _class_analysis_log(job: ClassAnalysisJob, message: str) -> None:
    entry = {"timestamp": time.time(), "message": str(message or "")}
    job.logs.append(entry)
    if len(job.logs) > MAX_JOB_LOGS:
        job.logs[:] = job.logs[-MAX_JOB_LOGS:]
    job.message = str(message or "")
    job.updated_at = time.time()
    try:
        logger.info("[class-analysis %s] %s", job.job_id[:8], message)
    except Exception:
        pass


def _class_analysis_update(
    job: ClassAnalysisJob,
    *,
    status: Optional[str] = None,
    progress: Optional[float] = None,
    message: Optional[str] = None,
    error: Optional[str] = None,
    result: Optional[Dict[str, Any]] = None,
) -> None:
    if status is not None:
        job.status = status
    if progress is not None:
        job.progress = clamp_progress(progress, fallback=job.progress)
    if message is not None:
        if str(message or "") != str(job.message or ""):
            _class_analysis_log(job, str(message or ""))
        else:
            job.message = str(message or "")
            job.updated_at = time.time()
    if error is not None:
        job.error = error
    if result is not None:
        job.result = result
        job.updated_at = time.time()


def _serialize_class_analysis_job(job: ClassAnalysisJob) -> Dict[str, Any]:
    return {
        "job_id": job.job_id,
        "status": job.status,
        "progress": json_sanitize(job.progress),
        "message": job.message,
        "request": json_sanitize(job.request),
        "logs": json_sanitize(job.logs),
        "summary": json_sanitize(
            (job.result or {}).get("summary") if isinstance(job.result, dict) else None
        ),
        "error": json_sanitize(job.error),
        "created_at": job.created_at,
        "updated_at": job.updated_at,
    }


def _class_analysis_json_safe(value: Any) -> Any:
    if isinstance(value, np.ndarray):
        return [_class_analysis_json_safe(v) for v in value.tolist()]
    if isinstance(value, np.generic):
        return value.item()
    if isinstance(value, dict):
        return {str(k): _class_analysis_json_safe(v) for k, v in value.items()}
    if isinstance(value, (list, tuple)):
        return [_class_analysis_json_safe(v) for v in value]
    return value


def _class_analysis_safe_slug(value: str, fallback: str = "source") -> str:
    cleaned = re.sub(r"[^A-Za-z0-9._-]+", "_", str(value or "")).strip("._-")
    return cleaned or fallback


def _class_analysis_safe_relpath(value: str, fallback: str = "image.jpg") -> Path:
    parts = []
    for raw_part in Path(str(value or "")).parts:
        if raw_part in {"", ".", ".."}:
            continue
        safe = _class_analysis_safe_slug(raw_part, "")
        if safe:
            parts.append(safe)
    if not parts:
        parts = [fallback]
    return Path(*parts)


def _class_analysis_storage_root(
    *,
    create: bool = True,
    detail: str = "class_analysis_path_invalid",
) -> Path:
    try:
        raw_root = CLASS_ANALYSIS_ROOT
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("class analysis root is a symlink")
        if create:
            raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("class analysis root is a symlink")
        if raw_root.exists() and not raw_root.is_dir():
            raise ValueError("class analysis root is not a directory")
        return raw_root.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _class_analysis_cache_storage_root(*, create: bool = False) -> Optional[Path]:
    try:
        raw_root = CLASS_ANALYSIS_CACHE_ROOT
        if _storage_path_has_symlink_component(raw_root):
            return None
        if create:
            raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            return None
        if raw_root.exists() and not raw_root.is_dir():
            return None
        if not create and not raw_root.exists():
            return None
        return raw_root.resolve(strict=False)
    except Exception:
        return None


def _class_analysis_job_dir(
    job_id: str,
    *,
    create: bool = False,
    detail: str = "class_analysis_path_invalid",
) -> Path:
    safe_job_id = _class_analysis_safe_slug(str(job_id or ""), "job")
    try:
        root = _class_analysis_storage_root(create=True, detail=detail)
        candidate = root / safe_job_id
        if _storage_path_has_symlink_component(candidate):
            raise ValueError("class analysis job dir is a symlink")
        if create:
            candidate.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(candidate):
            raise ValueError("class analysis job dir is a symlink")
        if candidate.exists() and not candidate.is_dir():
            raise ValueError("class analysis job path is not a directory")
        resolved = candidate.resolve(strict=False)
        if not _path_is_within_root_impl(resolved, root) or resolved.parent != root:
            raise ValueError("class analysis job path escapes root")
        return resolved
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _class_analysis_active_workspace_paths(
    workspace_dir_value: Any,
    manifest_path_value: Any,
) -> Tuple[Path, Optional[Path]]:
    try:
        class_root = _class_analysis_storage_root(
            create=True,
            detail="active_workspace_path_invalid",
        )
        workspace_raw = Path(str(workspace_dir_value or "")).expanduser()
        if _storage_path_has_symlink_component(workspace_raw):
            raise ValueError("active workspace dir is a symlink")
        workspace_dir = workspace_raw.resolve(strict=True)
        if not workspace_dir.is_dir() or not _path_is_within_root_impl(workspace_dir, class_root):
            raise ValueError("active workspace dir is outside class analysis root")
        manifest_path: Optional[Path] = None
        manifest_raw_value = str(manifest_path_value or "").strip()
        if manifest_raw_value:
            manifest_raw = Path(manifest_raw_value).expanduser()
            if _storage_path_has_symlink_component(manifest_raw):
                raise ValueError("active workspace manifest is a symlink")
            manifest_path = manifest_raw.resolve(strict=True)
            if (
                not manifest_path.is_file()
                or not _path_is_within_root_impl(manifest_path, workspace_dir)
            ):
                raise ValueError("active workspace manifest is outside workspace")
        return workspace_dir, manifest_path
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_path_invalid") from exc


def _class_analysis_source(payload: Dict[str, Any]) -> Dict[str, Any]:
    source_mode = str(payload.get("source_mode") or payload.get("mode") or "linked").strip().lower()
    if source_mode in {"active_workspace", "workspace"}:
        workspace_dir, manifest_path = _class_analysis_active_workspace_paths(
            payload.get("workspace_dir"),
            payload.get("workspace_manifest_path"),
        )
        manifest_path_raw = str(payload.get("workspace_manifest_path") or "").strip()
        manifest = payload.get("workspace_manifest") if isinstance(payload.get("workspace_manifest"), dict) else None
        if manifest is None and manifest_path_raw and manifest_path is not None:
            manifest = _load_json_metadata(manifest_path) or {}
        if not isinstance(manifest, dict):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_manifest_invalid")
        labelmap = [str(x) for x in manifest.get("labelmap") or payload.get("labelmap") or []]
        return {
            "source_mode": "active_workspace",
            "source_id": str(payload.get("workspace_id") or payload.get("job_id") or "active"),
            "source_key": f"active:{payload.get('workspace_id') or payload.get('job_id') or 'workspace'}",
            "dataset_root": workspace_dir,
            "yolo_layout": str(payload.get("yolo_layout") or manifest.get("yolo_layout") or "flat"),
            "manifest": manifest,
            "labelmap": labelmap,
        }
    if source_mode in {"dataset", "linked"}:
        dataset_id = str(payload.get("dataset_id") or "").strip()
        if not dataset_id:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="dataset_id_required")
        entry = _resolve_dataset_entry(dataset_id)
        dataset_root = _dataset_effective_root_from_entry(entry)
        manifest = _annotation_manifest_for_entry(entry)
        return {
            "source_mode": "linked",
            "source_id": dataset_id,
            "source_key": f"linked:{dataset_id}",
            "dataset_root": dataset_root,
            "yolo_layout": str(entry.get("yolo_layout") or "flat"),
            "manifest": manifest,
            "labelmap": list(manifest.get("labelmap") or entry.get("classes") or []),
        }
    if source_mode in {"transient", "open_path"}:
        session_id = str(payload.get("session_id") or "").strip()
        if not session_id:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="session_id_required")
        session = _resolve_transient_session(session_id)
        dataset_root = _validate_linked_dataset_path(str(session.get("dataset_root") or ""))
        manifest = get_transient_annotation_manifest(session_id)
        return {
            "source_mode": "transient",
            "source_id": session_id,
            "source_key": f"transient:{session_id}",
            "dataset_root": dataset_root,
            "yolo_layout": str(session.get("yolo_layout") or "flat"),
            "manifest": manifest,
            "labelmap": list(manifest.get("labelmap") or session.get("classes") or []),
        }
    raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="class_analysis_source_invalid")


def _class_analysis_parse_yolo_geometry(
    line: str,
    *,
    image_width: int,
    image_height: int,
) -> Optional[Dict[str, Any]]:
    parts = str(line or "").strip().split()
    if len(parts) < 5:
        return None
    try:
        class_id = int(float(parts[0]))
    except Exception:
        return None
    if len(parts) >= 7:
        points: List[Tuple[float, float]] = []
        for idx in range(1, len(parts) - 1, 2):
            try:
                nx = float(parts[idx])
                ny = float(parts[idx + 1])
            except Exception:
                continue
            points.append(
                (
                    max(0.0, min(float(image_width), nx * float(image_width))),
                    max(0.0, min(float(image_height), ny * float(image_height))),
                )
            )
        if len(points) < 3:
            return None
        xs = [pt[0] for pt in points]
        ys = [pt[1] for pt in points]
        x1, x2 = max(0.0, min(xs)), min(float(image_width), max(xs))
        y1, y2 = max(0.0, min(ys)), min(float(image_height), max(ys))
        if x2 <= x1 or y2 <= y1:
            return None
        return {
            "class_id": class_id,
            "kind": "polygon",
            "bbox_xyxy": [x1, y1, x2, y2],
            "points": [[float(x), float(y)] for x, y in points],
        }
    try:
        cx = float(parts[1]) * float(image_width)
        cy = float(parts[2]) * float(image_height)
        bw = float(parts[3]) * float(image_width)
        bh = float(parts[4]) * float(image_height)
    except Exception:
        return None
    if bw <= 0 or bh <= 0:
        return None
    x1 = max(0.0, min(float(image_width), cx - (bw / 2.0)))
    y1 = max(0.0, min(float(image_height), cy - (bh / 2.0)))
    x2 = max(0.0, min(float(image_width), cx + (bw / 2.0)))
    y2 = max(0.0, min(float(image_height), cy + (bh / 2.0)))
    if x2 <= x1 or y2 <= y1:
        return None
    return {"class_id": class_id, "kind": "bbox", "bbox_xyxy": [x1, y1, x2, y2]}


def _class_analysis_crop_bounds(
    bbox_xyxy: Sequence[float],
    *,
    image_width: int,
    image_height: int,
    crop_mode: str,
    padding_ratio: float,
) -> Tuple[int, int, int, int]:
    return _embedding_crop_bounds(
        bbox_xyxy,
        image_width=image_width,
        image_height=image_height,
        crop_mode=crop_mode,
        padding_ratio=padding_ratio,
    )


def _class_analysis_cache_digest(value: Any) -> str:
    payload = json.dumps(_class_analysis_json_safe(value), sort_keys=True, separators=(",", ":"))
    return hashlib.sha256(payload.encode("utf-8")).hexdigest()


def _class_analysis_file_sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with Path(path).open("rb") as handle:
        while True:
            chunk = handle.read(1024 * 1024)
            if not chunk:
                break
            digest.update(chunk)
    return digest.hexdigest()


def _class_analysis_embedding_cache_path(cache_key: str) -> Path:
    safe_key = re.sub(r"[^a-fA-F0-9]", "", str(cache_key or ""))[:64]
    if not safe_key:
        safe_key = hashlib.sha256(str(cache_key or "empty").encode("utf-8")).hexdigest()
    return CLASS_ANALYSIS_CACHE_ROOT / "embeddings" / safe_key[:2] / f"{safe_key}.npy"


def _class_analysis_thumbnail_cache_path(crop_cache_key: str) -> Path:
    safe_key = re.sub(r"[^a-fA-F0-9]", "", str(crop_cache_key or ""))[:64]
    if not safe_key:
        safe_key = hashlib.sha256(str(crop_cache_key or "empty").encode("utf-8")).hexdigest()
    return CLASS_ANALYSIS_CACHE_ROOT / "thumbnails" / safe_key[:2] / f"{safe_key}.jpg"


def _class_analysis_prepare_write_path(path: Path, root: Path) -> Optional[Path]:
    try:
        root_resolved = root.resolve()
        if _storage_path_has_symlink_component(root):
            return None
        raw_path = Path(path)
        parent = raw_path.parent
        if _storage_path_has_symlink_component(parent):
            return None
        parent_resolved = parent.resolve(strict=False)
        if not _path_is_within_root_impl(parent_resolved, root_resolved):
            return None
        parent.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(parent):
            return None
        if raw_path.is_symlink():
            raw_path.unlink(missing_ok=True)
        elif raw_path.exists() and raw_path.is_dir():
            return None
        target_resolved = raw_path.resolve(strict=False)
    except Exception:
        return None
    if not _path_is_within_root_impl(target_resolved, root_resolved):
        return None
    return raw_path


def _class_analysis_prepare_dir(path: Path, root: Path) -> Optional[Path]:
    try:
        root_resolved = root.resolve()
        if _storage_path_has_symlink_component(root):
            return None
        raw_path = Path(path)
        if _storage_path_has_symlink_component(raw_path):
            return None
        parent_resolved = raw_path.parent.resolve(strict=False)
        if not _path_is_within_root_impl(parent_resolved, root_resolved):
            return None
        raw_path.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_path) or not raw_path.is_dir():
            return None
        resolved = raw_path.resolve(strict=True)
    except Exception:
        return None
    if not _path_is_within_root_impl(resolved, root_resolved):
        return None
    return resolved


def _class_analysis_write_json(path: Path, root: Path, value: Any) -> Path:
    _write_text_within_root_atomic(
        path,
        root,
        json.dumps(_class_analysis_json_safe(value), ensure_ascii=False, indent=2),
        detail="class_analysis_write_path_forbidden",
        context="class analysis",
    )
    return path


