def _class_analysis_copy_file_within_roots(
    src: Path,
    dest: Path,
    *,
    source_root: Path,
    dest_root: Path,
) -> bool:
    src_path = _safe_existing_regular_file_within_root_impl(src, source_root)
    if src_path is None:
        return False

    def copy_source(handle: Any) -> None:
        with src_path.open("rb") as source_handle:
            shutil.copyfileobj(source_handle, handle)

    try:
        _class_analysis_write_binary(
            dest,
            dest_root,
            copy_source,
        )
    except Exception:
        return False
    return True


def _class_analysis_embedding_cache_key(crop_cache_key: str, head: Dict[str, Any]) -> str:
    encoder_type = str(head.get("encoder_type") or "dinov3").strip().lower()
    encoder_model = str(head.get("encoder_model") or head.get("clip_model") or "").strip()
    return _class_analysis_cache_digest(
        {
            "version": CLASS_ANALYSIS_CACHE_VERSION,
            "crop_key": str(crop_cache_key or ""),
            "encoder_type": encoder_type,
            "encoder_model": encoder_model,
            "normalize_embeddings": bool(head.get("normalize_embeddings")),
            "dinov3_pooling": _embedding_normalize_dinov3_pooling(head.get("dinov3_pooling")),
            "cradio_pooling": normalize_cradio_pooling(head.get("cradio_pooling")),
            "embedding_aggregation": _embedding_normalize_aggregation(head.get("embedding_aggregation")),
            "embedding_salad_head_id": str(head.get("embedding_salad_head_id") or "").strip(),
        }
    )


def _class_analysis_load_cached_embedding(cache_path: Path) -> Optional[np.ndarray]:
    cache_root = _class_analysis_cache_storage_root(create=False)
    if cache_root is None:
        return None
    safe_cache_path = _safe_existing_regular_file_within_root_impl(
        cache_path, cache_root
    )
    if safe_cache_path is None:
        return None
    try:
        cached = np.load(safe_cache_path)
        arr = np.asarray(cached, dtype=np.float32)
    except Exception:
        return None
    if arr.ndim != 1 or arr.size <= 0:
        return None
    if not np.all(np.isfinite(arr)):
        return None
    return arr.astype(np.float32, copy=False)


def _class_analysis_cached_embedding_valid(crop_cache_key: str, head: Dict[str, Any]) -> bool:
    crop_key = str(crop_cache_key or "").strip()
    if not crop_key:
        return False
    cache_key = _class_analysis_embedding_cache_key(crop_key, head)
    cache_path = _class_analysis_embedding_cache_path(cache_key)
    return _class_analysis_load_cached_embedding(cache_path) is not None


def _class_analysis_normalize_preprocess_mode(value: Any) -> str:
    return _embedding_normalize_preprocess(value)


def _class_analysis_normalize_embedding_adjustment(value: Any) -> str:
    return _embedding_normalize_adjustment(value)


def _class_analysis_preprocess_crop(
    crop: Image.Image,
    *,
    mode: str,
    canonical_size: int,
) -> Image.Image:
    return _embedding_preprocess_crop(crop, mode=mode, canonical_size=canonical_size)


def _class_analysis_stratified_indices(
    records: Sequence[Dict[str, Any]],
    *,
    cap: int,
    seed: int,
) -> List[int]:
    total = len(records)
    if cap <= 0 or total <= cap:
        return list(range(total))
    rng = random.Random(int(seed))
    by_class: Dict[str, List[int]] = {}
    for idx, record in enumerate(records):
        by_class.setdefault(str(record.get("class_name") or ""), []).append(idx)
    selected: Set[int] = set()
    class_names = sorted(by_class)
    base = max(1, cap // max(1, len(class_names)))
    for class_name in class_names:
        choices = list(by_class[class_name])
        rng.shuffle(choices)
        selected.update(choices[: min(base, len(choices))])
    remaining_slots = max(0, cap - len(selected))
    if remaining_slots > 0:
        rest = [idx for idx in range(total) if idx not in selected]
        rng.shuffle(rest)
        selected.update(rest[:remaining_slots])
    return sorted(selected)


def _class_analysis_sample_cap(value: Any) -> int:
    if value is None:
        return 0
    if isinstance(value, str) and not value.strip():
        return 0
    try:
        parsed = int(float(value))
    except (TypeError, ValueError):
        return 0
    return max(0, parsed)


def _class_analysis_record_covariates(records: Sequence[Dict[str, Any]]) -> Tuple[np.ndarray, List[str]]:
    return _embedding_covariates_from_records(records)


def _class_analysis_normalize_rows(values: np.ndarray) -> np.ndarray:
    return _embedding_normalize_rows(values)


def _class_analysis_apply_embedding_adjustment(
    embeddings: np.ndarray,
    records: Sequence[Dict[str, Any]],
    *,
    mode: str,
) -> Tuple[np.ndarray, Dict[str, Any]]:
    mode_norm = _class_analysis_normalize_embedding_adjustment(mode)
    info: Dict[str, Any] = {"mode": mode_norm, "applied": False}
    embeddings = np.asarray(embeddings, dtype=np.float32)
    if mode_norm == "none":
        return _class_analysis_normalize_rows(embeddings), info
    covariates, names = _class_analysis_record_covariates(records)
    if embeddings.ndim != 2 or covariates.shape[0] != embeddings.shape[0] or embeddings.shape[0] < 6:
        info["skipped_reason"] = "not_enough_points"
        return _class_analysis_normalize_rows(embeddings), info
    std = covariates.std(axis=0)
    keep = std > 1e-6
    if not np.any(keep):
        info["skipped_reason"] = "constant_covariates"
        return _class_analysis_normalize_rows(embeddings), info
    selected = covariates[:, keep]
    selected_names = [name for name, use in zip(names, keep.tolist()) if use]
    selected = (selected - selected.mean(axis=0, keepdims=True)) / selected.std(axis=0, keepdims=True)
    design = np.concatenate(
        [np.ones((selected.shape[0], 1), dtype=np.float32), selected.astype(np.float32)],
        axis=1,
    )
    try:
        beta, *_ = np.linalg.lstsq(design, embeddings, rcond=None)
        adjusted = embeddings - design @ beta
    except Exception as exc:
        info["skipped_reason"] = f"residualization_failed:{exc}"
        return _class_analysis_normalize_rows(embeddings), info
    info.update(
        {
            "applied": True,
            "covariates": selected_names,
            "point_count": int(embeddings.shape[0]),
        }
    )
    return _class_analysis_normalize_rows(adjusted.astype(np.float32, copy=False)), info


def _class_analysis_pearson(x: np.ndarray, y: np.ndarray) -> float:
    if x.size < 3 or y.size != x.size:
        return 0.0
    x_std = float(x.std())
    y_std = float(y.std())
    if x_std <= 1e-12 or y_std <= 1e-12:
        return 0.0
    return float(np.mean((x - x.mean()) * (y - y.mean())) / (x_std * y_std))


def _class_analysis_projection_diagnostics(
    records: Sequence[Dict[str, Any]],
    coords: np.ndarray,
) -> Dict[str, Any]:
    coords = np.asarray(coords, dtype=np.float32)
    if coords.ndim != 2 or coords.shape[0] != len(records) or coords.shape[0] < 3:
        return {
            "axis_correlations": {},
            "strongest_size_axis": {"axis": "", "metric": "", "correlation": 0.0},
        }
    covariates, names = _class_analysis_record_covariates(records)
    axes = {"x": coords[:, 0], "y": coords[:, 1] if coords.shape[1] > 1 else np.zeros(coords.shape[0])}
    axis_correlations: Dict[str, Dict[str, float]] = {}
    strongest = {"axis": "", "metric": "", "correlation": 0.0}
    for axis_name, values in axes.items():
        axis_correlations[axis_name] = {}
        for idx, metric in enumerate(names):
            corr = _class_analysis_pearson(values, covariates[:, idx])
            axis_correlations[axis_name][metric] = corr
            if abs(corr) > abs(float(strongest["correlation"])):
                strongest = {"axis": axis_name, "metric": metric, "correlation": corr}
    return {
        "axis_correlations": axis_correlations,
        "strongest_size_axis": strongest,
    }


def _class_analysis_encoder_display_name(encoder_type: str, encoder_model: str = "") -> str:
    encoder_norm = str(encoder_type or "").strip().lower()
    if encoder_norm == "dinov3":
        return "DINOv3"
    if encoder_norm == "clip":
        return f"CLIP {encoder_model}".strip()
    if encoder_norm == "cradio":
        model_tail = str(encoder_model or CRADIO_DEFAULT_MODEL).split("/")[-1]
        return f"C-RADIOv4 {model_tail}".strip()
    return encoder_norm.upper() or "encoder"


def _class_analysis_progress_message(
    *,
    done: int,
    total: int,
    started_at: float,
) -> str:
    if done <= 0 or total <= 0:
        return ""
    elapsed = max(0.001, time.time() - started_at)
    rate = done / elapsed
    if rate <= 0:
        return ""
    remaining = max(0, total - done)
    eta_seconds = int(round(remaining / rate))
    if eta_seconds >= 90:
        eta = f"{max(1, eta_seconds // 60)}m left"
    elif eta_seconds > 0:
        eta = f"{eta_seconds}s left"
    else:
        eta = "finishing"
    return f"{rate:.1f}/s, {eta}"


def _class_analysis_encode_crops(
    crops: Sequence[Any],
    *,
    job: ClassAnalysisJob,
    head: Dict[str, Any],
    batch_size: int,
    progress_start: float = 0.18,
    progress_end: float = 0.70,
    records: Optional[Sequence[Dict[str, Any]]] = None,
    cache_stats: Optional[Dict[str, int]] = None,
) -> Optional[np.ndarray]:
    total = len(crops)
    if total <= 0:
        return None
    resolved_batch = max(1, min(int(batch_size or 64), total))
    encoder_type = str(head.get("encoder_type") or "dinov3").strip().lower()
    encoder_model = str(head.get("encoder_model") or head.get("clip_model") or "").strip()
    encoder_label = _class_analysis_encoder_display_name(encoder_type, encoder_model)
    feature_slots: List[Optional[np.ndarray]] = [None] * total
    missing_indices: List[int] = []
    cache_hits = 0
    cache_misses = 0
    cache_errors = 0
    cache_keys: List[str] = [""] * total
    if records and len(records) == total:
        for idx, record in enumerate(records):
            crop_key = str(record.get("crop_cache_key") or "").strip()
            if not crop_key:
                cache_misses += 1
                missing_indices.append(idx)
                continue
            cache_key = _class_analysis_embedding_cache_key(crop_key, head)
            cache_keys[idx] = cache_key
            cache_path = _class_analysis_embedding_cache_path(cache_key)
            if cache_path.exists():
                cached = _class_analysis_load_cached_embedding(cache_path)
                if cached is not None:
                    feature_slots[idx] = cached
                    cache_hits += 1
                    _close_crop_item(crops[idx])
                    continue
                else:
                    cache_errors += 1
            cache_misses += 1
            missing_indices.append(idx)
    else:
        missing_indices = list(range(total))
        cache_misses = total
    batch_count = int(math.ceil(len(missing_indices) / resolved_batch)) if missing_indices else 0
    started_at = time.time()
    if cache_stats is not None:
        cache_stats.update(
            {
                "hits": int(cache_hits),
                "misses": int(cache_misses),
                "errors": int(cache_errors),
                "total": int(total),
            }
        )
    with CLASS_ANALYSIS_JOBS_LOCK:
        _class_analysis_update(
            job,
            progress=progress_start,
            message=(
                f"Preparing {encoder_label} for {total} crops "
                f"({cache_hits} cache hits, {len(missing_indices)} to encode) ..."
            ),
        )
    if not missing_indices:
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(
                job,
                progress=progress_end,
                message=f"Loaded {total}/{total} cached embeddings for {encoder_label}.",
            )
        stacked = np.stack([np.asarray(item, dtype=np.float32) for item in feature_slots if item is not None], axis=0)
        return stacked.astype(np.float32, copy=False)
    done_encoded = 0
    for batch_index, start in enumerate(range(0, len(missing_indices), resolved_batch), start=1):
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        end = min(len(missing_indices), start + resolved_batch)
        batch_indices = missing_indices[start:end]
        batch_progress = progress_start + (progress_end - progress_start) * ((cache_hits + done_encoded) / max(1, total))
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(
                job,
                progress=batch_progress,
                message=(
                    f"Encoding crops with {encoder_label}: batch {batch_index}/{batch_count} "
                    f"({cache_hits + done_encoded}-{cache_hits + done_encoded + len(batch_indices)} of {total}, "
                    f"{cache_hits} cached) ..."
                ),
            )
        batch_features = _encode_embedding_items_for_head(
            [crops[idx] for idx in batch_indices],
            head=head,
            batch_size_override=resolved_batch,
        )
        if batch_features is None or batch_features.size == 0:
            return None
        batch_arr = np.asarray(batch_features, dtype=np.float32)
        if batch_arr.shape[0] != len(batch_indices):
            return None
        for local_idx, record_idx in enumerate(batch_indices):
            feature = batch_arr[local_idx].astype(np.float32, copy=False)
            feature_slots[record_idx] = feature
            cache_key = cache_keys[record_idx]
            if cache_key:
                cache_path = _class_analysis_embedding_cache_path(cache_key)
                try:
                    cache_root = _class_analysis_cache_storage_root(create=True)
                    if cache_root is None:
                        raise OSError("class_analysis_cache_root_forbidden")
                    _class_analysis_write_npy(
                        cache_path,
                        cache_root,
                        feature,
                    )
                except Exception:
                    cache_errors += 1
        for crop in [crops[idx] for idx in batch_indices]:
            _close_crop_item(crop)
        done_encoded += len(batch_indices)
        done = cache_hits + done_encoded
        progress = progress_start + (progress_end - progress_start) * (done / max(1, total))
        speed = _class_analysis_progress_message(done=done, total=total, started_at=started_at)
        speed_text = f" • {speed}" if speed else ""
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(
                job,
                progress=progress,
                message=f"Encoded {done}/{total} crops with {encoder_label}{speed_text}.",
            )
    if cache_stats is not None:
        cache_stats.update(
            {
                "hits": int(cache_hits),
                "misses": int(cache_misses),
                "errors": int(cache_errors),
                "total": int(total),
            }
        )
    if any(item is None for item in feature_slots):
        return None
    return np.stack([np.asarray(item, dtype=np.float32) for item in feature_slots], axis=0).astype(np.float32, copy=False)


def _class_analysis_collect_records(
    payload: Dict[str, Any],
    *,
    job: ClassAnalysisJob,
    out_dir: Path,
) -> Tuple[List[Dict[str, Any]], List[Any], Dict[str, Any]]:
    source = _class_analysis_source(payload)
    manifest = source["manifest"]
    labelmap = [str(x) for x in source.get("labelmap") or []]
    scope = str(payload.get("analysis_scope") or "selected_class").strip().lower()
    if scope not in {"selected_class", "all_classes"}:
        scope = "selected_class"
    selected_class = str(payload.get("class_name") or "").strip()
    if scope == "selected_class" and not selected_class:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="class_name_required")
    crop_mode = str(payload.get("crop_mode") or "padded_square").strip().lower()
    padding_ratio = _coerce_float(payload.get("padding_ratio"), 0.08, minimum=0.0, maximum=1.0)
    preprocess_mode = _class_analysis_normalize_preprocess_mode(payload.get("preprocess_mode"))
    canonical_size = min(1024, _coerce_int(payload.get("canonical_size"), 336, minimum=64))
    background_mode = _embedding_normalize_background_mode(payload.get("background_mode"))
    embedding_view_mode = _embedding_normalize_view_mode(payload.get("embedding_view_mode"))
    encoder_type_for_cache = str(payload.get("encoder_type") or "dinov3").strip().lower()
    if encoder_type_for_cache not in {"clip", "dinov3", "cradio"}:
        encoder_type_for_cache = "dinov3"
    encoder_model_for_cache = str(payload.get("encoder_model") or "").strip()
    if not encoder_model_for_cache:
        if encoder_type_for_cache == "clip":
            encoder_model_for_cache = DEFAULT_CLIP_MODEL
        elif encoder_type_for_cache == "cradio":
            encoder_model_for_cache = CRADIO_DEFAULT_MODEL
        else:
            encoder_model_for_cache = CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
    embedding_head_for_cache = {
        "encoder_type": encoder_type_for_cache,
        "encoder_model": encoder_model_for_cache,
        "clip_model": encoder_model_for_cache,
        "normalize_embeddings": True,
        "dinov3_pooling": _embedding_normalize_dinov3_pooling(payload.get("dinov3_pooling")),
        "cradio_pooling": normalize_cradio_pooling(payload.get("cradio_pooling")),
        "embedding_aggregation": _embedding_normalize_aggregation(payload.get("embedding_aggregation")),
        "embedding_salad_head_id": str(payload.get("embedding_salad_head_id") or "").strip(),
    }
    seed = _coerce_int(payload.get("seed"), 42)
    sample_cap = _class_analysis_sample_cap(payload.get("sample_cap"))
    defer_crop_materialization = sample_cap > 0
    rows = list(manifest.get("images") or [])
    raw_records: List[Dict[str, Any]] = []
    raw_crops: List[Any] = []
    thumb_dir = out_dir / "thumbnails"
    if _class_analysis_prepare_dir(thumb_dir, out_dir) is None:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="class_analysis_path_invalid")
    total_candidate_objects = 0
    source_key = str(source.get("source_key") or "source")
    row_count = max(1, len(rows))
    progress_started_at = time.time()
    last_progress_at = 0.0
    image_hashes: Dict[str, str] = {}

    def materialize_crop_for_record(record: Dict[str, Any]) -> Tuple[Any, List[Dict[str, Any]], bool]:
        crop_cache_key = str(record.get("crop_cache_key") or "").strip()
        point_id = str(record.get("point_id") or "").strip()
        thumb_path = thumb_dir / f"{point_id}.jpg"
        cached_thumb = _class_analysis_thumbnail_cache_path(crop_cache_key)
        cache_root = _class_analysis_cache_storage_root(create=False)
        can_reuse = bool(
            cache_root is not None
            and crop_cache_key
            and point_id
            and cached_thumb.exists()
            and _class_analysis_cached_embedding_valid(crop_cache_key, embedding_head_for_cache)
        )
        if can_reuse:
            try:
                if not _class_analysis_copy_file_within_roots(
                    cached_thumb,
                    thumb_path,
                    source_root=cache_root,
                    dest_root=out_dir,
                ):
                    raise OSError("class_analysis_thumbnail_cache_forbidden")
                return Image.new("RGB", (1, 1), (0, 0, 0)), [], True
            except Exception:
                can_reuse = False
        image_path_value = str(record.get("_image_path") or "").strip()
        if not image_path_value:
            split_value = _annotation_normalise_split(record.get("split"))
            rel_value = _annotation_normalise_image_relpath(record.get("image_relpath"))
            image_path = _resolve_annotation_image_path(
                Path(source["dataset_root"]),
                str(source.get("yolo_layout") or "flat"),
                split_value,
                rel_value,
            )
        else:
            image_path = Path(image_path_value)
        with Image.open(image_path) as loaded_img:
            pil_for_crop = loaded_img.convert("RGB")
        try:
            views, selected_crop_bounds, selected_view_metadata = _embedding_make_crop_views(
                pil_for_crop,
                record.get("bbox_xyxy") or [0, 0, 1, 1],
                crop_mode=crop_mode,
                padding_ratio=padding_ratio,
                preprocess_mode=preprocess_mode,
                canonical_size=canonical_size,
                background_mode=background_mode,
                view_mode=embedding_view_mode,
            )
            embedding_crop_item = tuple(views) if len(views) > 1 else views[0]
            record["crop_xyxy"] = [int(v) for v in selected_crop_bounds]
            thumb = pil_for_crop.crop(selected_crop_bounds).copy()
            thumb.thumbnail((256, 256))
            try:
                thumb_write_path = _class_analysis_write_jpeg(thumb_path, out_dir, thumb)
                if crop_cache_key:
                    cache_dest_root = _class_analysis_cache_storage_root(create=True)
                    if cache_dest_root is not None:
                        _class_analysis_copy_file_within_roots(
                            thumb_write_path,
                            cached_thumb,
                            source_root=out_dir,
                            dest_root=cache_dest_root,
                        )
            finally:
                try:
                    thumb.close()
                except Exception:
                    pass
            return embedding_crop_item, selected_view_metadata, False
        finally:
            try:
                pil_for_crop.close()
            except Exception:
                pass

    for row_idx, row in enumerate(rows):
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        split = _annotation_normalise_split(row.get("split"))
        rel = _annotation_normalise_image_relpath(row.get("image_relpath") or row.get("image_name"))
        label_lines = [str(line).strip() for line in (row.get("label_lines") or []) if str(line).strip()]
        if not label_lines:
            continue
        try:
            image_path = _resolve_annotation_image_path(
                Path(source["dataset_root"]),
                str(source.get("yolo_layout") or "flat"),
                split,
                rel,
            )
            image_hash_key = str(image_path)
            if image_hash_key not in image_hashes:
                image_hashes[image_hash_key] = _class_analysis_file_sha256(image_path)
            with Image.open(image_path) as loaded_img:
                pil_img = loaded_img.convert("RGB")
        except Exception as exc:
            _class_analysis_log(job, f"Skipped {split}/{rel.as_posix()}: {exc}")
            continue
        try:
            image_width, image_height = pil_img.size
            for line_idx, line in enumerate(label_lines):
                now = time.time()
                if now - last_progress_at >= 1.0:
                    progress = 0.02 + 0.14 * (row_idx / row_count)
                    speed = _class_analysis_progress_message(
                        done=max(1, row_idx),
                        total=row_count,
                        started_at=progress_started_at,
                    )
                    speed_text = f" • {speed}" if speed else ""
                    with CLASS_ANALYSIS_JOBS_LOCK:
                        _class_analysis_update(
                            job,
                            progress=progress,
                            message=(
                                f"Collecting crops: image {row_idx + 1}/{len(rows)}, "
                                f"{len(raw_records)} objects queued{speed_text}."
                            ),
                        )
                    last_progress_at = now
                parsed = _class_analysis_parse_yolo_geometry(
                    line, image_width=image_width, image_height=image_height
                )
                if not parsed:
                    continue
                class_id = int(parsed["class_id"])
                class_name = labelmap[class_id] if 0 <= class_id < len(labelmap) else f"class_{class_id}"
                if scope == "selected_class" and class_name != selected_class:
                    continue
                total_candidate_objects += 1
                primary_crop_mode, primary_padding_ratio, _primary_view = _embedding_view_specs(
                    crop_mode=crop_mode,
                    padding_ratio=padding_ratio,
                    view_mode=embedding_view_mode,
                )[0]
                crop_bounds = _class_analysis_crop_bounds(
                    parsed["bbox_xyxy"],
                    image_width=image_width,
                    image_height=image_height,
                    crop_mode=primary_crop_mode,
                    padding_ratio=primary_padding_ratio,
                )
                crop_cache_key = _class_analysis_cache_digest(
                    {
                        "version": CLASS_ANALYSIS_CACHE_VERSION,
                        "image_sha256": image_hashes.get(str(image_path), ""),
                        "bbox_xyxy": [round(float(v), 4) for v in parsed["bbox_xyxy"]],
                        "crop_xyxy": [int(v) for v in crop_bounds],
                        "crop_mode": crop_mode,
                        "padding_ratio": round(float(padding_ratio), 6),
                        "preprocess_mode": preprocess_mode,
                        "canonical_size": int(canonical_size),
                        "background_mode": background_mode,
                        "embedding_view_mode": embedding_view_mode,
                    }
                )
                cached_thumb = _class_analysis_thumbnail_cache_path(crop_cache_key)
                cache_root = _class_analysis_cache_storage_root(create=False)
                point_seed = "|".join(
                    [
                        source_key,
                        split,
                        rel.as_posix(),
                        str(line_idx),
                        str(class_id),
                        ",".join(str(round(float(v), 2)) for v in parsed["bbox_xyxy"]),
                    ]
                )
                point_id = hashlib.sha1(point_seed.encode("utf-8")).hexdigest()[:20]
                thumb_path = thumb_dir / f"{point_id}.jpg"
                can_reuse_crop = (
                    cache_root is not None
                    and cached_thumb.exists()
                    and _class_analysis_cached_embedding_valid(
                        crop_cache_key,
                        embedding_head_for_cache,
                    )
                )
                if defer_crop_materialization:
                    embedding_crop = None
                    view_metadata = []
                elif can_reuse_crop:
                    try:
                        if not _class_analysis_copy_file_within_roots(
                            cached_thumb,
                            thumb_path,
                            source_root=cache_root,
                            dest_root=out_dir,
                        ):
                            raise OSError("class_analysis_thumbnail_cache_forbidden")
                    except Exception:
                        can_reuse_crop = False
                if can_reuse_crop:
                    embedding_crop = Image.new("RGB", (1, 1), (0, 0, 0))
                    view_metadata = []
                else:
                    views, crop_bounds, view_metadata = _embedding_make_crop_views(
                        pil_img,
                        parsed["bbox_xyxy"],
                        crop_mode=crop_mode,
                        padding_ratio=padding_ratio,
                        preprocess_mode=preprocess_mode,
                        canonical_size=canonical_size,
                        background_mode=background_mode,
                        view_mode=embedding_view_mode,
                    )
                    embedding_crop = tuple(views) if len(views) > 1 else views[0]
                    thumb = pil_img.crop(crop_bounds).copy()
                    thumb.thumbnail((256, 256))
                    try:
                        thumb_write_path = _class_analysis_write_jpeg(thumb_path, out_dir, thumb)
                        cache_dest_root = _class_analysis_cache_storage_root(create=True)
                        if cache_dest_root is not None:
                            _class_analysis_copy_file_within_roots(
                                thumb_write_path,
                                cached_thumb,
                                source_root=out_dir,
                                dest_root=cache_dest_root,
                            )
                    except Exception:
                        pass
                    try:
                        thumb.close()
                    except Exception:
                        pass
                raw_records.append(
                    {
                        "point_id": point_id,
                        "source_mode": source.get("source_mode"),
                        "source_id": source.get("source_id"),
                        "source_key": source_key,
                        "split": split,
                        "image_relpath": rel.as_posix(),
                        "frontend_image_key": str(row.get("frontend_image_key") or row.get("image_key") or ""),
                        "image_name": row.get("image_name") or rel.name,
                        "image_row_index": row_idx,
                        "label_line_index": line_idx,
                        "label_line": line,
                        "class_id": class_id,
                        "class_name": class_name,
                        "kind": parsed.get("kind") or "bbox",
                        "bbox_xyxy": [round(float(v), 3) for v in parsed["bbox_xyxy"]],
                        "crop_xyxy": [int(v) for v in crop_bounds],
                        "width": int(round(float(parsed["bbox_xyxy"][2]) - float(parsed["bbox_xyxy"][0]))),
                        "height": int(round(float(parsed["bbox_xyxy"][3]) - float(parsed["bbox_xyxy"][1]))),
                        "background_mode": background_mode,
                        "embedding_view_mode": embedding_view_mode,
                        "embedding_views": view_metadata,
                        "crop_cache_key": crop_cache_key,
                        "crop_cache_reused": bool(can_reuse_crop),
                        "thumbnail_url": f"/class_analysis/jobs/{job.job_id}/thumbnail/{point_id}",
                        "_image_path": str(image_path) if defer_crop_materialization else "",
                    }
                )
                raw_crops.append(embedding_crop)
        finally:
            try:
                pil_img.close()
            except Exception:
                pass
        if time.time() - last_progress_at >= 0.75 or row_idx == len(rows) - 1:
            progress = 0.02 + 0.14 * ((row_idx + 1) / row_count)
            speed = _class_analysis_progress_message(
                done=row_idx + 1,
                total=row_count,
                started_at=progress_started_at,
            )
            speed_text = f" • {speed}" if speed else ""
            with CLASS_ANALYSIS_JOBS_LOCK:
                _class_analysis_update(
                    job,
                    progress=progress,
                    message=(
                        f"Collected crops from {row_idx + 1}/{len(rows)} images, "
                        f"{len(raw_records)} objects queued{speed_text}."
                    ),
                )
            last_progress_at = time.time()
    selected_indices = _class_analysis_stratified_indices(raw_records, cap=sample_cap, seed=seed)
    records = [raw_records[idx] for idx in selected_indices]
    if defer_crop_materialization:
        crops = []
        materialized_records: List[Dict[str, Any]] = []
        materialize_started_at = time.time()
        for idx, record in enumerate(records):
            if job.cancel_event.is_set():
                raise RuntimeError("cancelled")
            if idx == 0 or idx % 25 == 0 or idx == len(records) - 1:
                progress = 0.16 + 0.02 * (idx / max(1, len(records)))
                speed = _class_analysis_progress_message(
                    done=max(1, idx),
                    total=max(1, len(records)),
                    started_at=materialize_started_at,
                )
                speed_text = f" • {speed}" if speed else ""
                with CLASS_ANALYSIS_JOBS_LOCK:
                    _class_analysis_update(
                        job,
                        progress=progress,
                        message=f"Preparing selected crops: {idx + 1}/{len(records)}{speed_text}.",
                    )
            try:
                crop_item, view_metadata, reused_crop = materialize_crop_for_record(record)
            except Exception as exc:
                _class_analysis_log(job, f"Skipped sampled crop {record.get('image_name') or record.get('image_relpath')}: {exc}")
                continue
            record["embedding_views"] = view_metadata
            record["crop_cache_reused"] = bool(reused_crop)
            record.pop("_image_path", None)
            materialized_records.append(record)
            crops.append(crop_item)
        records = materialized_records
    else:
        selected_index_set = set(selected_indices)
        for idx, crop_item in enumerate(raw_crops):
            if idx not in selected_index_set:
                _close_crop_item(crop_item)
        crops = [raw_crops[idx] for idx in selected_indices]
        for record in records:
            record.pop("_image_path", None)
    summary = {
        "source_mode": source.get("source_mode"),
        "source_id": source.get("source_id"),
        "source_key": source_key,
        "dataset_label": manifest.get("dataset_label"),
        "analysis_scope": scope,
        "selected_class": selected_class if scope == "selected_class" else "",
        "labelmap": labelmap,
        "image_count": len(rows),
        "total_candidate_objects": total_candidate_objects,
        "sampled": len(records) < len(raw_records),
        "object_count": len(records),
        "raw_object_count": len(raw_records),
        "sample_cap": sample_cap,
        "crop_mode": crop_mode,
        "padding_ratio": padding_ratio,
        "preprocess_mode": preprocess_mode,
        "canonical_size": canonical_size,
        "background_mode": background_mode,
        "embedding_view_mode": embedding_view_mode,
        "dinov3_pooling": _embedding_normalize_dinov3_pooling(payload.get("dinov3_pooling")),
        "embedding_aggregation": _embedding_normalize_aggregation(payload.get("embedding_aggregation")),
        "embedding_salad_head_id": str(payload.get("embedding_salad_head_id") or "").strip(),
        "crop_cache": {
            "reused": sum(1 for record in records if record.get("crop_cache_reused")),
            "total": len(records),
        },
    }
    return records, crops, summary


def _class_analysis_project_embeddings(
    embeddings: np.ndarray,
    *,
    projection: str,
    projection_neighbor_k: int,
    seed: int,
    warnings: List[str],
) -> Tuple[np.ndarray, str]:
    n_samples = int(embeddings.shape[0])
    if n_samples <= 1:
        return np.zeros((n_samples, 2), dtype=np.float32), "single"
    projection_norm = str(projection or "pca").strip().lower()
    if projection_norm == "umap":
        try:
            import umap
            resolved_neighbors = int(projection_neighbor_k or 50)
            if resolved_neighbors <= 0:
                resolved_neighbors = n_samples - 1
            resolved_neighbors = max(2, min(resolved_neighbors, n_samples - 1))

            reducer = umap.UMAP(
                n_components=2,
                n_neighbors=resolved_neighbors,
                min_dist=0.08,
                metric="cosine",
                random_state=int(seed),
            )
            return reducer.fit_transform(embeddings).astype(np.float32), "umap"
        except Exception as exc:
            warnings.append(f"UMAP unavailable; used PCA fallback ({exc}).")
    n_components = 2 if min(embeddings.shape) >= 2 else 1
    coords = PCA(n_components=n_components, random_state=int(seed)).fit_transform(embeddings)
    if coords.shape[1] == 1:
        coords = np.concatenate([coords, np.zeros((coords.shape[0], 1), dtype=coords.dtype)], axis=1)
    return coords.astype(np.float32), "pca"


def _class_analysis_cluster_embeddings(
    embeddings: np.ndarray,
    *,
    seed: int,
    max_k: int,
) -> Tuple[np.ndarray, Dict[str, Any]]:
    n_samples = int(embeddings.shape[0])
    if n_samples < 4:
        return np.zeros(n_samples, dtype=int), {
            "method": "none",
            "best_k": 1 if n_samples else 0,
            "candidates": [],
            "clusters": [],
        }
    best_labels: Optional[np.ndarray] = None
    best_score = -999.0
    candidates: List[Dict[str, Any]] = []
    upper_k = max(2, min(int(max_k or 8), 8, n_samples - 1))
    for k in range(2, upper_k + 1):
        try:
            model = MiniBatchKMeans(
                n_clusters=k,
                random_state=int(seed),
                batch_size=max(64, k * 16),
                n_init=5,
            )
            labels = model.fit_predict(embeddings)
            if len(set(labels.tolist())) < 2:
                continue
            sample_size = min(2000, n_samples) if n_samples > 2000 else None
            score = float(
                silhouette_score(
                    embeddings,
                    labels,
                    metric="cosine",
                    sample_size=sample_size,
                    random_state=int(seed) if sample_size else None,
                )
            )
            candidates.append({"k": k, "silhouette": score})
            if best_labels is None or score > best_score:
                best_score = score
                best_labels = labels
        except Exception as exc:
            candidates.append({"k": k, "error": str(exc)})
    if best_labels is None:
        return np.zeros(n_samples, dtype=int), {"method": "kmeans", "best_k": 1, "candidates": candidates, "clusters": []}
    valid_scores = [c for c in candidates if "silhouette" in c]
    best_candidate = max(valid_scores, key=lambda c: float(c["silhouette"])) if valid_scores else {"k": 1}
    return best_labels.astype(int), {
        "method": "kmeans",
        "best_k": int(best_candidate.get("k") or 1),
        "candidates": candidates,
        "clusters": [],
    }


def _class_analysis_build_result(
    records: List[Dict[str, Any]],
    embeddings: np.ndarray,
    *,
    summary: Dict[str, Any],
    projection: str,
    projection_neighbor_k: int,
    neighbor_k: int,
    seed: int,
) -> Dict[str, Any]:
    warnings: List[str] = []
    n_samples = len(records)
    coords, projection_used = _class_analysis_project_embeddings(
        embeddings,
        projection=projection,
        projection_neighbor_k=projection_neighbor_k,
        seed=seed,
        warnings=warnings,
    )
    diagnostics = _class_analysis_projection_diagnostics(records, coords)
    labels, cluster_summary = _class_analysis_cluster_embeddings(
        embeddings, seed=seed, max_k=8
    )
    neighbor_count = min(max(1, int(neighbor_k or 15)) + 1, max(1, n_samples))
    neighbor_ids_by_idx: List[List[int]] = [[] for _ in records]
    neighbor_dist_by_idx: List[List[float]] = [[] for _ in records]
    if n_samples >= 2:
        nn = NearestNeighbors(n_neighbors=neighbor_count, metric="cosine")
        nn.fit(embeddings)
        distances, indices = nn.kneighbors(embeddings, return_distance=True)
        for idx in range(n_samples):
            pairs = [
                (int(j), float(d))
                for j, d in zip(indices[idx].tolist(), distances[idx].tolist())
                if int(j) != idx
            ][: max(1, int(neighbor_k or 15))]
            neighbor_ids_by_idx[idx] = [p[0] for p in pairs]
            neighbor_dist_by_idx[idx] = [p[1] for p in pairs]
    cluster_centroids: Dict[int, np.ndarray] = {}
    for cluster_id in sorted(set(labels.tolist())):
        idxs = np.flatnonzero(labels == cluster_id)
        if idxs.size:
            cluster_centroids[int(cluster_id)] = embeddings[idxs].mean(axis=0)
    raw_outlier = np.zeros(n_samples, dtype=np.float32)
    for idx in range(n_samples):
        centroid = cluster_centroids.get(int(labels[idx]))
        if centroid is not None:
            raw_outlier[idx] = float(np.linalg.norm(embeddings[idx] - centroid))
    outlier_scores = np.zeros(n_samples, dtype=np.float32)
    for cluster_id in sorted(set(labels.tolist())):
        idxs = np.flatnonzero(labels == cluster_id)
        vals = raw_outlier[idxs]
        if vals.size <= 1:
            continue
        lo = float(vals.min())
        hi = float(vals.max())
        if hi > lo:
            outlier_scores[idxs] = (vals - lo) / (hi - lo)
    scope = str(summary.get("analysis_scope") or "")
    points: List[Dict[str, Any]] = []
    wrong_class_candidates: List[Dict[str, Any]] = []
    for idx, record in enumerate(records):
        neighbor_indices = neighbor_ids_by_idx[idx]
        neighbor_classes = [str(records[n].get("class_name") or "") for n in neighbor_indices]
        counts = Counter(neighbor_classes)
        current_class = str(record.get("class_name") or "")
        total_neighbors = max(1, len(neighbor_classes))
        same_ratio = float(counts.get(current_class, 0) / total_neighbors)
        other_counts = {cls: count for cls, count in counts.items() if cls and cls != current_class}
        suggested_class = ""
        top_other_ratio = 0.0
        if other_counts:
            suggested_class, top_count = max(other_counts.items(), key=lambda item: item[1])
            top_other_ratio = float(top_count / total_neighbors)
        suspicion_score = max(0.0, top_other_ratio - same_ratio)
        is_suspicious = bool(
            scope == "all_classes" and top_other_ratio >= 0.65 and same_ratio <= 0.35
        )
        point = {
            **record,
            "projection": [float(coords[idx, 0]), float(coords[idx, 1])],
            "cluster_id": int(labels[idx]) if n_samples else 0,
            "outlier_score": float(outlier_scores[idx]),
            "neighbor_ids": [records[n]["point_id"] for n in neighbor_indices],
            "neighbor_distances": neighbor_dist_by_idx[idx],
            "neighbor_class_counts": dict(counts),
            "same_class_neighbor_ratio": same_ratio,
            "top_other_neighbor_ratio": top_other_ratio,
            "suggested_neighbor_class": suggested_class,
            "wrong_class_suspicion": suspicion_score,
            "is_wrong_class_candidate": is_suspicious,
        }
        points.append(point)
        if is_suspicious:
            wrong_class_candidates.append(
                {
                    "point_id": point["point_id"],
                    "class_name": current_class,
                    "suggested_neighbor_class": suggested_class,
                    "wrong_class_suspicion": suspicion_score,
                    "top_other_neighbor_ratio": top_other_ratio,
                    "same_class_neighbor_ratio": same_ratio,
                    "image_relpath": point["image_relpath"],
                }
            )
    clusters: List[Dict[str, Any]] = []
    for cluster_id in sorted(set(labels.tolist())) if n_samples else []:
        idxs = np.flatnonzero(labels == cluster_id)
        if idxs.size == 0:
            continue
        centroid = embeddings[idxs].mean(axis=0)
        distances = np.linalg.norm(embeddings[idxs] - centroid, axis=1)
        medoid_idx = int(idxs[int(np.argmin(distances))])
        clusters.append(
            {
                "cluster_id": int(cluster_id),
                "size": int(idxs.size),
                "class_counts": dict(Counter(str(records[i].get("class_name") or "") for i in idxs)),
                "medoid_point_id": records[medoid_idx]["point_id"],
                "mean_outlier_score": float(outlier_scores[idxs].mean()) if idxs.size else 0.0,
            }
        )
    class_counts = Counter(str(point.get("class_name") or "") for point in points)
    projection_neighbor_raw = int(projection_neighbor_k if projection_neighbor_k is not None else 50)
    if projection_used == "umap":
        projection_neighbor_resolved = n_samples - 1 if projection_neighbor_raw <= 0 else projection_neighbor_raw
        projection_neighbor_resolved = max(2, min(projection_neighbor_resolved, max(1, n_samples - 1)))
    else:
        projection_neighbor_resolved = None
    summary = {
        **summary,
        "projection": projection_used,
        "projection_neighbor_k": projection_neighbor_raw,
        "projection_neighbor_k_resolved": projection_neighbor_resolved,
        "neighbor_k": int(neighbor_k or 15),
        "class_counts": dict(class_counts),
        "cluster_count": len(clusters),
        "wrong_class_candidate_count": len(wrong_class_candidates),
        "warnings": warnings,
    }
    cluster_summary["clusters"] = clusters
    return {
        "summary": summary,
        "points": points,
        "clusters": cluster_summary,
        "diagnostics": diagnostics,
        "wrong_class_candidates": sorted(
            wrong_class_candidates,
            key=lambda item: float(item.get("wrong_class_suspicion") or 0.0),
            reverse=True,
        ),
    }


def _run_class_analysis_job(job: ClassAnalysisJob) -> None:
    try:
        out_dir = _class_analysis_job_dir(job.job_id, create=True)
        job.thumbnail_dir = str(out_dir / "thumbnails")
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(job, status="running", progress=0.02, message="Collecting crops ...")
        records, crops, summary = _class_analysis_collect_records(job.request, job=job, out_dir=out_dir)
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        if len(records) < 2:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="not_enough_objects_for_analysis")
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(
                job,
                progress=0.18,
                message=f"Encoding {len(records)} crops with {job.request.get('encoder_type') or 'dinov3'} ...",
            )
        encoder_type = str(job.request.get("encoder_type") or "dinov3").strip().lower()
        if encoder_type not in {"clip", "dinov3", "cradio"}:
            encoder_type = "dinov3"
        encoder_model = str(job.request.get("encoder_model") or "").strip()
        if encoder_type == "clip":
            encoder_model = encoder_model or DEFAULT_CLIP_MODEL
        elif encoder_type == "cradio":
            encoder_model = normalize_cradio_model(encoder_model)
        else:
            encoder_model = encoder_model or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
        batch_size = _coerce_int(job.request.get("batch_size"), 64, minimum=1)
        cache_stats: Dict[str, int] = {}
        feats = _class_analysis_encode_crops(
            crops,
            job=job,
            head={
                "encoder_type": encoder_type,
                "encoder_model": encoder_model,
                "clip_model": encoder_model,
                "normalize_embeddings": True,
                "dinov3_pooling": _embedding_normalize_dinov3_pooling(job.request.get("dinov3_pooling")),
                "cradio_pooling": normalize_cradio_pooling(job.request.get("cradio_pooling")),
                "embedding_aggregation": _embedding_normalize_aggregation(job.request.get("embedding_aggregation")),
                "embedding_salad_head_id": str(job.request.get("embedding_salad_head_id") or "").strip(),
            },
            batch_size=batch_size,
            records=records,
            cache_stats=cache_stats,
        )
        if feats is None or feats.size == 0:
            raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="embedding_failed")
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        embeddings = np.asarray(feats, dtype=np.float32)
        raw_embeddings = _class_analysis_normalize_rows(embeddings)
        embedding_adjustment = _class_analysis_normalize_embedding_adjustment(job.request.get("embedding_adjustment"))
        embeddings, adjustment_info = _class_analysis_apply_embedding_adjustment(
            raw_embeddings,
            records,
            mode=embedding_adjustment,
        )
        _class_analysis_write_npz(
            out_dir / "embeddings.npz",
            out_dir,
            embeddings=embeddings,
            raw_embeddings=raw_embeddings,
        )
        metadata_text = "".join(
            json.dumps(_class_analysis_json_safe(record), ensure_ascii=False) + "\n"
            for record in records
        )
        _class_analysis_write_text(out_dir / "metadata.jsonl", out_dir, metadata_text)
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(job, progress=0.72, message="Projecting and scoring graph ...")
        result = _class_analysis_build_result(
            records,
            embeddings,
            summary={
                **summary,
                "encoder_type": encoder_type,
                "encoder_model": encoder_model,
                "dinov3_pooling": _embedding_normalize_dinov3_pooling(job.request.get("dinov3_pooling")),
                "cradio_pooling": normalize_cradio_pooling(job.request.get("cradio_pooling")),
                "embedding_aggregation": _embedding_normalize_aggregation(job.request.get("embedding_aggregation")),
                "embedding_salad_head_id": str(job.request.get("embedding_salad_head_id") or "").strip(),
                "embedding_adjustment": embedding_adjustment,
                "embedding_adjustment_info": adjustment_info,
                "embedding_cache": cache_stats,
            },
            projection=str(job.request.get("projection") or "pca"),
            projection_neighbor_k=_coerce_int(job.request.get("projection_neighbor_k"), 50, minimum=0),
            neighbor_k=_coerce_int(job.request.get("neighbor_k"), 15, minimum=1),
            seed=_coerce_int(job.request.get("seed"), 42),
        )
        result_path = out_dir / "result.json"
        _class_analysis_write_json(result_path, out_dir, result)
        _class_analysis_write_json(out_dir / "config.json", out_dir, job.request)
        with CLASS_ANALYSIS_JOBS_LOCK:
            job.result_path = str(result_path)
            _class_analysis_update(
                job,
                status="completed",
                progress=1.0,
                message="Class analysis completed.",
                result=result,
            )
    except RuntimeError as exc:
        with CLASS_ANALYSIS_JOBS_LOCK:
            if str(exc) == "cancelled":
                _class_analysis_update(job, status="cancelled", progress=job.progress, message="Class analysis cancelled.")
            else:
                _class_analysis_update(job, status="failed", message=str(exc), error=str(exc))
    except HTTPException as exc:
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(job, status="failed", message=str(exc.detail), error=str(exc.detail))
    except Exception as exc:  # noqa: BLE001
        logger.exception("[class-analysis %s] job crashed", job.job_id[:8])
        with CLASS_ANALYSIS_JOBS_LOCK:
            _class_analysis_update(job, status="failed", message="Class analysis crashed.", error=str(exc))


def _normalize_class_analysis_request(payload: Dict[str, Any]) -> Dict[str, Any]:
    request_payload = dict(payload or {})
    request_payload.setdefault("analysis_scope", "selected_class")
    request_payload.setdefault("encoder_type", "dinov3")
    request_payload.setdefault("encoder_model", CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL)
    request_payload.setdefault("projection", "pca")
    request_payload.setdefault("projection_neighbor_k", 50)
    request_payload.setdefault("crop_mode", "padded_square")
    request_payload.setdefault("padding_ratio", 0.08)
    request_payload.setdefault("preprocess_mode", "canonical")
    request_payload.setdefault("canonical_size", 336)
    request_payload.setdefault("dinov3_pooling", "pooler")
    request_payload.setdefault("cradio_pooling", "summary")
    request_payload.setdefault("embedding_aggregation", "pooled")
    request_payload.setdefault("embedding_salad_head_id", "")
    request_payload.setdefault("background_mode", "full_crop")
    request_payload.setdefault("embedding_view_mode", "single")
    request_payload.setdefault("embedding_adjustment", "remove_size_bias")
    request_payload.setdefault("sample_cap", 0)
    request_payload.setdefault("neighbor_k", 15)
    request_payload["encoder_type"] = str(request_payload.get("encoder_type") or "dinov3").strip().lower()
    if request_payload["encoder_type"] not in {"clip", "dinov3", "cradio"}:
        request_payload["encoder_type"] = "dinov3"
    if not str(request_payload.get("encoder_model") or "").strip():
        if request_payload["encoder_type"] == "clip":
            request_payload["encoder_model"] = DEFAULT_CLIP_MODEL
        elif request_payload["encoder_type"] == "cradio":
            request_payload["encoder_model"] = CRADIO_DEFAULT_MODEL
        else:
            request_payload["encoder_model"] = CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
    if request_payload["encoder_type"] == "cradio":
        request_payload["cradio_pooling"] = normalize_cradio_pooling(request_payload.get("cradio_pooling"))
    request_payload["embedding_aggregation"] = _embedding_normalize_aggregation(
        request_payload.get("embedding_aggregation")
    )
    request_payload["embedding_salad_head_id"] = str(
        request_payload.get("embedding_salad_head_id") or ""
    ).strip()
    if request_payload["embedding_aggregation"] == "local_salad":
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_class_analysis_disabled")
    request_payload["embedding_salad_head_id"] = ""
    return request_payload


def _enqueue_class_analysis_job(request_payload: Dict[str, Any], *, job_id: Optional[str] = None) -> Dict[str, Any]:
    _prune_job_registry(CLASS_ANALYSIS_JOBS, CLASS_ANALYSIS_JOBS_LOCK)
    resolved_job_id = job_id or f"ca_{uuid.uuid4().hex[:10]}"
    job = ClassAnalysisJob(job_id=resolved_job_id, request=request_payload)
    with CLASS_ANALYSIS_JOBS_LOCK:
        _class_analysis_log(job, "Class analysis queued.")
    _register_job_and_start_thread(
        job=job,
        registry=CLASS_ANALYSIS_JOBS,
        lock=CLASS_ANALYSIS_JOBS_LOCK,
        target=_run_class_analysis_job,
        args=(job,),
        name=f"class-analysis-{resolved_job_id[:8]}",
    )
    return {"job_id": resolved_job_id}


def create_class_analysis_job(payload: Dict[str, Any]) -> Dict[str, Any]:
    request_payload = _normalize_class_analysis_request(payload)
    _class_analysis_source(request_payload)
    return _enqueue_class_analysis_job(request_payload)


async def create_class_analysis_active_workspace_job(manifest_json: str, files: List[UploadFile]) -> Dict[str, Any]:
    try:
        manifest_payload = json.loads(str(manifest_json or "{}"))
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_manifest_json_invalid") from exc
    if not isinstance(manifest_payload, dict):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_manifest_invalid")

    labelmap = [
        str(name or "").strip()
        for name in (manifest_payload.get("labelmap") or [])
        if str(name or "").strip()
    ]
    input_rows = list(manifest_payload.get("images") or [])
    if not labelmap:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_labelmap_required")
    if not input_rows:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_images_required")

    job_id = f"ca_{uuid.uuid4().hex[:10]}"
    out_dir: Optional[Path] = None
    queued = False
    try:
        out_dir = _class_analysis_job_dir(job_id, create=True)
        workspace_dir = out_dir / "active_workspace"
        images_dir = workspace_dir / "images"

        saved_uploads: Dict[str, str] = {}
        total_written = 0
        for upload in files or []:
            original_name = str(upload.filename or "").strip()
            if not original_name:
                continue
            safe_rel = _class_analysis_safe_relpath(original_name)
            safe_name = safe_rel.as_posix()
            if safe_name in saved_uploads:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_duplicate_upload")
            target = images_dir / safe_rel
            target_path = _class_analysis_prepare_write_path(target, workspace_dir)
            if target_path is None:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_path_invalid")
            tmp_target_path = _class_analysis_prepare_write_path(
                target_path.with_suffix(f"{target_path.suffix}.{uuid.uuid4().hex}.tmp"),
                workspace_dir,
            )
            if tmp_target_path is None:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_path_invalid")
            size = 0
            fd: Optional[int] = None
            try:
                flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
                if hasattr(os, "O_NOFOLLOW"):
                    flags |= os.O_NOFOLLOW
                fd = os.open(tmp_target_path, flags, 0o644)
                with os.fdopen(fd, "wb") as handle:
                    fd = None
                    while True:
                        chunk = await upload.read(1024 * 1024)
                        if not chunk:
                            break
                        size += len(chunk)
                        total_written += len(chunk)
                        if CLASS_ANALYSIS_ACTIVE_UPLOAD_MAX_BYTES and size > CLASS_ANALYSIS_ACTIVE_UPLOAD_MAX_BYTES:
                            raise HTTPException(
                                status_code=HTTP_413_CONTENT_TOO_LARGE,
                                detail="active_workspace_upload_too_large",
                            )
                        if (
                            CLASS_ANALYSIS_ACTIVE_UPLOAD_QUOTA_BYTES
                            and total_written > CLASS_ANALYSIS_ACTIVE_UPLOAD_QUOTA_BYTES
                        ):
                            raise HTTPException(
                                status_code=HTTP_413_CONTENT_TOO_LARGE,
                                detail="active_workspace_upload_quota_exceeded",
                            )
                        handle.write(chunk)
                if size <= 0:
                    raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_empty_upload")
                os.replace(tmp_target_path, target_path)
            finally:
                if fd is not None:
                    try:
                        os.close(fd)
                    except OSError:
                        pass
                if tmp_target_path.exists() or tmp_target_path.is_symlink():
                    tmp_target_path.unlink(missing_ok=True)
                close_fn = getattr(upload, "close", None)
                if callable(close_fn):
                    close_result = close_fn()
                    if hasattr(close_result, "__await__"):
                        await close_result
            saved_uploads[original_name] = safe_name
            saved_uploads[safe_name] = safe_name

        rows: List[Dict[str, Any]] = []
        uploaded_names = set(saved_uploads.values())
        for row in input_rows:
            if not isinstance(row, dict):
                continue
            source_rel = str(row.get("upload_name") or row.get("image_relpath") or row.get("image_name") or "").strip()
            if not source_rel:
                continue
            safe_rel = _class_analysis_safe_relpath(saved_uploads.get(source_rel) or source_rel)
            safe_name = safe_rel.as_posix()
            if safe_name not in uploaded_names:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_image_upload_missing")
            label_lines = [
                str(line or "").strip()
                for line in (row.get("label_lines") or [])
                if str(line or "").strip()
            ]
            if not label_lines:
                continue
            rows.append(
                {
                    "split": _annotation_normalise_split(row.get("split") or "train"),
                    "image_relpath": safe_name,
                    "image_name": str(row.get("image_name") or row.get("frontend_image_key") or safe_name),
                    "frontend_image_key": str(row.get("frontend_image_key") or row.get("image_key") or row.get("image_name") or ""),
                    "label_lines": label_lines,
                    "text_label": str(row.get("text_label") or ""),
                }
            )
        if not rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="active_workspace_no_labeled_rows")

        manifest_out = {
            "dataset_label": str(manifest_payload.get("dataset_label") or "Active Label Images workspace"),
            "labelmap": labelmap,
            "images": rows,
            "yolo_layout": "flat",
            "source_mode": "active_workspace",
        }
        manifest_path = workspace_dir / "manifest.json"
        _class_analysis_write_json(manifest_path, workspace_dir, manifest_out)

        request_options = manifest_payload.get("request") if isinstance(manifest_payload.get("request"), dict) else {}
        request_payload = _normalize_class_analysis_request(
            {
                **request_options,
                "source_mode": "active_workspace",
                "workspace_id": job_id,
                "workspace_dir": str(workspace_dir),
                "workspace_manifest_path": str(manifest_path),
                "yolo_layout": "flat",
                "labelmap": labelmap,
            }
        )
        result = _enqueue_class_analysis_job(request_payload, job_id=job_id)
        queued = True
        job = CLASS_ANALYSIS_JOBS.get(job_id)
        if job:
            _class_analysis_log(job, f"Active workspace snapshot queued with {len(rows)} images.")
        return result
    except Exception:
        if not queued and out_dir is not None:
            shutil.rmtree(out_dir, ignore_errors=True)
        raise


def _get_class_analysis_job(job_id: str) -> ClassAnalysisJob:
    with CLASS_ANALYSIS_JOBS_LOCK:
        job = CLASS_ANALYSIS_JOBS.get(str(job_id or ""))
    if not job:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="job_not_found")
    return job


def get_class_analysis_job(job_id: str) -> Dict[str, Any]:
    return _serialize_class_analysis_job(_get_class_analysis_job(job_id))


def _safe_job_result_json_path(raw_path: Optional[str], root: Path) -> Optional[Path]:
    if not raw_path:
        return None
    return _safe_existing_regular_file_within_root_impl(Path(str(raw_path)), root)


def get_class_analysis_result(job_id: str) -> Dict[str, Any]:
    job = _get_class_analysis_job(job_id)
    if isinstance(job.result, dict):
        return job.result
    result_path = _safe_job_result_json_path(job.result_path, CLASS_ANALYSIS_ROOT)
    if result_path is not None:
        return _load_json_metadata(result_path) or {}
    if job.status in {"queued", "running", "cancelling"}:
        raise HTTPException(status_code=HTTP_428_PRECONDITION_REQUIRED, detail="job_not_finished")
    raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="result_not_found")


def get_class_analysis_thumbnail(job_id: str, point_id: str):
    job = _get_class_analysis_job(job_id)
    point_clean = _class_analysis_safe_slug(point_id, "")
    if not point_clean:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="thumbnail_not_found")
    thumb_dir_raw = Path(job.thumbnail_dir or "")
    if thumb_dir_raw.is_symlink():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="thumbnail_not_found")
    try:
        thumb_dir = thumb_dir_raw.resolve(strict=True)
        class_root = CLASS_ANALYSIS_ROOT.resolve()
    except Exception:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="thumbnail_not_found") from None
    if not _path_is_within_root_impl(thumb_dir, class_root):
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="thumbnail_not_found")
    thumb_path = _safe_existing_regular_file_within_root_impl(
        thumb_dir / f"{point_clean}.jpg", thumb_dir
    )
    if thumb_path is None:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="thumbnail_not_found")
    return FileResponse(str(thumb_path), media_type="image/jpeg")


def cancel_class_analysis_job(job_id: str) -> Dict[str, Any]:
    job = _get_class_analysis_job(job_id)
    with CLASS_ANALYSIS_JOBS_LOCK:
        if job.status in {"completed", "failed", "cancelled"}:
            raise HTTPException(status_code=HTTP_428_PRECONDITION_REQUIRED, detail="job_not_cancellable")
        job.cancel_event.set()
        _class_analysis_update(job, status="cancelling", message="Cancellation requested ...")
    return {"status": job.status}


def _data_ingestion_log(job: DataIngestionJob, message: str) -> None:
    entry = {"timestamp": time.time(), "message": str(message or "")}
    job.logs.append(entry)
    if len(job.logs) > MAX_JOB_LOGS:
        job.logs[:] = job.logs[-MAX_JOB_LOGS:]
    job.message = str(message or "")
    job.updated_at = time.time()
    try:
        logger.info("[data-ingestion %s] %s", job.job_id[:8], message)
    except Exception:
        pass


def _data_ingestion_update(
    job: DataIngestionJob,
    *,
    status: Optional[str] = None,
    progress: Optional[float] = None,
    message: Optional[str] = None,
    error: Optional[str] = None,
    result: Optional[Dict[str, Any]] = None,
) -> None:
    if status is not None:
        job.status = status
    if progress is not None:
        job.progress = clamp_progress(progress, fallback=job.progress)
    if message is not None:
        if str(message or "") != str(job.message or ""):
            _data_ingestion_log(job, str(message or ""))
        else:
            job.message = str(message or "")
            job.updated_at = time.time()
    if error is not None:
        job.error = error
    if result is not None:
        job.result = result
        job.updated_at = time.time()


def _serialize_data_ingestion_job(job: DataIngestionJob) -> Dict[str, Any]:
    return {
        "job_id": job.job_id,
        "kind": job.kind,
        "status": job.status,
        "progress": json_sanitize(job.progress),
        "message": job.message,
        "request": json_sanitize(job.request),
        "logs": json_sanitize(job.logs),
        "summary": json_sanitize(
            (job.result or {}).get("summary") if isinstance(job.result, dict) else None
        ),
        "error": json_sanitize(job.error),
        "created_at": job.created_at,
        "updated_at": job.updated_at,
    }


def _data_ingestion_storage_root(
    *,
    create: bool = True,
    detail: str = "data_ingestion_path_invalid",
) -> Path:
    try:
        raw_root = DATA_INGESTION_ROOT
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("data ingestion root is a symlink")
        if create:
            raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("data ingestion root is a symlink")
        if raw_root.exists() and not raw_root.is_dir():
            raise ValueError("data ingestion root is not a directory")
        return raw_root.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _data_ingestion_job_dir(
    job_id: str,
    *,
    create: bool = False,
    detail: str = "data_ingestion_path_invalid",
) -> Path:
    safe_job_id = _class_analysis_safe_slug(str(job_id or ""), "job")
    try:
        root = _data_ingestion_storage_root(create=True, detail=detail)
        candidate = root / safe_job_id
        if _storage_path_has_symlink_component(candidate):
            raise ValueError("data ingestion job dir is a symlink")
        if create:
            candidate.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(candidate):
            raise ValueError("data ingestion job dir is a symlink")
        if candidate.exists() and not candidate.is_dir():
            raise ValueError("data ingestion job path is not a directory")
        resolved = candidate.resolve(strict=False)
        if not _path_is_within_root_impl(resolved, root) or resolved.parent != root:
            raise ValueError("data ingestion job path escapes root")
        return resolved
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _cleanup_data_ingestion_job_dir(root_dir: Optional[Path]) -> None:
    if root_dir is None:
        return
    try:
        raw_root = Path(root_dir)
        if raw_root.is_symlink():
            raw_root.unlink(missing_ok=True)
            return
        if _storage_path_has_symlink_component(raw_root.parent):
            return
        ingestion_root = _data_ingestion_storage_root(create=False)
        resolved = raw_root.resolve(strict=True)
    except Exception:
        return
    if (
        not resolved.is_dir()
        or not _path_is_within_root_impl(resolved, ingestion_root)
        or resolved.parent != ingestion_root
    ):
        return
    shutil.rmtree(resolved, ignore_errors=True)


def _local_salad_head_path(head_id: str) -> Path:
    safe = _class_analysis_safe_slug(str(head_id or ""), "")
    if not safe:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_id_required")
    return _local_salad_head_root(create=False) / f"{safe}.pt"


def _local_salad_head_root(*, create: bool = False) -> Path:
    try:
        raw_root = LOCAL_SALAD_HEAD_ROOT
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("local SALAD head root is a symlink")
        if create:
            raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("local SALAD head root is a symlink")
        if raw_root.exists() and not raw_root.is_dir():
            raise ValueError("local SALAD head root is not a directory")
        return raw_root.resolve(strict=False)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_path_invalid") from exc


def _unique_local_salad_head_id(requested_name: str) -> str:
    base = _class_analysis_safe_slug(str(requested_name or ""), f"local_salad_{uuid.uuid4().hex[:8]}")
    candidate = base
    counter = 2
    while _local_salad_head_path(candidate).exists():
        candidate = f"{base}_{counter}"
        counter += 1
    return candidate


def _load_local_salad_head(
    head_id: str,
    *,
    device_name: str = "cpu",
    backend: Optional[str] = None,
) -> Tuple[Any, Dict[str, Any]]:
    path = _local_salad_head_path(head_id)
    try:
        root = _local_salad_head_root(create=False)
        if path.is_symlink():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_path_invalid")
        if not path.exists():
            raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="local_salad_head_not_found")
        resolved_path = path.resolve(strict=True)
        if not _path_is_within_root_impl(resolved_path, root):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_path_invalid")
    except HTTPException:
        raise
    except Exception:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_path_invalid")
    try:
        resolved_backend = resolve_local_salad_backend(backend)
        if resolved_backend == "mlx":
            return load_mlx_local_salad_head_file(resolved_path)
        return load_local_salad_head_file(resolved_path, device_name=device_name)
    except HTTPException:
        raise
    except ValueError as exc:
        detail = str(exc) or "local_salad_head_unsupported_format"
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc
    except Exception as exc:
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"local_salad_head_load_failed:{exc}") from exc


def _encode_local_salad_head_np(head: Any, patch_tokens: Any, global_token: Any = None) -> np.ndarray:
    if is_mlx_local_salad_head(head):
        return encode_local_salad_mlx(head, patch_tokens, global_token=global_token)
    with torch.no_grad():
        feats = head(patch_tokens, global_token=global_token)
    return feats.detach().float().cpu().numpy().astype(np.float32)


def _list_local_salad_heads() -> List[Dict[str, Any]]:
    entries: List[Dict[str, Any]] = []
    try:
        root = _local_salad_head_root(create=False)
    except HTTPException:
        return entries
    if not root.exists():
        return entries
    for path in sorted(root.glob("*.pt")):
        try:
            if not _path_is_within_root_impl(path.resolve(), root):
                continue
        except Exception:
            continue
        entry: Dict[str, Any] = {
            "id": path.stem,
            "filename": path.name,
            "path": str(path),
            "updated_at": path.stat().st_mtime,
            "status": "available",
        }
        try:
            _head, metadata = load_local_salad_head_file(path, device_name="cpu")
            config = dict(metadata.get("config") or {})
            entry.update(
                {
                    "label": metadata.get("label") or path.stem,
                    "encoder_type": metadata.get("encoder_type") or "dinov3",
                    "encoder_model": metadata.get("encoder_model") or "",
                    "cradio_pooling": metadata.get("cradio_pooling") or None,
                    "salad_backend": metadata.get("salad_backend") or "torch",
                    "train_image_count": metadata.get("train_image_count") or 0,
                    "source_mode": metadata.get("source_mode") or "",
                    "reference_source": metadata.get("reference_source") or metadata.get("source_mode") or "",
                    "reference_dataset_id": metadata.get("reference_dataset_id") or "",
                    "reference_dataset_label": metadata.get("reference_dataset_label") or "",
                    "reference_label": metadata.get("reference_label") or "",
                    "reference_fingerprint": metadata.get("reference_fingerprint") if isinstance(metadata.get("reference_fingerprint"), dict) else None,
                    "descriptor_dim": int(config.get("token_dim") or 0)
                    + int(config.get("num_clusters") or 0) * int(config.get("cluster_dim") or 0),
                    "config": config,
                }
            )
        except Exception as exc:
            entry["status"] = f"unreadable:{exc}"
            entry["label"] = path.stem
        entries.append(entry)
    return entries


def _data_ingestion_sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def _data_ingestion_zip_member_is_unsafe(name: str) -> bool:
    raw = str(name or "")
    parts = Path(raw).parts
    return (
        not raw
        or raw.startswith("/")
        or raw.startswith("\\")
        or PureWindowsPath(raw).is_absolute()
        or ".." in parts
        or any(part in {"", ".", ".."} for part in parts)
    )


def _data_ingestion_zip_info_is_symlink(info: zipfile.ZipInfo) -> bool:
    mode = (int(info.external_attr or 0) >> 16) & 0xFFFF
    return stat.S_ISLNK(mode)


def _data_ingestion_validate_zip_infos(
    zf: zipfile.ZipFile,
    *,
    allowed_names: Set[str],
    detail_prefix: str,
    max_uncompressed_bytes: int,
) -> None:
    total_uncompressed = 0
    for info in zf.infolist():
        name = str(info.filename or "")
        if _data_ingestion_zip_member_is_unsafe(name) or name not in allowed_names:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=f"{detail_prefix}_invalid_path")
        if _data_ingestion_zip_info_is_symlink(info):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=f"{detail_prefix}_symlink_unsupported")
        total_uncompressed += max(0, int(info.file_size or 0))
        if total_uncompressed > max_uncompressed_bytes:
            raise HTTPException(status_code=HTTP_413_CONTENT_TOO_LARGE, detail=f"{detail_prefix}_uncompressed_too_large")


def _data_ingestion_reference_fingerprint(
    prepared_rows: Sequence[Dict[str, Any]],
    *,
    source: str,
    dataset_id: str = "",
    label: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    for row in prepared_rows:
        rows.append(
            {
                "filename": str(row.get("filename") or row.get("saved_name") or ""),
                "source_type": str(row.get("source_type") or "image"),
                "frame_index": _coerce_int(row.get("frame_index"), 0, minimum=0),
                "width": _coerce_int(row.get("width"), 0, minimum=0),
                "height": _coerce_int(row.get("height"), 0, minimum=0),
                "size": _coerce_int(row.get("size"), 0, minimum=0),
                "split": str(row.get("split") or ""),
                "image_relpath": str(row.get("image_relpath") or ""),
                "source_dataset_id": str(row.get("source_dataset_id") or ""),
            }
        )
    rows.sort(key=lambda item: json.dumps(item, sort_keys=True, ensure_ascii=False))
    digest = hashlib.sha256(json.dumps(rows, sort_keys=True, ensure_ascii=False).encode("utf-8")).hexdigest()
    return {
        "version": 1,
        "source": str(source or ""),
        "dataset_id": str(dataset_id or ""),
        "label": str(label or ""),
        "image_count": len(rows),
        "content_hash": digest,
    }


def _data_ingestion_profile_bundle_manifest(profile_id: str, metadata: Dict[str, Any]) -> Dict[str, Any]:
    reference_fingerprint = metadata.get("reference_fingerprint") if isinstance(metadata.get("reference_fingerprint"), dict) else None
    profile_meta = {
        key: json_sanitize(metadata.get(key))
        for key in [
            "id",
            "label",
            "encoder_type",
            "encoder_model",
            "cradio_pooling",
            "train_image_count",
            "source_mode",
            "reference_source",
            "reference_dataset_id",
            "reference_dataset_label",
            "reference_label",
            "active_image_count",
            "epochs",
            "batch_size",
            "salad_backend",
            "created_at",
            "format",
            "policy",
            "trainer",
        ]
        if metadata.get(key) is not None
    }
    return {
        "bundle_version": REFERENCE_PROFILE_BUNDLE_VERSION,
        "exported_at": time.time(),
        "original_profile_id": str(profile_id or ""),
        "profile": profile_meta,
        "reference": {
            "source": str(metadata.get("reference_source") or metadata.get("source_mode") or ""),
            "dataset_id": str(metadata.get("reference_dataset_id") or ""),
            "dataset_label": str(metadata.get("reference_dataset_label") or ""),
            "label": str(metadata.get("reference_label") or ""),
        },
        "reference_fingerprint": reference_fingerprint,
        "fingerprint_status": "present" if reference_fingerprint else "missing_legacy",
    }


def export_data_ingestion_reference_profile(profile_id: str):
    safe_profile_id = _class_analysis_safe_slug(str(profile_id or ""), "")
    if not safe_profile_id:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_id_required")
    path = _local_salad_head_path(safe_profile_id)
    head_root = _local_salad_head_root(create=False)
    safe_path = _safe_existing_regular_file_within_root_impl(path, head_root)
    if safe_path is None:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="reference_profile_not_found")
    _head, metadata = _load_local_salad_head(safe_profile_id, device_name="cpu", backend="torch")
    profile_bytes = safe_path.read_bytes()
    manifest = _data_ingestion_profile_bundle_manifest(safe_profile_id, metadata)
    manifest_bytes = json.dumps(manifest, ensure_ascii=False, sort_keys=True, indent=2).encode("utf-8")
    checksums = {
        "manifest.json": _data_ingestion_sha256_bytes(manifest_bytes),
        "profile.pt": _data_ingestion_sha256_bytes(profile_bytes),
    }
    checksums_bytes = json.dumps(checksums, ensure_ascii=False, sort_keys=True, indent=2).encode("utf-8")
    tmp_dir = Path(tempfile.mkdtemp(prefix="reference_profile_export_"))
    try:
        zip_path = tmp_dir / f"{safe_profile_id}.reference_profile.zip"
        with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as zf:
            zf.writestr("manifest.json", manifest_bytes)
            zf.writestr("profile.pt", profile_bytes)
            zf.writestr("checksums.json", checksums_bytes)
        return FileResponse(
            path=str(zip_path),
            media_type="application/zip",
            filename=f"{safe_profile_id}.reference_profile.zip",
            background=BackgroundTask(shutil.rmtree, tmp_dir, ignore_errors=True),
        )
    except Exception as exc:  # noqa: BLE001
        shutil.rmtree(tmp_dir, ignore_errors=True)
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"reference_profile_export_failed:{exc}") from exc


def _import_data_ingestion_reference_profile_zip(zip_path: Path) -> Dict[str, Any]:
    try:
        zip_size = int(zip_path.stat().st_size)
    except Exception:
        zip_size = 0
    if zip_size <= 0:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_empty")
    if zip_size > REFERENCE_PROFILE_BUNDLE_MAX_BYTES:
        raise HTTPException(status_code=HTTP_413_CONTENT_TOO_LARGE, detail="reference_profile_import_zip_too_large")
    allowed = {"manifest.json", "profile.pt", "checksums.json"}
    try:
        with zipfile.ZipFile(zip_path) as zf:
            names = set(zf.namelist())
            if len(names) != len(zf.infolist()):
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_duplicate_files")
            _data_ingestion_validate_zip_infos(
                zf,
                allowed_names=allowed,
                detail_prefix="reference_profile_import",
                max_uncompressed_bytes=REFERENCE_PROFILE_BUNDLE_MAX_UNCOMPRESSED_BYTES,
            )
            if allowed - names:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_missing_files")
            manifest_bytes = zf.read("manifest.json")
            profile_bytes = zf.read("profile.pt")
            checksums = json.loads(zf.read("checksums.json").decode("utf-8"))
    except zipfile.BadZipFile as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_invalid_zip") from exc
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=f"reference_profile_import_failed:{exc}") from exc
    if not isinstance(checksums, dict):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_bad_checksums")
    if checksums.get("manifest.json") != _data_ingestion_sha256_bytes(manifest_bytes):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_checksum_mismatch")
    if checksums.get("profile.pt") != _data_ingestion_sha256_bytes(profile_bytes):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_checksum_mismatch")
    try:
        manifest = json.loads(manifest_bytes.decode("utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_manifest_invalid") from exc
    if not isinstance(manifest, dict) or manifest.get("bundle_version") != REFERENCE_PROFILE_BUNDLE_VERSION:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_unsupported_bundle")

    tmp_dir = Path(tempfile.mkdtemp(prefix="reference_profile_validate_"))
    try:
        temp_profile = tmp_dir / "profile.pt"
        temp_profile.write_bytes(profile_bytes)
        _head, loaded_metadata = load_local_salad_head_file(temp_profile, device_name="cpu")
        try:
            payload = torch.load(temp_profile, map_location="cpu", weights_only=True)
        except TypeError:
            payload = torch.load(temp_profile, map_location="cpu")
        if not isinstance(payload, dict):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_payload_invalid")
        existing_meta = dict(payload.get("metadata") or {})
        profile_manifest = manifest.get("profile") if isinstance(manifest.get("profile"), dict) else {}
        requested_label = str(existing_meta.get("label") or profile_manifest.get("label") or manifest.get("original_profile_id") or "reference_profile")
        with LOCAL_SALAD_HEAD_LOCK:
            new_id = _unique_local_salad_head_id(requested_label)
            head_root = _local_salad_head_root(create=True)
            head_path = _local_salad_head_path(new_id)
            head_write_path = _class_analysis_prepare_write_path(head_path, head_root)
            if head_write_path is None:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="reference_profile_import_path_invalid")
            new_meta = {
                **existing_meta,
                "id": new_id,
                "label": requested_label,
                "original_profile_id": str(manifest.get("original_profile_id") or existing_meta.get("id") or ""),
                "imported_at": time.time(),
                "imported_from_bundle": REFERENCE_PROFILE_BUNDLE_VERSION,
            }
            if isinstance(manifest.get("reference_fingerprint"), dict):
                new_meta["reference_fingerprint"] = manifest["reference_fingerprint"]
            payload["metadata"] = new_meta
            _class_analysis_write_binary(
                head_write_path,
                head_root,
                lambda handle: torch.save(payload, handle),
                detail="reference_profile_import_path_invalid",
            )
        imported_entry = next((entry for entry in _list_local_salad_heads() if entry.get("id") == new_id), None)
        return {
            "status": "imported",
            "id": new_id,
            "label": requested_label,
            "original_profile_id": str(manifest.get("original_profile_id") or loaded_metadata.get("id") or ""),
            "profile": imported_entry or {"id": new_id, "label": requested_label},
            "reference": manifest.get("reference") if isinstance(manifest.get("reference"), dict) else {},
            "reference_fingerprint": manifest.get("reference_fingerprint") if isinstance(manifest.get("reference_fingerprint"), dict) else None,
        }
    except HTTPException:
        raise
    except ValueError as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=str(exc) or "reference_profile_import_payload_invalid") from exc
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)


async def import_data_ingestion_reference_profile(file: UploadFile = File(...)):  # noqa: B008
    tmp_dir = Path(tempfile.mkdtemp(prefix="reference_profile_import_"))
    try:
        zip_path = tmp_dir / "upload.zip"
        written = 0
        with zip_path.open("wb") as handle:
            while True:
                chunk = await file.read(1024 * 1024)
                if not chunk:
                    break
                written += len(chunk)
                if written > REFERENCE_PROFILE_BUNDLE_MAX_BYTES:
                    raise HTTPException(status_code=HTTP_413_CONTENT_TOO_LARGE, detail="reference_profile_import_zip_too_large")
                handle.write(chunk)
        return _import_data_ingestion_reference_profile_zip(zip_path)
    finally:
        try:
            await file.close()
        except Exception:
            pass
        shutil.rmtree(tmp_dir, ignore_errors=True)


def _local_salad_head_reference_matches_request(metadata: Dict[str, Any], request: Dict[str, Any]) -> bool:
    head_source = str(metadata.get("reference_source") or metadata.get("source_mode") or "").strip()
    head_dataset_id = str(metadata.get("reference_dataset_id") or "").strip()
    head_label = str(metadata.get("reference_label") or metadata.get("reference_dataset_label") or "").strip()
    request_source = str(request.get("reference_source") or request.get("source_mode") or "").strip()
    request_dataset_id = str(request.get("reference_dataset_id") or "").strip()
    request_label = str(request.get("reference_label") or request.get("reference_dataset_label") or "").strip()
    if not head_source and not head_dataset_id:
        return False
    if request_source == "backend_dataset":
        return bool(head_dataset_id and request_dataset_id and head_dataset_id == request_dataset_id)
    if request_source == "active_label_images":
        if head_dataset_id or request_dataset_id:
            return bool(head_dataset_id and request_dataset_id and head_dataset_id == request_dataset_id)
        if head_label and request_label and head_label != request_label:
            return False
        return head_source == "active_label_images"
    return False


def _validate_local_salad_head_reference(head_id: str, request: Dict[str, Any]) -> Dict[str, Any]:
    if not str(head_id or "").strip():
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_required")
    _head, metadata = _load_local_salad_head(head_id, device_name="cpu", backend="torch")
    if not _local_salad_head_reference_matches_request(metadata, request):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_reference_mismatch")
    return dict(metadata)


