async def _data_ingestion_save_uploads(files: Sequence[Any], target_dir: Path, field_name: str) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    used: Set[str] = set()
    for idx, upload in enumerate(files or []):
        original = str(getattr(upload, "filename", "") or "").strip()
        if not original:
            continue
        ext = Path(original).suffix.lower()
        safe_stem = _data_ingestion_safe_media_name(original, f"{field_name}_{idx:05d}")
        safe_name = f"{idx:05d}_{safe_stem}{ext}"
        while safe_name in used:
            safe_name = f"{idx:05d}_{safe_stem}_{uuid.uuid4().hex[:6]}{ext}"
        used.add(safe_name)
        target = target_dir / safe_name
        try:
            await _write_upload_file(
                upload,
                target,
                max_bytes=DATA_INGESTION_UPLOAD_MAX_BYTES,
                quota_root=target_dir,
                quota_limit=DATA_INGESTION_UPLOAD_QUOTA_BYTES,
            )
        finally:
            close_fn = getattr(upload, "close", None)
            if callable(close_fn):
                close_result = close_fn()
                if hasattr(close_result, "__await__"):
                    await close_result
        try:
            size = target.stat().st_size
        except OSError:
            size = 0
        if size <= 0:
            try:
                target.unlink()
            except OSError:
                pass
            continue
        rows.append(
            {
                "path": str(target),
                "filename": original,
                "saved_name": safe_name,
                "size": size,
                "field": field_name,
            }
        )
    return rows


def _data_ingestion_dataset_media_rows(
    dataset_id: str,
    *,
    field_name: str,
    max_count: int = 0,
) -> List[Dict[str, Any]]:
    safe_id = str(dataset_id or "").strip()
    if not safe_id:
        return []
    entry = _resolve_dataset_entry(safe_id)
    label = str(entry.get("label") or entry.get("id") or safe_id)
    dataset_root = _dataset_effective_root_from_entry(entry).resolve()
    image_rows = _annotation_collect_images(entry)
    max_items = _coerce_int(max_count, 0, minimum=0)
    out: List[Dict[str, Any]] = []
    for idx, image_row in enumerate(image_rows):
        try:
            image_path = Path(str(image_row.get("image_path") or "")).resolve()
        except Exception:
            continue
        if not _path_is_within_root_impl(image_path, dataset_root):
            continue
        if not image_path.exists() or not image_path.is_file():
            continue
        if image_path.suffix.lower() not in DATA_INGESTION_IMAGE_EXTS:
            continue
        try:
            size = image_path.stat().st_size
        except OSError:
            size = 0
        if size <= 0:
            continue
        split = str(image_row.get("split") or "train")
        rel = str(image_row.get("image_relpath") or image_path.name)
        out.append(
            {
                "path": str(image_path),
                "filename": f"{split}/{rel}",
                "saved_name": image_path.name,
                "size": size,
                "field": field_name,
                "source_dataset_id": safe_id,
                "source_dataset_label": label,
                "split": split,
                "image_relpath": rel,
                "dataset_index": idx,
            }
        )
        if max_items > 0 and len(out) >= max_items:
            break
    return out


def _data_ingestion_open_image(path: Path) -> Image.Image:
    img = Image.open(path)
    img.load()
    return img.convert("RGB")


def _data_ingestion_prepare_media(
    job: DataIngestionJob,
    rows: Sequence[Dict[str, Any]],
    *,
    out_dir: Path,
    frame_interval: float,
    max_frames_per_video: int,
    progress_start: float,
    progress_end: float,
) -> List[Dict[str, Any]]:
    prepared: List[Dict[str, Any]] = []
    total = max(1, len(rows))
    ffmpeg_path = shutil.which("ffmpeg")
    for idx, row in enumerate(rows):
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        path = Path(str(row.get("path") or ""))
        ext = path.suffix.lower()
        pct = progress_start + (progress_end - progress_start) * (idx / total)
        _data_ingestion_update(job, progress=pct, message=f"Preparing media {idx + 1}/{len(rows)} ...")
        if ext in DATA_INGESTION_IMAGE_EXTS:
            try:
                with _data_ingestion_open_image(path) as img:
                    width, height = img.size
                prepared.append(
                    {
                        **row,
                        "image_path": str(path),
                        "source_type": "image",
                        "frame_index": 0,
                        "width": width,
                        "height": height,
                    }
                )
            except Exception as exc:
                _data_ingestion_log(job, f"Skipped unreadable image {path.name}: {exc}")
            continue
        if ext in DATA_INGESTION_VIDEO_EXTS:
            if not ffmpeg_path:
                raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="ffmpeg_required_for_video_ingestion")
            video_dir = out_dir / _data_ingestion_safe_media_name(path.name, f"video_{idx:05d}")
            if _storage_path_has_symlink_component(video_dir):
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_path_invalid")
            video_dir.mkdir(parents=True, exist_ok=True)
            if _storage_path_has_symlink_component(video_dir):
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_path_invalid")
            fps_expr = f"fps=1/{max(0.1, float(frame_interval or 1.0)):.3f}"
            pattern = video_dir / "frame_%06d.jpg"
            cmd = [
                ffmpeg_path,
                "-hide_banner",
                "-loglevel",
                "error",
                "-i",
                str(path),
                "-vf",
                fps_expr,
            ]
            if int(max_frames_per_video or 0) > 0:
                cmd += ["-frames:v", str(int(max_frames_per_video))]
            cmd += [str(pattern)]
            try:
                subprocess.run(cmd, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
            except subprocess.CalledProcessError as exc:
                detail = (exc.stderr or exc.stdout or str(exc)).strip()
                _data_ingestion_log(job, f"Video frame extraction failed for {path.name}: {detail[:500]}")
                continue
            frames = sorted(video_dir.glob("frame_*.jpg"))
            for frame_idx, frame_path in enumerate(frames):
                try:
                    with _data_ingestion_open_image(frame_path) as img:
                        width, height = img.size
                    prepared.append(
                        {
                            **row,
                            "image_path": str(frame_path),
                            "source_type": "video_frame",
                            "frame_index": frame_idx,
                            "width": width,
                            "height": height,
                        }
                    )
                except Exception:
                    continue
            _data_ingestion_log(job, f"Extracted {len(frames)} frames from {path.name}.")
    return prepared


def _data_ingestion_encoder_label(encoder: str, base_encoder: str) -> str:
    if str(encoder or "").strip().lower() == "local_salad":
        return f"local SALAD ({'C-RADIOv4' if base_encoder == 'cradio' else 'DINOv3'})"
    if str(base_encoder or "").strip().lower() == "cradio":
        return "C-RADIOv4 pooled"
    return "DINOv3 pooled"


def _data_ingestion_get_dinov3(model_name: str, device_name: Optional[str] = None) -> Tuple[Any, Any, str, str]:
    resolved_model = str(model_name or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL).strip() or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
    target_device = device_name or _dinov3_resolve_device_impl(device, cuda_disabled=dinov3_cuda_disabled)
    model_obj, processor_obj = _load_dinov3_backbone(resolved_model, target_device)
    if model_obj is None or processor_obj is None:
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="dinov3_load_failed")
    return model_obj, processor_obj, resolved_model, target_device


def _data_ingestion_encode_prepared_images(
    prepared: Sequence[Dict[str, Any]],
    *,
    job: DataIngestionJob,
    encoder: str,
    model_name: str,
    salad_head_id: str = "",
    cradio_pooling: str = "summary",
    batch_size: int = 16,
    progress_start: float = 0.35,
    progress_end: float = 0.82,
) -> np.ndarray:
    if not prepared:
        return np.empty((0, 0), dtype=np.float32)
    encoder_norm = str(encoder or "dinov3_pooled").strip().lower()
    salad_head: Optional[Any] = None
    salad_meta: Dict[str, Any] = {}
    if encoder_norm == "local_salad":
        if not str(salad_head_id or "").strip():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_required")
        salad_head, salad_meta = _load_local_salad_head(salad_head_id, device_name="cpu")
    base_encoder = "cradio" if encoder_norm == "cradio_pooled" else "dinov3"
    if encoder_norm == "local_salad":
        base_encoder = str(salad_meta.get("encoder_type") or "dinov3").strip().lower()
        if base_encoder not in {"dinov3", "cradio"}:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_encoder_unsupported")
        model_name = str(salad_meta.get("encoder_model") or model_name or "").strip()
    if base_encoder == "cradio":
        resolved_model_name = normalize_cradio_model(model_name)
        device_name = resolve_cradio_torch_device(model_name=resolved_model_name)
        model_obj, processor_obj, resolved_model, device_name = _load_cradio_backbone_cached(
            resolved_model_name,
            device_name,
            raise_on_error=True,
        )
        if encoder_norm == "local_salad":
            salad_device_name = device_name if device_name != "mlx" else resolve_cradio_aux_torch_device()
            salad_head, salad_meta = _load_local_salad_head(salad_head_id, device_name=salad_device_name)
    else:
        model_obj, processor_obj, resolved_model, device_name = _data_ingestion_get_dinov3(model_name)
        if encoder_norm == "local_salad":
            salad_head, salad_meta = _load_local_salad_head(salad_head_id, device_name=device_name)
    resolved_batch = max(1, min(int(batch_size or 16), len(prepared)))
    features: List[np.ndarray] = []
    total = len(prepared)
    started = time.time()
    for start in range(0, total, resolved_batch):
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        batch_rows = prepared[start : start + resolved_batch]
        images: List[Image.Image] = []
        try:
            for row in batch_rows:
                images.append(_data_ingestion_open_image(Path(str(row.get("image_path") or ""))))
            if base_encoder == "cradio":
                pooling = normalize_cradio_pooling(
                    salad_meta.get("cradio_pooling") if encoder_norm == "local_salad" else cradio_pooling
                )
                if encoder_norm == "local_salad":
                    _base, spatial_tokens, summary_tokens = encode_cradio_images(
                        model_obj,
                        processor_obj,
                        device_name,
                        images,
                        pooling=pooling,
                        normalize=False,
                        return_tokens=True,
                    )
                    if spatial_tokens.ndim != 3 or spatial_tokens.shape[1] <= 0:
                        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="cradio_spatial_tokens_missing")
                    assert salad_head is not None
                    if is_mlx_local_salad_head(salad_head):
                        features.append(_encode_local_salad_head_np(salad_head, spatial_tokens, summary_tokens))
                    else:
                        with torch.no_grad():
                            salad_device = next(salad_head.parameters()).device
                            features.append(
                                _encode_local_salad_head_np(
                                    salad_head,
                                    torch.from_numpy(spatial_tokens).to(salad_device),
                                    torch.from_numpy(summary_tokens).to(salad_device),
                                )
                            )
                else:
                    features.append(
                        encode_cradio_images(
                            model_obj,
                            processor_obj,
                            device_name,
                            images,
                            pooling=pooling,
                            normalize=True,
                        )
                    )
            else:
                inputs = processor_obj(images=images, return_tensors="pt")
                inputs = {k: v.to(device_name) for k, v in inputs.items()}
                with torch.no_grad():
                    outputs = model_obj(**inputs)
                    last_hidden = getattr(outputs, "last_hidden_state", None)
                    if encoder_norm == "local_salad":
                        if last_hidden is None or last_hidden.ndim != 3 or last_hidden.shape[1] <= 1:
                            raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="dinov3_patch_tokens_missing")
                        global_token = getattr(outputs, "pooler_output", None)
                        if global_token is None:
                            global_token = last_hidden[:, 0, :]
                        assert salad_head is not None
                        features.append(_encode_local_salad_head_np(salad_head, last_hidden[:, 1:, :], global_token))
                        continue
                    else:
                        feats = getattr(outputs, "pooler_output", None)
                        if feats is None and last_hidden is not None:
                            feats = last_hidden[:, 0, :]
                        if feats is None:
                            feats = outputs[0]
                    feats = torch.nn.functional.normalize(feats.float(), dim=-1)
                features.append(feats.detach().cpu().numpy().astype(np.float32))
        finally:
            for img in images:
                try:
                    img.close()
                except Exception:
                    pass
        done = min(total, start + len(batch_rows))
        speed = _class_analysis_progress_message(done=done, total=total, started_at=started)
        progress = progress_start + (progress_end - progress_start) * (done / max(1, total))
        _data_ingestion_update(
            job,
            progress=progress,
            message=f"Encoding {done}/{total} images with {_data_ingestion_encoder_label(encoder_norm, base_encoder)}"
            + (f" ({speed})" if speed else ""),
        )
    if not features:
        return np.empty((0, 0), dtype=np.float32)
    return np.concatenate(features, axis=0).astype(np.float32, copy=False)


def _run_data_ingestion_analysis_job(job: DataIngestionJob) -> None:
    try:
        out_dir = _data_ingestion_job_dir(job.job_id, create=True)
        media_dir = out_dir / "media"
        request = dict(job.request or {})
        candidate_rows = list(request.get("candidate_uploads") or [])
        reference_rows = list(request.get("reference_uploads") or [])
        if not candidate_rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_candidate_files")
        if not reference_rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_reference_files")
        encoder = str(request.get("encoder") or "local_salad").strip().lower()
        if encoder != "local_salad":
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_encoder_unsupported")
        model_name = str(
            request.get("encoder_model") or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL
        ).strip()
        cradio_pooling = normalize_cradio_pooling(request.get("cradio_pooling"))
        salad_head_id = str(request.get("salad_head_id") or "").strip()
        salad_head_meta = _validate_local_salad_head_reference(salad_head_id, request)
        salad_base_encoder = str(salad_head_meta.get("encoder_type") or "dinov3").strip().lower()
        if salad_base_encoder not in {"dinov3", "cradio"}:
            salad_base_encoder = "dinov3"
        salad_encoder_model = str(salad_head_meta.get("encoder_model") or "").strip()
        if not salad_encoder_model:
            salad_encoder_model = CRADIO_DEFAULT_MODEL if salad_base_encoder == "cradio" else model_name
        salad_cradio_pooling = (
            normalize_cradio_pooling(salad_head_meta.get("cradio_pooling"))
            if salad_base_encoder == "cradio"
            else cradio_pooling
        )
        _data_ingestion_update(job, status="running", progress=0.02, message="Preparing candidate media ...")
        frame_interval = _coerce_float(request.get("frame_interval"), 1.0, minimum=0.1)
        max_frames = _coerce_int(request.get("max_frames_per_video"), 200, minimum=0)
        candidates = _data_ingestion_prepare_media(
            job,
            candidate_rows,
            out_dir=media_dir / "candidates",
            frame_interval=frame_interval,
            max_frames_per_video=max_frames,
            progress_start=0.03,
            progress_end=0.18,
        )
        if not candidates:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_candidate_images")
        _data_ingestion_update(job, progress=0.19, message="Preparing reference dataset media ...")
        references = _data_ingestion_prepare_media(
            job,
            reference_rows,
            out_dir=media_dir / "references",
            frame_interval=frame_interval,
            max_frames_per_video=max_frames,
            progress_start=0.19,
            progress_end=0.28,
        )
        if not references:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_reference_images")
        batch_size = _coerce_int(request.get("batch_size"), 16, minimum=1)
        candidate_embeddings = _data_ingestion_encode_prepared_images(
            candidates,
            job=job,
            encoder=encoder,
            model_name=model_name,
            salad_head_id=salad_head_id,
            cradio_pooling=cradio_pooling,
            batch_size=batch_size,
            progress_start=0.30,
            progress_end=0.72,
        )
        reference_embeddings = _data_ingestion_encode_prepared_images(
            references,
            job=job,
            encoder=encoder,
            model_name=model_name,
            salad_head_id=salad_head_id,
            cradio_pooling=cradio_pooling,
            batch_size=batch_size,
            progress_start=0.72,
            progress_end=0.88,
        )
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        keep_fraction = _data_ingestion_keep_fraction(request.get("keep_fraction"), 0.2)
        selected, novelty_scores = _data_ingestion_greedy_indices(
            candidate_embeddings,
            keep_fraction=keep_fraction,
            reference_embeddings=reference_embeddings,
        )
        selected_set = set(selected)
        ranked_items: List[Dict[str, Any]] = []
        rank_by_idx = {idx: rank + 1 for rank, idx in enumerate(selected)}
        for idx, row in enumerate(candidates):
            ranked_items.append(
                {
                    "item_id": f"item_{idx:06d}",
                    "index": idx,
                    "rank": rank_by_idx.get(idx),
                    "keep": idx in selected_set,
                    "diversity_score": float(novelty_scores[idx]) if idx < len(novelty_scores) else 0.0,
                    "filename": row.get("filename") or Path(str(row.get("image_path") or "")).name,
                    "saved_name": row.get("saved_name") or "",
                    "source_type": row.get("source_type") or "image",
                    "frame_index": row.get("frame_index") or 0,
                    "width": row.get("width") or 0,
                    "height": row.get("height") or 0,
                    "image_path": row.get("image_path") or "",
                }
            )
        ranked_items.sort(
            key=lambda item: (
                0 if item.get("keep") else 1,
                int(item.get("rank") or 10**9),
                -float(item.get("diversity_score") or 0.0),
            )
        )
        summary = {
            **_data_ingestion_diversity_summary(
                candidate_embeddings,
                selected_indices=selected,
                reference_embeddings=reference_embeddings,
            ),
            "keep_fraction": keep_fraction,
            "encoder": encoder,
            "encoder_type": salad_base_encoder,
            "base_encoder": salad_base_encoder,
            "encoder_model": salad_encoder_model or CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL,
            "cradio_pooling": salad_cradio_pooling,
            "salad_head_id": salad_head_id,
            "salad_head_backend": salad_head_meta.get("salad_backend") or salad_head_meta.get("backend") or "",
            "reference_count": len(references),
            "reference_source": str(request.get("reference_source") or request.get("source_mode") or ""),
            "reference_dataset_id": str(request.get("reference_dataset_id") or ""),
            "reference_dataset_label": str(request.get("reference_dataset_label") or ""),
            "reference_label": str(request.get("reference_label") or ""),
            "candidate_upload_count": len(candidate_rows),
            "candidate_image_count": len(candidates),
            "local_salad_policy": LOCAL_SALAD_POLICY,
            "local_salad_trainer": LOCAL_SALAD_TRAINER,
        }
        result = {"summary": summary, "items": ranked_items}
        result_path = out_dir / "result.json"
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        _class_analysis_write_json(result_path, out_dir, result)
        _class_analysis_write_npz(
            out_dir / "embeddings.npz",
            out_dir,
            candidate_embeddings=candidate_embeddings,
            reference_embeddings=reference_embeddings if reference_embeddings is not None else np.empty((0, 0), dtype=np.float32),
        )
        with DATA_INGESTION_JOBS_LOCK:
            job.result_path = str(result_path)
            _data_ingestion_update(job, status="completed", progress=1.0, message="Data ingestion analysis completed.", result=result)
    except RuntimeError as exc:
        with DATA_INGESTION_JOBS_LOCK:
            if str(exc) == "cancelled":
                _data_ingestion_update(job, status="cancelled", message="Data ingestion cancelled.")
            else:
                _data_ingestion_update(job, status="failed", message=str(exc), error=str(exc))
    except HTTPException as exc:
        with DATA_INGESTION_JOBS_LOCK:
            _data_ingestion_update(job, status="failed", progress=1.0, message=str(exc.detail), error=str(exc.detail))
    except Exception as exc:  # noqa: BLE001
        logger.exception("[data-ingestion %s] analysis crashed", job.job_id[:8])
        with DATA_INGESTION_JOBS_LOCK:
            _data_ingestion_update(job, status="failed", progress=1.0, message="Data ingestion crashed.", error=str(exc))


def _data_ingestion_train_view(img: Image.Image, rng: random.Random) -> Image.Image:
    work = img.convert("RGB")
    width, height = work.size
    if width > 8 and height > 8:
        scale = rng.uniform(0.72, 1.0)
        crop_w = max(8, int(width * scale))
        crop_h = max(8, int(height * scale))
        left = rng.randint(0, max(0, width - crop_w))
        top = rng.randint(0, max(0, height - crop_h))
        work = work.crop((left, top, left + crop_w, top + crop_h))
    if rng.random() < 0.5:
        work = work.transpose(Image.Transpose.FLIP_LEFT_RIGHT)
    return work


def _local_salad_training_stage(progress: float) -> str:
    pct = clamp_progress(progress, fallback=0.0) or 0.0
    if pct < 0.18:
        return "Preparing reference media"
    if pct < 0.35:
        return "Encoding reference views"
    if pct < 0.70:
        return "Training reference profile"
    if pct < 0.94:
        return "Optimizing reference profile"
    return "Finalizing reference profile"


def _data_ingestion_dinov3_tokens(
    model_obj: Any,
    processor_obj: Any,
    device_name: str,
    images: Sequence[Image.Image],
) -> Tuple[torch.Tensor, torch.Tensor]:
    inputs = processor_obj(images=list(images), return_tensors="pt")
    inputs = {k: v.to(device_name) for k, v in inputs.items()}
    with torch.no_grad():
        outputs = model_obj(**inputs)
    last_hidden = getattr(outputs, "last_hidden_state", None)
    if last_hidden is None or last_hidden.ndim != 3 or last_hidden.shape[1] <= 1:
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail="dinov3_patch_tokens_missing")
    global_token = getattr(outputs, "pooler_output", None)
    if global_token is None:
        global_token = last_hidden[:, 0, :]
    return last_hidden[:, 1:, :].detach(), global_token.detach()


def _run_local_salad_training_job(job: DataIngestionJob) -> None:
    try:
        out_dir = _data_ingestion_job_dir(job.job_id, create=True)
        media_dir = out_dir / "train_media"
        request = dict(job.request or {})
        upload_rows = list(request.get("train_uploads") or [])
        if not upload_rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_no_training_files")
        _data_ingestion_update(job, status="running", progress=0.02, message="Preparing reference media ...")
        frame_interval = _coerce_float(request.get("frame_interval"), 1.0, minimum=0.1)
        max_frames = _coerce_int(request.get("max_frames_per_video"), 200, minimum=0)
        prepared = _data_ingestion_prepare_media(
            job,
            upload_rows,
            out_dir=media_dir,
            frame_interval=frame_interval,
            max_frames_per_video=max_frames,
            progress_start=0.03,
            progress_end=0.18,
        )
        max_images = _coerce_int(request.get("max_train_images"), 0, minimum=0)
        if max_images > 0 and len(prepared) > max_images:
            rnd = random.Random(_coerce_int(request.get("seed"), 42))
            prepared = [prepared[idx] for idx in sorted(rnd.sample(range(len(prepared)), max_images))]
        if len(prepared) < 2:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_needs_at_least_two_images")
        reference_fingerprint = _data_ingestion_reference_fingerprint(
            prepared,
            source=str(request.get("reference_source") or request.get("source_mode") or ""),
            dataset_id=str(request.get("reference_dataset_id") or ""),
            label=str(request.get("reference_dataset_label") or request.get("reference_label") or ""),
        )
        _data_ingestion_update(job, progress=0.18, message="Encoding reference views ...")
        encoder_type = str(request.get("encoder_type") or "dinov3").strip().lower()
        if encoder_type not in {"dinov3", "cradio"}:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_encoder_unsupported")
        model_name = str(
            request.get("encoder_model")
            or (CRADIO_DEFAULT_MODEL if encoder_type == "cradio" else CLASS_ANALYSIS_DEFAULT_DINOV3_MODEL)
        ).strip()
        cradio_pooling = normalize_cradio_pooling(request.get("cradio_pooling"))
        if encoder_type == "cradio":
            device_name = resolve_cradio_torch_device(
                str(request.get("cradio_backend") or "auto"),
                model_name=model_name,
            )
            model_obj, processor_obj, resolved_model, device_name = _load_cradio_backbone_cached(
                model_name,
                device_name,
                raise_on_error=True,
            )
            with _data_ingestion_open_image(Path(str(prepared[0].get("image_path")))) as probe_img:
                _probe_feats, probe_tokens, _probe_summary = encode_cradio_images(
                    model_obj,
                    processor_obj,
                    device_name,
                    [probe_img],
                    pooling=cradio_pooling,
                    normalize=False,
                    return_tokens=True,
                )
            hidden_size = int(probe_tokens.shape[-1])
            salad_device_name = device_name if device_name != "mlx" else resolve_cradio_aux_torch_device()
        else:
            model_obj, processor_obj, resolved_model, device_name = _data_ingestion_get_dinov3(model_name)
            salad_device_name = device_name
            hidden_size = int(getattr(getattr(model_obj, "config", None), "hidden_size", 0) or 0)
            if hidden_size <= 0:
                # Probe one image if the config does not expose hidden_size.
                with _data_ingestion_open_image(Path(str(prepared[0].get("image_path")))) as probe_img:
                    patches, _global = _data_ingestion_dinov3_tokens(model_obj, processor_obj, device_name, [probe_img])
                hidden_size = int(patches.shape[-1])
        config = LocalSALADConfig(
            num_channels=hidden_size,
            num_clusters=_coerce_int(request.get("num_clusters"), 64, minimum=4),
            cluster_dim=_coerce_int(request.get("cluster_dim"), 128, minimum=8),
            token_dim=_coerce_int(request.get("token_dim"), 256, minimum=8),
            hidden_dim=_coerce_int(request.get("hidden_dim"), 512, minimum=64),
            dropout=_coerce_float(request.get("dropout"), 0.3, minimum=0.0, maximum=0.8),
        )
        salad_backend = resolve_local_salad_backend(request.get("local_salad_backend"))
        learning_rate = _coerce_float(request.get("learning_rate"), 1e-4, minimum=1e-7)
        weight_decay = _coerce_float(request.get("weight_decay"), 1e-4, minimum=0.0)
        if salad_backend == "mlx":
            head: Any = MLXLocalSALADHead(config)
            optimizer = make_mlx_local_salad_optimizer(
                learning_rate=learning_rate,
                weight_decay=weight_decay,
            )
        else:
            head = LocalSALADHead(config).to(salad_device_name)
            head.train()
            optimizer = torch.optim.AdamW(
                head.parameters(),
                lr=learning_rate,
                weight_decay=weight_decay,
            )
        epochs = _coerce_int(request.get("epochs"), 3, minimum=1)
        batch_size = max(2, _coerce_int(request.get("batch_size"), 8, minimum=2))
        temperature = _coerce_float(request.get("temperature"), 0.07, minimum=0.001)
        seed = _coerce_int(request.get("seed"), 42)
        rng = random.Random(seed)
        losses: List[float] = []
        total_steps = max(1, epochs * math.ceil(len(prepared) / batch_size))
        step = 0
        for epoch in range(epochs):
            if job.cancel_event.is_set():
                raise RuntimeError("cancelled")
            order = list(range(len(prepared)))
            rng.shuffle(order)
            for start in range(0, len(order), batch_size):
                batch_ids = order[start : start + batch_size]
                if len(batch_ids) < 2:
                    continue
                images_left: List[Image.Image] = []
                images_right: List[Image.Image] = []
                originals: List[Image.Image] = []
                try:
                    for idx in batch_ids:
                        original = _data_ingestion_open_image(Path(str(prepared[idx].get("image_path") or "")))
                        originals.append(original)
                        images_left.append(_data_ingestion_train_view(original, rng))
                        images_right.append(_data_ingestion_train_view(original, rng))
                    if encoder_type == "cradio":
                        _feats_a, patches_a_np, global_a_np = encode_cradio_images(
                            model_obj,
                            processor_obj,
                            device_name,
                            images_left,
                            pooling=cradio_pooling,
                            normalize=False,
                            return_tokens=True,
                        )
                        _feats_b, patches_b_np, global_b_np = encode_cradio_images(
                            model_obj,
                            processor_obj,
                            device_name,
                            images_right,
                            pooling=cradio_pooling,
                            normalize=False,
                            return_tokens=True,
                        )
                        if salad_backend == "mlx":
                            patches_a, global_a = patches_a_np, global_a_np
                            patches_b, global_b = patches_b_np, global_b_np
                        else:
                            patches_a = torch.from_numpy(patches_a_np).to(salad_device_name)
                            patches_b = torch.from_numpy(patches_b_np).to(salad_device_name)
                            global_a = torch.from_numpy(global_a_np).to(salad_device_name)
                            global_b = torch.from_numpy(global_b_np).to(salad_device_name)
                    else:
                        patches_a, global_a = _data_ingestion_dinov3_tokens(model_obj, processor_obj, device_name, images_left)
                        patches_b, global_b = _data_ingestion_dinov3_tokens(model_obj, processor_obj, device_name, images_right)
                    if salad_backend == "mlx":
                        loss_value = mlx_local_salad_train_step(
                            head,
                            optimizer,
                            patches_a,
                            global_a,
                            patches_b,
                            global_b,
                            temperature=temperature,
                            max_grad_norm=1.0,
                        )
                    else:
                        optimizer.zero_grad(set_to_none=True)
                        desc_a = head(patches_a, global_token=global_a)
                        desc_b = head(patches_b, global_token=global_b)
                        loss = symmetric_infonce_loss(desc_a, desc_b, temperature=temperature)
                        loss.backward()
                        torch.nn.utils.clip_grad_norm_(head.parameters(), 1.0)
                        optimizer.step()
                        loss_value = float(loss.detach().cpu().item())
                    losses.append(float(loss_value))
                finally:
                    for img in [*images_left, *images_right, *originals]:
                        try:
                            img.close()
                        except Exception:
                            pass
                step += 1
                progress = 0.18 + 0.72 * (step / total_steps)
                recent = float(np.mean(losses[-10:])) if losses else 0.0
                stage = _local_salad_training_stage(progress)
                _data_ingestion_update(
                    job,
                    progress=progress,
                    message=f"{stage} • epoch {epoch + 1}/{epochs}, step {step}/{total_steps}, loss {recent:.4f}",
                )
        if job.cancel_event.is_set():
            raise RuntimeError("cancelled")
        requested_name = str(request.get("head_name") or "").strip() or f"local_salad_{time.strftime('%Y%m%d_%H%M%S')}"
        with LOCAL_SALAD_HEAD_LOCK:
            if job.cancel_event.is_set():
                raise RuntimeError("cancelled")
            head_id = _unique_local_salad_head_id(requested_name)
            head_path = _local_salad_head_path(head_id)
            head_root = _local_salad_head_root(create=True)
            head_write_path = _class_analysis_prepare_write_path(
                head_path,
                head_root,
            )
            if head_write_path is None:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_head_path_invalid")
            metadata = {
                "id": head_id,
                "label": requested_name,
                "encoder_type": encoder_type,
                "encoder_model": resolved_model,
                "cradio_pooling": cradio_pooling if encoder_type == "cradio" else None,
                "train_image_count": len(prepared),
                "source_mode": str(request.get("source_mode") or "uploaded_media"),
                "reference_source": str(request.get("reference_source") or request.get("source_mode") or ""),
                "reference_dataset_id": str(request.get("reference_dataset_id") or ""),
                "reference_dataset_label": str(request.get("reference_dataset_label") or ""),
                "reference_label": str(request.get("reference_label") or ""),
                "reference_fingerprint": reference_fingerprint,
                "active_image_count": _coerce_int(request.get("active_image_count"), 0, minimum=0),
                "epochs": epochs,
                "batch_size": batch_size,
                "learning_rate": learning_rate,
                "weight_decay": weight_decay,
                "salad_backend": salad_backend,
                "loss_final": float(losses[-1]) if losses else None,
                "loss_mean_last10": float(np.mean(losses[-10:])) if losses else None,
                "created_at": time.time(),
                "format": LOCAL_SALAD_CACHE_VERSION,
                "policy": LOCAL_SALAD_POLICY,
                "trainer": LOCAL_SALAD_TRAINER,
            }
            head_payload = {
                "format": LOCAL_SALAD_CACHE_VERSION,
                "config": config.to_dict(),
                "state_dict": mlx_local_salad_state_dict(head) if is_mlx_local_salad_head(head) else head.cpu().state_dict(),
                "metadata": metadata,
            }
            _class_analysis_write_binary(
                head_write_path,
                head_root,
                lambda handle: torch.save(head_payload, handle),
                detail="local_salad_head_path_invalid",
            )
        result = {
            "summary": {
                "head_id": head_id,
                "path": str(head_write_path),
                "descriptor_dim": head.output_dim,
                **metadata,
            },
            "losses": losses,
        }
        result_path = out_dir / "result.json"
        _class_analysis_write_json(result_path, out_dir, result)
        with DATA_INGESTION_JOBS_LOCK:
            job.result_path = str(result_path)
            _data_ingestion_update(job, status="completed", progress=1.0, message=f"Reference profile saved: {head_id}", result=result)
    except RuntimeError as exc:
        with DATA_INGESTION_JOBS_LOCK:
            if str(exc) == "cancelled":
                _data_ingestion_update(job, status="cancelled", message="Local SALAD training cancelled.")
            else:
                _data_ingestion_update(job, status="failed", message=str(exc), error=str(exc))
    except HTTPException as exc:
        with DATA_INGESTION_JOBS_LOCK:
            _data_ingestion_update(job, status="failed", progress=1.0, message=str(exc.detail), error=str(exc.detail))
    except Exception as exc:  # noqa: BLE001
        logger.exception("[data-ingestion %s] local SALAD training crashed", job.job_id[:8])
        with DATA_INGESTION_JOBS_LOCK:
            _data_ingestion_update(job, status="failed", progress=1.0, message="Local SALAD training crashed.", error=str(exc))


async def create_data_ingestion_analysis_job(manifest_json: str, candidate_files: List[Any], reference_files: List[Any]) -> Dict[str, Any]:
    try:
        manifest = json.loads(str(manifest_json or "{}"))
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_manifest_json_invalid") from exc
    if not isinstance(manifest, dict):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_manifest_invalid")
    if not candidate_files:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_candidate_files")
    encoder = str(manifest.get("encoder") or "local_salad").strip().lower()
    if encoder != "local_salad":
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_encoder_unsupported")
    reference_source = str(manifest.get("reference_source") or manifest.get("source_mode") or "").strip()
    reference_dataset_id = str(manifest.get("reference_dataset_id") or "").strip()
    if not reference_files and not (reference_source == "backend_dataset" and reference_dataset_id):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_reference_files")
    _validate_local_salad_head_reference(str(manifest.get("salad_head_id") or "").strip(), manifest)
    job_id = f"di_{uuid.uuid4().hex[:10]}"
    out_dir: Optional[Path] = None
    try:
        out_dir = _data_ingestion_job_dir(job_id, create=True)
        candidate_rows = await _data_ingestion_save_uploads(candidate_files, out_dir / "uploads" / "candidates", "candidate")
        reference_rows = await _data_ingestion_save_uploads(reference_files, out_dir / "uploads" / "references", "reference")
        if reference_source == "backend_dataset" and reference_dataset_id:
            reference_rows.extend(
                _data_ingestion_dataset_media_rows(
                    reference_dataset_id,
                    field_name="reference",
                    max_count=_coerce_int(manifest.get("max_reference_images") or manifest.get("max_train_images"), 0, minimum=0),
                )
            )
        if not reference_rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_no_reference_files")
    except Exception:
        if out_dir is not None:
            _cleanup_data_ingestion_job_dir(out_dir)
        raise
    request_payload = {
        **manifest,
        "candidate_uploads": candidate_rows,
        "reference_uploads": reference_rows,
    }
    job = DataIngestionJob(job_id=job_id, kind="analysis", request=request_payload)
    with DATA_INGESTION_JOBS_LOCK:
        _data_ingestion_log(job, f"Queued data ingestion analysis with {len(candidate_rows)} candidate uploads and {len(reference_rows)} reference images.")
    try:
        _register_job_and_start_thread(
            job=job,
            registry=DATA_INGESTION_JOBS,
            lock=DATA_INGESTION_JOBS_LOCK,
            target=_run_data_ingestion_analysis_job,
            args=(job,),
            name=f"data-ingest-{job_id[:8]}",
        )
    except Exception:
        if out_dir is not None:
            _cleanup_data_ingestion_job_dir(out_dir)
        raise
    return {"job_id": job_id}


async def create_local_salad_training_job(manifest_json: str, files: List[Any]) -> Dict[str, Any]:
    try:
        manifest = json.loads(str(manifest_json or "{}"))
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="salad_train_manifest_json_invalid") from exc
    if not isinstance(manifest, dict):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="salad_train_manifest_invalid")
    encoder_type = str(manifest.get("encoder_type") or "dinov3").strip().lower()
    if encoder_type not in {"dinov3", "cradio"}:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_encoder_unsupported")
    job_id = f"salad_{uuid.uuid4().hex[:10]}"
    out_dir: Optional[Path] = None
    try:
        out_dir = _data_ingestion_job_dir(job_id, create=True)
        rows = await _data_ingestion_save_uploads(files, out_dir / "uploads" / "train", "train")
        reference_source = str(manifest.get("reference_source") or manifest.get("source_mode") or "").strip()
        reference_dataset_id = str(manifest.get("reference_dataset_id") or "").strip()
        if reference_source == "backend_dataset" and reference_dataset_id:
            rows.extend(
                _data_ingestion_dataset_media_rows(
                    reference_dataset_id,
                    field_name="train",
                    max_count=_coerce_int(manifest.get("max_train_images"), 0, minimum=0),
                )
            )
        if not rows:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="local_salad_no_training_files")
    except Exception:
        if out_dir is not None:
            _cleanup_data_ingestion_job_dir(out_dir)
        raise
    request_payload = {**manifest, "train_uploads": rows}
    job = DataIngestionJob(job_id=job_id, kind="local_salad_train", request=request_payload)
    with DATA_INGESTION_JOBS_LOCK:
        _data_ingestion_log(job, f"Queued local SALAD training with {len(rows)} uploads.")
    try:
        _register_job_and_start_thread(
            job=job,
            registry=DATA_INGESTION_JOBS,
            lock=DATA_INGESTION_JOBS_LOCK,
            target=_run_local_salad_training_job,
            args=(job,),
            name=f"local-salad-{job_id[:8]}",
        )
    except Exception:
        if out_dir is not None:
            _cleanup_data_ingestion_job_dir(out_dir)
        raise
    return {"job_id": job_id}


def _get_data_ingestion_job(job_id: str) -> DataIngestionJob:
    with DATA_INGESTION_JOBS_LOCK:
        job = DATA_INGESTION_JOBS.get(str(job_id or ""))
    if not job:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="data_ingestion_job_not_found")
    return job


def get_data_ingestion_job(job_id: str) -> Dict[str, Any]:
    return _serialize_data_ingestion_job(_get_data_ingestion_job(job_id))


def get_data_ingestion_result(job_id: str) -> Dict[str, Any]:
    job = _get_data_ingestion_job(job_id)
    if isinstance(job.result, dict):
        return job.result
    result_path = _safe_job_result_json_path(job.result_path, DATA_INGESTION_ROOT)
    if result_path is not None:
        return _load_json_metadata(result_path) or {}
    if job.status in {"queued", "running", "cancelling"}:
        raise HTTPException(status_code=HTTP_428_PRECONDITION_REQUIRED, detail="job_not_finished")
    raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="result_not_found")


def _data_ingestion_result_item_id(item: Dict[str, Any]) -> str:
    raw = str(item.get("item_id") or "").strip()
    if raw:
        return raw
    return f"item_{_coerce_int(item.get('index'), 0, minimum=0):06d}"


def _data_ingestion_completed_analysis(job_id: str) -> Tuple[DataIngestionJob, Dict[str, Any], List[Dict[str, Any]], Path]:
    job = _get_data_ingestion_job(job_id)
    if job.kind != "analysis":
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="data_ingestion_accept_analysis_required")
    if job.status != "completed":
        raise HTTPException(status_code=HTTP_428_PRECONDITION_REQUIRED, detail="data_ingestion_analysis_not_completed")
    result = get_data_ingestion_result(job_id)
    items = [dict(item) for item in result.get("items") or [] if isinstance(item, dict)]
    if not items:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="data_ingestion_no_ranked_items")
    job_dir = _data_ingestion_job_dir(job.job_id, create=False)
    try:
        job_dir_resolved = job_dir.resolve(strict=True)
        root = _data_ingestion_storage_root(create=False)
        if not _path_is_within_root_impl(job_dir_resolved, root) or job_dir_resolved.parent != root:
            raise ValueError("job dir escapes data ingestion root")
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="data_ingestion_job_artifacts_missing") from exc
    return job, result, items, job_dir_resolved


def _data_ingestion_accept_config(payload: Dict[str, Any]) -> Dict[str, Any]:
    mode = str(payload.get("transform_mode") or payload.get("mode") or "tile").strip().lower()
    mode_aliases = {
        "fit": "resize_fit",
        "resize": "resize_fit",
        "stretch": "resize_stretch",
        "center": "center_crop",
    }
    mode = mode_aliases.get(mode, mode)
    if mode not in {"original", "resize_fit", "resize_stretch", "center_crop", "tile"}:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_mode_invalid")
    target_width = _coerce_int(payload.get("target_width"), 0, minimum=0)
    target_height = _coerce_int(payload.get("target_height"), 0, minimum=0)
    if mode != "original" and (target_width <= 0 or target_height <= 0):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_target_size_required")
    edge_policy = str(payload.get("tile_edge_policy") or payload.get("edge_policy") or "cover_no_padding").strip().lower()
    edge_policy = {
        "cover": "cover_no_padding",
        "pad": "pad_edges",
        "drop": "drop_partials",
    }.get(edge_policy, edge_policy)
    if edge_policy not in {"cover_no_padding", "pad_edges", "drop_partials"}:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_edge_policy_invalid")
    overlap = _coerce_float(payload.get("tile_overlap"), 0.0, minimum=0.0, maximum=0.9)
    quality = _coerce_int(payload.get("jpeg_quality"), 95, minimum=1)
    quality = min(100, max(1, quality))
    return {
        "mode": mode,
        "target_width": target_width,
        "target_height": target_height,
        "tile_edge_policy": edge_policy,
        "tile_overlap": overlap,
        "jpeg_quality": quality,
    }


def _data_ingestion_safe_source_file(item: Dict[str, Any], job_dir: Path) -> Path:
    raw_path = Path(str(item.get("image_path") or ""))
    safe_path = _safe_existing_regular_file_within_root_impl(raw_path, job_dir)
    if safe_path is None:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_source_missing")
    if safe_path.suffix.lower() not in DATA_INGESTION_IMAGE_EXTS:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_source_not_image")
    return safe_path


def _data_ingestion_selected_result_items(items: List[Dict[str, Any]], payload: Dict[str, Any]) -> List[Dict[str, Any]]:
    by_id = {_data_ingestion_result_item_id(item): item for item in items}
    raw_ids = payload.get("item_ids")
    if raw_ids is None:
        raw_ids = payload.get("accepted_item_ids")
    if isinstance(raw_ids, list) and raw_ids:
        selected: List[Dict[str, Any]] = []
        for raw_id in raw_ids:
            item_id = str(raw_id or "").strip()
            if item_id not in by_id:
                raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_item_id_invalid")
            selected.append(by_id[item_id])
        return selected
    return [item for item in items if bool(item.get("keep"))]


def _data_ingestion_tile_positions(size: int, tile: int, overlap: float, edge_policy: str) -> List[int]:
    size = max(1, int(size or 1))
    tile = max(1, int(tile or 1))
    step = max(1, int(round(tile * (1.0 - max(0.0, min(0.9, float(overlap or 0.0)))))))
    if edge_policy == "drop_partials":
        if size < tile:
            return [0]
        return list(range(0, max(1, size - tile + 1), step)) or [0]
    if edge_policy == "pad_edges":
        return list(range(0, size, step)) or [0]
    if size <= tile:
        return [0]
    positions = list(range(0, size - tile + 1, step))
    last = max(0, size - tile)
    if not positions or positions[-1] != last:
        positions.append(last)
    return positions


def _data_ingestion_output_id(item_id: str, mode: str, bounds: Sequence[int], config: Dict[str, Any], ordinal: int) -> str:
    raw = json.dumps(
        {
            "item_id": item_id,
            "mode": mode,
            "bounds": list(bounds),
            "target": [config.get("target_width"), config.get("target_height")],
            "edge": config.get("tile_edge_policy"),
            "overlap": config.get("tile_overlap"),
            "ordinal": ordinal,
        },
        sort_keys=True,
    )
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()[:24]


def _data_ingestion_plan_item_outputs(
    item: Dict[str, Any],
    *,
    job_dir: Path,
    config: Dict[str, Any],
) -> List[Dict[str, Any]]:
    source_path = _data_ingestion_safe_source_file(item, job_dir)
    item_id = _data_ingestion_result_item_id(item)
    filename = str(item.get("filename") or item.get("saved_name") or source_path.name)
    source_group = _data_ingestion_safe_media_name(Path(filename).stem or source_path.stem, "source")
    mode = str(config.get("mode") or "tile")
    with _data_ingestion_open_image(source_path) as img:
        width, height = img.size
    target_w = _coerce_int(config.get("target_width"), 0, minimum=0)
    target_h = _coerce_int(config.get("target_height"), 0, minimum=0)
    output_specs: List[Tuple[List[int], int, int, str]] = []
    if mode == "original":
        ext = source_path.suffix.lower() if source_path.suffix.lower() in DATA_INGESTION_IMAGE_EXTS else ".jpg"
        output_specs.append(([0, 0, width, height], width, height, ext))
    elif mode == "resize_fit":
        scale = min(target_w / max(1, width), target_h / max(1, height))
        out_w = max(1, int(round(width * scale)))
        out_h = max(1, int(round(height * scale)))
        output_specs.append(([0, 0, width, height], out_w, out_h, ".jpg"))
    elif mode in {"resize_stretch", "center_crop"}:
        output_specs.append(([0, 0, width, height], target_w, target_h, ".jpg"))
    else:
        edge_policy = str(config.get("tile_edge_policy") or "cover_no_padding")
        overlap = _coerce_float(config.get("tile_overlap"), 0.0, minimum=0.0, maximum=0.9)
        xs = _data_ingestion_tile_positions(width, target_w, overlap, edge_policy)
        ys = _data_ingestion_tile_positions(height, target_h, overlap, edge_policy)
        for y in ys:
            for x in xs:
                right = min(width, x + target_w)
                bottom = min(height, y + target_h)
                if right <= x or bottom <= y:
                    continue
                if edge_policy == "drop_partials" and (right - x < target_w or bottom - y < target_h) and (width >= target_w and height >= target_h):
                    continue
                out_w = target_w if edge_policy == "pad_edges" or (right - x == target_w) else right - x
                out_h = target_h if edge_policy == "pad_edges" or (bottom - y == target_h) else bottom - y
                output_specs.append(([x, y, right, bottom], out_w, out_h, ".jpg"))
    outputs: List[Dict[str, Any]] = []
    for ordinal, (bounds, out_w, out_h, ext) in enumerate(output_specs):
        output_id = _data_ingestion_output_id(item_id, mode, bounds, config, ordinal)
        suffix = "" if mode == "original" and len(output_specs) == 1 else f"_{mode}_{ordinal + 1:04d}"
        output_filename = f"{source_group}{suffix}_{output_id[:8]}{ext}"
        outputs.append(
            {
                "output_id": output_id,
                "item_id": item_id,
                "source_filename": filename,
                "source_type": str(item.get("source_type") or "image"),
                "frame_index": _coerce_int(item.get("frame_index"), 0, minimum=0),
                "source_width": width,
                "source_height": height,
                "source_bounds": bounds,
                "output_width": out_w,
                "output_height": out_h,
                "output_filename": output_filename,
                "zip_path": str(Path("images") / source_group / output_filename),
                "transform_mode": mode,
                "tile_edge_policy": config.get("tile_edge_policy"),
                "tile_overlap": config.get("tile_overlap"),
                "diversity_score": float(item.get("diversity_score") or 0.0),
                "rank": item.get("rank"),
                "original_keep": bool(item.get("keep")),
                "accepted": True,
                "_source_path": str(source_path),
            }
        )
    return outputs


def _data_ingestion_plan_accepted_outputs(
    job_id: str,
    payload: Dict[str, Any],
) -> Tuple[DataIngestionJob, Dict[str, Any], Dict[str, Any], List[Dict[str, Any]], Path]:
    job, result, items, job_dir = _data_ingestion_completed_analysis(job_id)
    config = _data_ingestion_accept_config(payload)
    selected_items = _data_ingestion_selected_result_items(items, payload)
    outputs: List[Dict[str, Any]] = []
    for item in selected_items:
        outputs.extend(_data_ingestion_plan_item_outputs(item, job_dir=job_dir, config=config))
    raw_output_ids = payload.get("output_ids")
    if raw_output_ids is None:
        raw_output_ids = payload.get("accepted_output_ids")
    if isinstance(raw_output_ids, list) and raw_output_ids:
        wanted = {str(output_id or "").strip() for output_id in raw_output_ids}
        by_id = {str(output.get("output_id") or ""): output for output in outputs}
        if not wanted.issubset(set(by_id.keys())):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_output_id_invalid")
        outputs = [by_id[output_id] for output_id in sorted(wanted)]
    return job, result, config, outputs, job_dir


def _data_ingestion_public_output(output: Dict[str, Any]) -> Dict[str, Any]:
    return {key: json_sanitize(value) for key, value in output.items() if not str(key).startswith("_")}


def _data_ingestion_render_output_image(output: Dict[str, Any], config: Dict[str, Any]) -> Image.Image:
    source_path = Path(str(output.get("_source_path") or ""))
    mode = str(output.get("transform_mode") or config.get("mode") or "tile")
    with _data_ingestion_open_image(source_path) as img:
        if mode == "original":
            return img.copy()
        if mode == "resize_fit":
            resized = img.copy()
            resized.thumbnail((max(1, int(output.get("output_width") or 1)), max(1, int(output.get("output_height") or 1))))
            return resized
        if mode == "resize_stretch":
            return img.resize((max(1, int(output.get("output_width") or 1)), max(1, int(output.get("output_height") or 1))), Image.Resampling.LANCZOS)
        if mode == "center_crop":
            target_w = max(1, int(output.get("output_width") or 1))
            target_h = max(1, int(output.get("output_height") or 1))
            src_w, src_h = img.size
            target_ratio = target_w / target_h
            src_ratio = src_w / max(1, src_h)
            if src_ratio > target_ratio:
                crop_w = max(1, int(round(src_h * target_ratio)))
                left = max(0, (src_w - crop_w) // 2)
                crop = img.crop((left, 0, left + crop_w, src_h))
            else:
                crop_h = max(1, int(round(src_w / target_ratio)))
                top = max(0, (src_h - crop_h) // 2)
                crop = img.crop((0, top, src_w, top + crop_h))
            try:
                return crop.resize((target_w, target_h), Image.Resampling.LANCZOS)
            finally:
                crop.close()
        bounds = [int(v) for v in output.get("source_bounds") or [0, 0, img.width, img.height]]
        x0, y0, x1, y1 = bounds
        crop = img.crop((max(0, x0), max(0, y0), min(img.width, x1), min(img.height, y1)))
        if str(config.get("tile_edge_policy") or "") == "pad_edges":
            target_w = max(1, int(config.get("target_width") or crop.width or 1))
            target_h = max(1, int(config.get("target_height") or crop.height or 1))
            padded = Image.new("RGB", (target_w, target_h), (0, 0, 0))
            padded.paste(crop, (0, 0))
            crop.close()
            return padded
        return crop


def _data_ingestion_image_jpeg_bytes(image: Image.Image, *, quality: int) -> bytes:
    buffer = io.BytesIO()
    image.convert("RGB").save(buffer, format="JPEG", quality=max(1, min(100, int(quality or 95))))
    return buffer.getvalue()


def preview_data_ingestion_accepted_export(job_id: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    _job, _result, config, outputs, job_dir = _data_ingestion_plan_accepted_outputs(job_id, payload)
    offset = _coerce_int(payload.get("offset"), 0, minimum=0)
    limit = min(ACCEPTED_EXPORT_MAX_PREVIEW_OUTPUTS, max(1, _coerce_int(payload.get("limit"), 80, minimum=1)))
    page_outputs = outputs[offset : offset + limit]
    preview_id = f"preview_{uuid.uuid4().hex[:12]}"
    preview_dir = job_dir / "accepted_exports" / preview_id
    thumb_dir = preview_dir / "thumbnails"
    prepared_thumb_dir = _class_analysis_prepare_dir(thumb_dir, job_dir)
    if prepared_thumb_dir is None:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_preview_path_invalid")
    preview_payload = {
        "preview_id": preview_id,
        "job_id": job_id,
        "created_at": time.time(),
        "config": config,
        "offset": offset,
        "limit": limit,
        "total_outputs": len(outputs),
    }
    _class_analysis_write_json(preview_dir / "preview.json", job_dir, preview_payload)
    returned: List[Dict[str, Any]] = []
    for output in page_outputs:
        thumb_path = prepared_thumb_dir / f"{output['output_id']}.jpg"
        image = _data_ingestion_render_output_image(output, config)
        try:
            image.thumbnail((ACCEPTED_EXPORT_THUMB_SIZE, ACCEPTED_EXPORT_THUMB_SIZE))
            _class_analysis_write_jpeg(thumb_path, job_dir, image, quality=82)
        finally:
            image.close()
        public = _data_ingestion_public_output(output)
        public["thumbnail_url"] = f"/data_ingestion/jobs/{job_id}/accepted_export/{preview_id}/thumbnail/{output['output_id']}"
        returned.append(public)
    return {
        "preview_id": preview_id,
        "total_outputs": len(outputs),
        "offset": offset,
        "limit": limit,
        "outputs": returned,
        "config": json_sanitize(config),
        "warnings": _data_ingestion_accepted_export_warnings(config),
    }


def get_data_ingestion_accepted_export_thumbnail(job_id: str, preview_id: str, output_id: str):
    _job, _result, _items, job_dir = _data_ingestion_completed_analysis(job_id)
    safe_preview = _class_analysis_safe_slug(preview_id, "")
    safe_output = re.sub(r"[^a-fA-F0-9]", "", str(output_id or ""))[:64]
    if not safe_preview or not safe_output:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="accepted_export_thumbnail_not_found")
    thumb_dir = job_dir / "accepted_exports" / safe_preview / "thumbnails"
    safe_path = _safe_existing_regular_file_within_root_impl(thumb_dir / f"{safe_output}.jpg", job_dir)
    if safe_path is None:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="accepted_export_thumbnail_not_found")
    return FileResponse(str(safe_path), media_type="image/jpeg")


def _data_ingestion_accepted_export_warnings(config: Dict[str, Any]) -> List[str]:
    warnings_out = ["Export is unsplit to avoid tile/frame leakage across train/val splits."]
    if str(config.get("mode")) == "tile":
        overlap = float(config.get("tile_overlap") or 0.0)
        if overlap > 0:
            warnings_out.append("Tile overlap creates near-duplicates; split by original source later, not by tile.")
        if str(config.get("tile_edge_policy")) == "cover_no_padding":
            warnings_out.append("Cover-no-padding shifts edge tiles inward, which may overlap neighboring tiles.")
    return warnings_out


def download_data_ingestion_accepted_export(job_id: str, payload: Dict[str, Any]):
    job, result, config, outputs, _job_dir = _data_ingestion_plan_accepted_outputs(job_id, payload)
    if not outputs:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_no_outputs")
    if len(outputs) > ACCEPTED_EXPORT_MAX_DOWNLOAD_OUTPUTS:
        raise HTTPException(status_code=HTTP_413_CONTENT_TOO_LARGE, detail="accepted_export_too_many_outputs")
    tmp_dir = Path(tempfile.mkdtemp(prefix="data_ingestion_accepted_export_"))
    safe_job = _class_analysis_safe_slug(job.job_id, "data_ingestion")
    try:
        zip_path = tmp_dir / f"{safe_job}_accepted.zip"
        public_outputs = [_data_ingestion_public_output(output) for output in outputs]
        summary = {
            "job_id": job.job_id,
            "profile_id": (result.get("summary") or {}).get("salad_head_id") or "",
            "created_at": time.time(),
            "transform": json_sanitize(config),
            "accepted_item_count": len({output.get("item_id") for output in outputs}),
            "output_count": len(outputs),
            "warnings": _data_ingestion_accepted_export_warnings(config),
        }
        manifest = {
            "version": 1,
            "summary": summary,
            "outputs": public_outputs,
        }
        with zipfile.ZipFile(zip_path, "w", compression=zipfile.ZIP_DEFLATED) as zf:
            for output in outputs:
                arcname = str(output.get("zip_path") or Path("images") / output.get("output_filename"))
                if _data_ingestion_zip_member_is_unsafe(arcname):
                    raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="accepted_export_output_path_invalid")
                if str(output.get("transform_mode")) == "original":
                    source_path = Path(str(output.get("_source_path") or ""))
                    zf.write(source_path, arcname=arcname)
                else:
                    image = _data_ingestion_render_output_image(output, config)
                    try:
                        zf.writestr(arcname, _data_ingestion_image_jpeg_bytes(image, quality=int(config.get("jpeg_quality") or 95)))
                    finally:
                        image.close()
            zf.writestr("manifest.json", json.dumps(manifest, ensure_ascii=False, indent=2))
            zf.writestr("summary.json", json.dumps(summary, ensure_ascii=False, indent=2))
        return FileResponse(
            path=str(zip_path),
            media_type="application/zip",
            filename=f"{safe_job}_accepted.zip",
            background=BackgroundTask(shutil.rmtree, tmp_dir, ignore_errors=True),
        )
    except HTTPException:
        shutil.rmtree(tmp_dir, ignore_errors=True)
        raise
    except Exception as exc:  # noqa: BLE001
        shutil.rmtree(tmp_dir, ignore_errors=True)
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"accepted_export_failed:{exc}") from exc


def cancel_data_ingestion_job(job_id: str) -> Dict[str, Any]:
    job = _get_data_ingestion_job(job_id)
    with DATA_INGESTION_JOBS_LOCK:
        if job.status in {"completed", "failed", "cancelled"}:
            raise HTTPException(status_code=HTTP_428_PRECONDITION_REQUIRED, detail="job_not_cancellable")
        job.cancel_event.set()
        _data_ingestion_update(job, status="cancelling", message="Cancellation requested ...")
    return {"status": job.status}


def list_glossary_library():
    entries = []
    try:
        root = _glossary_library_root(create=False)
    except HTTPException:
        return entries
    if not root.exists():
        return entries
    for path in sorted(root.glob("*.json")):
        try:
            if path.is_symlink():
                continue
            resolved = path.resolve(strict=True)
            if not _path_is_within_root_impl(resolved, root) or not resolved.is_file():
                continue
        except Exception:
            continue
        data = _load_json_metadata(path) or {}
        name = data.get("name") or path.stem
        glossary = data.get("glossary") or ""
        entries.append(
            {
                "name": name,
                "preview": _glossary_preview(str(glossary or ""), []),
                "updated_at": path.stat().st_mtime,
            }
        )
    return entries


def _glossary_library_root(*, create: bool = False) -> Path:
    try:
        raw_root = GLOSSARY_LIBRARY_ROOT
        if _storage_path_has_symlink_component(raw_root):
            raise RuntimeError("glossary root is a symlink")
        if create:
            raw_root.mkdir(parents=True, exist_ok=True)
        if raw_root.exists() and not raw_root.is_dir():
            raise RuntimeError("glossary root is not a directory")
        if _storage_path_has_symlink_component(raw_root):
            raise RuntimeError("glossary root is a symlink")
        return raw_root.resolve(strict=False)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid") from exc


def _glossary_library_safe_name(name: str) -> str:
    raw = str(name or "").strip()
    if not raw:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_name_required")
    if "/" in raw or "\\" in raw:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_name_invalid")
    safe = re.sub(r"[^a-zA-Z0-9._-]+", "-", raw).strip("-_.")
    if not safe:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_name_invalid")
    return safe


def _glossary_library_path(name: str) -> Tuple[Path, str]:
    safe = _glossary_library_safe_name(name)
    root = _glossary_library_root(create=False)
    path = root / f"{safe}.json"
    try:
        parent = path.parent.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid") from exc
    if not _path_is_within_root_impl(parent, root):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid")
    if not path.is_symlink():
        try:
            resolved = path.resolve(strict=False)
        except Exception as exc:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid") from exc
        if not _path_is_within_root_impl(resolved, root):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid")
    return path, safe


def get_glossary_entry(name: str):
    path, safe = _glossary_library_path(name)
    if path.is_symlink() or not path.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="glossary_not_found")
    data = _load_json_metadata(path) or {}
    glossary = data.get("glossary") if isinstance(data, dict) else ""
    return {"name": data.get("name") or safe, "glossary": glossary or ""}


def _write_glossary_entry_atomic(path: Path, safe: str, payload: Dict[str, Any]) -> None:
    root = _glossary_library_root(create=True)
    try:
        if _storage_path_has_symlink_component(path.parent):
            raise ValueError("glossary parent has a symlink component")
        parent = path.parent.resolve(strict=False)
        if parent != root or not _path_is_within_root_impl(parent, root):
            raise ValueError("glossary parent escapes root")
        if not path.is_symlink():
            target = path.resolve(strict=False)
            if not _path_is_within_root_impl(target, root):
                raise ValueError("glossary target escapes root")
        if path.exists() and not path.is_file() and not path.is_symlink():
            raise ValueError("glossary target is not a file")
        tmp_path = root / f".{safe}.{os.getpid()}.{uuid.uuid4().hex}.tmp"
        if _storage_path_has_symlink_component(tmp_path.parent) or tmp_path.is_symlink():
            raise ValueError("glossary temp path invalid")
        tmp_target = tmp_path.resolve(strict=False)
        if not _path_is_within_root_impl(tmp_target, root):
            raise ValueError("glossary temp path escapes root")
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="glossary_path_invalid") from exc
    try:
        flags = os.O_WRONLY | os.O_CREAT | os.O_TRUNC
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(tmp_path, flags, 0o644)
        with os.fdopen(fd, "w", encoding="utf-8") as handle:
            json.dump(payload, handle, ensure_ascii=False, indent=2)
        os.replace(tmp_path, path)
    except Exception as exc:
        raise HTTPException(
            status_code=HTTP_500_INTERNAL_SERVER_ERROR,
            detail=f"glossary_save_failed:{exc}",
        ) from exc
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)


def save_glossary_entry(name: str, glossary: str):
    _glossary_library_root(create=True)
    path, safe = _glossary_library_path(name)
    payload = {"name": name, "glossary": glossary}
    _write_glossary_entry_atomic(path, safe, payload)
    return {"status": "saved", "name": name}


def delete_glossary_entry(name: str):
    path, _safe = _glossary_library_path(name)
    if not path.exists() and not path.is_symlink():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="glossary_not_found")
    path.unlink(missing_ok=True)
    return {"status": "deleted", "name": name}


def list_qwen_datasets():
    return [entry for entry in _list_all_datasets() if entry.get("source") == "qwen"]


def delete_qwen_dataset(dataset_id: str):
    raw_id = str(dataset_id or "").strip()
    if (
        not raw_id
        or raw_id in {".", ".."}
        or "/" in raw_id
        or "\\" in raw_id
        or Path(raw_id).is_absolute()
    ):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_id_invalid")
    qwen_root = _qwen_dataset_storage_root(
        create=False, detail="qwen_dataset_delete_forbidden"
    )
    dataset_path = qwen_root / raw_id
    if dataset_path.is_symlink():
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_delete_forbidden"
        )
    try:
        dataset_root = dataset_path.resolve(strict=True)
    except Exception:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_not_found") from None
    if not dataset_root.exists() or not dataset_root.is_dir():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_not_found")
    if not _path_is_within_root_impl(dataset_root, qwen_root):
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_delete_forbidden"
        )
    blocking_registry = _active_job_registry_referencing_path_root(dataset_root)
    if blocking_registry:
        raise HTTPException(
            status_code=HTTP_409_CONFLICT,
            detail=f"qwen_dataset_delete_blocked_active_jobs:{blocking_registry}",
        )
    return _soft_delete_managed_dataset_tree(
        dataset_path,
        [QWEN_DATASET_ROOT],
        dataset_id=raw_id,
        entry={
            "id": raw_id,
            "label": raw_id,
            "dataset_root": str(dataset_root),
            "source": "qwen",
            "storage_mode": "managed",
        },
    )


def init_qwen_dataset_upload(run_name: Optional[str]) -> Dict[str, Any]:
    job_id = uuid.uuid4().hex
    root_dir = _qwen_dataset_upload_job_dir(job_id, create=True)
    (root_dir / "train").mkdir(parents=True, exist_ok=True)
    (root_dir / "val").mkdir(parents=True, exist_ok=True)
    job = QwenDatasetUploadJob(job_id=job_id, root_dir=root_dir, run_name=run_name)
    with QWEN_DATASET_UPLOADS_LOCK:
        QWEN_DATASET_UPLOADS[job_id] = job
    return {"job_id": job_id}


def upload_qwen_dataset_chunk(
    job_id: str, split: str, image_name: str, annotation_line: str, file: UploadFile
):
    try:
        with QWEN_DATASET_UPLOADS_LOCK:
            job = QWEN_DATASET_UPLOADS.get(job_id)
        if not job:
            raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_job_not_found")
        with job.lock:
            with QWEN_DATASET_UPLOADS_LOCK:
                if QWEN_DATASET_UPLOADS.get(job_id) is not job:
                    raise HTTPException(
                        status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_job_not_found"
                    )
            split = split.lower()
            if split not in {"train", "val"}:
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_split_invalid"
                )
            annotation_text = str(annotation_line or "").strip()
            if "\n" in annotation_text or "\r" in annotation_text:
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_annotation_invalid"
                )
            try:
                annotation_payload = json.loads(annotation_text)
            except Exception as exc:  # noqa: BLE001
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_annotation_invalid"
                ) from exc
            if not isinstance(annotation_payload, dict):
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_annotation_invalid"
                )
            if job.root_dir.is_symlink():
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_source_path_invalid",
                )
            try:
                job_root_resolved = job.root_dir.resolve(strict=True)
            except Exception as exc:  # noqa: BLE001
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_source_path_invalid",
                ) from exc
            if not job_root_resolved.is_dir():
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_source_path_invalid",
                )
            split_root_raw = job.root_dir / split
            if split_root_raw.is_symlink():
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_split_path_invalid",
                )
            split_root = split_root_raw.resolve(strict=False)
            if not _path_is_within_root_impl(split_root, job_root_resolved):
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_split_path_invalid",
                )
            split_root.mkdir(parents=True, exist_ok=True)
            if split_root_raw.is_symlink():
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_split_path_invalid",
                )
            raw_image_name = image_name or file.filename or f"{uuid.uuid4().hex}.jpg"
            image_name_safe = Path(raw_image_name).name or f"{uuid.uuid4().hex}.jpg"
            if image_name_safe.lower() == "annotations.jsonl":
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_image_name_reserved",
                )
            annotation_payload["image"] = image_name_safe
            annotation_text = json.dumps(annotation_payload, ensure_ascii=False, separators=(",", ":"))
            image_candidate = split_root / image_name_safe
            if image_candidate.is_symlink():
                raise HTTPException(status_code=HTTP_409_CONFLICT, detail="qwen_dataset_image_exists")
            image_path = image_candidate.resolve()
            if not _path_is_within_root_impl(image_path, split_root.resolve()):
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_image_path_invalid"
                )
            if image_path.exists():
                raise HTTPException(status_code=HTTP_409_CONFLICT, detail="qwen_dataset_image_exists")
            written_box = {"bytes": 0}

            def write_upload_image(handle: Any) -> None:
                while True:
                    chunk = file.file.read(1024 * 1024)
                    if not chunk:
                        break
                    written_box["bytes"] += len(chunk)
                    if QWEN_DATASET_CHUNK_MAX_BYTES and written_box["bytes"] > QWEN_DATASET_CHUNK_MAX_BYTES:
                        raise HTTPException(
                            status_code=HTTP_413_CONTENT_TOO_LARGE,
                            detail="qwen_dataset_chunk_too_large",
                        )
                    handle.write(chunk)
                if written_box["bytes"] <= 0:
                    raise HTTPException(
                        status_code=HTTP_400_BAD_REQUEST,
                        detail="qwen_dataset_empty_image",
                    )

            try:
                _qwen_upload_write_binary_within_root(
                    image_path,
                    split_root,
                    write_upload_image,
                    detail="qwen_dataset_image_path_invalid",
                )
            except Exception:
                try:
                    image_path.unlink(missing_ok=True)
                except Exception:
                    pass
                raise
            ann_path = split_root / "annotations.jsonl"
            if ann_path.is_symlink():
                try:
                    image_path.unlink(missing_ok=True)
                except Exception:
                    pass
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_annotation_path_invalid",
                )
            try:
                _qwen_upload_append_text_within_root(
                    ann_path,
                    split_root,
                    annotation_text + "\n",
                )
            except Exception:
                try:
                    image_path.unlink(missing_ok=True)
                except Exception:
                    pass
                raise
            if split == "train":
                job.train_count += 1
            else:
                job.val_count += 1
            job.updated_at = time.time()
            return {
                "status": "ok",
                "job_id": job_id,
                "train_count": job.train_count,
                "val_count": job.val_count,
            }
    finally:
        try:
            file.file.close()
        except Exception:
            pass


def finalize_qwen_dataset_upload(job_id: str, metadata: Dict[str, Any], run_name: Optional[str]):
    with QWEN_DATASET_UPLOADS_LOCK:
        job = QWEN_DATASET_UPLOADS.get(job_id)
    if not job:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_job_not_found")
    with job.lock:
        with QWEN_DATASET_UPLOADS_LOCK:
            if QWEN_DATASET_UPLOADS.get(job_id) is not job:
                raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_dataset_job_not_found")
        if job.train_count + job.val_count <= 0:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_dataset_empty")
        if not isinstance(metadata, dict):
            metadata = {}
        base_id = run_name or metadata.get("id") or job.run_name or job_id
        base_id = _sanitize_yolo_run_id_impl(str(base_id)) or str(job_id)
        classes = metadata.get("classes") or []
        labelmap = [str(c).strip() for c in classes if str(c).strip()]
        source_root = _qwen_dataset_upload_resolve_source_root(job)
        _validate_qwen_dataset_upload_source_tree(
            source_root,
            allow_replaceable_top_level=True,
        )
        created_at = time.time()

        with QWEN_DATASET_FINALIZE_LOCK:
            qwen_root = _qwen_dataset_storage_root(
                create=True, detail="qwen_dataset_target_invalid"
            )
            dataset_id_final = _unique_dataset_name(base_id, root=qwen_root)
            target_root = qwen_root / dataset_id_final
            target_resolved = target_root.resolve(strict=False)
            if not _path_is_within_root_impl(target_resolved, qwen_root):
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail="qwen_dataset_target_invalid",
                )
            if target_root.exists() or target_root.is_symlink():
                raise HTTPException(
                    status_code=HTTP_409_CONFLICT,
                    detail="qwen_dataset_target_exists",
                )

            try:
                for stale_name in (QWEN_METADATA_FILENAME, "dataset_meta.json"):
                    (source_root / stale_name).unlink(missing_ok=True)
                labelmap_path = source_root / "labelmap.txt"
                if labelmap_path.is_symlink():
                    labelmap_path.unlink(missing_ok=True)
                if labelmap:
                    _qwen_upload_write_text_within_root(
                        labelmap_path,
                        source_root,
                        "\n".join(labelmap) + "\n",
                    )
                else:
                    labelmap_path.unlink(missing_ok=True)
                meta = {
                    "id": dataset_id_final,
                    "label": dataset_id_final,
                    "classes": labelmap,
                    "context": metadata.get("context") or "",
                    "created_at": created_at,
                    "train_count": job.train_count,
                    "val_count": job.val_count,
                    "image_count": job.train_count + job.val_count,
                    "signature": _compute_dir_signature_impl(source_root),
                    "type": "bbox",
                }
                _qwen_upload_write_text_within_root(
                    source_root / "metadata.json",
                    source_root,
                    json.dumps(meta, ensure_ascii=False, indent=2),
                )
                dataset_meta = {
                    "context": meta["context"],
                    "classes": labelmap,
                    "created_at": int(created_at * 1000),
                }
                _qwen_upload_write_text_within_root(
                    source_root / "dataset_meta.json",
                    source_root,
                    json.dumps(dataset_meta, ensure_ascii=False, indent=2),
                )
                _validate_qwen_dataset_upload_source_tree(source_root)
                shutil.move(str(source_root), target_root)
            except HTTPException:
                if target_root.exists():
                    shutil.rmtree(target_root, ignore_errors=True)
                raise
            except Exception as exc:  # noqa: BLE001
                if target_root.exists():
                    shutil.rmtree(target_root, ignore_errors=True)
                raise HTTPException(
                    status_code=HTTP_500_INTERNAL_SERVER_ERROR,
                    detail=f"qwen_dataset_finalize_failed:{exc}",
                ) from exc

        with QWEN_DATASET_UPLOADS_LOCK:
            if QWEN_DATASET_UPLOADS.get(job_id) is job:
                QWEN_DATASET_UPLOADS.pop(job_id, None)
        return meta


def _cleanup_qwen_dataset_upload_root(root_dir: Path) -> None:
    try:
        raw_root = Path(root_dir)
        if raw_root.is_symlink():
            raw_root.unlink(missing_ok=True)
            return
        if _storage_path_has_symlink_component(raw_root.parent):
            return
        upload_root = _qwen_dataset_upload_storage_root(
            create=False, detail="qwen_dataset_upload_path_invalid"
        )
        resolved = raw_root.resolve(strict=True)
    except Exception:
        return
    if (
        not resolved.is_dir()
        or not _path_is_within_root_impl(resolved, upload_root)
        or resolved.parent != upload_root
    ):
        return
    shutil.rmtree(resolved, ignore_errors=True)


def cancel_qwen_dataset_upload(job_id: str):
    with QWEN_DATASET_UPLOADS_LOCK:
        job = QWEN_DATASET_UPLOADS.get(job_id)
    if not job:
        return {"status": "missing", "job_id": job_id}
    with job.lock:
        with QWEN_DATASET_UPLOADS_LOCK:
            if QWEN_DATASET_UPLOADS.get(job_id) is not job:
                return {"status": "missing", "job_id": job_id}
            QWEN_DATASET_UPLOADS.pop(job_id, None)
        _cleanup_qwen_dataset_upload_root(job.root_dir)
        return {"status": "cancelled", "job_id": job_id}


def list_sam3_datasets():
    return _list_all_datasets()


def _sam3_entry_needs_annotation_materialized_view(entry: Dict[str, Any]) -> bool:
    storage_mode = str(entry.get("storage_mode") or "managed").strip().lower()
    yolo_layout = str(entry.get("yolo_layout") or "").strip().lower()
    if storage_mode == "linked" or yolo_layout != "split":
        return True
    try:
        overlay_root = _dataset_overlay_root_from_entry(entry, ensure=False)
    except Exception:
        return False
    if not overlay_root.exists():
        return False
    return any(path.is_file() for path in overlay_root.rglob("*.txt"))


def _reset_materialized_dataset_root(raw_root: Path, allowed_root: Path, *, detail: str) -> Path:
    try:
        if _storage_path_has_symlink_component(allowed_root):
            raise ValueError("materialization allowed root is a symlink")
        allowed_resolved = allowed_root.resolve(strict=False)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("materialization target is a symlink")
        raw_parent = raw_root.parent
        if _storage_path_has_symlink_component(raw_parent):
            raise ValueError("materialization parent is a symlink")
        parent_resolved = raw_parent.resolve(strict=False)
        if not _path_is_within_root_impl(parent_resolved, allowed_resolved):
            raise ValueError("materialization parent escapes root")
        target_resolved = raw_root.resolve(strict=False)
        if not _path_is_within_root_impl(target_resolved, allowed_resolved):
            raise ValueError("materialization target escapes root")
        if raw_root.exists():
            if not raw_root.is_dir():
                raise ValueError("materialization target is not a directory")
            shutil.rmtree(raw_root)
        if raw_root.exists() or raw_root.is_symlink():
            raise ValueError("materialization target cleanup failed")
        raw_root.mkdir(parents=True, exist_ok=False)
        if _storage_path_has_symlink_component(raw_root):
            raise ValueError("materialization target is a symlink after create")
        created = raw_root.resolve(strict=True)
        if not _path_is_within_root_impl(created, allowed_resolved):
            raise ValueError("materialization target escapes root after create")
        return created
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _materialize_sam3_annotation_view(entry: Dict[str, Any]) -> Dict[str, Any]:
    dataset_root = _dataset_effective_root_from_entry(entry)
    storage_root = _dataset_guarded_meta_storage_root_from_entry(
        entry,
        ensure=False,
        detail="sam3_materialize_path_invalid",
    )
    materialized_root_raw = (
        storage_root / DATASET_ANNOTATION_OVERLAY_DIRNAME / "sam3_materialized"
    )
    materialized_root = _reset_materialized_dataset_root(
        materialized_root_raw,
        storage_root,
        detail="sam3_materialize_path_invalid",
    )
    for split in ("train", "val"):
        (materialized_root / split / "images").mkdir(parents=True, exist_ok=True)
        (materialized_root / split / "labels").mkdir(parents=True, exist_ok=True)

    labelmap = [str(item).strip() for item in (entry.get("classes") or []) if str(item).strip()]
    if not labelmap:
        labelmap = _dataset_labelmap_from_root(dataset_root)
    if not labelmap:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="sam3_labelmap_missing")
    _materialized_dataset_write_text_within_root(
        materialized_root / "labelmap.txt",
        materialized_root,
        "\n".join(labelmap) + "\n",
        detail="sam3_materialize_path_invalid",
    )

    yolo_layout = str(entry.get("yolo_layout") or "flat")
    counts = {"train": 0, "val": 0}
    dataset_root_resolved = dataset_root.resolve()
    for row in _annotation_collect_images(entry):
        try:
            split = _annotation_normalise_split(row.get("split"))
            image_relpath = _annotation_normalise_image_relpath(row.get("image_relpath"))
        except HTTPException:
            continue
        image_path_raw = row.get("image_path")
        if image_path_raw is None:
            continue
        try:
            image_source = Path(str(image_path_raw)).resolve()
        except Exception:
            continue
        if not _path_is_within_root_impl(image_source, dataset_root_resolved):
            continue
        lines = _annotation_effective_label_lines(entry, split, image_relpath)
        overlay_label_path = _annotation_overlay_label_path(entry, split, image_relpath)
        source_label_path = _annotation_source_label_path(
            dataset_root, yolo_layout, split, image_relpath
        )
        if not lines and not overlay_label_path.exists() and not source_label_path.exists():
            continue
        target_image = materialized_root / split / "images" / image_relpath
        target_label = materialized_root / split / "labels" / image_relpath.with_suffix(".txt")
        _copy2_if_different(image_source, target_image)
        _materialized_dataset_write_text_within_root(
            target_label,
            materialized_root,
            "\n".join(lines) + ("\n" if lines else ""),
            detail="sam3_materialize_path_invalid",
        )
        counts[split] += 1

    meta = _convert_yolo_dataset_to_coco_impl(materialized_root)
    meta["id"] = str(entry.get("id") or meta.get("id") or materialized_root.name)
    meta["label"] = str(entry.get("label") or meta.get("label") or meta["id"])
    meta["source"] = "annotation_overlay"
    meta["source_dataset_root"] = str(dataset_root)
    meta["annotation_storage_root"] = str(storage_root)
    meta["classes"] = labelmap
    meta["train_count"] = counts["train"]
    meta["val_count"] = counts["val"]
    meta["image_count"] = counts["train"] + counts["val"]
    _persist_sam3_dataset_metadata_impl(
        materialized_root, meta, meta_name=SAM3_DATASET_META_NAME, logger=logger
    )
    return meta


def _resolve_sam3_dataset_meta(dataset_id: str) -> Dict[str, Any]:
    entry = _resolve_dataset_entry_impl(dataset_id, list_all_datasets_fn=_list_all_datasets)
    dataset_root = _resolve_sam3_or_qwen_dataset(dataset_id)
    annotations_path = dataset_root / "train" / "annotations.jsonl"
    train_images = dataset_root / "train" / "images"
    train_labels = dataset_root / "train" / "labels"
    if entry and entry.get("qwen_ready"):
        meta = _convert_qwen_dataset_to_coco_impl(dataset_root)
    elif entry and entry.get("yolo_ready") and _sam3_entry_needs_annotation_materialized_view(entry):
        meta = _materialize_sam3_annotation_view(entry)
    elif annotations_path.exists():
        meta = _convert_qwen_dataset_to_coco_impl(dataset_root)
    elif train_images.exists() and train_labels.exists():
        meta = _convert_yolo_dataset_to_coco_impl(dataset_root)
    else:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST, detail="sam3_dataset_type_unsupported"
        )
    if not meta.get("dataset_root"):
        meta["dataset_root"] = str(dataset_root)
    return meta


def convert_sam3_dataset(dataset_id: str):
    meta = _resolve_sam3_dataset_meta(dataset_id)
    return meta


def list_sam3_dataset_classes(dataset_id: str):
    entry = _resolve_dataset_entry(dataset_id)
    classes = entry.get("classes") or []
    if classes:
        return {"dataset_id": dataset_id, "classes": classes}
    dataset_root = Path(entry["dataset_root"])
    labelmap_path = dataset_root / "labelmap.txt"
    if labelmap_path.exists():
        classes = [
            line.strip()
            for line in labelmap_path.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    return {"dataset_id": dataset_id, "classes": classes}


