def _tune_clip_head_for_selected_steps_image_first(
    *,
    cat_id: int,
    class_name: str,
    steps: Sequence[Dict[str, Any]],
    val_ids: Sequence[int],
    images: Dict[int, Dict[str, Any]],
    gt_by_image_cat: Dict[int, Dict[int, List[List[float]]]],
    payload: AgentMiningRequest,
    clip_head: Dict[str, Any],
    clip_head_target_index: int,
    workers: Optional[Sequence[_Sam3GreedyEvalWorker]],
    log_every: int,
    log_fn: Optional[Callable[[str], None]],
    cancel_event: Optional[threading.Event],
    progress_callback: Optional[Callable[[int, int], None]],
    export_hard_negatives: bool,
) -> Dict[str, Any]:
    all_gt_scores: Dict[Any, float] = {}
    fp_scores: List[float] = []
    total_preds = 0
    total_gt = 0
    for idx, step in enumerate(steps or [], start=1):
        if cancel_event is not None and cancel_event.is_set():
            break
        prompt = str(step.get("prompt") or "").strip()
        if not prompt:
            continue
        metrics = _evaluate_prompt_for_class(
            prompt,
            cat_id=int(cat_id),
            image_ids=val_ids,
            gt_by_image_cat=gt_by_image_cat,
            images=images,
            score_threshold=float(step.get("seed_threshold", payload.seed_threshold)),
            max_dets=int(step.get("max_results", payload.max_results)),
            iou_threshold=float(payload.iou_threshold),
            image_cache={},
        )
        total_preds += int(metrics.get("preds", 0))
        total_gt = max(total_gt, int(metrics.get("gts", 0)))
        fp_scores.extend(float(v) for v in (metrics.get("fp_scores") or []))
        for key, score in (metrics.get("gt_best_scores") or {}).items():
            prev = all_gt_scores.get(key)
            all_gt_scores[key] = float(score) if prev is None else max(float(prev), float(score))
        if callable(progress_callback):
            try:
                progress_callback(idx, max(1, len(steps)))
            except Exception:
                pass
    matches = len(all_gt_scores)
    fps = len(fp_scores)
    precision = float(matches / (matches + fps)) if (matches + fps) else 0.0
    recall = float(matches / total_gt) if total_gt > 0 else 0.0
    return {
        "gts": int(total_gt),
        "matches": int(matches),
        "fps": int(fps),
        "duplicates": 0,
        "preds": int(total_preds),
        "precision": float(precision),
        "recall": float(recall),
        "coverage_rate": float(recall),
        "det_rate": float(total_preds / max(1, len(val_ids))),
        "clip_head_min_prob": float(getattr(payload, "clip_head_min_prob", 0.0)),
        "clip_head_margin": float(getattr(payload, "clip_head_margin", 0.0)),
        "clip_head_background_margin": float(getattr(payload, "clip_head_background_margin", 0.0)),
    }


def _apply_agent_recipe_to_image(
    recipe_obj: Dict[str, Any],
    *,
    image: Dict[str, Any],
    dataset_id: str,
    images: Dict[int, Dict[str, Any]],
    mask_threshold: float,
    min_size: float,
    simplify_epsilon: float,
    max_results: int,
    class_id: Optional[int],
    class_name: Optional[str],
    clip_head_min_prob_override: Optional[float],
    clip_head_margin_override: Optional[float],
    extra_clip_classifier_path: Optional[str],
    extra_clip_min_prob: Optional[float],
    extra_clip_margin: Optional[float],
    warnings: List[str],
) -> List[QwenDetection]:
    image_path = Path(str(image.get("path") or "")).expanduser()
    if not image_path.exists():
        warnings.append("agent_recipe_image_missing")
        return []
    try:
        with Image.open(image_path) as opened:
            pil_img = opened.convert("RGB")
    except Exception:
        warnings.append("agent_recipe_image_open_failed")
        return []
    mode = _classify_agent_recipe_mode_impl(recipe_obj)
    prompts: List[Tuple[str, float, int]] = []
    if mode == "steps":
        steps = recipe_obj.get("steps") or []
        for step in steps:
            if not isinstance(step, dict):
                continue
            if step.get("enabled") is False:
                continue
            prompt = str(step.get("prompt") or "").strip()
            if not prompt:
                continue
            try:
                seed_threshold = float(
                    step.get("seed_threshold", recipe_obj.get("seed_threshold", 0.0))
                )
            except Exception:
                seed_threshold = 0.0
            try:
                step_max_results = int(step.get("max_results", max_results))
            except Exception:
                step_max_results = int(max_results)
            prompts.append((prompt, seed_threshold, max(1, step_max_results)))
    else:
        for prompt in recipe_obj.get("text_prompts") or []:
            cleaned = str(prompt).strip()
            if cleaned:
                prompts.append(
                    (cleaned, float(recipe_obj.get("seed_threshold", 0.0) or 0.0), int(max_results))
                )
    if not prompts:
        fallback = str(class_name or recipe_obj.get("class_name") or "").strip()
        if fallback:
            prompts = [(fallback, 0.0, int(max_results))]
        else:
            warnings.append("agent_recipe_no_prompts")
            return []
    detections: List[QwenDetection] = []
    for prompt, seed_thr, step_max in prompts:
        try:
            step_dets = _run_sam3_text_inference(
                pil_img,
                prompt,
                threshold=float(max(0.0, min(1.0, seed_thr))),
                mask_threshold=float(mask_threshold),
                limit=max(1, int(step_max)),
                min_size=float(min_size),
                simplify_epsilon=float(simplify_epsilon),
            )
        except Exception:
            warnings.append(f"agent_recipe_prompt_failed:{prompt}")
            continue
        for det in step_dets or []:
            if class_id is not None:
                det.class_id = int(class_id)
            if class_name:
                det.class_name = str(class_name)
            detections.append(det)
    if not detections:
        return []
    dedupe_iou = float(recipe_obj.get("dedupe_iou") or 0.5)
    deduped = _dedupe_qwen_detections_iou(
        detections,
        img_w=pil_img.width,
        img_h=pil_img.height,
        iou_thresh=dedupe_iou,
    )
    return deduped[: max(1, int(max_results))]


def _suggest_prompts_for_dataset(payload: PromptHelperSuggestRequest) -> Dict[str, Any]:
    dataset_root = _resolve_coco_index_dataset_root(payload.dataset_id)
    coco, _, _ = _load_coco_index_impl(dataset_root)
    classes: List[Dict[str, Any]] = []
    for idx, cat in enumerate(coco.get("categories") or []):
        try:
            cat_id = int(cat.get("id", idx))
        except Exception:
            cat_id = idx
        class_name = str(cat.get("name", f"class_{cat_id}"))
        prompts = _generate_prompt_variants_for_class(
            class_name, int(payload.max_synonyms), bool(payload.use_qwen)
        )
        classes.append(
            {
                "class_id": cat_id,
                "class_name": class_name,
                "default_prompts": prompts,
            }
        )
    return {
        "dataset_id": payload.dataset_id,
        "classes": classes,
        "config": {"max_synonyms": int(payload.max_synonyms), "use_qwen": bool(payload.use_qwen)},
    }


class _Sam1SegWorker:
    def __init__(self, device: torch.device):
        self.device = device

    def process_image(
        self,
        *,
        image_id: int,
        pil_img: Image.Image,
        tasks: Sequence[Dict[str, Any]],
        min_threshold: float,
        mask_threshold: float,
        max_results: int,
        min_size: float,
        simplify: float,
        return_masks: bool,
    ) -> Dict[str, List[Dict[str, Any]]]:
        np_img = np.asarray(pil_img.convert("RGB"))
        outputs: Dict[str, List[Dict[str, Any]]] = {}
        for task in tasks:
            task_id = str(task.get("id") or "")
            bbox = task.get("bbox") or []
            if not task_id or not isinstance(bbox, (list, tuple)) or len(bbox) < 4:
                continue
            x, y, w, h = [float(v) for v in bbox[:4]]
            box_xyxy = np.array([x, y, x + w, y + h], dtype=np.float32)
            try:
                masks, scores, _ = _predict_with_cache(
                    np_img,
                    token=None,
                    variant="sam1",
                    image_name=f"seg_builder_{image_id}",
                    box=box_xyxy,
                    multimask_output=True,
                )
            except Exception:
                outputs[task_id] = []
                continue
            dets: List[Dict[str, Any]] = []
            masks_arr = (
                np.asarray(masks)
                if masks is not None
                else np.zeros((0, pil_img.height, pil_img.width), dtype=np.uint8)
            )
            scores_arr = (
                np.asarray(scores).reshape(-1)
                if scores is not None
                else np.zeros((len(masks_arr),), dtype=np.float32)
            )
            order = list(range(len(masks_arr)))
            order.sort(
                key=lambda i: float(scores_arr[i]) if i < len(scores_arr) else 0.0, reverse=True
            )
            for idx in order[: max(1, int(max_results))]:
                score = float(scores_arr[idx]) if idx < len(scores_arr) else 0.0
                if score < float(min_threshold):
                    continue
                mask = np.asarray(masks_arr[idx]).astype(np.uint8)
                if min_size > 0 and float(np.count_nonzero(mask)) < float(min_size):
                    continue
                dets.append({"score": score, "mask_array": mask})
            outputs[task_id] = dets
        return outputs

    def close(self) -> None:
        return


class _Sam3SegWorker:
    def __init__(self, device: torch.device):
        self.device = device

    def process_image(
        self,
        *,
        image_id: int,
        pil_img: Image.Image,
        tasks: Sequence[Dict[str, Any]],
        min_threshold: float,
        mask_threshold: float,
        max_results: int,
        min_size: float,
        simplify: float,
        return_masks: bool,
    ) -> Dict[str, List[Dict[str, Any]]]:
        outputs: Dict[str, List[Dict[str, Any]]] = {}
        for task in tasks:
            task_id = str(task.get("id") or "")
            bbox = task.get("bbox") or []
            if not task_id or not isinstance(bbox, (list, tuple)) or len(bbox) < 4:
                continue
            try:
                dets, masks = _run_sam3_visual_inference(
                    pil_img,
                    (float(bbox[0]), float(bbox[1]), float(bbox[2]), float(bbox[3])),
                    threshold=float(min_threshold),
                    mask_threshold=float(mask_threshold),
                    limit=max(1, int(max_results)),
                    return_masks=True,
                    min_size=float(min_size),
                    simplify_epsilon=float(simplify),
                )
            except Exception:
                outputs[task_id] = []
                continue
            entries: List[Dict[str, Any]] = []
            for idx, det in enumerate(dets or []):
                score = float(det.score or 0.0)
                mask_arr = None
                if isinstance(masks, list) and idx < len(masks):
                    mask_arr = masks[idx]
                entries.append({"score": score, "mask_array": mask_arr})
            outputs[task_id] = entries
        return outputs

    def close(self) -> None:
        return


class _Sam3MiningPool:
    def __init__(self, devices: Sequence[torch.device]):
        self.workers = [_Sam3SegWorker(dev) for dev in (devices or [torch.device("cpu")])]

    def close(self) -> None:
        for worker in self.workers:
            try:
                worker.close()
            except Exception:
                continue


def _persist_qwen_run_metadata(
    result_path: Path,
    config: QwenTrainingConfig,
    result: QwenTrainingResult,
) -> Dict[str, Any]:
    model_id = _safe_run_name(getattr(config, "run_name", None), result_path.name)
    checkpoints = [str(p) for p in (getattr(result, "checkpoints", None) or [])]
    metadata = {
        "id": model_id,
        "label": getattr(config, "run_name", None) or result_path.name,
        "model_id": getattr(config, "model_id", None),
        "requested_model_id": getattr(config, "requested_model_id", None),
        "requested_model_metadata": getattr(config, "requested_model_metadata", {}) or {},
        "training_model_id": getattr(config, "model_id", None),
        "runtime_platform": getattr(config, "runtime_platform", QWEN_PLATFORM_TRANSFORMERS),
        "path": str(result_path),
        "latest_checkpoint": getattr(result, "latest_checkpoint", None),
        "checkpoints": checkpoints,
        "epochs_ran": int(getattr(result, "epochs_ran", 0) or 0),
        "created_at": time.time(),
        "training_mode": getattr(config, "training_mode", None),
        "dataset_root": getattr(config, "dataset_root", None),
    }
    requested_metadata = metadata.get("requested_model_metadata")
    if isinstance(requested_metadata, dict):
        metadata["abliterated"] = bool(requested_metadata.get("abliterated"))
        metadata["quantization"] = requested_metadata.get("quantization")
        metadata["quantization_backend"] = requested_metadata.get("quantization_backend")
        metadata["training_note"] = requested_metadata.get("training_note")
    result_metadata = getattr(result, "metadata", None)
    if isinstance(result_metadata, dict):
        metadata.update(result_metadata)
    _write_qwen_run_metadata_file(result_path, metadata)
    return metadata


def _write_qwen_run_metadata_file(result_path: Path, metadata: Dict[str, Any]) -> bool:
    tmp_path: Optional[Path] = None
    try:
        if _storage_path_has_symlink_component(result_path):
            return False
        result_path.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(result_path):
            return False
        run_root = result_path.resolve(strict=True)
        if not run_root.is_dir():
            return False
        meta_path = run_root / QWEN_METADATA_FILENAME
        if meta_path.is_symlink():
            meta_path.unlink(missing_ok=True)
        elif meta_path.exists() and not meta_path.is_file():
            return False
        try:
            meta_path.resolve(strict=False).relative_to(run_root)
        except Exception:
            return False
        tmp_path = run_root / f".{QWEN_METADATA_FILENAME}.{uuid.uuid4().hex}.tmp"
        flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(tmp_path, flags, 0o644)
        with os.fdopen(fd, "w", encoding="utf-8") as handle:
            handle.write(json.dumps(metadata, ensure_ascii=False, indent=2))
        os.replace(tmp_path, meta_path)
        return True
    except Exception:
        if tmp_path is not None:
            try:
                tmp_path.unlink(missing_ok=True)
            except Exception:
                pass
        return False


def _qwen_training_runs_root(*, create: bool, detail: str) -> Path:
    job_root_raw = QWEN_JOB_ROOT
    try:
        if _storage_path_has_symlink_component(job_root_raw):
            raise ValueError("job root is symlink")
        if create:
            job_root_raw.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(job_root_raw):
            raise ValueError("job root is symlink")
        if job_root_raw.exists() and not job_root_raw.is_dir():
            raise ValueError("job root is not a directory")
        job_root = job_root_raw.resolve(strict=False)
        runs_raw = job_root_raw / "runs"
        if _storage_path_has_symlink_component(runs_raw):
            raise ValueError("runs root is symlink")
        if create:
            runs_raw.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(runs_raw):
            raise ValueError("runs root is symlink")
        if runs_raw.exists() and not runs_raw.is_dir():
            raise ValueError("runs root is not a directory")
        runs_root = runs_raw.resolve(strict=False)
        if not _path_is_within_root_impl(runs_root, job_root):
            raise ValueError("runs root escapes job root")
        return runs_root
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _qwen_train_int(
    value: Any,
    default: int,
    *,
    minimum: int,
    maximum: Optional[int] = None,
) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError, OverflowError):
        return int(default)
    if parsed < minimum:
        return int(default)
    if maximum is not None:
        parsed = min(parsed, int(maximum))
    return parsed


def _qwen_train_float(
    value: Any,
    default: float,
    *,
    minimum: float,
    maximum: Optional[float] = None,
) -> float:
    try:
        parsed = float(value)
    except (TypeError, ValueError, OverflowError):
        return float(default)
    if not math.isfinite(parsed) or parsed < minimum:
        return float(default)
    if maximum is not None:
        parsed = min(parsed, float(maximum))
    return parsed


def _training_splits_root(job_root: Path, *, create: bool, detail: str) -> Path:
    try:
        if _storage_path_has_symlink_component(job_root):
            raise ValueError("job root is symlink")
        if create:
            job_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(job_root):
            raise ValueError("job root is symlink")
        if job_root.exists() and not job_root.is_dir():
            raise ValueError("job root is not a directory")
        job_root_resolved = job_root.resolve(strict=False)
        split_parent_raw = job_root / "splits"
        if _storage_path_has_symlink_component(split_parent_raw):
            raise ValueError("split root is symlink")
        if create:
            split_parent_raw.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(split_parent_raw):
            raise ValueError("split root is symlink")
        if split_parent_raw.exists() and not split_parent_raw.is_dir():
            raise ValueError("split root is not a directory")
        split_parent = split_parent_raw.resolve(strict=False)
        if not _path_is_within_root_impl(split_parent, job_root_resolved):
            raise ValueError("split root escapes job root")
        return split_parent
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _training_split_paths(
    job_root: Path,
    job_id: str,
    *,
    detail: str,
    create_parent: bool = False,
) -> Tuple[Path, Path, Path]:
    raw_id = str(job_id or "").strip()
    if (
        not raw_id
        or raw_id in {".", ".."}
        or "/" in raw_id
        or "\\" in raw_id
        or Path(raw_id).is_absolute()
    ):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    split_parent = _training_splits_root(job_root, create=create_parent, detail=detail)
    raw_split = split_parent / raw_id
    try:
        split_root = raw_split.resolve(strict=False)
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc
    if not _path_is_within_root_impl(split_root, split_parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail)
    return split_parent, raw_split, split_root


def _cleanup_training_split(job_root: Path, job_id: str, *, detail: str) -> None:
    try:
        _, raw_split, split_root = _training_split_paths(job_root, job_id, detail=detail)
    except HTTPException:
        return
    try:
        if raw_split.is_symlink():
            raw_split.unlink(missing_ok=True)
            return
        if not split_root.exists():
            return
        if split_root.is_dir():
            shutil.rmtree(split_root, ignore_errors=True)
        else:
            split_root.unlink(missing_ok=True)
    except Exception:
        return


def _training_split_cache_size(job_root: Path, *, detail: str) -> Dict[str, int]:
    try:
        cache_root = _training_splits_root(job_root, create=False, detail=detail)
    except HTTPException:
        return {"bytes": 0}
    return {"bytes": _dir_size_bytes_impl(cache_root)}


def _training_split_cache_purge(
    job_root: Path,
    registry: Dict[str, Any],
    lock: threading.Lock,
    *,
    blocked_detail: str,
    invalid_detail: str,
) -> Dict[str, Any]:
    cache_root_raw = job_root / "splits"
    if _active_jobs_reference_path_root(registry, lock, cache_root_raw):
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail=blocked_detail)
    if cache_root_raw.is_symlink():
        cache_root_raw.unlink(missing_ok=True)
        return {"status": "ok", "deleted_bytes": 0, "deleted_entries": 1}
    try:
        cache_root = _training_splits_root(job_root, create=False, detail=invalid_detail)
    except HTTPException:
        return {"status": "ok", "deleted_bytes": 0, "deleted_entries": 0}
    deleted_bytes = _dir_size_bytes_impl(cache_root)
    deleted_entries = _purge_directory(cache_root)
    return {"status": "ok", "deleted_bytes": deleted_bytes, "deleted_entries": deleted_entries}


def _qwen_training_split_root(job_id: str) -> Path:
    _, raw_split, split_root = _training_split_paths(
        QWEN_JOB_ROOT,
        job_id,
        detail="qwen_split_path_invalid",
        create_parent=True,
    )
    if raw_split.is_symlink():
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_split_path_invalid")
    return split_root


def _cleanup_qwen_training_split(job_id: str) -> None:
    _cleanup_training_split(QWEN_JOB_ROOT, job_id, detail="qwen_split_path_invalid")


def _qwen_training_annotation_path(dataset_root: Path, split_name: str) -> Optional[Path]:
    split_norm = str(split_name or "").strip().lower()
    if split_norm not in {"train", "val"}:
        return None
    try:
        dataset_root_resolved = dataset_root.resolve(strict=True)
        ann_path = (dataset_root / split_norm / "annotations.jsonl").resolve(strict=True)
    except Exception:
        return None
    if not _path_is_within_root_impl(ann_path, dataset_root_resolved):
        return None
    if not ann_path.is_file():
        return None
    return ann_path


def _prepare_qwen_training_split(
    dataset_root: Path,
    job_id: str,
    *,
    val_percent: float,
    split_seed: int,
    log_messages: Optional[List[str]] = None,
) -> Path:
    dataset_root = dataset_root.resolve()

    def _annotation_entries(split_name: str) -> List[Tuple[Dict[str, Any], Path]]:
        ann_path = _qwen_training_annotation_path(dataset_root, split_name)
        if ann_path is None:
            return []
        entries: List[Tuple[Dict[str, Any], Path]] = []
        with ann_path.open("r", encoding="utf-8") as handle:
            for line in handle:
                line = line.strip()
                if not line:
                    continue
                try:
                    payload = json.loads(line)
                except Exception:
                    continue
                if not isinstance(payload, dict):
                    continue
                image_name = payload.get("image")
                if not isinstance(image_name, str) or not image_name.strip():
                    continue
                source = _find_qwen_split_image_source(dataset_root, split_name, image_name)
                if source is None:
                    continue
                entries.append((payload, source))
        return entries

    entries = _annotation_entries("train") + _annotation_entries("val")
    if len(entries) < 2:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_training_split_empty")
    rnd = random.Random(int(split_seed))
    rnd.shuffle(entries)
    vp = max(0.0, min(float(val_percent), 0.9))
    val_count = int(len(entries) * vp)
    if val_count <= 0:
        val_count = 1
    if val_count >= len(entries):
        val_count = len(entries) - 1
    val_entries = entries[:val_count]
    train_entries = entries[val_count:]
    if not train_entries or not val_entries:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_training_split_empty")

    split_root = _qwen_training_split_root(job_id)
    if split_root.exists():
        shutil.rmtree(split_root, ignore_errors=True)
    (split_root / "train" / "images").mkdir(parents=True, exist_ok=True)
    (split_root / "val" / "images").mkdir(parents=True, exist_ok=True)

    def _write_split(split_name: str, split_entries: Sequence[Tuple[Dict[str, Any], Path]]) -> int:
        ann_path = split_root / split_name / "annotations.jsonl"
        lines: List[str] = []
        for idx, (payload, source) in enumerate(split_entries):
            try:
                rel = _normalise_relative_path(payload.get("image"))
            except HTTPException:
                continue
            safe_name = f"{idx:06d}_{rel.name or 'image'}"
            rel_out = Path(safe_name)
            dst = split_root / split_name / "images" / rel_out
            _link_or_copy_file(source, dst, overwrite=True)
            payload_out = dict(payload)
            payload_out["image"] = rel_out.as_posix()
            lines.append(json.dumps(payload_out, ensure_ascii=False, separators=(",", ":")) + "\n")
        _qwen_training_write_text_within_root(ann_path, split_root, "".join(lines))
        return len(lines)

    train_count = _write_split("train", train_entries)
    val_count_written = _write_split("val", val_entries)
    if train_count <= 0 or val_count_written <= 0:
        shutil.rmtree(split_root, ignore_errors=True)
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_training_split_empty")

    source_meta = _load_json_metadata(dataset_root / QWEN_METADATA_FILENAME) or {}
    meta = {
        **source_meta,
        "id": f"{source_meta.get('id') or dataset_root.name}_{str(job_id)[:8]}_split",
        "label": source_meta.get("label") or dataset_root.name,
        "created_at": time.time(),
        "source_dataset_root": str(dataset_root),
        "train_count": train_count,
        "val_count": val_count_written,
        "image_count": train_count + val_count_written,
        "random_split": True,
        "split_seed": int(split_seed),
        "val_percent": float(vp),
        "signature": _compute_dir_signature_impl(split_root),
        "type": source_meta.get("type") or "bbox",
    }
    _qwen_training_write_text_within_root(
        split_root / QWEN_METADATA_FILENAME,
        split_root,
        json.dumps(meta, ensure_ascii=False, indent=2),
    )
    summary = (
        f"Qwen split: {train_count} train / {val_count_written} val "
        f"(seed={int(split_seed)}, val_percent={vp:.2f}, src={dataset_root}) -> {split_root}"
    )
    logger.info(summary)
    if log_messages is not None:
        log_messages.append(summary)
    return split_root


def _find_qwen_split_image_source(
    dataset_root: Path, split_name: str, image_name: str
) -> Optional[Path]:
    try:
        rel = _normalise_relative_path(image_name)
    except HTTPException:
        return None
    roots = [
        dataset_root / split_name / "images",
        dataset_root / split_name,
        dataset_root / "images",
        dataset_root,
    ]
    for root in roots:
        try:
            root_resolved = root.resolve()
            candidate = (root / rel).resolve()
        except Exception:
            continue
        if not _path_is_within_root_impl(candidate, dataset_root):
            continue
        try:
            candidate.relative_to(root_resolved)
        except ValueError:
            continue
        if candidate.exists() and candidate.is_file():
            return candidate
    return None


def _qwen_training_clean_cuda_devices(devices: Optional[str]) -> Optional[str]:
    raw = str(devices or "").strip()
    if not raw:
        return None
    cleaned: List[str] = []
    seen: set[str] = set()
    for part in raw.split(","):
        value_raw = part.strip()
        if not value_raw:
            continue
        if not re.fullmatch(r"\d+", value_raw):
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_invalid_devices")
        value = str(int(value_raw))
        if value in seen:
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_duplicate_devices")
        seen.add(value)
        cleaned.append(value)
    return ",".join(cleaned) if cleaned else None


def _resolve_qwen_training_devices(
    devices: Optional[str],
    *,
    runtime_platform: str,
    prep_logs: Optional[List[str]] = None,
) -> Optional[str]:
    raw = str(devices or "").strip()
    if not raw:
        return None
    if runtime_platform == QWEN_PLATFORM_MLX:
        if prep_logs is not None:
            prep_logs.append("Ignoring CUDA device selection for MLX Qwen training")
        return None
    cleaned = _qwen_training_clean_cuda_devices(raw)
    if not cleaned:
        return None
    if not torch.cuda.is_available():
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="qwen_cuda_devices_unavailable",
        )
    try:
        device_count = int(torch.cuda.device_count())
    except Exception:
        device_count = 0
    if device_count <= 0:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail="qwen_cuda_devices_unavailable",
        )
    invalid = [int(value) for value in cleaned.split(",") if int(value) >= device_count]
    if invalid:
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail=f"qwen_invalid_devices:available=0-{device_count - 1}",
        )
    return cleaned


def _build_qwen_config(
    payload: QwenTrainRequest, job_id: str, prep_logs: Optional[List[str]] = None
) -> QwenTrainingConfig:
    if QwenTrainingConfig is None:
        raise HTTPException(
            status_code=HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"qwen_training_unavailable:{QWEN_TRAINING_IMPORT_ERROR}",
        )
    dataset_root = _resolve_sam3_or_qwen_dataset_impl(
        payload.dataset_id,
        list_all_datasets_fn=_list_all_datasets,
        resolve_dataset_legacy_fn=lambda dataset_id: _resolve_dataset_legacy_impl(
            dataset_id,
            qwen_root=QWEN_DATASET_ROOT,
            sam3_root=SAM3_DATASET_ROOT,
            registry_root=DATASET_REGISTRY_ROOT,
            http_exception_cls=HTTPException,
        ),
    )
    if bool(payload.random_split):
        dataset_root = _prepare_qwen_training_split(
            dataset_root,
            job_id,
            val_percent=_qwen_train_float(payload.val_percent, 0.2, minimum=0.0, maximum=0.9),
            split_seed=_qwen_train_int(payload.split_seed, 42, minimum=0, maximum=2**32 - 1),
            log_messages=prep_logs,
        )
    train_jsonl = _qwen_training_annotation_path(dataset_root, "train")
    val_jsonl = _qwen_training_annotation_path(dataset_root, "val")
    if train_jsonl is None:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_train_split_missing")
    if val_jsonl is None:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_val_split_missing")
    run_name = _safe_run_name(payload.run_name, f"qwen_{payload.dataset_id}_{job_id[:8]}")
    runs_root = _qwen_training_runs_root(create=True, detail="qwen_run_path_invalid")
    result_path = (runs_root / run_name).resolve(strict=False)
    if not _path_is_within_root_impl(result_path, runs_root):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="qwen_run_path_invalid")
    if result_path.exists():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="run_name_exists")
    if prep_logs is not None:
        prep_logs.append(f"Dataset: {dataset_root}")
        prep_logs.append(f"Output: {result_path}")
    requested_model_id = payload.model_id
    if requested_model_id and str(requested_model_id).strip().lower() in {"default", "base"}:
        requested_model_id = None
    requested_model_id = (
        requested_model_id
        or (active_qwen_metadata or {}).get("model_id")
        or QWEN_MODEL_NAME
    )
    requested_model_id = str(requested_model_id or "").strip() or QWEN_MODEL_NAME
    requested_runtime_platform = (
        QWEN_PLATFORM_MLX if is_qwen_mlx_model_id(requested_model_id) else QWEN_PLATFORM_TRANSFORMERS
    )
    requested_model_metadata = (
        qwen_mlx_metadata_for_model(requested_model_id)
        if requested_runtime_platform == QWEN_PLATFORM_MLX
        else qwen_transformers_metadata_for_model(requested_model_id)
    )
    if requested_model_metadata.get("training_supported") is False:
        training_note = str(
            requested_model_metadata.get("training_note")
            or "Select a dense Transformers Qwen3-VL checkpoint for Qwen training."
        )
        raise HTTPException(
            status_code=HTTP_400_BAD_REQUEST,
            detail=f"qwen_model_training_unsupported:{training_note}",
        )
    if requested_runtime_platform == QWEN_PLATFORM_MLX:
        training_model_id = resolve_mlx_model_id(
            requested_model_id,
            default_mlx_model_id=QWEN_MLX_MODEL_NAME,
            default_quantization=QWEN_MLX_DEFAULT_QUANTIZATION,
        )
    else:
        training_model_id = resolve_qwen_training_model_id(requested_model_id)
    if prep_logs is not None:
        prep_logs.append(f"Requested Qwen model: {requested_model_id}")
        prep_logs.append(f"Training backend: {requested_runtime_platform}")
        if training_model_id != requested_model_id:
            prep_logs.append(
                f"Adapter training base: {training_model_id} (resolved from quantized inference model)"
            )
        if requested_runtime_platform == QWEN_PLATFORM_MLX:
            prep_logs.append("MLX-VLM path uses existing dataset splits and disables CUDA-only knobs")
    accumulate_grad_batches = _qwen_train_int(
        payload.accumulate_grad_batches,
        8,
        minimum=1,
        maximum=1024,
    )
    if requested_runtime_platform == QWEN_PLATFORM_MLX:
        accumulate_grad_batches = 1
    min_pixels = _qwen_train_int(
        payload.min_pixels,
        28 * 28 * 16,
        minimum=1024,
        maximum=28 * 28 * 4096,
    )
    max_pixels = _qwen_train_int(
        payload.max_pixels,
        28 * 28 * 576,
        minimum=1024,
        maximum=28 * 28 * 8192,
    )
    if max_pixels < min_pixels:
        max_pixels = max(min_pixels, 28 * 28 * 576)
    qwen_devices = _resolve_qwen_training_devices(
        payload.devices,
        runtime_platform=requested_runtime_platform,
        prep_logs=prep_logs,
    )
    kwargs = {
        "dataset_root": str(dataset_root),
        "result_path": str(result_path),
        "model_id": training_model_id,
        "requested_model_id": requested_model_id,
        "requested_model_metadata": requested_model_metadata,
        "runtime_platform": requested_runtime_platform,
        "training_mode": payload.training_mode or "official_lora",
        "system_prompt": payload.system_prompt or DEFAULT_SYSTEM_PROMPT,
        "run_name": run_name,
        "devices": qwen_devices,
        "batch_size": _qwen_train_int(payload.batch_size, 1, minimum=1, maximum=128),
        "max_epochs": _qwen_train_int(payload.max_epochs, 3, minimum=1, maximum=10000),
        "lr": _qwen_train_float(payload.lr, 2e-4, minimum=1e-9, maximum=1.0),
        "accumulate_grad_batches": accumulate_grad_batches,
        "warmup_steps": _qwen_train_int(payload.warmup_steps, 50, minimum=0, maximum=1_000_000),
        "num_workers": _qwen_train_int(payload.num_workers, 0, minimum=0, maximum=128),
        "lora_rank": _qwen_train_int(payload.lora_rank, 8, minimum=1, maximum=4096),
        "lora_alpha": _qwen_train_int(payload.lora_alpha, 16, minimum=1, maximum=16384),
        "lora_dropout": _qwen_train_float(payload.lora_dropout, 0.05, minimum=0.0, maximum=1.0),
        "lora_target_modules": (
            payload.lora_target_modules
            if payload.lora_target_modules
            else ["q_proj", "k_proj", "v_proj", "o_proj"]
        ),
        "seed": _qwen_train_int(payload.seed, 1337, minimum=0, maximum=2**32 - 1),
        "log_every_n_steps": (
            _qwen_train_int(payload.log_every_n_steps, 10, minimum=1, maximum=1_000_000)
        ),
        "max_pixels": max_pixels,
        "min_pixels": min_pixels,
        "max_length": (
            _qwen_train_int(payload.max_length, 2048, minimum=256, maximum=262_144)
            if payload.max_length is not None
            else None
        ),
        "train_limit": (
            int(payload.train_limit)
            if payload.train_limit is not None and payload.train_limit > 0
            else None
        ),
        "val_limit": (
            int(payload.val_limit)
            if payload.val_limit is not None and payload.val_limit > 0
            else None
        ),
    }
    return QwenTrainingConfig(**kwargs)


def _coord_roundtrip_smoke() -> None:
    width, height = 1920, 1080
    sample = (123.5, 234.25, 789.75, 902.0)
    bbox_2d = _xyxy_to_qwen_bbox(width, height, *sample)
    rt = _qwen_bbox_to_xyxy(width, height, bbox_2d)
    err = max(abs(float(a) - float(b)) for a, b in zip(sample, rt, strict=False))
    if err > 5.0:
        raise RuntimeError(f"coord_roundtrip_failed:max_err={err:.4f}")


def _build_seed_threshold_sweep_grid(
    *, base_seed_threshold: float, observed_scores: Sequence[float], limit: int = 64
) -> List[float]:
    values = {0.0, float(max(0.0, min(1.0, base_seed_threshold)))}
    for score in observed_scores or []:
        try:
            values.add(float(max(0.0, min(1.0, score))))
        except Exception:
            continue
    ordered = sorted(values)
    if limit and len(ordered) > limit:
        step = max(1, int(len(ordered) / max(1, limit)))
        sampled = ordered[::step]
        if 0.0 not in sampled:
            sampled.insert(0, 0.0)
        if base_seed_threshold not in sampled:
            sampled.append(float(base_seed_threshold))
        ordered = sorted(set(sampled))[:limit]
    return ordered


def _compute_seed_threshold_curve(
    *,
    gt_best_scores: Dict[Any, float],
    fp_scores: Sequence[float],
    thresholds: Sequence[float],
) -> List[Dict[str, Any]]:
    curve = []
    total_gt = len(gt_best_scores)
    for thr in sorted(thresholds):
        matches = sum(1 for v in gt_best_scores.values() if float(v) >= float(thr))
        fps = sum(1 for v in fp_scores if float(v) >= float(thr))
        precision = matches / (matches + fps) if (matches + fps) else 1.0
        recall = matches / total_gt if total_gt else 0.0
        curve.append(
            {
                "threshold": float(thr),
                "matches": int(matches),
                "fps": int(fps),
                "precision": float(precision),
                "recall": float(recall),
            }
        )
    return curve


def _select_seed_threshold_operating_point(
    curve: Sequence[Dict[str, Any]],
    *,
    min_precision: Optional[float] = None,
    max_fps: Optional[int] = None,
) -> Optional[Dict[str, Any]]:
    if not curve:
        return None
    candidates = []
    for point in curve:
        if min_precision is not None and float(point.get("precision", 0.0)) < float(min_precision):
            continue
        if max_fps is not None and int(point.get("fps", 0)) > int(max_fps):
            continue
        candidates.append(point)
    if candidates:
        candidates.sort(
            key=lambda p: (
                int(p.get("matches", 0)),
                float(p.get("precision", 0.0)),
                -float(p.get("threshold", 0.0)),
            ),
            reverse=True,
        )
        return candidates[0]
    # fallback: pick highest precision, then matches, then lowest threshold
    fallback = list(curve)
    fallback.sort(
        key=lambda p: (
            float(p.get("precision", 0.0)),
            int(p.get("matches", 0)),
            -float(p.get("threshold", 0.0)),
        ),
        reverse=True,
    )
    return fallback[0] if fallback else None


def _summarize_seed_threshold_curve_for_prompt(
    *,
    gt_best_scores: Dict[Any, float],
    fp_scores: Sequence[float],
    base_seed_threshold: float,
    curve_limit: int = 12,
) -> Dict[str, Any]:
    thresholds = _build_seed_threshold_sweep_grid(
        base_seed_threshold=base_seed_threshold,
        observed_scores=list(gt_best_scores.values()) + list(fp_scores),
        limit=curve_limit,
    )
    curve = _compute_seed_threshold_curve(
        gt_best_scores=gt_best_scores,
        fp_scores=fp_scores,
        thresholds=thresholds,
    )
    recommended = _select_seed_threshold_operating_point(curve, min_precision=None)
    rec_thr = float(recommended.get("threshold")) if recommended else float(base_seed_threshold)
    return {
        "seed_threshold_curve": curve[:curve_limit],
        "seed_threshold_base": float(base_seed_threshold),
        "seed_threshold_recommended": float(rec_thr),
    }


def _build_steps_recipe_step_list_from_selected_stats(
    selected: Sequence[Dict[str, Any]],
    *,
    prompts_fallback: Optional[Sequence[str]],
    payload: AgentMiningRequest,
) -> Tuple[List[str], List[Dict[str, Any]]]:
    steps: List[Dict[str, Any]] = []
    prompts: List[str] = []
    if not selected and prompts_fallback:
        for prompt in prompts_fallback:
            prompts.append(str(prompt))
            steps.append(
                {
                    "prompt": str(prompt),
                    "seed_threshold": float(getattr(payload, "seed_threshold", 0.0)),
                }
            )
        return prompts, steps
    for entry in selected:
        prompt = str(entry.get("prompt") or "")
        if not prompt:
            continue
        seed_thr = entry.get("selected_seed_threshold")
        if seed_thr is None:
            seed_thr = entry.get("seed_threshold")
        if seed_thr is None:
            seed_thr = getattr(payload, "seed_threshold", 0.0)
        prompts.append(prompt)
        steps.append({"prompt": prompt, "seed_threshold": float(seed_thr)})
    return prompts, steps


def _normalize_steps_for_head_tuning(
    steps: Sequence[Dict[str, Any]], *, payload: AgentMiningRequest
) -> List[Dict[str, Any]]:
    normalized: List[Dict[str, Any]] = []
    for step in steps or []:
        if not step.get("enabled", True):
            continue
        prompt = step.get("prompt")
        if not prompt:
            continue
        normalized.append(
            {
                "prompt": prompt,
                "seed_threshold": float(step.get("seed_threshold", payload.seed_threshold)),
                "expand_threshold": float(step.get("expand_threshold", payload.expand_threshold)),
                "max_visual_seeds": int(
                    step.get("max_visual_seeds", payload.steps_max_visual_seeds_per_step)
                ),
                "seed_dedupe_iou": float(step.get("seed_dedupe_iou", payload.seed_dedupe_iou)),
                "dedupe_iou": float(step.get("dedupe_iou", payload.dedupe_iou)),
                "max_results": int(step.get("max_results", payload.max_results)),
            }
        )
    return normalized


def _build_steps_tier2_candidate_grid(
    *, base_seed_dedupe_iou: float, base_dedupe_iou: float, max_trials: int
) -> List[Dict[str, Any]]:
    offsets = [-0.1, 0.0, 0.1]
    candidates: List[Dict[str, Any]] = []
    seen = set()
    for off_seed in offsets:
        for off_det in offsets:
            seed_val = max(0.0, min(1.0, float(base_seed_dedupe_iou) + off_seed))
            det_val = max(0.0, min(1.0, float(base_dedupe_iou) + off_det))
            key = (round(seed_val, 4), round(det_val, 4))
            if key in seen:
                continue
            seen.add(key)
            candidates.append({"seed_dedupe_iou": seed_val, "dedupe_iou": det_val})
    if max_trials:
        candidates = candidates[: max(1, int(max_trials))]
    return candidates


def _select_steps_from_seed_prompt_stats(
    prompt_stats: Sequence[Dict[str, Any]],
    *,
    max_steps: int,
    target_precision: Optional[float],
    early_stop: Optional[Dict[str, Any]] = None,
    log_fn: Optional[Callable[[str], None]] = None,
    max_candidates_per_prompt: int = 4,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    target_precision_value = float(target_precision) if target_precision is not None else 0.0
    selected: List[Dict[str, Any]] = []
    for entry in prompt_stats:
        curve = entry.get("seed_threshold_curve") or []
        curve = list(curve)[:max_candidates_per_prompt]
        candidates = [c for c in curve if float(c.get("precision", 0.0)) >= target_precision_value]
        if candidates:
            candidates.sort(
                key=lambda c: (
                    int(c.get("matches", 0)),
                    float(c.get("precision", 0.0)),
                    -float(c.get("threshold", 0.0)),
                ),
                reverse=True,
            )
            best = candidates[0]
        elif curve:
            curve.sort(
                key=lambda c: (
                    float(c.get("precision", 0.0)),
                    int(c.get("matches", 0)),
                    -float(c.get("threshold", 0.0)),
                ),
                reverse=True,
            )
            best = curve[0]
        else:
            best = {"threshold": entry.get("seed_threshold", 0.0)}
        threshold = float(best.get("threshold", 0.0))
        gt_scores = entry.get("gt_best_scores") or {}
        matched_keys = {key for key, score in gt_scores.items() if float(score) >= float(threshold)}
        selected.append(
            {
                **entry,
                "selected_seed_threshold": threshold,
                "matched_keys": matched_keys,
            }
        )
    selected.sort(
        key=lambda e: (len(e.get("matched_keys") or []), float(e.get("precision", 0.0))),
        reverse=True,
    )
    coverage: set = set()
    chosen: List[Dict[str, Any]] = []
    for entry in selected:
        if len(chosen) >= int(max_steps):
            break
        matched_keys = set(entry.get("matched_keys") or [])
        if matched_keys and matched_keys.issubset(coverage):
            continue
        coverage |= matched_keys
        chosen.append(entry)
    info: Dict[str, Any] = {"target_precision": float(target_precision_value)}
    early_cfg = dict(early_stop or {})
    if early_cfg.get("enabled"):
        min_steps = max(1, int(early_cfg.get("min_steps") or 1))
        capped = chosen[: max(min_steps, min(int(max_steps), len(chosen)))]
        if len(capped) < len(chosen):
            info["early_stop"] = {
                "enabled": True,
                "selected_steps": len(capped),
                "max_steps": int(max_steps),
                "mode": str(early_cfg.get("mode") or "balanced"),
                "reason": "min_steps_cap",
            }
            chosen = capped
            if callable(log_fn):
                try:
                    log_fn(
                        f"[steps] Early-stop applied: selected {len(chosen)}/{int(max_steps)} steps "
                        f"(mode={early_cfg.get('mode') or 'balanced'})"
                    )
                except Exception:
                    pass
        else:
            info["early_stop"] = {
                "enabled": True,
                "selected_steps": len(chosen),
                "max_steps": int(max_steps),
                "mode": str(early_cfg.get("mode") or "balanced"),
                "reason": "not_triggered",
            }
    else:
        info["early_stop"] = {
            "enabled": False,
            "selected_steps": len(chosen),
            "max_steps": int(max_steps),
        }
    return chosen, info


def _generate_steps_global_mutations(
    *,
    base_candidate: Dict[str, Any],
    seed_stats: Sequence[Dict[str, Any]],
    payload: AgentMiningRequest,
    max_mutations: int,
    target_precision: float,
    enable_max_results: bool,
    enable_ordering: bool,
) -> List[Dict[str, Any]]:
    base_steps = _normalize_steps_for_head_tuning(
        base_candidate.get("steps") or [], payload=payload
    )
    stats_by_prompt = {
        str(s.get("prompt") or ""): s for s in seed_stats if str(s.get("prompt") or "")
    }
    mutations: List[Dict[str, Any]] = []
    for prompt in sorted(stats_by_prompt.keys()):
        stat = stats_by_prompt[prompt]
        thr = stat.get("seed_threshold_recommended")
        if thr is None:
            curve = stat.get("seed_threshold_curve") or []
            if curve:
                thr = curve[0].get("threshold")
        if thr is None:
            thr = payload.seed_threshold
        steps = []
        seen = set()
        for step in base_steps:
            if step["prompt"] == prompt:
                step = {**step, "seed_threshold": float(thr)}
            if step["prompt"] in seen:
                continue
            seen.add(step["prompt"])
            steps.append(step)
        if prompt not in seen:
            steps.append(
                {
                    "prompt": prompt,
                    "seed_threshold": float(thr),
                    "expand_threshold": float(payload.expand_threshold),
                    "max_visual_seeds": int(payload.steps_max_visual_seeds_per_step),
                    "seed_dedupe_iou": float(payload.seed_dedupe_iou),
                    "dedupe_iou": float(payload.dedupe_iou),
                    "max_results": int(
                        payload.max_results if enable_max_results else payload.max_results
                    ),
                }
            )
        if enable_ordering:
            steps = sorted(steps, key=lambda s: str(s.get("prompt") or ""))
        mutations.append({"steps": steps, "sig": f"{prompt}:{float(thr):.6f}"})
        if max_mutations and len(mutations) >= max_mutations:
            break
    return mutations


def _successive_halving_search(
    *,
    candidates: Sequence[Any],
    budgets: Sequence[int],
    evaluator: Any,
    keep_ratio: float,
) -> Tuple[Any, List[Dict[str, Any]]]:
    if not budgets or sorted(budgets) != list(budgets):
        raise ValueError("budgets must be increasing")
    history = []
    current = list(candidates)
    for budget in budgets:
        scored = []
        for cand in current:
            score, meta = evaluator(cand, budget)
            scored.append((score, cand, meta))
        scored.sort(key=lambda row: row[0], reverse=True)
        keep = max(1, int(len(scored) * keep_ratio))
        history.append(
            {
                "budget": budget,
                "candidates": [row[1] for row in scored],
                "scores": [row[0] for row in scored],
            }
        )
        current = [row[1] for row in scored[:keep]]
    best = current[0] if current else None
    return best, history


def _run_steps_global_successive_halving_rounds(
    *,
    base_candidate: Dict[str, Any],
    budgets: Sequence[int],
    keep_ratio: float,
    rounds: int,
    max_trials: int,
    mutate: Any,
    evaluator: Any,
) -> Tuple[Dict[str, Any], List[Dict[str, Any]]]:
    best = dict(base_candidate)
    history: List[Dict[str, Any]] = []
    for round_idx in range(int(rounds)):
        candidates = mutate(best, round_idx) or []
        candidates = list(candidates)[:max_trials]
        best_candidate, stage_history = _successive_halving_search(
            candidates=candidates, budgets=budgets, evaluator=evaluator, keep_ratio=keep_ratio
        )
        if best_candidate is not None:
            best = best_candidate
        history.append({"round": round_idx, "history": stage_history, "best": best})
    return best, history


def _refine_steps_prompt_subset_seed_stage(
    prompt_stats: Sequence[Dict[str, Any]],
    selected: Sequence[Dict[str, Any]],
    *,
    max_steps: int,
    target_precision: float,
    max_iters: int,
    top_k: int,
    base_seed_threshold: float,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    info: Dict[str, Any] = {"enabled": True, "history": []}
    refined = [dict(s) for s in selected]
    # Drop redundant prompts.
    coverage_map = {}
    for entry in refined:
        matched_raw = entry.get("matched_keys")
        if matched_raw:
            matched = set(matched_raw)
            entry["matched_keys"] = matched
            coverage_map[entry.get("prompt")] = matched
            continue
        threshold = float(entry.get("selected_seed_threshold") or base_seed_threshold)
        gt_scores = entry.get("gt_best_scores") or {}
        matched = {k for k, v in gt_scores.items() if float(v) >= threshold}
        entry["matched_keys"] = matched
        coverage_map[entry.get("prompt")] = matched
    changed = True
    while changed:
        changed = False
        for entry in list(refined):
            prompt = entry.get("prompt")
            matched = set(entry.get("matched_keys") or [])
            others = set()
            for other in refined:
                if other is entry:
                    continue
                others |= set(other.get("matched_keys") or [])
            if matched and matched.issubset(others):
                refined.remove(entry)
                info["history"].append({"op": "drop_redundant", "dropped": prompt})
                changed = True
                break
    # Swap in a better prompt if it adds coverage.
    if max_iters and prompt_stats:
        current_coverage = set()
        for entry in refined:
            current_coverage |= set(entry.get("matched_keys") or [])
        for candidate in prompt_stats[:top_k]:
            prompt = candidate.get("prompt")
            if not prompt:
                continue
            threshold = float(candidate.get("seed_threshold_recommended") or base_seed_threshold)
            gt_scores = candidate.get("gt_best_scores") or {}
            cand_keys = {k for k, v in gt_scores.items() if float(v) >= threshold}
            if not cand_keys:
                continue
            if not cand_keys.issubset(current_coverage):
                # replace weakest prompt
                if refined:
                    refined.sort(key=lambda e: len(e.get("matched_keys") or []))
                    dropped = refined.pop(0)
                    info["history"].append(
                        {"op": "swap", "dropped": dropped.get("prompt"), "added": prompt}
                    )
                refined.append(
                    {
                        **candidate,
                        "selected_seed_threshold": threshold,
                        "matched_keys": cand_keys,
                    }
                )
                current_coverage |= cand_keys
                if len(refined) >= max_steps:
                    break
    return refined[:max_steps], info


def _agent_compact_tool_response(result: AgentToolResult) -> Dict[str, Any]:
    payload = {"tool": result.name, "result": result.result}
    if result.error:
        payload["error"] = result.error
    return payload


def _parse_tool_call_json(raw_text: str) -> Tuple[Optional[Dict[str, Any]], Optional[str]]:
    if not raw_text:
        return None, "empty"
    snippet = raw_text
    if "<tool_call>" in raw_text and "</tool_call>" in raw_text:
        try:
            snippet = raw_text.split("<tool_call>", 1)[1].split("</tool_call>", 1)[0]
        except Exception:
            snippet = raw_text
    snippet = snippet.strip()
    try:
        payload = json.loads(snippet)
        return payload, None
    except Exception as exc:  # noqa: BLE001
        return None, f"parse_error:{exc}"


