async def _save_upload_file(
    upload: UploadFile,
    root: Path,
    *,
    max_bytes: Optional[int] = None,
    quota_root: Optional[Path] = None,
    quota_limit: Optional[int] = None,
) -> Path:
    rel_path = _normalise_relative_path(upload.filename)
    root_resolved = _safe_upload_write_root(root, detail="invalid_relative_path")
    dest_raw = root_resolved / rel_path
    if _classifier_path_has_symlink_component(dest_raw, root_resolved):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    dest = dest_raw.resolve(strict=False)
    if not _path_is_within_root_impl(dest, root_resolved):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    if dest.exists() or dest.is_symlink():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="upload_exists")
    await _write_upload_file(
        upload,
        dest,
        max_bytes=max_bytes,
        quota_root=quota_root or root_resolved,
        quota_limit=quota_limit,
    )
    return dest


def _validate_upload_size(upload: UploadFile, *, max_bytes: int = BASE64_IMAGE_MAX_BYTES) -> None:
    if not max_bytes:
        return
    try:
        size = upload.size  # Starlette UploadFile may have size attr
    except Exception:
        size = None
    if size is not None and size > max_bytes:
        raise HTTPException(status_code=HTTP_413_CONTENT_TOO_LARGE, detail="upload_too_large")


def _validate_upload_extension(filename: str, allowed_exts: set[str], detail: str) -> None:
    suffix = Path(filename).suffix.lower()
    if allowed_exts and suffix not in allowed_exts:
        raise HTTPException(status_code=HTTP_415_UNSUPPORTED_MEDIA_TYPE, detail=detail)


def _safe_upload_write_root(root: Path, *, detail: str) -> Path:
    try:
        raw_root = Path(root)
        if _storage_path_has_symlink_component(raw_root):
            raise RuntimeError("upload_root_symlink")
        raw_root.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_root) or not raw_root.is_dir():
            raise RuntimeError("upload_root_invalid")
        return raw_root.resolve(strict=True)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


def _safe_upload_subdir(subdir: str, *, detail: str) -> Path:
    try:
        if _storage_path_has_symlink_component(UPLOAD_ROOT):
            raise RuntimeError("upload_root_symlink")
        UPLOAD_ROOT.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(UPLOAD_ROOT) or not UPLOAD_ROOT.is_dir():
            raise RuntimeError("upload_root_invalid")
        upload_root = UPLOAD_ROOT.resolve(strict=True)
        raw_dir = UPLOAD_ROOT / subdir
        if _storage_path_has_symlink_component(raw_dir):
            raise RuntimeError("upload_subdir_symlink")
        raw_dir.mkdir(parents=True, exist_ok=True)
        if _storage_path_has_symlink_component(raw_dir) or not raw_dir.is_dir():
            raise RuntimeError("upload_subdir_invalid")
        resolved_dir = raw_dir.resolve(strict=True)
        if not _path_is_within_root_impl(resolved_dir, upload_root):
            raise RuntimeError("upload_subdir_escape")
        return resolved_dir
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail=detail) from exc


async def _save_asset(
    upload: UploadFile,
    *,
    subdir: str,
    allowed_exts: Optional[set[str]] = None,
    max_bytes: Optional[int] = None,
    quota_bytes: Optional[int] = None,
) -> str:
    dest_dir = _safe_upload_subdir(subdir, detail=f"{subdir}_root_invalid")
    rel_name = Path(upload.filename or f"asset_{uuid.uuid4().hex}").name
    dest_path = dest_dir / rel_name
    if allowed_exts:
        _validate_upload_extension(rel_name, allowed_exts, "upload_extension_not_allowed")
    if dest_path.exists() or dest_path.is_symlink():
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="upload_exists")
    _validate_upload_size(upload, max_bytes=max_bytes or ASSET_MAX_BYTES)
    await _write_upload_file(
        upload,
        dest_path,
        max_bytes=max_bytes or ASSET_MAX_BYTES,
        quota_root=dest_dir,
        quota_limit=quota_bytes or ASSET_UPLOAD_QUOTA_BYTES,
    )
    return str(dest_path.resolve())


async def _write_upload_file(
    upload: UploadFile,
    dest: Path,
    *,
    max_bytes: Optional[int] = None,
    quota_root: Optional[Path] = None,
    quota_limit: Optional[int] = None,
    allow_overwrite: bool = False,
) -> None:
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    dest.parent.mkdir(parents=True, exist_ok=True)
    if _storage_path_has_symlink_component(dest.parent):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
    if dest.is_symlink():
        if not allow_overwrite:
            raise HTTPException(status_code=HTTP_409_CONFLICT, detail="upload_exists")
    if dest.exists() and not allow_overwrite:
        raise HTTPException(status_code=HTTP_409_CONFLICT, detail="upload_exists")
    tmp_path = dest.with_suffix(dest.suffix + f".tmp.{os.getpid()}")
    if tmp_path.is_symlink():
        tmp_path.unlink(missing_ok=True)
    elif tmp_path.exists():
        if tmp_path.is_dir():
            raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="invalid_relative_path")
        tmp_path.unlink()
    written = 0
    existing = _dir_size_bytes_impl(quota_root) if quota_root and quota_limit else 0
    try:
        flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(tmp_path, flags, 0o644)
        with os.fdopen(fd, "wb") as handle:
            while True:
                chunk = await upload.read(1024 * 1024)
                if not chunk:
                    break
                written += len(chunk)
                if max_bytes and written > max_bytes:
                    raise HTTPException(
                        status_code=HTTP_413_CONTENT_TOO_LARGE, detail="upload_too_large"
                    )
                if quota_root and quota_limit and existing + written > quota_limit:
                    raise HTTPException(
                        status_code=HTTP_413_CONTENT_TOO_LARGE, detail="upload_quota_exceeded"
                    )
                handle.write(chunk)
        os.replace(tmp_path, dest)
    finally:
        if tmp_path.exists() or tmp_path.is_symlink():
            tmp_path.unlink(missing_ok=True)
    await upload.close()


def _artifacts_to_payload(artifacts: TrainingArtifacts) -> Dict[str, Any]:
    data = asdict(artifacts)
    return data


def _clip_training_cleanup_path(temp_dir: Optional[str]) -> Optional[Path]:
    raw = str(temp_dir or "").strip()
    if not raw:
        return None
    raw_path = Path(raw)
    if not raw_path.name.startswith("clip_train_"):
        return None
    try:
        temp_root = Path(tempfile.gettempdir()).resolve(strict=False)
        if _storage_path_has_symlink_component(raw_path.parent):
            return None
        parent_resolved = raw_path.parent.resolve(strict=False)
    except Exception:
        return None
    if parent_resolved != temp_root:
        return None
    if raw_path.is_symlink():
        return raw_path
    try:
        resolved = raw_path.resolve(strict=False)
    except Exception:
        return None
    if not _path_is_within_root_impl(resolved, temp_root) or resolved.parent != temp_root:
        return None
    return resolved


def _cleanup_clip_training_temp_dir(temp_dir: Optional[str]) -> None:
    cleanup_path = _clip_training_cleanup_path(temp_dir)
    if cleanup_path is None:
        return
    try:
        if cleanup_path.is_symlink():
            cleanup_path.unlink(missing_ok=True)
        elif cleanup_path.exists() and cleanup_path.is_dir():
            shutil.rmtree(cleanup_path, ignore_errors=True)
    except Exception:
        return


def _cleanup_job(job: ClipTrainingJob) -> None:
    _cleanup_clip_training_temp_dir(job.temp_dir)


def _publish_clip_training_artifacts(artifacts: TrainingArtifacts) -> TrainingArtifacts:
    classifiers_root = _safe_upload_subdir("classifiers", detail="classifiers_root_invalid")
    labelmaps_root = _safe_upload_subdir("labelmaps", detail="labelmaps_root_invalid")

    model_src = Path(artifacts.model_path).resolve()
    labelmap_src = Path(artifacts.labelmap_path).resolve()
    meta_src = Path(artifacts.meta_path).resolve()

    model_dst = classifiers_root / model_src.name
    labelmap_dst = labelmaps_root / labelmap_src.name
    meta_dst = classifiers_root / meta_src.name

    try:
        if model_src.exists():
            _link_or_copy_file(model_src, model_dst, overwrite=True)
            artifacts.model_path = str(model_dst)
    except Exception as exc:
        logger.warning("Failed to publish CLIP classifier %s: %s", model_src, exc)
    try:
        if meta_src.exists():
            _link_or_copy_file(meta_src, meta_dst, overwrite=True)
            artifacts.meta_path = str(meta_dst)
    except Exception as exc:
        logger.warning("Failed to publish CLIP meta %s: %s", meta_src, exc)
    try:
        if labelmap_src.exists():
            _link_or_copy_file(labelmap_src, labelmap_dst, overwrite=True)
            artifacts.labelmap_path = str(labelmap_dst)
    except Exception as exc:
        logger.warning("Failed to publish CLIP labelmap %s: %s", labelmap_src, exc)

    return artifacts


def _refresh_active_classifier_if_current(artifacts: TrainingArtifacts) -> bool:
    global clf, active_classifier_path, active_labelmap_path, active_label_list, clip_last_error
    global active_encoder_type, active_encoder_model
    global active_classifier_meta, active_head_normalize_embeddings, active_classifier_head

    if not active_classifier_path:
        return False
    try:
        model_path = Path(artifacts.model_path).resolve()
        current_path = Path(active_classifier_path).resolve()
    except Exception:
        return False
    if model_path != current_path:
        return False

    new_clf = _joblib_load(str(model_path))
    meta_obj: Dict[str, Any] = {}
    explicit_meta_path = Path(artifacts.meta_path) if artifacts.meta_path else None
    meta_path = (
        _safe_existing_regular_file_within_root_impl(explicit_meta_path, model_path.parent)
        if explicit_meta_path is not None and explicit_meta_path.name.endswith(".meta.pkl")
        else _safe_classifier_meta_path_impl(model_path)
    )
    if meta_path is not None:
        loaded_meta = _joblib_load(str(meta_path))
        if isinstance(loaded_meta, dict):
            meta_obj = dict(loaded_meta)

    labelmap_path = Path(artifacts.labelmap_path) if artifacts.labelmap_path else None
    labelmap_entries = _load_labelmap_file(labelmap_path, strict=True) if labelmap_path else []
    new_head = _load_clip_head_from_classifier_impl(
        model_path,
        joblib_load_fn=_joblib_load,
        http_exception_cls=HTTPException,
        clip_head_background_indices_fn=_clip_head_background_indices,
        resolve_head_normalize_embeddings_fn=_resolve_head_normalize_embeddings_impl,
        infer_clip_model_fn=_infer_clip_model_from_embedding_dim_impl,
        active_clip_model_name=clip_model_name,
        default_clip_model=DEFAULT_CLIP_MODEL,
        logger=logger,
    )

    with clip_lock:
        clf = new_clf
        active_classifier_path = str(model_path)
        if labelmap_path is not None:
            active_labelmap_path = str(labelmap_path.resolve())
            active_label_list = list(labelmap_entries)
        active_classifier_meta = meta_obj
        active_encoder_type = str(meta_obj.get("encoder_type") or "clip").strip().lower() or "clip"
        active_encoder_model = (
            str(meta_obj.get("encoder_model") or meta_obj.get("clip_model") or "").strip()
            or None
        )
        active_head_normalize_embeddings = _resolve_active_head_normalize_embeddings_impl(
            meta_obj,
            new_clf,
            default=True,
            resolve_head_normalize_embeddings_fn=_resolve_head_normalize_embeddings_impl,
        )
        active_classifier_head = new_head if isinstance(new_head, dict) else None
        clip_last_error = None
    logger.info("Refreshed active classifier artifacts from completed training: %s", model_path)
    return True


def _current_active_payload() -> Dict[str, Any]:
    head = _active_classifier_head_for_inference()
    encoder_ready = _active_encoder_ready()
    encoder_error = clip_last_error
    return {
        "clip_model": clip_model_name,
        "classifier_path": active_classifier_path,
        "labelmap_path": active_labelmap_path,
        "clip_ready": encoder_ready,
        "clip_error": clip_last_error,
        "clip_warnings": list(classifier_artifact_warnings),
        "labelmap_entries": list(active_label_list),
        "encoder_type": active_encoder_type,
        "encoder_model": active_encoder_model,
        "encoder_ready": encoder_ready,
        "encoder_error": encoder_error,
        "logit_adjustment_inference": (
            bool(head.get("logit_adjustment_inference"))
            if isinstance(head, dict)
            else None
        ),
    }


def _active_encoder_ready() -> bool:
    if clf is None:
        return False
    classifier_path = str(active_classifier_path or "").strip()
    if not classifier_path or not os.path.isfile(classifier_path):
        _clear_active_classifier_state("classifier_not_found")
        return False
    if str(active_encoder_type or "").strip().lower() == "dinov3":
        return bool(
            dinov3_initialized and dinov3_model is not None and dinov3_processor is not None
        )
    if str(active_encoder_type or "").strip().lower() == "cradio":
        return bool(
            cradio_initialized
            and _cradio_runtime_ready(cradio_model, cradio_processor, cradio_model_device)
        )
    return bool(clip_initialized and clip_model is not None and clip_preprocess is not None)


def _cradio_runtime_ready(model_obj: Any, processor_obj: Any, device_name: Optional[str]) -> bool:
    """C-RADIO MLX intentionally has no processor object; Torch backends do."""
    if model_obj is None:
        return False
    if processor_obj is not None:
        return True
    return str(device_name or "").strip().lower() == "mlx"


def _classifier_embedding_dim_multiplier(
    encoder_type: str,
    meta: Optional[Mapping[str, Any]],
) -> int:
    """Return the saved recipe's feature-width multiplier over the base encoder width."""
    meta_map = meta or {}
    multiplier = 1
    view_mode = _embedding_normalize_view_mode(meta_map.get("embedding_view_mode"))
    if view_mode != "single":
        multiplier *= 2
    encoder_type_norm = str(encoder_type or "clip").strip().lower()
    if encoder_type_norm == "dinov3":
        pooling = _embedding_normalize_dinov3_pooling(meta_map.get("dinov3_pooling"))
        if pooling == "cls_patch_concat":
            multiplier *= 2
    elif encoder_type_norm == "cradio":
        pooling = normalize_cradio_pooling(meta_map.get("cradio_pooling"))
        if pooling == "summary_spatial_concat":
            multiplier *= 2
    return max(1, int(multiplier))


def _classifier_base_dim_from_head_dim(
    head_dim: Optional[int],
    *,
    encoder_type: str,
    meta: Optional[Mapping[str, Any]],
) -> Optional[int]:
    if head_dim is None:
        return None
    try:
        dim = int(head_dim)
    except Exception:
        return None
    multiplier = _classifier_embedding_dim_multiplier(encoder_type, meta)
    if multiplier > 1 and dim > 0 and dim % multiplier == 0:
        return dim // multiplier
    return dim


def _classifier_expected_head_dim(
    base_dim: Optional[int],
    *,
    encoder_type: str,
    meta: Optional[Mapping[str, Any]],
) -> Optional[int]:
    if base_dim is None:
        return None
    try:
        dim = int(base_dim)
    except Exception:
        return None
    return dim * _classifier_embedding_dim_multiplier(encoder_type, meta)


def _classifier_cradio_base_dim(model_obj: Any) -> Optional[int]:
    candidates: List[Any] = []
    cfg = getattr(model_obj, "config", None)
    if cfg is not None:
        candidates.extend(
            [
                getattr(cfg, "hidden_size", None),
                getattr(cfg, "embed_dim", None),
                getattr(cfg, "projection_dim", None),
            ]
        )
    candidates.extend(
        [
            getattr(model_obj, "output_dim", None),
            getattr(model_obj, "embed_dim", None),
            getattr(model_obj, "hidden_size", None),
        ]
    )
    for candidate in candidates:
        try:
            value = candidate() if callable(candidate) else candidate
            dim = int(value)
        except Exception:
            continue
        if dim > 0:
            return dim
    return None


def predict_base64(payload: Base64Payload):
    # If CLIP/logreg not loaded, return error message in "prediction"
    if not _active_encoder_ready():
        return PredictResponse(
            prediction=str(ERROR_MESSAGE), uuid=None, error="clip_unavailable"
        )  # messy ... returning the error message int as str. Crap logic needs cleanup

    pil_img, _np_img, _token = _resolve_detector_image_impl(
        payload.image_base64,
        payload.image_token,
        fetch_preloaded_fn=_fetch_preloaded_image,
        decode_image_fn=lambda b64: _decode_image_base64_impl(
            b64,
            max_bytes=BASE64_IMAGE_MAX_BYTES,
            max_dim=BASE64_IMAGE_MAX_DIM,
            allow_downscale=True,
        ),
        store_preloaded_fn=_store_preloaded_image,
        hash_fn=lambda payload: hashlib.md5(payload).hexdigest(),
    )
    xyxy = None
    raw_bbox = getattr(payload, "bbox_xyxy", None)
    if raw_bbox is not None:
        try:
            values = [float(v) for v in list(raw_bbox)[:4]]
            if len(values) == 4:
                source_w = float(getattr(payload, "image_width", None) or pil_img.width)
                source_h = float(getattr(payload, "image_height", None) or pil_img.height)
                scale_x = (float(pil_img.width) / source_w) if source_w > 0 else 1.0
                scale_y = (float(pil_img.height) / source_h) if source_h > 0 else 1.0
                xyxy = [
                    values[0] * scale_x,
                    values[1] * scale_y,
                    values[2] * scale_x,
                    values[3] * scale_y,
                ]
        except Exception:
            xyxy = None
    if xyxy is None:
        xyxy = [0.0, 0.0, float(pil_img.width), float(pil_img.height)]
    feats_np = _encode_classifier_xyxy_for_active(pil_img, xyxy)
    if feats_np is None or not isinstance(feats_np, np.ndarray) or feats_np.size == 0:
        return PredictResponse(prediction=str(ERROR_MESSAGE), uuid=None, error="clip_unavailable")
    bg_guard = bool(payload.background_guard) if payload.background_guard is not None else False
    details = _clip_auto_predict_details(feats_np, background_guard=bg_guard)
    return PredictResponse(
        prediction=str(details.get("label") or "unknown"),
        proba=details.get("proba"),
        second_label=details.get("second_label"),
        second_proba=details.get("second_proba"),
        margin=details.get("margin"),
        error=details.get("error"),
        uuid=payload.uuid,
    )


app.include_router(
    build_predict_base64_router(
        predict_fn=predict_base64,
        request_cls=Base64Payload,
        response_cls=PredictResponse,
    )
)


