def download_yolo_run(run_id: str):
    run_dir = _yolo_run_dir_impl(
        run_id,
        create=False,
        job_root=YOLO_JOB_ROOT,
        sanitize_fn=_sanitize_yolo_run_id_impl,
        http_exception_cls=HTTPException,
    )
    if not run_dir.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="yolo_run_not_found")
    meta = _yolo_load_run_meta_impl(run_dir, meta_name=YOLO_RUN_META_NAME)
    run_name = meta.get("config", {}).get("run_name") or meta.get("job_id") or run_id
    safe_name = _sanitize_yolo_run_id_impl(run_name)
    buffer = io.BytesIO()
    with zipfile.ZipFile(buffer, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        keep_files = set(YOLO_KEEP_FILES)
        if meta.get("head_graft"):
            for yaml_path in run_dir.glob("*.yaml"):
                keep_files.add(yaml_path.name)
        for filename in sorted(keep_files):
            path = run_dir / filename
            _zip_write_safe_file(zf, path, run_dir, filename)
    buffer.seek(0)
    headers = {"Content-Disposition": f'attachment; filename="{safe_name}.zip"'}
    return StreamingResponse(buffer, media_type="application/zip", headers=headers)


def download_yolo_head_graft_bundle(job_id: str):
    run_dir = _yolo_run_dir_impl(
        job_id,
        create=False,
        job_root=YOLO_JOB_ROOT,
        sanitize_fn=_sanitize_yolo_run_id_impl,
        http_exception_cls=HTTPException,
    )
    if not run_dir.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="yolo_run_not_found")
    meta = _yolo_load_run_meta_impl(run_dir, meta_name=YOLO_RUN_META_NAME)
    if not meta.get("head_graft"):
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="yolo_head_graft_not_found")
    run_name = meta.get("config", {}).get("run_name") or meta.get("job_id") or job_id
    safe_name = _sanitize_yolo_run_id_impl(run_name)
    required = {"best.pt", "labelmap.txt", "head_graft_audit.jsonl", YOLO_RUN_META_NAME}
    missing = [
        name
        for name in sorted(required)
        if not _safe_regular_file_within_root(run_dir / name, run_dir)
    ]
    if missing:
        raise HTTPException(
            status_code=HTTP_412_PRECONDITION_FAILED,
            detail={"error": "yolo_head_graft_bundle_incomplete", "missing": missing},
        )
    buffer = io.BytesIO()
    with zipfile.ZipFile(buffer, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        for filename in sorted(required):
            path = run_dir / filename
            _zip_write_safe_file(zf, path, run_dir, filename)
        for yaml_path in sorted(run_dir.glob("*.yaml")):
            _zip_write_safe_file(zf, yaml_path, run_dir, yaml_path.name)
    buffer.seek(0)
    headers = {"Content-Disposition": f'attachment; filename="{safe_name}_head_graft_bundle.zip"'}
    return StreamingResponse(buffer, media_type="application/zip", headers=headers)


def delete_yolo_run(run_id: str):
    run_dir = _yolo_run_dir_impl(
        run_id,
        create=False,
        job_root=YOLO_JOB_ROOT,
        sanitize_fn=_sanitize_yolo_run_id_impl,
        http_exception_cls=HTTPException,
    )
    if not run_dir.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="yolo_run_not_found")
    blocking_registry = _active_job_registry_blocking_run_delete(
        run_id,
        run_dir,
        [
            ("yolo_training", YOLO_TRAINING_JOBS, YOLO_TRAINING_JOBS_LOCK),
            ("yolo_head_graft", YOLO_HEAD_GRAFT_JOBS, YOLO_HEAD_GRAFT_JOBS_LOCK),
        ],
    )
    if blocking_registry:
        raise HTTPException(
            status_code=HTTP_409_CONFLICT,
            detail=f"yolo_run_delete_blocked_active_jobs:{blocking_registry}",
        )
    active = _load_detector_active_payload_raw(YOLO_ACTIVE_PATH)
    active_best = str(active.get("best_path") or "")
    active_matches = str(active.get("run_id") or "") == str(run_id)
    if not active_matches and active_best:
        try:
            active_matches = _path_is_within_root_impl(
                Path(active_best).resolve(strict=False),
                run_dir.resolve(strict=False),
            )
        except Exception:
            active_matches = False
    try:
        shutil.rmtree(run_dir)
    except Exception as exc:  # noqa: BLE001
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=str(exc)) from exc
    if active_matches:
        try:
            YOLO_ACTIVE_PATH.unlink(missing_ok=True)
        except Exception:
            pass
        _clear_yolo_infer_state()
    return {"status": "deleted", "run_id": run_id}


