def _builtin_qwen_model_entries() -> List[Dict[str, Any]]:
    default_entry = {
        "id": "default",
        "label": "Base Qwen 3",
        "type": "builtin",
        "metadata": _default_qwen_metadata(),
        "path": None,
        "created_at": None,
    }
    transformers_entries: List[Dict[str, Any]] = []
    for entry in QWEN_TRANSFORMERS_MODEL_OPTIONS:
        model_id = str(entry.get("id") or entry.get("model_id") or "")
        training_supported = bool(entry.get("training_supported", True))
        metadata = {
            "id": model_id,
            "label": str(entry.get("label") or model_id),
            "system_prompt": DEFAULT_SYSTEM_PROMPT,
            "dataset_context": str(entry.get("dataset_context") or "Qwen3-VL Transformer model."),
            "classes": [],
            "model_id": model_id,
            "model_family": "qwen3",
            "source": str(entry.get("source") or "huggingface"),
            "runtime_platform": QWEN_PLATFORM_TRANSFORMERS,
            "quantization": entry.get("quantization"),
            "quantization_backend": entry.get("quantization_backend"),
            "quantized": bool(entry.get("quantized")),
            "abliterated": bool(entry.get("abliterated")),
            "variant": entry.get("variant"),
            "size": entry.get("size"),
            "training_supported": training_supported,
            "training_modes": list(
                entry.get("training_modes")
                or (["official_lora", "trl_qlora"] if training_supported else [])
            ),
            "training_model_id": entry.get("training_model_id") or model_id,
            "training_note": entry.get("training_note"),
            "min_pixels": QWEN_MIN_PIXELS,
            "max_pixels": QWEN_MAX_PIXELS,
        }
        transformers_entries.append(
            {
                "id": model_id,
                "label": str(entry.get("label") or model_id),
                "type": "builtin_transformers",
                "metadata": metadata,
                "path": None,
                "created_at": None,
            }
        )
    mlx_entries: List[Dict[str, Any]] = []
    for entry in QWEN_MLX_MODEL_OPTIONS:
        model_id = str(entry.get("id") or entry.get("model_id") or "")
        vision_supported = entry.get("vision_inference_supported", True) is not False
        training_supported = bool(entry.get("training_supported", True)) and vision_supported
        default_training_note = (
            "MLX-VLM trains LoRA adapters directly on Apple Silicon. Quantized MLX checkpoints use "
            "the same adapter path as QLoRA-style training."
        )
        metadata = {
            "id": model_id,
            "label": str(entry.get("label") or model_id),
            "system_prompt": DEFAULT_SYSTEM_PROMPT,
            "dataset_context": "MLX quantized Qwen3-VL model for Apple Silicon inference.",
            "classes": [],
            "model_id": model_id,
            "model_family": "qwen3",
            "source": str(entry.get("source") or "mlx-community"),
            "runtime_platform": QWEN_PLATFORM_MLX,
            "quantization": entry.get("quantization"),
            "abliterated": bool(entry.get("abliterated")),
            "variant": entry.get("variant"),
            "size": entry.get("size"),
            "vision_inference_supported": vision_supported,
            "inference_supported": vision_supported,
            "compatibility_note": entry.get("compatibility_note"),
            "training_supported": training_supported,
            "training_modes": ["official_lora", "trl_qlora"] if training_supported else [],
            "training_model_id": model_id,
            "training_note": entry.get("training_note") or default_training_note,
            "min_pixels": QWEN_MIN_PIXELS,
            "max_pixels": QWEN_MAX_PIXELS,
        }
        mlx_entries.append(
            {
                "id": model_id,
                "label": str(entry.get("label") or model_id),
                "type": "builtin_mlx",
                "metadata": metadata,
                "path": None,
                "created_at": None,
            }
        )
    return [default_entry, *transformers_entries, *mlx_entries]


def _get_builtin_qwen_model_entry(model_id: str) -> Optional[Dict[str, Any]]:
    for entry in _builtin_qwen_model_entries():
        if str(entry.get("id")) == str(model_id):
            return entry
    return None


def list_qwen_models():
    _clear_unusable_active_qwen_model_path()
    entries = _list_qwen_model_entries()
    data = []
    for entry in _builtin_qwen_model_entries():
        entry["active"] = entry.get("id") == active_qwen_model_id
        metadata = entry.get("metadata") or {}
        if entry.get("type") == "builtin":
            platform_name = _resolve_qwen_runtime_platform(
                metadata.get("model_id") or entry.get("id"),
                metadata=metadata,
            )
        else:
            platform_name = metadata.get("runtime_platform") or _resolve_qwen_runtime_platform(
                metadata.get("model_id") or entry.get("id"),
                metadata=metadata,
            )
        availability = _qwen_model_local_state(
            metadata.get("model_id") or entry.get("id"),
            platform_name,
            entry_path=entry.get("path"),
        )
        if entry.get("type") == "builtin_mlx" and isinstance(metadata, dict):
            cached_incompatible = _qwen_mlx_cached_checkpoint_incompatibility_detail(
                str(metadata.get("model_id") or entry.get("id")),
                availability,
            )
            if cached_incompatible:
                metadata["vision_inference_supported"] = False
                metadata["inference_supported"] = False
                metadata["training_supported"] = False
                metadata["training_modes"] = []
                metadata["compatibility_note"] = cached_incompatible
                metadata["training_note"] = cached_incompatible
        entry["availability"] = availability
        if isinstance(metadata, dict):
            metadata["availability"] = availability
        data.append(entry)
    for entry in entries:
        entry["active"] = entry.get("id") == active_qwen_model_id
        metadata = entry.get("metadata") or {}
        platform_name = metadata.get("runtime_platform") or _resolve_qwen_runtime_platform(
            metadata.get("model_id") or entry.get("id"),
            adapter_path=Path(entry["path"]) if entry.get("path") else None,
            metadata=metadata,
        )
        availability = _qwen_model_local_state(
            metadata.get("model_id") or entry.get("id"),
            platform_name,
            entry_path=entry.get("path"),
        )
        entry["availability"] = availability
        if isinstance(metadata, dict):
            metadata["availability"] = availability
        data.append(entry)
    return {
        "active": active_qwen_model_id,
        "models": data,
        "memory": _qwen_memory_snapshot(),
        "progress": qwen_progress(),
    }


def activate_qwen_model(payload: QwenModelActivateRequest):
    model_id = (payload.model_id or "").strip()
    if not model_id:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="model_id_required")
    if model_id == "default":
        _set_active_qwen_model_default()
    else:
        builtin = _get_builtin_qwen_model_entry(model_id)
        if builtin and builtin.get("type") in {"builtin_mlx", "builtin_transformers"}:
            fallback_metadata = (
                qwen_mlx_metadata_for_model(model_id)
                if builtin.get("type") == "builtin_mlx"
                else qwen_transformers_metadata_for_model(model_id)
            )
            metadata = builtin.get("metadata") or fallback_metadata
            if builtin.get("type") == "builtin_mlx" and (
                metadata.get("vision_inference_supported") is False
                or metadata.get("inference_supported") is False
            ):
                note = str(metadata.get("compatibility_note") or "").strip()
                if not note:
                    note = "Selected MLX checkpoint is not compatible with image inference."
                raise HTTPException(
                    status_code=HTTP_400_BAD_REQUEST,
                    detail=f"qwen_mlx_incompatible_checkpoint:{model_id}: {note}",
                )
            _set_active_qwen_model_builtin(model_id, metadata)
        else:
            entry = _get_qwen_model_entry(model_id)
            if not entry:
                raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="qwen_model_not_found")
            latest = entry.get("path")
            if not latest or not _qwen_checkpoint_is_usable(
                Path(latest), entry.get("metadata") or {}
            ):
                raise HTTPException(
                    status_code=HTTP_404_NOT_FOUND, detail="qwen_model_missing_checkpoint"
                )
            _set_active_qwen_model_custom(model_id, Path(latest), entry.get("metadata") or {})
    return {
        "active": active_qwen_model_id,
        "metadata": active_qwen_metadata,
    }


app.include_router(
    build_qwen_models_router(
        list_models_fn=list_qwen_models,
        activate_fn=activate_qwen_model,
        activate_cls=QwenModelActivateRequest,
    )
)


