def start_calibration_job(payload: CalibrationRequest = Body(...)):
    labelmap, _glossary = _agent_load_labelmap_meta(payload.dataset_id)
    if not labelmap:
        raise HTTPException(status_code=HTTP_400_BAD_REQUEST, detail="calibration_labelmap_missing")
    images = _calibration_list_images(payload.dataset_id)
    if not images:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_images_missing")
    job = _start_calibration_job_impl(
        payload,
        job_cls=CalibrationJob,
        jobs=CALIBRATION_JOBS,
        jobs_lock=CALIBRATION_JOBS_LOCK,
        run_job_fn=_calibration_run_job,
        calibration_root=CALIBRATION_ROOT,
    )
    return _serialize_calibration_job_impl(job)


def list_calibration_jobs():
    _prune_job_registry(CALIBRATION_JOBS, CALIBRATION_JOBS_LOCK)
    with CALIBRATION_JOBS_LOCK:
        live_jobs = {
            job_id: _serialize_calibration_job_impl(job)
            for job_id, job in CALIBRATION_JOBS.items()
        }
    jobs_by_id = {}
    for payload in _list_persisted_calibration_job_payloads_impl(
        CALIBRATION_ROOT,
        mark_interrupted=False,
    ):
        if not isinstance(payload, dict):
            continue
        persisted_job_id = str(payload.get("job_id") or "").strip()
        if not persisted_job_id:
            continue
        if persisted_job_id not in live_jobs and str(payload.get("status") or "") in {"queued", "running"}:
            payload = _load_persisted_calibration_job_payload_impl(
                CALIBRATION_ROOT,
                persisted_job_id,
                mark_interrupted=True,
            ) or payload
        jobs_by_id[persisted_job_id] = payload
    for payload in _list_canonical_deployment_jobs_impl(CALIBRATION_ROOT):
        if not isinstance(payload, dict):
            continue
        bundle_job_id = str(payload.get("job_id") or "").strip()
        if not bundle_job_id:
            continue
        jobs_by_id.setdefault(bundle_job_id, payload)
    jobs_by_id.update(live_jobs)
    jobs = list(jobs_by_id.values())
    jobs.sort(key=lambda j: float(j.get("created_at") or 0.0), reverse=True)
    return jobs


def get_calibration_job(job_id: str):
    with CALIBRATION_JOBS_LOCK:
        job = CALIBRATION_JOBS.get(job_id)
    if job:
        return _serialize_calibration_job_impl(job)
    persisted = _load_persisted_calibration_job_payload_impl(
        CALIBRATION_ROOT,
        job_id,
        mark_interrupted=True,
    )
    if persisted:
        return persisted
    canonical_bundle = _get_canonical_deployment_job_impl(CALIBRATION_ROOT, job_id)
    if canonical_bundle:
        return canonical_bundle
    raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")


def cancel_calibration_job(job_id: str):
    with CALIBRATION_JOBS_LOCK:
        job = CALIBRATION_JOBS.get(job_id)
    if job:
        job = _cancel_calibration_job_impl(
            job_id,
            jobs=CALIBRATION_JOBS,
            jobs_lock=CALIBRATION_JOBS_LOCK,
            http_exception_cls=HTTPException,
            time_fn=time.time,
        )
        return _serialize_calibration_job_impl(job)
    persisted = _load_persisted_calibration_job_payload_impl(
        CALIBRATION_ROOT,
        job_id,
        mark_interrupted=True,
    )
    if persisted:
        return persisted
    raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")


def get_calibration_report_bundle(job_id: str):
    safe_job_id = _sanitize_yolo_run_id_impl(str(job_id)) or str(job_id)
    if safe_job_id != str(job_id):
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")
    try:
        calibration_root = _resolve_calibration_storage_root_impl(CALIBRATION_ROOT)
    except ValueError as exc:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found") from exc
    job_dir_raw = calibration_root / safe_job_id
    if job_dir_raw.is_symlink() or _storage_path_has_symlink_component(job_dir_raw.parent):
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")
    job_dir = job_dir_raw.resolve(strict=False)
    if not _path_is_within_root_impl(job_dir, calibration_root) or job_dir.parent != calibration_root:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")

    def _resolve_job_report_path(candidate_raw: Path) -> Optional[Path]:
        try:
            raw = candidate_raw if candidate_raw.is_absolute() else job_dir_raw / candidate_raw
            if raw.is_symlink() or _storage_path_has_symlink_component(raw.parent):
                return None
            resolved = raw.resolve(strict=False)
        except Exception:
            return None
        if not _path_is_within_root_impl(resolved, job_dir):
            return None
        return resolved

    path = _resolve_job_report_path(job_dir_raw / "report_bundle.json")
    if path is None:
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")
    if not path.exists():
        with CALIBRATION_JOBS_LOCK:
            job = CALIBRATION_JOBS.get(job_id)
        if not job:
            raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")
        result = job.result if isinstance(job.result, dict) else {}
        report_path = result.get("report_bundle_json")
        if report_path:
            resolved_report_path = _resolve_job_report_path(Path(str(report_path)))
            if resolved_report_path is None:
                raise HTTPException(
                    status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found"
                )
            path = resolved_report_path
        if not _path_is_within_root_impl(path, job_dir):
            raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_job_not_found")
    if not path.exists():
        raise HTTPException(status_code=HTTP_404_NOT_FOUND, detail="calibration_report_bundle_not_found")
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=HTTP_500_INTERNAL_SERVER_ERROR, detail=f"calibration_report_bundle_unreadable:{exc}") from exc


